import type { VercelRequest, VercelResponse } from '@vercel/node';
import * as firebaseAdmin from 'firebase-admin';

// Tratamento para o empacotador da Vercel
const admin = firebaseAdmin.default || firebaseAdmin;

// Inicialização segura com Cold Start
try {
  if (!admin.apps?.length) {
    const privateKey = process.env.FIREBASE_PRIVATE_KEY
      ? process.env.FIREBASE_PRIVATE_KEY.replace(/\\n/g, '\n').replace(/"/g, '')
      : undefined;

    if (privateKey && process.env.FIREBASE_PROJECT_ID) {
      admin.initializeApp({
        credential: admin.credential.cert({
          projectId: process.env.FIREBASE_PROJECT_ID,
          clientEmail: process.env.FIREBASE_CLIENT_EMAIL,
          privateKey: privateKey,
        }),
      });
    }
  }
} catch (error) {
  console.error("Crash no Firebase Init:", error);
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  try {
    const { courseId } = req.query;

    if (!courseId || typeof courseId !== 'string') {
      return res.status(400).json({ success: false, error: 'ID do curso inválido' });
    }

    const db = admin.firestore();

    // 1. Busca Matrículas Diretas (Coleção course_enrollments)
    const directEnrollmentsSnap = await db.collection('course_enrollments')
      .where('courseId', '==', courseId)
      .get();

    const directEnrollments = directEnrollmentsSnap.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));

    // 2. Busca Alunos para verificar acesso via Combo (Coleção users -> array access)
    // Buscamos alunos ativos para filtrar em memória os que possuem o curso no array 'access'
    const studentsSnap = await db.collection('users')
      .where('role', '==', 'student')
      .get();

    const studentMap = new Map<string, any>();

    // Parte A: Processar alunos que ganharam acesso via Combo/Produto
    studentsSnap.docs.forEach(doc => {
      const userData = doc.data();
      const accessArray = userData.access || [];

      // Verifica se existe um item de acesso do tipo 'course' para este courseId e que esteja ativo
      const courseAccess = accessArray.find((acc: any) => 
        acc.type === 'course' && 
        acc.targetId === courseId && 
        acc.isActive === true
      );

      if (courseAccess) {
        studentMap.set(doc.id, {
          id: doc.id,
          userId: doc.id,
          userName: userData.name || userData.displayName || 'Sem Nome',
          userEmail: userData.email || '',
          userPhone: userData.phone || userData.whatsapp || userData.contact || '',
          userCpf: userData.cpf || '',
          userAvatar: userData.photoURL || '',
          enrollmentType: (courseAccess.id && String(courseAccess.id).startsWith('mig_')) ? 'MIGRACAO' : 'REGULAR',
          accessOrigin: (courseAccess.id && String(courseAccess.id).startsWith('mig_')) ? 'MIGRATION' : 'COMBO',
          expiresAt: courseAccess.endDate ? (courseAccess.endDate.toDate ? courseAccess.endDate.toDate().toISOString() : courseAccess.endDate) : null,
          releasedAt: courseAccess.startDate ? (courseAccess.startDate.toDate ? courseAccess.startDate.toDate().toISOString() : courseAccess.startDate) : (userData.createdAt?.toDate ? userData.createdAt.toDate().toISOString() : userData.createdAt),
          active: courseAccess.isActive !== false
        });
      }
    });

    // Parte B: Processar Matrículas Diretas (Sobrescrevendo ou complementando)
    for (const enrollment of directEnrollments) {
      const userId = (enrollment as any).userId;
      if (!userId) continue;

      let userProfile = studentMap.get(userId);

      if (!userProfile) {
        // Busca no snap de usuários carregados
        const userDoc = studentsSnap.docs.find(d => d.id === userId);
        if (userDoc) {
          const userData = userDoc.data();
          userProfile = { 
            id: userDoc.id,
            userId: userDoc.id,
            userName: userData.name || userData.displayName || 'Sem Nome',
            userEmail: userData.email || '',
            userPhone: userData.phone || userData.whatsapp || userData.contact || '',
            userCpf: userData.cpf || '',
            userAvatar: userData.photoURL || '',
            createdAt: userData.createdAt
          };
        } else {
          // Se não encontrou no snap (ex: role não é 'student'), busca no Firestore
          const docRef = await db.collection('users').doc(userId).get();
          if (docRef.exists) {
            const userData = docRef.data() || {};
            userProfile = { 
              id: docRef.id,
              userId: docRef.id,
              userName: userData.name || userData.displayName || 'Sem Nome',
              userEmail: userData.email || '',
              userPhone: userData.phone || userData.whatsapp || userData.contact || '',
              userCpf: userData.cpf || '',
              userAvatar: userData.photoURL || '',
              createdAt: userData.createdAt
            };
          }
        }
      }

      if (userProfile) {
        studentMap.set(userId, {
          ...userProfile,
          enrollmentType: (enrollment as any).enrollmentType || 'REGULAR',
          accessOrigin: 'DIRECT',
          expiresAt: (enrollment as any).expiresAt ? ((enrollment as any).expiresAt.toDate ? (enrollment as any).expiresAt.toDate().toISOString() : (enrollment as any).expiresAt) : null,
          releasedAt: (enrollment as any).releasedAt ? ((enrollment as any).releasedAt.toDate ? (enrollment as any).releasedAt.toDate().toISOString() : (enrollment as any).releasedAt) : ((enrollment as any).createdAt ? ((enrollment as any).createdAt.toDate ? (enrollment as any).createdAt.toDate().toISOString() : (enrollment as any).createdAt) : (userProfile.createdAt?.toDate ? userProfile.createdAt.toDate().toISOString() : userProfile.createdAt)),
          active: (enrollment as any).active !== false
        });
      }
    }

    const aggregatedStudents = Array.from(studentMap.values());

    // 6. Retorno
    return res.status(200).json({ success: true, students: aggregatedStudents });

  } catch (error) {
    console.error("Erro ao buscar alunos do curso:", error);
    return res.status(500).json({ success: false, error: 'Erro interno ao buscar alunos' });
  }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import * as firebaseAdmin from 'firebase-admin';
import { fetchPandaVideoTranscription } from '../src/backend/services/pandaVideoService.js';
import { generateStudyMaterial } from '../src/backend/services/geminiService.js';

// Correção ESM/CJS: Garante que pegamos o objeto correto na Vercel
const admin = (firebaseAdmin as any).default || firebaseAdmin;

export const maxDuration = 60;

// Inicialização segura no topo (aproveitando o Cold Start)
try {
  if (!admin.apps?.length) {
    const privateKey = process.env.FIREBASE_PRIVATE_KEY
      ? process.env.FIREBASE_PRIVATE_KEY.replace(/\\n/g, '\n').replace(/"/g, '')
      : undefined;

    if (privateKey && process.env.FIREBASE_PROJECT_ID) {
      admin.initializeApp({
        credential: admin.credential.cert({
          projectId: process.env.FIREBASE_PROJECT_ID,
          clientEmail: process.env.FIREBASE_CLIENT_EMAIL,
          privateKey: privateKey,
        }),
      });
    }
  }
} catch (error) {
  console.error("🔴 CRASH GLOBAL NO FIREBASE INIT:", error);
}

const dbAdmin = admin.firestore();

/**
 * Função auxiliar para extrair o ID do Panda Video de uma URL
 */
function extractPandaId(url: string): string | null {
  try {
    if (!url) return null;
    if (!url.includes('http')) return url.split('?v=')[1] || url.split('/embed/')[1] || url.split('/video/')[1] || url;

    const urlObj = new URL(url);
    const v = urlObj.searchParams.get('v');
    if (v) return v;

    const pathParts = urlObj.pathname.split('/').filter(Boolean);
    // Se a URL for do tipo .../embed/ID ou .../video/ID
    if (url.includes('/embed/') || url.includes('/video/')) {
      return pathParts[pathParts.length - 1];
    }

    return pathParts[pathParts.length - 1] || url;
  } catch {
    return url;
  }
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  // Apenas aceita requisições POST
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Método não permitido' });
  }

  try {
    const { lessonIds, folderTitle } = req.body;

    // Validações básicas
    if (!lessonIds || !Array.isArray(lessonIds) || lessonIds.length === 0) {
      return res.status(400).json({ success: false, error: 'IDs das aulas (lessonIds) são obrigatórios.' });
    }

    if (!folderTitle) {
      return res.status(400).json({ success: false, error: 'folderTitle é obrigatório.' });
    }

    const pandaVideoIds: string[] = [];

    // 1. Buscar os conteúdos das aulas no Firestore
    for (const lessonId of lessonIds) {
      try {
        const snapshot = await dbAdmin.collection('course_contents')
          .where('lessonId', '==', lessonId)
          .get();

        snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (data.type === 'video' && data.videoPlatform === 'panda' && data.videoUrl) {
            const pandaId = extractPandaId(data.videoUrl);
            if (pandaId && !pandaVideoIds.includes(pandaId)) {
              pandaVideoIds.push(pandaId);
            }
          }
        });
      } catch (err) {
        console.error(`Erro ao buscar conteúdos da aula ${lessonId}:`, err);
      }
    }

    if (pandaVideoIds.length === 0) {
      return res.status(404).json({ 
        success: false, 
        error: 'Nenhum vídeo do Panda Video encontrado nas aulas selecionadas.' 
      });
    }

    // 2. Extrair transcrições de todos os vídeos encontrados
    let fullTranscription = '';
    for (const videoId of pandaVideoIds) {
      try {
        const transcription = await fetchPandaVideoTranscription(videoId);
        fullTranscription += transcription + '\n\n';
      } catch (error) {
        console.error(`Erro ao extrair transcrição do vídeo ${videoId}:`, error);
      }
    }

    if (!fullTranscription.trim()) {
      return res.status(404).json({ 
        success: false, 
        error: 'Não foi possível extrair nenhuma transcrição dos vídeos selecionados.' 
      });
    }

    const geminiKey = process.env.MINHA_CHAVE_GEMINI;
    if (!geminiKey) {
      throw new Error("A variável MINHA_CHAVE_GEMINI não foi encontrada no servidor.");
    }

    // 3. Gerar material didático usando o Gemini
    const generatedText = await generateStudyMaterial(fullTranscription, folderTitle);

    // 4. Retornar o material gerado
    return res.status(200).json({ 
      success: true, 
      markdown: generatedText 
    });

  } catch (error) {
    console.error("Erro crítico na geração de material didático:", error);
    return res.status(500).json({ 
      success: false, 
      error: error instanceof Error ? error.message : "Erro interno no servidor ao processar IA." 
    });
  }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';

interface PandaVideo {
  id: string;
  video_id?: string;
  title: string;
  name?: string;
  folder_id?: string | null;
  folderId?: string | null;
  video_player_url?: string;
  embed_url?: string;
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'GET') return res.status(405).end();

  try {
    const apiKey = process.env.PANDA_API_KEY;
    if (!apiKey) {
      return res.status(500).json({ success: false, error: "PANDA_API_KEY não configurada no ambiente." });
    }

    const search = req.query.search as string;

    let url = 'https://api-v2.pandavideo.com.br/videos?limit=1000';
    if (search) {
      url += `&title=${encodeURIComponent(search)}`;
    }

    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'Authorization': apiKey,
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`Erro na API do Panda: ${response.status}`);
    }

    const data = await response.json();
    const videos = data.videos || data || [];

    const cleanVideos = Array.isArray(videos) ? videos.map((v: any) => ({
      id: v.id,
      video_id: v.video_id || v.id,
      panda_id: v.video_id || v.id,
      external_id: v.external_id || null,
      playback_id: v.playback_id || null,
      title: v.title || v.name || 'Sem título',
      video_player_url: v.video_player_url || v.embed_url || null
    })) : [];

    return res.status(200).json({ success: true, videos: cleanVideos });
  } catch (error) {
    console.error("Erro ao listar vídeos do Panda:", error);
    return res.status(500).json({ success: false, error: "Falha ao carregar vídeos do Panda." });
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Users, UserCheck, UserPlus, GraduationCap, MessageCircle, ExternalLink, Search, Link as LinkIcon, X, Copy, Check, RefreshCw } from 'lucide-react';
import { CourseEnrollment } from '../../../types/course';
import { differenceInDays, parseISO, format } from 'date-fns';
import toast from 'react-hot-toast';

interface AdminCourseStudentsTabProps {
  courseId: string;
}

export function AdminCourseStudentsTab({ courseId }: AdminCourseStudentsTabProps) {
  const [enrollments, setEnrollments] = useState<CourseEnrollment[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<'ALL' | 'REGULAR' | 'MIGRACAO' | 'BOLSISTA'>('ALL');
  const [showMigrationModal, setShowMigrationModal] = useState(false);
  const [migrationConfig, setMigrationConfig] = useState({
    expiresAt: format(new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), 'yyyy-MM-dd'),
    accessDurationDays: 365
  });
  const [generatedLink, setGeneratedLink] = useState<{ id: string; url: string; embed: string } | null>(null);
  const [isCreatingLink, setIsCreatingLink] = useState(false);

  // Métricas
  const [metrics, setMetrics] = useState({
    total: 0,
    regular: 0,
    migration: 0,
    scholarship: 0
  });

  const fetchLock = useRef(''); // Armazena o ID do curso já carregado

  const loadStudents = useCallback(async () => {
    if (!courseId) return;
    setLoading(true);
    try {
      fetchLock.current = courseId;
      const response = await fetch(`/api/admin/courses/${courseId}/students`);
      const data = await response.json();

      if (data.success) {
        const realStudents = (data.students || []) as CourseEnrollment[];

        // Ordenação Alfabética Real (Defensiva)
        realStudents.sort((a, b) => (a?.userName || '').localeCompare(b?.userName || ''));

        setEnrollments(realStudents);

        // Cálculo Dinâmico das Métricas
        setMetrics({
          total: realStudents.length,
          regular: realStudents.filter(s => s?.enrollmentType === 'REGULAR' || !s?.enrollmentType).length,
          migration: realStudents.filter(s => s?.enrollmentType === 'MIGRACAO').length,
          scholarship: realStudents.filter(s => s?.enrollmentType === 'BOLSISTA').length
        });
      }
    } catch (error) {
      fetchLock.current = ''; // Destranca em caso de erro para permitir retry
      console.error("Erro ao buscar alunos reais:", error);
    } finally {
      setLoading(false);
    }
  }, [courseId]);

  useEffect(() => {
    // Se não tem ID, ou se o ID atual já foi carregado, aborta (quebra o loop)
    if (!courseId || fetchLock.current === courseId) return;

    loadStudents();

    // Cleanup: Reseta o lock ao sair da aba, forçando um novo fetch ao voltar
    return () => { fetchLock.current = ''; };
  }, [courseId, loadStudents]);

  const handleSync = () => {
    fetchLock.current = '';
    loadStudents();
  };

  // Formatação de CPF
  const formatCPF = (cpf?: string) => {
    if (!cpf) return '---';
    const clean = cpf.replace(/\D/g, '');
    return clean.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, "$1.$2.$3-$4");
  };

  // Link WhatsApp
  const getWhatsAppLink = (phone?: string) => {
    if (!phone) return null;
    const clean = phone.replace(/\D/g, '');
    return `https://wa.me/55${clean}`;
  };

  // Cálculo de dias restantes
  const getRemainingDays = (expiresAt?: string) => {
    if (!expiresAt) return { label: 'Sem validade', color: 'text-zinc-500' };
    const now = new Date();
    try {
      const expiration = parseISO(expiresAt);
      const days = differenceInDays(expiration, now);

      if (days < 0) return { label: 'Expirado', color: 'text-red-500' };
      if (days === 0) return { label: 'Expira hoje', color: 'text-orange-500' };
      return { label: `${days} dias restantes`, color: 'text-emerald-400' };
    } catch (e) {
      return { label: 'Data inválida', color: 'text-zinc-500' };
    }
  };

  const filteredEnrollments = (enrollments || []).filter(e => {
    const searchLower = (searchTerm || '').toLowerCase();
    const matchName = (e?.userName || '').toLowerCase().includes(searchLower);
    const matchEmail = (e?.userEmail || '').toLowerCase().includes(searchLower);
    const matchCpf = (e?.userCpf || '').includes(searchTerm);

    const matchesSearch = matchName || matchEmail || matchCpf;
    const matchesFilter = filterType === 'ALL' || e.enrollmentType === filterType;
    return matchesSearch && matchesFilter;
  });

  const handleCreateMigrationLink = async () => {
    setIsCreatingLink(true);
    try {
      const response = await fetch(`/api/admin/courses/${courseId}/migration-links`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          expiresAt: migrationConfig.expiresAt,
          accessDurationDays: migrationConfig.accessDurationDays
        })
      });
      const data = await response.json();
      if (data.success) {
        const fullUrl = `${window.location.origin}${data.link}`;
        setGeneratedLink({
          id: data.id,
          url: fullUrl,
          embed: `<iframe src="${fullUrl}" width="100%" height="600px" frameborder="0"></iframe>`
        });
        toast.success('Link de migração gerado!');
      } else {
        toast.error(data.error || 'Erro ao gerar link');
      }
    } catch (error) {
      console.error("Erro ao criar link:", error);
      toast.error('Erro de conexão');
    } finally {
      setIsCreatingLink(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success('Copiado para a área de transferência!');
  };

  if (loading) {
    return (
      <div className="flex justify-center py-20">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-red-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-zinc-900/50 border border-zinc-800 p-4 rounded-xl flex items-center gap-4">
          <div className="p-3 bg-zinc-800 rounded-lg text-white">
            <Users size={24} />
          </div>
          <div>
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Total Alunos</p>
            <h3 className="text-2xl font-black text-white">{metrics.total}</h3>
          </div>
        </div>

        <div className="bg-zinc-900/50 border border-zinc-800 p-4 rounded-xl flex items-center gap-4">
          <div className="p-3 bg-emerald-500/10 rounded-lg text-emerald-500">
            <UserCheck size={24} />
          </div>
          <div>
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Regulares</p>
            <h3 className="text-2xl font-black text-white">{metrics.regular}</h3>
          </div>
        </div>

        <div className="bg-zinc-900/50 border border-zinc-800 p-4 rounded-xl flex items-center gap-4">
          <div className="p-3 bg-blue-500/10 rounded-lg text-blue-500">
            <UserPlus size={24} />
          </div>
          <div>
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Migração</p>
            <h3 className="text-2xl font-black text-white">{metrics.migration}</h3>
          </div>
        </div>

        <div className="bg-zinc-900/50 border border-zinc-800 p-4 rounded-xl flex items-center gap-4">
          <div className="p-3 bg-purple-500/10 rounded-lg text-purple-500">
            <GraduationCap size={24} />
          </div>
          <div>
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Bolsistas</p>
            <h3 className="text-2xl font-black text-white">{metrics.scholarship}</h3>
          </div>
        </div>
      </div>

      {/* Filters and Search */}
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-zinc-900/30 p-4 rounded-xl border border-zinc-800/50">
        <div className="flex flex-col md:flex-row gap-4 items-center w-full md:w-auto">
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={18} />
            <input 
              type="text"
              placeholder="Buscar por nome, email ou CPF..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-2 pl-10 pr-4 text-sm text-white focus:outline-none focus:border-red-600 transition-colors"
            />
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button
              onClick={handleSync}
              className="flex items-center gap-2 px-4 py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-bold uppercase tracking-wider transition-all border border-zinc-700 justify-center"
              title="Sincronizar dados"
            >
              <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
              Sincronizar
            </button>
            <button
              onClick={() => setShowMigrationModal(true)}
              className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold uppercase tracking-wider transition-all shadow-lg shadow-blue-900/20 w-full md:w-auto justify-center"
            >
              <LinkIcon size={16} />
              Cadastrar Link de Migração
            </button>
          </div>
        </div>

        <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
          {(['ALL', 'REGULAR', 'MIGRACAO', 'BOLSISTA'] as const).map((type) => (
            <button
              key={type}
              onClick={() => setFilterType(type)}
              className={`px-4 py-2 rounded-lg text-[10px] font-bold uppercase tracking-widest transition-all whitespace-nowrap ${
                filterType === type 
                ? 'bg-red-600 text-white shadow-lg shadow-red-900/20' 
                : 'bg-zinc-900 text-zinc-500 hover:text-zinc-300 border border-zinc-800'
              }`}
            >
              {type === 'ALL' ? 'Todos' : type}
            </button>
          ))}
        </div>
      </div>

      {/* Students Table */}
      <div className="bg-zinc-900/50 border border-zinc-800 rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-zinc-800 bg-zinc-950/50">
                <th className="px-6 py-4 text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Aluno</th>
                <th className="px-6 py-4 text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Documento</th>
                <th className="px-6 py-4 text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Contatos</th>
                <th className="px-6 py-4 text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Acesso</th>
                <th className="px-6 py-4 text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Grupo</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-800/50">
              {(filteredEnrollments || []).length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-20 text-center text-zinc-500 italic">
                    Nenhum aluno encontrado com os filtros aplicados.
                  </td>
                </tr>
              ) : (
                (filteredEnrollments || []).map((enrollment) => {
                  const remaining = getRemainingDays(enrollment.expiresAt);
                  const waLink = getWhatsAppLink(enrollment.userPhone);

                  return (
                    <tr key={enrollment.id} className="hover:bg-white/5 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 rounded-full bg-zinc-800 border border-zinc-700 flex items-center justify-center overflow-hidden shrink-0">
                            {enrollment.userAvatar ? (
                              <img src={enrollment.userAvatar} alt={enrollment.userName} className="w-full h-full object-cover" referrerPolicy="no-referrer" />
                            ) : (
                              <span className="text-zinc-400 font-bold text-sm">
                                {(() => {
                                  const userNameString = enrollment?.userName || 'Aluno';
                                  return userNameString
                                    .split(' ')
                                    .filter(Boolean)
                                    .map(n => n[0])
                                    .join('')
                                    .slice(0, 2)
                                    .toUpperCase() || '👤';
                                })()}
                              </span>
                            )}
                          </div>
                          <div>
                            <p className="text-white font-bold text-sm group-hover:text-red-500 transition-colors">{enrollment.userName}</p>
                            <p className="text-zinc-500 text-xs">{enrollment.userEmail}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-zinc-300 font-mono text-xs">{formatCPF(enrollment.userCpf)}</span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          {waLink && (
                            <a 
                              href={waLink} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="p-2 bg-emerald-500/10 text-emerald-500 hover:bg-emerald-500 hover:text-white rounded-lg transition-all"
                              title="Abrir WhatsApp"
                            >
                              <MessageCircle size={16} />
                            </a>
                          )}
                          <button 
                            onClick={() => window.location.href = `mailto:${enrollment.userEmail}`}
                            className="p-2 bg-zinc-800 text-zinc-400 hover:bg-zinc-700 hover:text-white rounded-lg transition-all"
                            title="Enviar E-mail"
                          >
                            <ExternalLink size={16} />
                          </button>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="space-y-1">
                          <p className="text-zinc-400 text-[10px] uppercase font-bold">
                            Expira em: <span className="text-white">
                              {enrollment.expiresAt ? format(parseISO(enrollment.expiresAt), 'dd/MM/yyyy') : '---'}
                            </span>
                          </p>
                          <p className={`text-xs font-bold ${remaining.color}`}>{remaining.label}</p>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter border ${
                          enrollment.enrollmentType === 'REGULAR' 
                          ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' 
                          : enrollment.enrollmentType === 'MIGRACAO'
                          ? 'bg-blue-500/10 text-blue-500 border-blue-500/20'
                          : 'bg-purple-500/10 text-purple-500 border-purple-500/20'
                        }`}>
                          {enrollment.enrollmentType}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
      {/* Migration Link Modal */}
      {showMigrationModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-zinc-900 border border-zinc-800 rounded-2xl w-full max-w-lg overflow-hidden shadow-2xl">
            <div className="p-6 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-500/10 rounded-lg text-blue-500">
                  <LinkIcon size={20} />
                </div>
                <h3 className="text-lg font-black text-white uppercase tracking-tighter">Link de Migração</h3>
              </div>
              <button 
                onClick={() => {
                  setShowMigrationModal(false);
                  setGeneratedLink(null);
                }}
                className="text-zinc-500 hover:text-white transition-colors"
              >
                <X size={24} />
              </button>
            </div>

            <div className="p-6 space-y-6">
              {!generatedLink ? (
                <>
                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-2">Validade do Link (Até quando pode ser usado)</label>
                      <input 
                        type="date"
                        value={migrationConfig.expiresAt}
                        onChange={(e) => setMigrationConfig({ ...migrationConfig, expiresAt: e.target.value })}
                        className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-blue-500 transition-all"
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-2">Dias de Acesso (Duração da matrícula)</label>
                      <input 
                        type="number"
                        value={migrationConfig.accessDurationDays}
                        onChange={(e) => setMigrationConfig({ ...migrationConfig, accessDurationDays: parseInt(e.target.value) })}
                        className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-blue-500 transition-all"
                        placeholder="Ex: 365"
                      />
                    </div>
                  </div>

                  <button
                    onClick={handleCreateMigrationLink}
                    disabled={isCreatingLink}
                    className="w-full py-4 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white font-black uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-blue-900/20"
                  >
                    {isCreatingLink ? 'Gerando...' : 'Gerar Link e Código Embed'}
                  </button>
                </>
              ) : (
                <div className="space-y-6 animate-in zoom-in-95 duration-300">
                  <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                    <div className="flex items-center gap-2 text-emerald-500 mb-1">
                      <Check size={16} />
                      <span className="text-xs font-bold uppercase tracking-wider">Link Gerado com Sucesso!</span>
                    </div>
                    <p className="text-zinc-400 text-xs">O link está ativo e pronto para ser compartilhado ou embarcado.</p>
                  </div>

                  <div className="space-y-4">
                    <div>
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-2">URL Direta</label>
                      <div className="flex gap-2">
                        <input 
                          readOnly
                          value={generatedLink.url}
                          className="flex-1 bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2 text-xs text-zinc-400 focus:outline-none"
                        />
                        <button 
                          onClick={() => copyToClipboard(generatedLink.url)}
                          className="p-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg transition-colors"
                        >
                          <Copy size={16} />
                        </button>
                      </div>
                    </div>

                    <div>
                      <label className="block text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-2">Código Iframe (Embed)</label>
                      <div className="flex gap-2">
                        <textarea 
                          readOnly
                          rows={3}
                          value={generatedLink.embed}
                          className="flex-1 bg-zinc-950 border border-zinc-800 rounded-lg px-3 py-2 text-[10px] font-mono text-zinc-400 focus:outline-none resize-none"
                        />
                        <button 
                          onClick={() => copyToClipboard(generatedLink.embed)}
                          className="p-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg transition-colors self-start"
                        >
                          <Copy size={16} />
                        </button>
                      </div>
                    </div>
                  </div>

                  <button
                    onClick={() => {
                      setShowMigrationModal(false);
                      setGeneratedLink(null);
                    }}
                    className="w-full py-3 bg-zinc-800 hover:bg-zinc-700 text-white font-bold uppercase tracking-widest rounded-xl transition-all"
                  >
                    Fechar
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { 
  Plus, Trash2, ChevronRight, ChevronDown, 
  PlayCircle, FileText, BrainCircuit, Layers, X,
  ArrowUp, ArrowDown, StickyNote
} from 'lucide-react';
import { MindMapNode, Flashcard } from '../../../services/metaService';
import { CourseEditalTopic, LinkedLesson, MaterialPDF } from '../../../../types/courseEdital';
import { courseService } from '../../../../services/courseService';

import MindMapManager from '../../metas/tools/mindmap/MindMapManager';
import FlashcardEditor from '../../metas/tools/FlashcardEditor';
import { LinkLessonModal } from './LinkLessonModal';
import { ConfirmationModal } from '../../../../components/ui/ConfirmationModal';
import { RichTextEditor } from '../../../../components/ui/RichTextEditor';

interface Props {
  topic: CourseEditalTopic;
  onUpdate: (updated: CourseEditalTopic) => void;
  onDelete: () => void;
  depth?: number;
  courseId: string;
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalTopic: React.FC<Props> = ({ 
    topic, onUpdate, onDelete, depth = 0, courseId,
    onMoveUp, onMoveDown, isFirst, isLast
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(topic.name);
  const [isUploading, setIsUploading] = useState(false);
  const [nextPdfType, setNextPdfType] = useState<'TEORIA' | 'QUESTOES'>('TEORIA');

  // Estados para Observação
  const [isEditingObservation, setIsEditingObservation] = useState(false);

  // Estados para Modais das Ferramentas
  const [activeTool, setActiveTool] = useState<'MAP' | 'FLASHCARD' | 'LESSON_LINK' | null>(null);

  // Estados para Modal de Exclusão de Subtópico
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [subtopicToDelete, setSubtopicToDelete] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- HANDLERS BÁSICOS ---
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== topic.name) {
        onUpdate({ ...topic, name: localName });
    }
  };

  const handleAddSubtopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newSub: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Subtópico',
        subtopics: [],
        linkedLessons: [],
        materialPdfs: [],
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({ ...topic, subtopics: [...topic.subtopics, newSub] });
    setIsExpanded(true);
  };

  const handleSubtopicUpdate = (updatedSub: CourseEditalTopic) => {
    onUpdate({
        ...topic,
        subtopics: topic.subtopics.map(s => s.id === updatedSub.id ? updatedSub : s)
    });
  };

  // --- LÓGICA DE EXCLUSÃO DE SUBTÓPICO ---

  // 1. Solicita exclusão (Abre Modal)
  const handleSubtopicDeleteRequest = (subId: string) => {
    setSubtopicToDelete(subId);
    setIsDeleteModalOpen(true);
  };

  // 2. Confirma exclusão (Remove do array e fecha modal)
  const confirmSubtopicDelete = () => {
    if(subtopicToDelete) {
        onUpdate({
            ...topic,
            subtopics: topic.subtopics.filter(s => s.id !== subtopicToDelete)
        });
        setIsDeleteModalOpen(false);
        setSubtopicToDelete(null);
    }
  };

  // --- REORDENAÇÃO DE SUBTÓPICOS ---
  const handleMoveSubtopic = (index: number, direction: 'up' | 'down') => {
      const subs = topic.subtopics;
      if ((direction === 'up' && index === 0) || (direction === 'down' && index === subs.length - 1)) return;

      const newSubs = [...subs];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;

      [newSubs[index], newSubs[targetIndex]] = [newSubs[targetIndex], newSubs[index]];

      onUpdate({ ...topic, subtopics: newSubs });
  };

  // --- HANDLERS DE CONTEÚDO (IA/LINK/PDF) ---
  const handleUpdateMindMap = (nodes: MindMapNode[]) => {
    onUpdate({ ...topic, contentData: { ...topic.contentData, mindMap: nodes } });
  };

  const handleUpdateFlashcards = (cards: Flashcard[]) => {
    onUpdate({ ...topic, contentData: { ...topic.contentData, flashcards: cards } });
  };

  const handleSaveLinkedLessons = (selectedLessons: LinkedLesson[]) => {
      onUpdate({ ...topic, linkedLessons: selectedLessons });
  };

  const handleRemoveLesson = (lessonId: string) => {
      const newLessons = (topic.linkedLessons || []).filter(l => l.id !== lessonId);
      onUpdate({ ...topic, linkedLessons: newLessons });
  };

  const handleUploadPDFClick = () => fileInputRef.current?.click();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          setIsUploading(true);
          try {
              const result = await courseService.uploadEditalFile(file, courseId, topic.id);
              const newPdf: MaterialPDF = {
                  title: file.name,
                  url: result.url,
                  storagePath: result.path,
                  pdfType: nextPdfType
              };
              const updatedPdfs = [...(topic.materialPdfs || []), newPdf];
              onUpdate({ ...topic, materialPdfs: updatedPdfs });
          } catch (_error) {
              alert("Erro ao fazer upload do PDF.");
          } finally {
              setIsUploading(false);
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      }
  };

  const handleRemovePDF = (url: string) => {
      const newPdfs = (topic.materialPdfs || []).filter(p => p.url !== url);
      onUpdate({ ...topic, materialPdfs: newPdfs });
  };

  const handleUpdatePdfType = (url: string, type: 'TEORIA' | 'QUESTOES') => {
      const newPdfs = (topic.materialPdfs || []).map(p => 
          p.url === url ? { ...p, pdfType: type } : p
      );
      onUpdate({ ...topic, materialPdfs: newPdfs });
  };


  // Badges e Estilos
  const mapCount = topic.contentData?.mindMap?.length || 0;
  const flashCount = topic.contentData?.flashcards?.length || 0;
  const lessonsCount = topic.linkedLessons?.length || 0;
  const pdfsCount = topic.materialPdfs?.length || 0;
  const hasObservation = !!topic.observation && topic.observation.trim() !== '<p><br></p>' && topic.observation.trim() !== '';

  const isSubtopic = depth > 0;
  const containerClass = isSubtopic 
    ? "bg-[#121418] border-l-2 border-l-zinc-700 ml-4 my-1" 
    : "bg-zinc-900 border border-zinc-800 my-1 rounded-lg";

  return (
    <div className={`flex flex-col ${containerClass} transition-all animate-in fade-in`}>

      {/* HEADER DO TÓPICO */}
      <div 
        className={`flex items-center justify-between group hover:bg-zinc-800/50 p-2 transition-colors cursor-pointer ${isSubtopic ? 'rounded-r' : 'rounded'}`} 
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-2 flex-1 min-w-0">
          <button className={`text-zinc-500 hover:text-white transition-colors w-5 flex justify-center`}>
             {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {isEditingName ? (
              <input 
                 value={localName}
                 onChange={(e) => setLocalName(e.target.value)}
                 onBlur={handleNameBlur}
                 onClick={e => e.stopPropagation()}
                 autoFocus
                 className="bg-black border border-zinc-600 rounded px-2 py-0.5 text-xs text-white focus:outline-none focus:border-blue-500 w-full max-w-[400px]"
              />
          ) : (
              <div className="flex items-center gap-2 overflow-hidden flex-wrap">
                <span 
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    className={`hover:text-white text-xs cursor-text transition-colors truncate font-medium ${isSubtopic ? 'text-zinc-400' : 'text-zinc-200'}`}
                >
                    {topic.name}
                </span>

                {lessonsCount > 0 && <span className="text-[9px] bg-blue-500/10 text-blue-400 px-1.5 py-0.5 rounded border border-blue-500/20 flex items-center gap-0.5"><PlayCircle size={8}/> {lessonsCount}</span>}
                {pdfsCount > 0 && <span className="text-[9px] bg-orange-500/10 text-orange-400 px-1.5 py-0.5 rounded border border-orange-500/20 flex items-center gap-0.5"><FileText size={8}/> {pdfsCount}</span>}
                {mapCount > 0 && <span className="text-[9px] bg-purple-500/10 text-purple-400 px-1.5 py-0.5 rounded border border-purple-500/20 flex items-center gap-0.5"><BrainCircuit size={8}/> Mapa</span>}
                {flashCount > 0 && <span className="text-[9px] bg-pink-500/10 text-pink-400 px-1.5 py-0.5 rounded border border-pink-500/20 flex items-center gap-0.5"><Layers size={8}/> Cards</span>}
                {hasObservation && <span className="text-[9px] bg-yellow-500/10 text-yellow-400 px-1.5 py-0.5 rounded border border-yellow-500/20 flex items-center gap-0.5"><StickyNote size={8}/> Obs</span>}
              </div>
          )}
        </div>

        {/* BOTÕES DE AÇÃO (HOVER) */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>

            {/* Reordenação */}
            <div className="flex items-center bg-black/40 rounded border border-zinc-800 mr-2">
                <button onClick={onMoveUp} disabled={isFirst} className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-l disabled:opacity-20" title="Mover para Cima">
                    <ArrowUp size={10} />
                </button>
                <div className="w-px h-3 bg-zinc-800"></div>
                <button onClick={onMoveDown} disabled={isLast} className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-r disabled:opacity-20" title="Mover para Baixo">
                    <ArrowDown size={10} />
                </button>
            </div>

            {/* Botão de Observação */}
            <button 
                onClick={() => { setIsEditingObservation(!isEditingObservation); setIsExpanded(true); }}
                className={`p-1.5 rounded mr-2 transition-colors ${isEditingObservation || (topic.observation && topic.observation !== '<p><br></p>' && topic.observation !== '') ? 'text-yellow-500 bg-yellow-500/10' : 'text-gray-400 hover:text-yellow-500 hover:bg-yellow-500/10'}`} 
                title="Adicionar/Editar Observação"
            >
                <StickyNote size={14} />
            </button>

            {/* Atalhos Rápidos */}
            <div className="flex bg-zinc-900 border border-zinc-800 rounded mr-2 overflow-hidden shadow-sm">
                <button onClick={() => setActiveTool('LESSON_LINK')} className="p-1.5 text-blue-500 hover:bg-blue-900/30 hover:text-blue-400" title="Vincular Aulas"><PlayCircle size={12} /></button>
                <div className="w-px bg-zinc-800"></div>

                <div className="flex items-center bg-zinc-950/50">
                    <select 
                        value={nextPdfType}
                        onChange={(e) => setNextPdfType(e.target.value as any)}
                        className="bg-transparent text-[8px] text-zinc-400 px-1 border-none focus:ring-0 cursor-pointer hover:text-white"
                        title="Tipo do próximo PDF"
                        onClick={e => e.stopPropagation()}
                    >
                        <option value="TEORIA">TEORIA</option>
                        <option value="QUESTOES">QUESTÕES</option>
                    </select>
                    <button onClick={handleUploadPDFClick} disabled={isUploading} className="p-1.5 text-orange-500 hover:bg-orange-900/30 hover:text-orange-400 disabled:opacity-50" title="Upload PDF">
                        {isUploading ? <span className="animate-spin text-[8px]">↻</span> : <FileText size={12} />}
                    </button>
                </div>
                <input type="file" ref={fileInputRef} accept="application/pdf" className="hidden" onChange={handleFileChange} />

                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('MAP')} className="p-1.5 text-purple-500 hover:bg-purple-900/30 hover:text-purple-400" title="Mapa Mental"><BrainCircuit size={12} /></button>
                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('FLASHCARD')} className="p-1.5 text-pink-500 hover:bg-pink-900/30 hover:text-pink-400" title="Flashcards"><Layers size={12} /></button>
            </div>

            <button onClick={handleAddSubtopic} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded" title="Adicionar Subtópico">
                <Plus size={14} />
            </button>

            {/* BOTÃO EXCLUIR O PRÓPRIO TÓPICO */}
            <button onClick={onDelete} className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-900/20 rounded" title="Excluir">
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      {/* ÁREA DE CONTEÚDO (EXPANDIDA) */}
      {isExpanded && (
          <div className="pl-6 pr-2 pb-2 space-y-2 animate-in slide-in-from-top-1 duration-200">

              {/* --- ÁREA DE OBSERVAÇÃO --- */}
              {(isEditingObservation || (topic.observation && topic.observation !== '<p><br></p>' && topic.observation !== '')) && (
                  <div className="mb-4 mt-2">
                      {isEditingObservation ? (
                          <div className="space-y-2 animate-in fade-in">
                              <RichTextEditor 
                                  value={topic.observation || ''} 
                                  onChange={(val) => onUpdate({ ...topic, observation: val })}
                                  placeholder="Digite observações, dicas ou orientações para este tópico..."
                              />
                              <div className="flex justify-end">
                                  <button onClick={() => setIsEditingObservation(false)} className="px-4 py-1.5 bg-green-600 hover:bg-green-500 text-white text-[10px] uppercase font-bold rounded transition-colors">
                                      Concluir Observação
                                  </button>
                              </div>
                          </div>
                      ) : (
                          <div 
                            className="p-4 bg-[#16181c] border border-gray-800 rounded-lg group/obs relative cursor-pointer hover:border-yellow-500/50 transition-colors"
                            onClick={() => setIsEditingObservation(true)}
                            title="Clique para editar"
                          >
                            <span className="text-[10px] font-bold text-yellow-500 uppercase tracking-wider block mb-2 flex items-center gap-2">
                                <StickyNote size={12} /> Observação
                            </span>
                            <div className="prose prose-invert prose-sm max-w-none text-gray-300 text-xs" dangerouslySetInnerHTML={{ __html: topic.observation || '' }} />
                          </div>
                      )}
                  </div>
              )}

              {/* Lista de Aulas Vinculadas */}
              {topic.linkedLessons && topic.linkedLessons.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.linkedLessons.map(lesson => (
                          <div key={lesson.id} className="flex items-center gap-1.5 bg-blue-500/10 border border-blue-500/20 px-2 py-1 rounded text-[10px] text-blue-300 group/item hover:border-blue-500/40">
                              <PlayCircle size={10} />
                              <span className="truncate max-w-[150px]">{lesson.title}</span>
                              <button onClick={() => handleRemoveLesson(lesson.id)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                          </div>
                      ))}
                  </div>
              )}

              {/* Lista de PDFs */}
              {topic.materialPdfs && topic.materialPdfs.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.materialPdfs.map((pdf, idx) => {
                          const isTheory = (pdf.pdfType || 'TEORIA') === 'TEORIA';
                          return (
                            <div key={idx} className={`flex items-center gap-1.5 ${isTheory ? 'bg-yellow-500/10 border-yellow-500/20 text-yellow-300' : 'bg-orange-500/10 border-orange-500/20 text-orange-300'} border px-2 py-1 rounded text-[10px] group/item hover:border-opacity-50`}>
                                <FileText size={10} />
                                <span className="truncate max-w-[120px]">{pdf.title}</span>
                                <select 
                                    value={pdf.pdfType || 'TEORIA'}
                                    onChange={(e) => handleUpdatePdfType(pdf.url, e.target.value as any)}
                                    className="bg-transparent border-none text-[8px] p-0 focus:ring-0 cursor-pointer opacity-60 hover:opacity-100"
                                >
                                    <option value="TEORIA">T</option>
                                    <option value="QUESTOES">Q</option>
                                </select>
                                <button onClick={() => handleRemovePDF(pdf.url)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                            </div>
                          );
                      })}
                  </div>
              )}

              {/* Renderização Recursiva de Subtópicos */}
              {topic.subtopics.length > 0 && (
                <div className="pt-1 flex flex-col gap-1">
                    {topic.subtopics.map((sub, index) => (
                        <AdminCourseEditalTopic 
                            key={sub.id}
                            topic={sub}
                            onUpdate={handleSubtopicUpdate}
                            // Passa a função de solicitação de exclusão do SUBTÓPICO
                            onDelete={() => handleSubtopicDeleteRequest(sub.id)}
                            depth={depth + 1}
                            courseId={courseId}
                            onMoveUp={() => handleMoveSubtopic(index, 'up')}
                            onMoveDown={() => handleMoveSubtopic(index, 'down')}
                            isFirst={index === 0}
                            isLast={index === topic.subtopics.length - 1}
                        />
                    ))}
                </div>
              )}

              {/* Mensagem de Vazio */}
              {topic.subtopics.length === 0 && lessonsCount === 0 && pdfsCount === 0 && !hasObservation && !isEditingObservation && (
                  <div className="text-[10px] text-zinc-600 italic pl-2">Nenhum conteúdo vinculado.</div>
              )}
          </div>
      )}

      {/* --- MODAIS --- */}

      <LinkLessonModal 
        isOpen={activeTool === 'LESSON_LINK'}
        onClose={() => setActiveTool(null)}
        courseId={courseId}
        onSave={handleSaveLinkedLessons}
        initialSelectedIds={topic.linkedLessons?.map(l => l.id)}
      />

      {activeTool === 'MAP' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-5xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2"><BrainCircuit className="text-purple-500" /> Mapa Mental: {topic.name}</h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <MindMapManager nodes={topic.contentData?.mindMap || []} onChange={handleUpdateMindMap} />
                </div>
            </div>
        </div>,
        document.body
      )}

      {activeTool === 'FLASHCARD' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-4xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2"><Layers className="text-pink-500" /> Flashcards: {topic.name}</h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <FlashcardEditor cards={topic.contentData?.flashcards || []} onChange={handleUpdateFlashcards} />
                </div>
            </div>
        </div>,
        document.body
      )}

      {/* MODAL DE CONFIRMAÇÃO DE EXCLUSÃO (SUBTÓPICO) */}
      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
        onConfirm={confirmSubtopicDelete}
        title="Excluir Subtópico?"
        message="Tem certeza que deseja excluir este subtópico? Todo o conteúdo vinculado será perdido."
        confirmText="Excluir"
        variant="danger"
        onCancel={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
      />

    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { toast } from 'react-hot-toast';
import { X, Save, Loader2, Upload, Search, Folder, ChevronLeft, PlayCircle, FileText, FileQuestion, Layers } from 'lucide-react';
import { CourseContent, ContentType } from '../../../../../types/course';
import { courseService } from '../../../../../services/courseService';
import { RichTextEditor } from '../../../../ui/RichTextEditor';
import { pandaService } from '../../../../../services/pandaService';
import { extractPandaVideoId, getPandaEmbedUrl, PandaVideo } from '../../../../../utils/pandaUtils';

interface ContentModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: Partial<CourseContent>) => Promise<void>;
  initialData?: CourseContent | null;
  lessonId: string;
}

export function ContentModal({ isOpen, onClose, onSave, initialData, lessonId }: ContentModalProps) {
  // Estado base
  const [type, setType] = useState<ContentType>('video');
  const [title, setTitle] = useState('');
  const [loading, setLoading] = useState(false);

  // Estados específicos
  const [videoUrl, setVideoUrl] = useState('');
  const [videoPlatform, setVideoPlatform] = useState<'panda' | 'youtube'>('youtube');
  const [useAlternativePlayer, setUseAlternativePlayer] = useState(false);

  const [linkUrl, setLinkUrl] = useState('');
  const [embedCode, setEmbedCode] = useState('');
  const [textContent, setTextContent] = useState('');

  const [pdfFile, setPdfFile] = useState<File | null>(null);
  const [existingPdfUrl, setExistingPdfUrl] = useState('');
  const [pdfClassification, setPdfClassification] = useState<'TEORIA' | 'QUESTÕES' | 'TEORIA_QUESTÕES'>('TEORIA');
  const [selectingVideo, setSelectingVideo] = useState(false);

  // Panda Media Picker
  const [showPandaPicker, setShowPandaPicker] = useState(false);
  const [pandaVideos, setPandaVideos] = useState<{id: string, title: string, video_player_url?: string}[]>([]);
  const [pandaFolders, setPandaFolders] = useState<{id: string, name: string}[]>([]);
  const [loadingPanda, setLoadingPanda] = useState(false);
  const [pandaSearch, setPandaSearch] = useState('');
  const [currentFolderId, setCurrentFolderId] = useState<string | null>(null);
  const [folderHistory, setFolderHistory] = useState<string[]>([]);

  // Debounce para busca no Panda (ou navegação)
  useEffect(() => {
    if (!showPandaPicker) return;

    if (pandaSearch) {
        const timer = setTimeout(() => {
            fetchPandaVideos(pandaSearch);
        }, 500);
        return () => clearTimeout(timer);
    } else {
        fetchPandaExplorer(currentFolderId);
    }
  }, [pandaSearch, showPandaPicker, currentFolderId]);

  const fetchPandaVideos = async (search: string = '') => {
    setLoadingPanda(true);
    try {
      const videos = await pandaService.listVideos(search);
      setPandaVideos(videos);
      setPandaFolders([]); // Limpa pastas na busca por texto
    } catch (error) {
      console.error("Erro ao carregar vídeos do Panda:", error);
    } finally {
      setLoadingPanda(false);
    }
  };

  const fetchPandaExplorer = async (folderId: string | null = null) => {
    setLoadingPanda(true);
    try {
      const { folders, videos } = await pandaService.explorer(folderId);
      setPandaVideos(videos);
      setPandaFolders(folders);
    } catch (error) {
      console.error("Erro no explorer do Panda:", error);
    } finally {
      setLoadingPanda(false);
    }
  };

  const handleFolderClick = (folderId: string) => {
    if (currentFolderId) {
        setFolderHistory(prev => [...prev, currentFolderId]);
    } else {
        setFolderHistory(['root']);
    }
    setCurrentFolderId(folderId);
    setPandaSearch(''); // Limpa busca ao navegar
  };

  const handleGoBack = () => {
    const newHistory = [...folderHistory];
    const lastFolder = newHistory.pop();
    setFolderHistory(newHistory);
    setCurrentFolderId(lastFolder === 'root' ? null : (lastFolder || null));
    setPandaSearch('');
  };

  const handleSelectPandaVideo = async (video: PandaVideo) => {
    if (selectingVideo) return;

    const toastId = toast.loading("Buscando link do vídeo...");
    try {
      setSelectingVideo(true);

      // 1. Busca os detalhes completos do vídeo para garantir o Playback ID
      const videoDetails = await pandaService.getVideoDetails(video.id);

      if (!videoDetails) {
        throw new Error("Não foi possível carregar os detalhes do vídeo.");
      }

      // 2. Extração rigorosa (Parser de URL via utilitário)
      const playbackId = extractPandaVideoId(videoDetails);

      // 3. Trava de Segurança Definitiva (Fail-Fast)
      if (!playbackId) {
        toast.error("Falha Crítica: Playback ID não encontrado.", { id: toastId });
        console.error("Falha Crítica: Playback ID não encontrado nas URLs. Objeto:", videoDetails);
        alert("Erro: Este vídeo não possui uma URL de embed pública válida no Panda. O vídeo pode estar processando ou com o embed desativado no painel do Panda Vídeo.");
        return; // Impede a montagem de um player quebrado
      }

      // 4. Montagem Estrita da URL Ticto
      const tictoEmbedUrl = getPandaEmbedUrl(videoDetails, playbackId);

      // 5. Injeção no formulário
      setVideoUrl(tictoEmbedUrl);

      // Injeta o título do vídeo automaticamente
      if (videoDetails.title || videoDetails.name) {
          setTitle(videoDetails.title || videoDetails.name);
      }

      setVideoPlatform('panda');
      setShowPandaPicker(false);
      toast.success("Vídeo selecionado com sucesso!", { id: toastId });
    } catch (error) {
      console.error("Erro ao selecionar vídeo do Panda:", error);
      toast.error("Erro ao carregar os detalhes do vídeo.", { id: toastId });
    } finally {
      setSelectingVideo(false);
    }
  };

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setType(initialData.type);
        setTitle(initialData.title);
        setVideoUrl(initialData.videoUrl || '');
        setVideoPlatform(initialData.videoPlatform || 'youtube');
        setUseAlternativePlayer(initialData.useAlternativePlayer || false);
        setLinkUrl(initialData.linkUrl || '');
        setEmbedCode(initialData.embedCode || '');
        setTextContent(initialData.textContent || '');
        setExistingPdfUrl(initialData.fileUrl || '');
        setPdfClassification(initialData.pdfClassification || 'TEORIA');
      } else {
        // Reset
        setType('video');
        setTitle('');
        setVideoUrl('');
        setVideoPlatform('youtube');
        setUseAlternativePlayer(false);
        setLinkUrl('');
        setEmbedCode('');
        setTextContent('');
        setExistingPdfUrl('');
        setPdfFile(null);
        setPdfClassification('TEORIA');
      }
    }
  }, [isOpen, initialData]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setPdfFile(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title) return;
    setLoading(true);

    try {
      const data: Partial<CourseContent> = {
        title,
        type,
        lessonId
      };

      if (type === 'video') {
        data.videoUrl = videoUrl;
        data.videoPlatform = videoPlatform;
        if (videoPlatform === 'youtube') {
            data.useAlternativePlayer = useAlternativePlayer;
        }
      } 
      else if (type === 'link') {
        data.linkUrl = linkUrl;
      }
      else if (type === 'text') {
        data.textContent = textContent;
      }
      else if (type === 'embed') {
        data.embedCode = embedCode;
      }
      else if (type === 'pdf') {
        let finalPdfUrl = existingPdfUrl;
        if (pdfFile) {
            finalPdfUrl = await courseService.uploadPDF(pdfFile);
        }
        data.fileUrl = finalPdfUrl;
        data.pdfClassification = pdfClassification;
      }

      await onSave(data);
      onClose();
    } catch (error) {
      console.error(error);
      alert("Erro ao salvar conteúdo.");
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[80] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in">
      <div className="bg-[#121418] border border-gray-800 rounded-xl w-full max-w-2xl shadow-2xl flex flex-col max-h-[90vh]">

        <div className="p-6 border-b border-gray-800 flex justify-between items-center shrink-0 bg-zinc-900/50">
          <h2 className="text-xl font-bold text-white">
            {initialData ? 'Editar Conteúdo' : 'Adicionar Conteúdo'}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 overflow-y-auto custom-scrollbar">

          {/* Seleção de Tipo (Apenas na criação) */}
          {!initialData && (
            <div className="grid grid-cols-5 gap-2">
                {(['video', 'pdf', 'link', 'text', 'embed'] as ContentType[]).map((t) => (
                    <button
                        key={t}
                        type="button"
                        onClick={() => setType(t)}
                        className={`py-2 px-1 rounded text-[10px] font-bold uppercase transition-colors border ${type === t ? 'bg-red-600 border-red-600 text-white' : 'bg-black border-gray-800 text-gray-400 hover:border-gray-600'}`}
                    >
                        {t}
                    </button>
                ))}
            </div>
          )}

          {/* Título Geral */}
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Título do Conteúdo <span className="text-red-500">*</span></label>
            <input 
              type="text" 
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none"
              placeholder="Ex: Videoaula 01 ou Material de Apoio"
              required
            />
          </div>

          {/* --- CAMPOS ESPECÍFICOS POR TIPO --- */}

          {/* VÍDEO */}
          {type === 'video' && (
            <div className="space-y-4 bg-black/20 p-4 rounded border border-gray-800">
                <div className="flex gap-4">
                    <label className="flex items-center gap-2 cursor-pointer">
                        <input type="radio" checked={videoPlatform === 'youtube'} onChange={() => setVideoPlatform('youtube')} className="accent-red-600" />
                        <span className="text-sm text-gray-300">YouTube</span>
                    </label>
                    <label className="flex items-center gap-2 cursor-pointer">
                        <input type="radio" checked={videoPlatform === 'panda'} onChange={() => setVideoPlatform('panda')} className="accent-red-600" />
                        <span className="text-sm text-gray-300">Panda Vídeo</span>
                    </label>
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Link do Vídeo / Embed URL</label>
                    <div className="space-y-2">
                        <input 
                            type="url" 
                            value={videoUrl}
                            onChange={e => setVideoUrl(e.target.value)}
                            className="w-full bg-[#121418] border border-gray-700 rounded p-3 text-white focus:border-red-600 outline-none"
                            placeholder="https://..."
                        />
                        {videoPlatform === 'panda' && (
                            <button
                                type="button"
                                onClick={() => setShowPandaPicker(true)}
                                className="flex items-center gap-2 px-4 py-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded text-[10px] font-bold uppercase transition-colors"
                            >
                                <Search size={14} /> Buscar no Panda Video
                            </button>
                        )}
                    </div>
                </div>

                {videoPlatform === 'youtube' && (
                    <div className="flex items-center gap-3 p-3 bg-yellow-900/10 border border-yellow-900/30 rounded">
                        <input 
                            type="checkbox" 
                            id="altPlayer"
                            checked={useAlternativePlayer}
                            onChange={e => setUseAlternativePlayer(e.target.checked)}
                            className="w-4 h-4 accent-yellow-500 cursor-pointer"
                        />
                        <label htmlFor="altPlayer" className="text-sm text-yellow-500 font-bold cursor-pointer">
                            Ativar Player Alternativo (Segurança Anti-Cópia)
                        </label>
                    </div>
                )}
            </div>
          )}

          {/* PDF */}
          {type === 'pdf' && (
            <div className="space-y-4">
                <div className="border-2 border-dashed border-gray-700 rounded-lg p-6 flex flex-col items-center justify-center bg-black/20">
                    <input 
                        type="file" 
                        ref={fileInputRef}
                        accept="application/pdf"
                        onChange={handleFileSelect}
                        className="hidden"
                    />
                    <button 
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        className="px-4 py-2 bg-gray-800 hover:bg-gray-700 text-white rounded text-xs font-bold uppercase mb-2 flex items-center gap-2 transition-colors"
                    >
                        <Upload size={14} /> Selecionar PDF
                    </button>
                    {pdfFile ? (
                        <span className="text-green-500 text-sm font-bold">{pdfFile.name}</span>
                    ) : existingPdfUrl ? (
                        <span className="text-blue-400 text-sm">Arquivo atual cadastrado</span>
                    ) : (
                        <span className="text-gray-500 text-xs">Nenhum arquivo selecionado</span>
                    )}
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Classificação do PDF:</label>
                    <div className="grid grid-cols-3 gap-2">
                        {[
                            { id: 'TEORIA', label: 'TEORIA', icon: FileText },
                            { id: 'QUESTÕES', label: 'QUESTÕES', icon: FileQuestion },
                            { id: 'TEORIA_QUESTÕES', label: 'AMBOS', icon: Layers }
                        ].map((option) => (
                            <button
                                key={option.id}
                                type="button"
                                onClick={() => setPdfClassification(option.id as any)}
                                className={`flex flex-col items-center gap-2 py-3 px-1 rounded text-[9px] font-bold uppercase transition-all border ${pdfClassification === option.id ? 'bg-red-600 border-red-600 text-white shadow-lg shadow-red-600/20' : 'bg-black border-gray-800 text-gray-400 hover:border-gray-600'}`}
                            >
                                <option.icon size={18} />
                                {option.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Preview da Identificação Visual */}
                <div className="p-4 bg-black/40 rounded-lg border border-gray-800 space-y-3">
                    <div className="flex items-center justify-between">
                        <span className="text-[10px] text-gray-500 uppercase font-black tracking-widest">Preview na Lista</span>
                        <div className="h-px flex-1 bg-gray-800 mx-4"></div>
                    </div>

                    <div className="flex items-center gap-3 p-3 bg-[#1a1d24] border border-gray-700 rounded shadow-inner">
                        <div className="w-8 h-8 rounded bg-gray-900 flex items-center justify-center border border-gray-700">
                            <FileText size={16} className="text-yellow-500" />
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-0.5">
                                <h4 className="text-sm font-bold text-gray-200 truncate">{title || 'Título do Material'}</h4>
                                {(() => {
                                    let icon = <FileText size={10} />;
                                    let label = 'TEORIA';
                                    let colorClass = 'bg-blue-500/10 text-blue-400 border-blue-500/20';

                                    if (pdfClassification === 'QUESTÕES') {
                                        icon = <FileQuestion size={10} />;
                                        label = 'QUESTÕES';
                                        colorClass = 'bg-purple-500/10 text-purple-400 border-purple-500/20';
                                    } else if (pdfClassification === 'TEORIA_QUESTÕES') {
                                        icon = <Layers size={10} />;
                                        label = 'TEORIA + QUESTÕES';
                                        colorClass = 'bg-orange-500/10 text-orange-400 border-orange-500/20';
                                    }

                                    return (
                                        <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded border text-[9px] font-black uppercase tracking-tighter ${colorClass}`}>
                                            {icon}
                                            {label}
                                        </div>
                                    );
                                })()}
                            </div>
                            <span className="text-[10px] text-gray-500 uppercase tracking-wider">pdf</span>
                        </div>
                    </div>
                </div>

                <p className="text-[10px] text-gray-500 text-center">
                    * O arquivo receberá marca d&apos;água com CPF/Email do aluno automaticamente ao ser baixado.
                </p>
            </div>
          )}

          {/* LINK */}
          {type === 'link' && (
            <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">URL de Redirecionamento</label>
                <input 
                    type="url" 
                    value={linkUrl}
                    onChange={e => setLinkUrl(e.target.value)}
                    className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none"
                    placeholder="https://..."
                />
            </div>
          )}

          {/* TEXTO */}
          {type === 'text' && (
            <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Conteúdo do Texto</label>
                <RichTextEditor 
                    value={textContent} 
                    onChange={setTextContent} 
                />
            </div>
          )}

          {/* EMBED */}
          {type === 'embed' && (
            <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Código Embed (Iframe)</label>
                <textarea 
                    value={embedCode}
                    onChange={e => setEmbedCode(e.target.value)}
                    className="w-full h-32 bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none font-mono text-xs"
                    placeholder="<iframe src='...'></iframe>"
                />
            </div>
          )}

        </form>

        <div className="p-6 border-t border-gray-800 flex justify-end gap-3 shrink-0 bg-zinc-900/30">
            <button 
                type="button" 
                onClick={onClose} 
                className="px-4 py-2 text-gray-400 hover:text-white font-bold uppercase text-xs"
            >
                Cancelar
            </button>
            <button 
                type="button" 
                onClick={handleSubmit} 
                disabled={loading} 
                className="px-6 py-2 bg-red-600 hover:bg-red-500 text-white font-bold uppercase text-xs rounded disabled:opacity-50 flex items-center gap-2"
            >
                {loading ? (
                    <>
                        <Loader2 size={14} className="animate-spin" /> Salvando...
                    </>
                ) : (
                    <>
                        <Save size={14} /> Salvar Conteúdo
                    </>
                )}
            </button>
        </div>
      </div>

      {/* Modal do Panda Media Picker */}
      {showPandaPicker && (
        <div className="fixed inset-0 z-[90] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in zoom-in-95">
          <div className="bg-[#0a0b0d] border border-gray-800 rounded-2xl w-full max-w-lg shadow-2xl flex flex-col max-h-[80vh]">
            <div className="p-6 border-b border-gray-800 flex justify-between items-center bg-zinc-900/50">
              <div>
                <h3 className="text-lg font-bold text-white">Selecionar Vídeo do Panda</h3>
