            <div className="p-4 border-t border-gray-800 bg-zinc-900/20 text-center">
              <button 
                onClick={fetchPandaVideos}
                className="text-[10px] font-bold text-gray-500 hover:text-white uppercase tracking-widest transition-colors"
              >
                Atualizar Lista
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Folder, Download, Wand2 } from 'lucide-react';
import { CourseModule, CourseSubModule, CourseLesson } from '../../../../types/course';
import { courseService } from '../../../../services/courseService';
import { LessonItem } from './items/LessonItem';
import { SubModuleItem } from './items/SubModuleItem';
import { FolderModal } from './modals/FolderModal';
import { LessonModal } from './modals/LessonModal';
import { ConfirmationModal } from '../../ui/ConfirmationModal';
import { LessonContentManager } from '../lessons/LessonContentManager';
import { PDFTemplate } from '../../../../src/frontend/components/PDFTemplate';
import html2pdf from 'html2pdf.js';

interface ModuleContentManagerProps {
  module: CourseModule;
  onBack: () => void;
}

export function ModuleContentManager({ module, onBack }: ModuleContentManagerProps) {
  const [subModules, setSubModules] = useState<CourseSubModule[]>([]);
  const [lessons, setLessons] = useState<CourseLesson[]>([]);
  const [loading, setLoading] = useState(true);

  // Estados de Modais
  const [isFolderModalOpen, setIsFolderModalOpen] = useState(false);
  const [editingFolder, setEditingFolder] = useState<CourseSubModule | null>(null);

  const [isLessonModalOpen, setIsLessonModalOpen] = useState(false);
  const [editingLesson, setEditingLesson] = useState<CourseLesson | null>(null);
  const [targetFolderIdForNewLesson, setTargetFolderIdForNewLesson] = useState<string | null>(null);

  const [itemToDelete, setItemToDelete] = useState<{ type: 'folder' | 'lesson', id: string, title: string } | null>(null);
  const [lessonToMove, setLessonToMove] = useState<CourseLesson | null>(null);

  // Estado para Drill-down de Aula (Gerenciar Conteúdos)
  const [managingLesson, setManagingLesson] = useState<CourseLesson | null>(null);

  // NOVO ESTADO: Controla quais pastas estão abertas (persiste após updates)
  const [expandedFolders, setExpandedFolders] = useState<Record<string, boolean>>({});

  // Helper para abrir/fechar pasta
  const toggleFolder = (folderId: string) => {
    setExpandedFolders(prev => ({
      ...prev,
      [folderId]: !prev[folderId]
    }));
  };

  // NOVO ESTADO: Controle de Seleção para IA
  const [selectedLessonIds, setSelectedLessonIds] = useState<string[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedMarkdown, setGeneratedMarkdown] = useState<string | null>(null);

  // Novos Campos para Geração de PDF
  const [disciplinaName, setDisciplinaName] = useState('');
  const [disciplinaAssunto, setDisciplinaAssunto] = useState('');
  const [watermark, setWatermark] = useState<string | null>(null);
  const [includeTOC, setIncludeTOC] = useState(false);
  const containerRef = React.useRef<HTMLDivElement>(null);

  const toggleLessonSelection = (lessonId: string) => {
    setSelectedLessonIds(prev => 
      prev.includes(lessonId) 
        ? prev.filter(id => id !== lessonId) 
        : [...prev, lessonId]
    );
  };

  const handleGenerateMaterial = async () => {
    if (selectedLessonIds.length === 0) return;

    setIsGenerating(true);
    try {
      // Chamar a API de geração enviando apenas os IDs das aulas
      const response = await fetch('/api/generate-material', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          lessonIds: selectedLessonIds,
          folderTitle: module.title 
        })
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Erro do servidor (${response.status}): ${errorText.substring(0, 150)}`);
      }

      const data = await response.json();

      if (data.success) {
        setGeneratedMarkdown(data.markdown);
        console.log("Material gerado com sucesso!");
        console.log("--- MATERIAL DIDÁTICO GERADO (MARKDOWN) ---");
        console.log(data.markdown);
        console.log("-------------------------------------------");
        // Opcional: Limpar seleção
        setSelectedLessonIds([]);
      } else {
        console.error("Erro ao gerar material: " + (data.error || "Erro desconhecido"));
      }
    } catch (error) {
      console.error("Erro ao gerar material:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownloadPDF = () => {
    if (!generatedMarkdown) return;

    const originalElement = document.getElementById('insanus-pdf-container');
    if (!originalElement) {
        console.error("Erro: Container de PDF não encontrado.");
        return;
    }

    // Cria um clone perfeito para não bugar a tela do usuário
    const element = originalElement.cloneNode(true) as HTMLElement; 

    // Amarra o título com o próximo parágrafo numa div indestrutível
    const headings = element.querySelectorAll('h1, h2, h3, h4');
    headings.forEach(heading => {
      const nextEl = heading.nextElementSibling;
      // Se o próximo elemento existe e não é outro título...
      if (nextEl && !['H1', 'H2', 'H3', 'H4'].includes(nextEl.tagName)) {
        const wrapper = document.createElement('div');
        wrapper.style.pageBreakInside = 'avoid';
        // @ts-expect-error - breakInside is not in all CSSStyleDeclaration types
        wrapper.style.breakInside = 'avoid';
        if (heading.parentNode) {
          heading.parentNode.insertBefore(wrapper, heading);
          wrapper.appendChild(heading);
          wrapper.appendChild(nextEl);
        }
      }
    });

    const opt = {
      margin:       [25, 15, 25, 15], // [Top, Left, Bottom, Right] em mm
      filename:     `${disciplinaName || 'Material'} - ${disciplinaAssunto || 'Insanus'}.pdf`,
      image:        { type: 'jpeg', quality: 1 },
      html2canvas:  { scale: 2, useCORS: true, backgroundColor: '#ffffff' },
      pagebreak:    { mode: ['css', 'legacy'], avoid: ['p', 'h1', 'h2', 'h3', 'h4', 'li', 'blockquote'] },
      jsPDF:        { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-expect-error html2pdf is not typed
    html2pdf().set(opt).from(element).toPdf().get('pdf').then(function (pdf: { internal: { getNumberOfPages: () => number, pageSize: { getWidth: () => number, getHeight: () => number } }, setPage: (page: number) => void, setGState: (state: any) => void, GState: any, getImageProperties: (img: string) => { width: number, height: number }, addImage: (img: string, format: string, x: number, y: number, w: number, h: number) => void, setFont: (font: string, style: string) => void, setFontSize: (size: number) => void, text: (text: string, x: number, y: number, options?: any) => void, setLineWidth: (width: number) => void, line: (x1: number, y1: number, x2: number, y2: number) => void, setTextColor: (color: number) => void }) {
      const totalPages = pdf.internal.getNumberOfPages();
      const pageWidth = pdf.internal.pageSize.getWidth();
      const pageHeight = pdf.internal.pageSize.getHeight();

      for (let i = 1; i <= totalPages; i++) {
        pdf.setPage(i);

        // --- MARCA D'ÁGUA ---
        if (watermark) {
          try {
            // Configura opacidade para 10% (suportado no jsPDF mais recente)
            pdf.setGState(new pdf.GState({ opacity: 0.1 }));
            const imgProps = pdf.getImageProperties(watermark);
            const imgWidth = 140; // Largura base
            const imgHeight = (imgProps.height * imgWidth) / imgProps.width; // Altura proporcional
            const x = (pageWidth - imgWidth) / 2;
            const y = (pageHeight - imgHeight) / 2;
            pdf.addImage(watermark, 'PNG', x, y, imgWidth, imgHeight);
            pdf.setGState(new pdf.GState({ opacity: 1.0 })); // Restaura a opacidade para o texto
          } catch (e) {
            console.error("Erro ao aplicar marca d'água:", e);
          }
        }

        // --- CABEÇALHO ---
        pdf.setFont('helvetica', 'bold');
        pdf.setFontSize(11);
        // Texto Esquerda
        pdf.text("INSANUS CONCURSOS", 15, 15);
        // Texto Direita (Nome da Disciplina)
        pdf.setFont('helvetica', 'normal');
        pdf.text((disciplinaName || '').toUpperCase(), pageWidth - 15, 15, { align: 'right' });
        // Linha do Cabeçalho
        pdf.setLineWidth(0.5);
        pdf.line(15, 17, pageWidth - 15, 17);

        // --- RODAPÉ ---
        pdf.setFontSize(7);
        pdf.setTextColor(100);
        const copyrightText = "LEI DO DIREITO AUTORAL-N° 9.610 de 19 de FEVEREIRO de 1998\nPROIBE-SE A COMERCIALIZAÇÃO TOTAL OU PARCIAL DESSE MATERIAL OU DIVULGAÇÃO COM FINS COMERCIAIS OU NÃO,\nEM QUALQUER MEIO DE COMUNICAÇÃO, INCLUSIVE NA INTERNET, SEM AUTORIZAÇÃO EXPRESSA DO INSANUS CONCURSOS.";
        pdf.text(copyrightText, pageWidth / 2, pageHeight - 15, { align: 'center' });

        // Paginação
        pdf.setFontSize(10);
        pdf.setTextColor(0);
        pdf.text(String(i), pageWidth - 15, pageHeight - 10, { align: 'right' });
      }
    }).save();
  };

  // Carregar Dados
  const loadContent = async () => {
    setLoading(true);
    try {
      const [subs, less] = await Promise.all([
        courseService.getSubModules(module.id),
        courseService.getLessons(module.id)
      ]);
      setSubModules(subs);
      setLessons(less);
    } catch (error) {
      console.error("Erro ao carregar conteúdo", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadContent();
  }, [module.id]);

  // --- CRUD PASTAS ---
  const handleSaveFolder = async (title: string, publishDate: string | null) => {
    try {
      if (editingFolder) {
        await courseService.updateSubModule(editingFolder.id, { title, publishDate });
        // Atualização Otimista
        setSubModules(prev => prev.map(s => s.id === editingFolder.id ? { ...s, title, publishDate } : s));
      } else {
        const newOrder = subModules.length > 0 ? Math.max(...subModules.map(s => s.order)) + 1 : 1;
        const newId = await courseService.createSubModule({ 
            title, 
            moduleId: module.id, 
            order: newOrder,
            publishDate
        });

        // Atualização Otimista
        setSubModules(prev => [...prev, {
            id: newId,
            moduleId: module.id,
            title,
            order: newOrder,
            publishDate
        }]);

        // Abre a nova pasta
        setExpandedFolders(prev => ({ ...prev, [newId]: true }));
      }
      setIsFolderModalOpen(false); // Fecha o modal
      setEditingFolder(null); // Limpa edição
    } catch (error) {
      console.error("Erro ao salvar pasta:", error);
      loadContent(); // Reverte em caso de erro
    }
  };

  const handleDeleteFolder = async () => {
    if (itemToDelete && itemToDelete.type === 'folder') {
      await courseService.deleteSubModule(itemToDelete.id);
      await loadContent();
      setItemToDelete(null);
    }
  };

  // --- CRUD AULAS ---
  const handleSaveLesson = async (title: string, coverUrl: string, type: 'video' | 'pdf') => {
    try {
      if (editingLesson) {
        await courseService.updateLesson(editingLesson.id, { title, coverUrl, type });
        // Atualização Otimista
        setLessons(prev => prev.map(l => l.id === editingLesson.id ? { ...l, title, coverUrl, type } : l));
      } else {
        const targetFolderId = targetFolderIdForNewLesson || null;

        // Calcular ordem baseado na lista atual (otimista)
        const contextLessons = targetFolderId 
            ? lessons.filter(l => l.subModuleId === targetFolderId)
            : lessons.filter(l => !l.subModuleId);

        const newOrder = contextLessons.length > 0 ? Math.max(...contextLessons.map(l => l.order)) + 1 : 1;

        const lessonData = {
          title, 
          coverUrl, 
          moduleId: module.id, 
          subModuleId: targetFolderId, 
          order: newOrder,
          type
        };

        const newId = await courseService.createLesson(lessonData);

        // Adiciona na lista local imediatamente
        const newLesson: CourseLesson = {
            id: newId,
            ...lessonData,
            videoCount: 0,
            pdfCount: 0
        };
        setLessons(prev => [...prev, newLesson]);

        // Se criou dentro de uma pasta, garante que ela esteja aberta
        if (targetFolderId) {
            setExpandedFolders(prev => ({ ...prev, [targetFolderId]: true }));
        }
      }
      setIsLessonModalOpen(false);
      setEditingLesson(null);
      setTargetFolderIdForNewLesson(null);
    } catch (error) {
        console.error("Erro ao salvar aula:", error);
        loadContent(); // Reverte em caso de erro
    }
  };

  const handleDeleteLesson = async () => {
    if (itemToDelete && itemToDelete.type === 'lesson') {
      await courseService.deleteLesson(itemToDelete.id);
      await loadContent();
      setItemToDelete(null);
    }
  };

  // --- NOVA FUNÇÃO: Reordenar Aulas ---
  // contextId: ID da pasta (se estiver em pasta) ou null (se estiver na raiz)
  const handleReorderLesson = async (index: number, direction: 'up' | 'down', contextId: string | null) => {
    // 1. Filtra a lista correta (Pasta ou Raiz)
    const contextLessons = lessons
        .filter(l => l.subModuleId === contextId)
        // Garante que estamos operando na lista ordenada visualmente
        .sort((a, b) => (a.order || 0) - (b.order || 0));

    const targetIndex = direction === 'up' ? index - 1 : index + 1;

    // Verificações de segurança
    if (targetIndex < 0 || targetIndex >= contextLessons.length) return;

    // 2. Troca as posições na lista filtrada
    // Clonamos o array para não mutar o estado diretamente antes do set
    const reorderedGroup = [...contextLessons];

    // Swap objects in the array
    [reorderedGroup[index], reorderedGroup[targetIndex]] = [reorderedGroup[targetIndex], reorderedGroup[index]];

    // Recalculate 'order' for the whole group to be sequential
    const updates = reorderedGroup.map((l, idx) => ({ ...l, order: idx + 1 }));

    // 3. Atualiza o estado global de lessons
    const newAllLessons = lessons.map(l => {
        const updated = updates.find(u => u.id === l.id);
        return updated || l;
    });

    setLessons(newAllLessons); // Feedback visual imediato

    // 4. Salva no banco
    try {
        await courseService.reorderLessons(updates);
    } catch (error) {
        console.error("Erro ao salvar ordem das aulas", error);
        loadContent(); // Reverte em caso de erro
    }
  };

  // --- NOVA FUNÇÃO: Reordenar Conteúdo Misto (Pastas + Aulas Raiz) ---
  const handleReorderMixed = async (index: number, direction: 'up' | 'down') => {
    const mixedContent = [
      ...subModules.map(f => ({ type: 'folder' as const, id: f.id, order: f.order })),
      ...lessons.filter(l => !l.subModuleId).map(l => ({ type: 'lesson' as const, id: l.id, order: l.order }))
    ].sort((a, b) => (a.order || 0) - (b.order || 0));

    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= mixedContent.length) return;

    // Swap
    [mixedContent[index], mixedContent[targetIndex]] = [mixedContent[targetIndex], mixedContent[index]];

    // Recalculate orders
    const updates = mixedContent.map((item, idx) => ({ ...item, order: idx + 1 }));

    // Update local state
    setSubModules(prev => prev.map(s => {
      const update = updates.find(u => u.type === 'folder' && u.id === s.id);
      return update ? { ...s, order: update.order } : s;
    }).sort((a, b) => a.order - b.order));

    setLessons(prev => prev.map(l => {
      const update = updates.find(u => u.type === 'lesson' && u.id === l.id);
      return update ? { ...l, order: update.order } : l;
    }).sort((a, b) => a.order - b.order));

    // Save to DB
    try {
      await courseService.reorderMixedContent(updates);
    } catch (error) {
      console.error("Erro ao reordenar conteúdo misto", error);
      loadContent();
    }
  };

  const handleMoveLessonConfirm = async (targetFolderId: string | null) => {
    if (lessonToMove) {
        await courseService.moveLesson(lessonToMove.id, targetFolderId);
        await loadContent();
        setLessonToMove(null);
    }
  };

  // Filtrar aulas por pasta
  const getLessonsInFolder = (folderId: string) => lessons
    .filter(l => l.subModuleId === folderId)
    .sort((a, b) => (a.order || 0) - (b.order || 0));

  // Renderização do LessonContentManager
  if (managingLesson) {
      return (
          <LessonContentManager 
            lesson={managingLesson}
            onBack={() => setManagingLesson(null)}
          />
      );
  }

  return (
    <div className="space-y-6 animate-in fade-in">

      {/* Header */}
      <div className="flex items-center gap-4 border-b border-gray-800 pb-6">
        <button onClick={onBack} className="p-2 hover:bg-white/5 rounded-full text-gray-400 hover:text-white">
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
        </button>
        <div>
          <span className="text-gray-500 font-bold text-xs uppercase tracking-wider">Módulo</span>
          <h2 className="text-2xl font-black text-white uppercase">{module.title}</h2>
        </div>
        <div className="flex-1"></div>
        <div className="flex gap-3 items-end">
            {selectedLessonIds.length > 0 && (
                <div className="flex flex-col gap-2">
                    <div className="flex gap-2">
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] font-bold text-gray-500 uppercase">Disciplina</label>
                            <input 
                                type="text"
                                value={disciplinaName}
                                onChange={e => setDisciplinaName(e.target.value)}
                                placeholder="Ex: DIREITO CONSTITUCIONAL"
                                className="bg-black border border-gray-800 rounded px-3 py-2 text-xs text-white focus:border-red-600 outline-none w-48"
                            />
                        </div>
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] font-bold text-gray-500 uppercase">Assunto</label>
                            <input 
                                type="text"
                                value={disciplinaAssunto}
                                onChange={e => setDisciplinaAssunto(e.target.value)}
                                placeholder="Ex: SEGURANÇA PÚBLICA (ART. 144)"
                                className="bg-black border border-gray-800 rounded px-3 py-2 text-xs text-white focus:border-red-600 outline-none w-64"
                            />
                        </div>
                        <div className="flex flex-col gap-1">
                            <label className="text-[10px] font-bold text-gray-500 uppercase">Marca D&apos;água (Opcional)</label>
                            <input 
                                type="file" 
                                accept="image/*" 
                                onChange={(e) => {
                                    const file = e.target.files?.[0];
                                    if (file) {
                                        const reader = new FileReader();
                                        reader.onload = (event) => setWatermark(event.target?.result as string);
                                        reader.readAsDataURL(file);
                                    }
                                }} 
                                className="bg-black border border-gray-800 rounded px-2 py-1 text-[10px] text-white focus:border-red-600 outline-none w-48"
                            />
                        </div>
                        <div className="flex items-center gap-2 pt-4">
                            <input 
                                type="checkbox"
                                id="includeTOC"
                                checked={includeTOC}
                                onChange={e => setIncludeTOC(e.target.checked)}
                                className="w-4 h-4 rounded border-gray-800 bg-black text-red-600 focus:ring-red-600"
                            />
                            <label htmlFor="includeTOC" className="text-[10px] font-bold text-gray-400 uppercase cursor-pointer hover:text-white transition-colors">
                                Incluir Sumário (Índice) na primeira página
                            </label>
                        </div>
                    </div>
                    <button 
                        onClick={handleGenerateMaterial}
                        disabled={isGenerating || !disciplinaName || !disciplinaAssunto}
                        className={`px-4 py-2 ${isGenerating || !disciplinaName || !disciplinaAssunto ? 'bg-purple-900/50 text-purple-300' : 'bg-purple-600 hover:bg-purple-500 text-white'} font-bold uppercase text-xs rounded flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-900/20`}
                    >
                        {isGenerating ? (
                            <>
                                <div className="animate-spin rounded-full h-3 w-3 border-t-2 border-white"></div>
                                Gerando com IA...
                            </>
                        ) : (
                            <>
                                <Wand2 size={14} />
                                Gerar Material Didático (IA) ({selectedLessonIds.length})
                            </>
                        )}
                    </button>
                </div>
            )}

            {generatedMarkdown && (
                <div className="flex gap-2">
                    <button 
                        onClick={handleDownloadPDF}
                        className="bg-emerald-600 hover:bg-emerald-500 text-white font-bold uppercase text-xs rounded px-4 py-2 flex items-center gap-2 transition-all shadow-lg shadow-emerald-900/20"
                    >
                        <Download size={14} />
                        Baixar PDF Padrão Insanus
                    </button>
                </div>
            )}

            <button 
                onClick={() => { setEditingFolder(null); setIsFolderModalOpen(true); }}
                className="px-4 py-2 bg-[#1a1d24] border border-gray-700 hover:border-gray-500 text-white font-bold uppercase text-xs rounded flex items-center gap-2"
            >
                <Folder size={16} className="text-yellow-500" fill="currentColor" />
                Criar Pasta
            </button>
            <button 
                onClick={() => { setEditingLesson(null); setTargetFolderIdForNewLesson(null); setIsLessonModalOpen(true); }}
                className="px-6 py-2 bg-red-600 hover:bg-red-500 text-white font-bold uppercase text-xs rounded shadow-lg shadow-red-900/20 flex items-center gap-2"
            >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                Criar Aula
            </button>
        </div>
      </div>

      {/* Conteúdo */}
      <div className="space-y-4 max-w-4xl mx-auto">
        {loading ? (
            <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-red-600"></div></div>
        ) : (
            <>
                {/* Lista Unificada de Pastas e Aulas Raiz */}
                {[
                  ...subModules.map(folder => ({ type: 'folder' as const, id: folder.id, data: folder, order: folder.order })),
                  ...lessons.filter(l => !l.subModuleId).map(lesson => ({ type: 'lesson' as const, id: lesson.id, data: lesson, order: lesson.order }))
                ]
                .sort((a, b) => (a.order || 0) - (b.order || 0))
                .map((item, index, array) => {
                  if (item.type === 'folder') {
                    const folder = item.data;
                    return (
                      <SubModuleItem 
                        key={folder.id}
                        subModule={folder}
                        lessons={getLessonsInFolder(folder.id)}
                        onEdit={() => { setEditingFolder(folder); setIsFolderModalOpen(true); }}
                        onDelete={() => setItemToDelete({ type: 'folder', id: folder.id, title: folder.title })}
                        onAddLesson={() => { setEditingLesson(null); setTargetFolderIdForNewLesson(folder.id); setIsLessonModalOpen(true); }}
                        onEditLesson={(l) => { setEditingLesson(l); setIsLessonModalOpen(true); }}
                        onDeleteLesson={(l) => setItemToDelete({ type: 'lesson', id: l.id, title: l.title })}
                        onMoveLesson={setLessonToMove}
                        onManageLesson={setManagingLesson} 

                        onMoveUp={() => handleReorderMixed(index, 'up')}
                        onMoveDown={() => handleReorderMixed(index, 'down')}
                        onReorderLesson={(idx, dir) => handleReorderLesson(idx, dir, folder.id)}
                        isFirst={index === 0}
                        isLast={index === array.length - 1}

                        isOpen={!!expandedFolders[folder.id]}
                        onToggle={() => toggleFolder(folder.id)}

                        selectedLessonIds={selectedLessonIds}
                        onToggleLessonSelection={toggleLessonSelection}
                      />
                    );
                  } else {
                    const lesson = item.data;
                    return (
                      <LessonItem 
                        key={lesson.id}
                        lesson={lesson}
                        onEdit={() => { setEditingLesson(lesson); setIsLessonModalOpen(true); }}
                        onDelete={() => setItemToDelete({ type: 'lesson', id: lesson.id, title: lesson.title })}
                        onMove={() => setLessonToMove(lesson)}
                        onManageContent={() => setManagingLesson(lesson)} 
                        onReorderUp={() => handleReorderMixed(index, 'up')}
                        onReorderDown={() => handleReorderMixed(index, 'down')}
                        isFirst={index === 0}
                        isLast={index === array.length - 1}

                        isSelected={selectedLessonIds.includes(lesson.id)}
                        onToggleSelection={toggleLessonSelection}
                      />
                    );
                  }
                })}

                {lessons.length === 0 && subModules.length === 0 && (
                    <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                        <p className="text-gray-500">Este módulo está vazio.</p>
                    </div>
                )}
            </>
        )}
      </div>

      {/* --- MODAIS --- */}

      <FolderModal 
        isOpen={isFolderModalOpen}
        onClose={() => setIsFolderModalOpen(false)}
        onSave={handleSaveFolder}
        initialTitle={editingFolder?.title}
        initialPublishDate={editingFolder?.publishDate}
      />

      <LessonModal
        isOpen={isLessonModalOpen}
        onClose={() => setIsLessonModalOpen(false)}
        onSave={handleSaveLesson}
        initialTitle={editingLesson?.title}
        initialCover={editingLesson?.coverUrl}
        initialType={editingLesson?.type}
      />

      <ConfirmationModal 
        isOpen={!!itemToDelete}
        title={`Excluir ${itemToDelete?.type === 'folder' ? 'Pasta' : 'Aula'}?`}
        message={`Deseja excluir "${itemToDelete?.title}"?`}
        onConfirm={itemToDelete?.type === 'folder' ? handleDeleteFolder : handleDeleteLesson}
        onCancel={() => setItemToDelete(null)}
        isDanger
      />

      {/* Modal para Mover Aula */}
      {lessonToMove && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
            <div className="bg-[#121418] border border-gray-800 rounded-xl w-full max-w-sm shadow-2xl">
                <div className="p-4 border-b border-gray-800"><h3 className="text-white font-bold">Mover &quot;{lessonToMove.title}&quot; para...</h3></div>
                <div className="p-2 space-y-1">
                    <button 
                        onClick={() => handleMoveLessonConfirm(null)}
                        className={`w-full text-left px-4 py-3 rounded hover:bg-gray-800 text-sm ${!lessonToMove.subModuleId ? 'bg-red-900/20 text-red-400 border border-red-900/50' : 'text-gray-300'}`}
                    >
                        (Raiz do Módulo)
                    </button>
                    {subModules.map(folder => (
                        <button 
                            key={folder.id}
                            onClick={() => handleMoveLessonConfirm(folder.id)}
                            className={`w-full text-left px-4 py-3 rounded hover:bg-gray-800 text-sm flex items-center gap-2 ${lessonToMove.subModuleId === folder.id ? 'bg-red-900/20 text-red-400 border border-red-900/50' : 'text-gray-300'}`}
                        >
                            <svg className="w-4 h-4 text-yellow-500" fill="currentColor" viewBox="0 0 20 20"><path d="M2 6a2 2 0 012-2h5l2 2h5a2 2 0 01-2 2H4a2 2 0 01-2-2V6z" /></svg>
                            {folder.title}
                        </button>
                    ))}
                </div>
                <div className="p-4 border-t border-gray-800 flex justify-end">
                    <button onClick={() => setLessonToMove(null)} className="text-gray-400 hover:text-white text-xs font-bold uppercase">Cancelar</button>
                </div>
            </div>
        </div>
      )}

      {/* Template de PDF Oculto */}
      {generatedMarkdown && (
        <PDFTemplate 
          markdownText={generatedMarkdown}
          disciplinaName={disciplinaName}
          disciplinaAssunto={disciplinaAssunto}
          includeTOC={includeTOC}
          containerRef={containerRef}
        />
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { 
  FileText, Plus, Loader2, BarChart2, X, HelpCircle
} from 'lucide-react';
// import { useBlocker } from 'react-router-dom'; // REMOVIDO: Causa erro sem Data Router
import { Plan } from '../../../services/planService';
import { 
  getEdict, 
  toggleEdict, 
  addEdictDiscipline, 
  addEdictTopic, 
  addEdictSubtopic, 
  deleteEdictItem, 
  renameEdictItem,
  saveEdictStructure,
  linkGoalsToItem,
  unlinkGoalFromItem,
  getAllLinkedGoalIds,
  addStudyLevel,
  deleteStudyLevel,
  updateTopicLevel,
  toggleActiveUserMode, // Importado
  EdictStructure
} from '../../../services/edictService';
import { deepCloneSafe } from '../../../services/firestoreUtils';
import { getMetas, Meta, MetaType } from '../../../services/metaService';
import { getDisciplines, getTopics, Discipline, Topic } from '../../../services/structureService';
import { usePlanSync } from '../../../hooks/usePlanSync'; // Hook de Sync
import VerticalEdictItem from './VerticalEdictItem';
import ConfirmationModal from '../../ui/ConfirmationModal';
import GoalSelectorModal from './GoalSelectorModal';
import StudyLevelsModal from './StudyLevelsModal';
import SyncControlPanel from '../sync/SyncControlPanel'; // Botão de Sync

interface VerticalEdictManagerProps {
  plan: Plan;
  onUpdate: () => void; // Para atualizar o estado do plano pai (isEdictEnabled)
}

// Type for the full tree structure passed to Modal
type PlanTreeGroup = {
  discipline: Discipline;
  topics: {
    topic: Topic;
    metas: Meta[];
  }[];
};

const VerticalEdictManager: React.FC<VerticalEdictManagerProps> = ({ plan, onUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [structure, setStructure] = useState<EdictStructure | null>(null);
  const [expandedItems, setExpandedItems] = useState<string[]>([]);
  const [isActiveUserMode, setIsActiveUserMode] = useState(false); // Estado local do toggle

  // Data for Linking
  const [planStructureTree, setPlanStructureTree] = useState<PlanTreeGroup[]>([]);
  const [metaLookup, setMetaLookup] = useState<Record<string, Meta>>({});
  const [globalLinkedIds, setGlobalLinkedIds] = useState<Set<string>>(new Set());

  // States para Criação de Disciplina
  const [isCreatingDiscipline, setIsCreatingDiscipline] = useState(false);
  const [newDisciplineName, setNewDisciplineName] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  // States para Modal de Link
  const [isLinkModalOpen, setIsLinkModalOpen] = useState(false);
  const [linkTarget, setLinkTarget] = useState<{ disciplineId: string; topicId?: string; subtopicId?: string; name: string } | null>(null);

  // States para Modal de Níveis
  const [isLevelsModalOpen, setIsLevelsModalOpen] = useState(false);

  // Modal de Exclusão
  const [deleteData, setDeleteData] = useState<{
    type: 'discipline' | 'topic' | 'subtopic';
    ids: { disciplineId: string; topicId?: string; subtopicId?: string };
    name: string;
  } | null>(null);

  // Sync Logic Hook
  const { hasPendingChanges } = usePlanSync(plan.id);

  // PROTEÇÃO NATIVA (Browser Exit/Reload)
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (hasPendingChanges) {
        e.preventDefault();
        e.returnValue = ''; // Necessário para Chrome
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [hasPendingChanges]);

  // === INITIAL LOAD ===
  useEffect(() => {
    if (plan) {
        setIsActiveUserMode(plan.isActiveUserMode || false);
    }
    if (plan.id && plan.isEdictEnabled !== false) {
      loadEdictData();
      loadPlanStructureTree(); // Build Hierarchy
    }
  }, [plan.id, plan.isEdictEnabled, plan.isActiveUserMode]);

  const loadEdictData = async () => {
    if (!plan.id) return;
    setLoading(true);
    try {
      const data = await getEdict(plan.id);
      setStructure(data);

      // Calculate used IDs
      const usedIds = getAllLinkedGoalIds(data);
      setGlobalLinkedIds(usedIds);

      // Auto-expand disciplines if few
      if (data.disciplines.length <= 3) {
        setExpandedItems(data.disciplines.map(d => d.id));
      }
    } catch (error) {
      console.error("Erro ao carregar edital:", error);
    } finally {
      setLoading(false);
    }
  };

  // Build the hierarchical tree: Disciplines -> Topics -> Metas
  const loadPlanStructureTree = async () => {
    if (!plan.id) return;

    try {
      const disciplines = await getDisciplines(plan.id);
      const tree: PlanTreeGroup[] = [];
      const lookup: Record<string, Meta> = {};

      // Build tree sequentially to ensure data integrity
      for (const disc of disciplines) {
        if (!disc.id) continue;

        const topics = await getTopics(plan.id, disc.id);
        const topicsWithMetas: { topic: Topic; metas: Meta[] }[] = [];

        for (const topic of topics) {
          if (!topic.id) continue;

          const metas = await getMetas(plan.id, disc.id, topic.id);

          // Populate Lookup for rendering in Edict Items
          metas.forEach(m => {
            if (m.id) lookup[m.id] = m;
          });

          topicsWithMetas.push({ topic, metas });
        }

        // Only add disciplines that have topics (optional optimization)
        tree.push({
          discipline: disc,
          topics: topicsWithMetas
        });
      }

      setPlanStructureTree(tree);
      setMetaLookup(lookup);

    } catch (error) {
      console.error("Erro ao carregar estrutura do plano:", error);
    }
  };

  // === ACTIONS ===

  const handleEnableEdict = async () => {
    if (!plan.id) return;
    setLoading(true);
    try {
      await toggleEdict(plan.id, true);
      await loadEdictData();
      await loadPlanStructureTree();
      onUpdate();
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleToggleActiveUserMode = async () => {
    if (!plan.id) return;
    const newState = !isActiveUserMode;
    setIsActiveUserMode(newState);
    await toggleActiveUserMode(plan.id, newState);
    onUpdate(); // Atualiza o plano pai se necessário
  };

  // --- STUDY LEVELS ---

  const handleAddStudyLevel = async (name: string) => {
    if (!plan.id) return;
    await addStudyLevel(plan.id, name);
    await loadEdictData();
  };

  const handleDeleteStudyLevel = async (id: string) => {
    if (!plan.id) return;
    await deleteStudyLevel(plan.id, id);
    await loadEdictData();
  };

  const handleUpdateTopicLevel = async (disciplineId: string, topicId: string, levelId: string) => {
    if (!plan.id) return;
    // Otimista
    if (structure) {
        const newStructure = { ...structure };
        const disc = newStructure.disciplines.find(d => d.id === disciplineId);
        const topic = disc?.topics.find(t => t.id === topicId);
        if (topic) topic.studyLevelId = levelId || null;
        setStructure(newStructure);
    }
    await updateTopicLevel(plan.id, disciplineId, topicId, levelId || null);
  };

  // --- DISCIPLINE CREATION ---

  const openCreateDisciplineModal = () => {
    setNewDisciplineName("");
    setIsCreatingDiscipline(true);
  };

  const handleSaveDiscipline = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!plan.id || !newDisciplineName.trim()) return;

    setIsSubmitting(true);
    try {
      await addEdictDiscipline(plan.id, newDisciplineName);
      await loadEdictData(); // Refresh structure
      setIsCreatingDiscipline(false);
      setNewDisciplineName("");
    } catch (error) {
      console.error("Erro ao criar disciplina", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- TOPIC / SUBTOPIC CREATION ---

  const handleAddTopic = async (disciplineId: string) => {
    if (!plan.id) return;
    const name = "Novo Tópico"; 
    try {
      await addEdictTopic(plan.id, disciplineId, name);
      if (!expandedItems.includes(disciplineId)) {
        setExpandedItems(prev => [...prev, disciplineId]);
      }
      await loadEdictData();
    } catch (error) {
      console.error(error);
    }
  };

  const handleAddSubtopic = async (disciplineId: string, topicId: string) => {
    if (!plan.id) return;
    const name = "Novo Subtópico";
    try {
      await addEdictSubtopic(plan.id, disciplineId, topicId, name);
      if (!expandedItems.includes(topicId)) {
        setExpandedItems(prev => [...prev, topicId]);
      }
      await loadEdictData();
    } catch (error) {
      console.error(error);
    }
  };

  // --- GOAL LINKING ---

  const openLinkModal = (
    ids: { disciplineId: string; topicId?: string; subtopicId?: string },
    name: string
  ) => {
    setLinkTarget({ ...ids, name });
    setIsLinkModalOpen(true);
  };

  const handleConfirmLink = async (selectedGoals: { id: string, type: MetaType }[]) => {
    if (!plan.id || !linkTarget) return;
    try {
      await linkGoalsToItem(plan.id, linkTarget, selectedGoals);
      await loadEdictData(); // Recalcula usedIds e structure
    } catch (error) {
      console.error("Erro ao vincular metas:", error);
    }
  };

  const handleUnlinkGoal = async (
    ids: { disciplineId: string; topicId?: string; subtopicId?: string },
    goalId: string,
    type: MetaType
  ) => {
    if (!plan.id) return;
    try {
      await unlinkGoalFromItem(plan.id, ids, goalId, type);
      await loadEdictData(); // Refresh to update usedIds
    } catch (error) {
      console.error("Erro ao desvincular meta:", error);
    }
  };

  // --- DELETE LOGIC ---
  const requestDelete = (type: 'discipline' | 'topic' | 'subtopic', ids: any, name: string) => {
    setDeleteData({ type, ids, name });
  };

  const confirmDelete = async () => {
    if (!plan.id || !deleteData) return;
    try {
      await deleteEdictItem(plan.id, deleteData.type, deleteData.ids);
      setDeleteData(null);
      await loadEdictData();
    } catch (error) {
      console.error(error);
    }
  };

  // --- RENAME & UPDATE LOGIC ---
  const handleRename = async (type: 'discipline' | 'topic' | 'subtopic', ids: any, newName: string) => {
    if (!plan.id) return;
    try {
      await renameEdictItem(plan.id, type, ids, newName);
      // Otimista
      if (structure) {
        const newStructure = deepCloneSafe(structure);
        const disc = newStructure.disciplines.find(d => d.id === ids.disciplineId);
        if (disc) {
          if (type === 'discipline') {
            disc.name = newName;
          } else if (type === 'topic' && ids.topicId) {
            const topic = disc.topics.find(t => t.id === ids.topicId);
            if (topic) topic.name = newName;
          } else if (type === 'subtopic' && ids.topicId && ids.subtopicId) {
            const topic = disc.topics.find(t => t.id === ids.topicId);
            if (topic) {
              const sub = topic.subtopics.find(s => s.id === ids.subtopicId);
              if (sub) sub.name = newName;
            }
          }
        }
        setStructure(newStructure);
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleUpdateObservation = async (type: 'discipline' | 'topic' | 'subtopic', ids: any, newObservation: string) => {
    if (!plan.id) return;
    try {
      await updateEdictItem(plan.id, type, ids, { observation: newObservation });
      // Otimista
      if (structure) {
        const newStructure = deepCloneSafe(structure);
        const disc = newStructure.disciplines.find(d => d.id === ids.disciplineId);
        if (disc) {
          if (type === 'topic' && ids.topicId) {
            const topic = disc.topics.find(t => t.id === ids.topicId);
            if (topic) topic.observation = newObservation;
          } else if (type === 'subtopic' && ids.topicId && ids.subtopicId) {
            const topic = disc.topics.find(t => t.id === ids.topicId);
            if (topic) {
              const sub = topic.subtopics.find(s => s.id === ids.subtopicId);
              if (sub) sub.observation = newObservation;
            }
          }
        }
        setStructure(newStructure);
      }
    } catch (error) {
      console.error(error);
    }
  };

  // --- REORDER LOGIC ---
  const handleMove = async (
    type: 'discipline' | 'topic' | 'subtopic', 
    ids: { disciplineId: string, topicId?: string },
    index: number, 
    direction: 'up' | 'down'
  ) => {
    if (!structure || !plan.id) return;

    const newStructure = deepCloneSafe(structure);
    let itemsArray: any[] = [];

    if (type === 'discipline') {
      itemsArray = newStructure.disciplines;
    } else if (type === 'topic') {
      const disc = newStructure.disciplines.find(d => d.id === ids.disciplineId);
      if (disc) itemsArray = disc.topics;
    } else if (type === 'subtopic' && ids.topicId) {
      const disc = newStructure.disciplines.find(d => d.id === ids.disciplineId);
      const topic = disc?.topics.find(t => t.id === ids.topicId);
      if (topic) itemsArray = topic.subtopics;
    }

    if (itemsArray.length === 0) return;

    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= itemsArray.length) return;

    // Swap
    [itemsArray[index], itemsArray[targetIndex]] = [itemsArray[targetIndex], itemsArray[index]];

    setStructure(newStructure);
    await saveEdictStructure(plan.id, newStructure);
  };

  // --- EXPAND/COLLAPSE ---
  const toggleExpand = (id: string) => {
    setExpandedItems(prev => 
      prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
    );
  };

  // === RENDER ===

  if (!plan.isEdictEnabled) {
    return (
      <div className="h-full flex flex-col items-center justify-center gap-6 p-10 bg-zinc-900/20 rounded-2xl border border-zinc-800 border-dashed animate-in fade-in">
        <div className="w-20 h-20 bg-zinc-900 rounded-full flex items-center justify-center border-2 border-zinc-800">
          <FileText size={40} className="text-zinc-600" />
        </div>
        <div className="text-center space-y-2 max-w-md">
          <h3 className="text-xl font-black text-white uppercase tracking-tighter">Edital Verticalizado</h3>
          <p className="text-zinc-500 text-sm">
            Habilite esta funcionalidade para criar um checklist hierárquico do edital, permitindo que os alunos acompanhem item a item.
          </p>
        </div>
        <button 
          onClick={handleEnableEdict}
          disabled={loading}
          className="px-8 py-3 bg-brand-red hover:bg-red-600 text-white font-black uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-red-900/20 flex items-center gap-2"
        >
          {loading ? <Loader2 className="animate-spin" /> : 'Ativar Edital Verticalizado'}
        </button>
      </div>
    );
  }

  if (loading && !structure) {
    return <div className="flex justify-center p-10"><Loader2 className="animate-spin text-brand-red" /></div>;
  }

  return (
    <div className="h-full flex flex-col gap-4 animate-in fade-in slide-in-from-right-4 duration-500">
      {/* Header Actions */}
      <div className="flex justify-between items-center pb-4 border-b border-zinc-800">
        <h3 className="text-xs font-black text-zinc-400 uppercase tracking-widest flex items-center gap-2">
          <FileText size={14} /> Estrutura do Edital
        </h3>

        <div className="flex items-center gap-2">
          {/* Painel de Sincronização */}
          {plan.id && <SyncControlPanel planId={plan.id} variant="minimal" />}

          <div className="w-px h-6 bg-zinc-800 mx-2" />

          {/* ACTIVE USER TOGGLE */}
          <div className="flex items-center gap-3 mr-2 bg-zinc-900/30 px-3 py-1 rounded-lg border border-zinc-800/50">
             <div className="flex flex-col items-end">
                <div className="flex items-center gap-1 group relative cursor-help">
                   <span className={`text-[9px] font-black uppercase tracking-widest ${isActiveUserMode ? 'text-emerald-400' : 'text-zinc-500'}`}>
                      Usuário Ativo
                   </span>
                   <HelpCircle size={10} className="text-zinc-600" />

                   {/* Tooltip */}
                   <div className="absolute top-full right-0 mt-2 w-48 p-2 bg-zinc-950 border border-zinc-800 rounded-lg text-[9px] text-zinc-400 font-medium leading-relaxed opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-xl">
                      Permite que o aluno marque itens como concluídos manualmente, removendo-os da agenda futura.
                   </div>
                </div>
             </div>

             <button 
               onClick={handleToggleActiveUserMode}
               className={`relative w-9 h-5 rounded-full transition-colors duration-300 focus:outline-none border border-transparent ${
                 isActiveUserMode ? 'bg-emerald-500/20 border-emerald-500/50' : 'bg-zinc-800 border-zinc-700'
               }`}
             >
                <div 
                  className={`absolute top-0.5 left-0.5 w-3.5 h-3.5 rounded-full transition-transform duration-300 shadow-sm ${
                    isActiveUserMode ? 'translate-x-4 bg-emerald-400' : 'translate-x-0 bg-zinc-500'
                  }`}
                />
             </button>
          </div>

          <div className="w-px h-6 bg-zinc-800 mx-2" />

          <button 
            onClick={() => setIsLevelsModalOpen(true)}
            className="flex items-center gap-2 px-3 py-2 bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 hover:border-zinc-600 rounded-lg text-[10px] font-black uppercase text-zinc-400 hover:text-white tracking-widest transition-all"
          >
            <BarChart2 size={12} /> Gerenciar Níveis
          </button>
          <button 
            onClick={openCreateDisciplineModal}
            className="flex items-center gap-2 px-4 py-2 bg-brand-red hover:bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest transition-all shadow-lg shadow-red-900/20"
          >
            <Plus size={12} /> Nova Disciplina
          </button>
        </div>
      </div>

      {/* Tree Content */}
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 pb-20">
        {!structure?.disciplines.length && (
          <div className="text-center py-20 text-zinc-600 text-xs font-bold uppercase border-2 border-dashed border-zinc-900 rounded-xl">
            Nenhuma disciplina cadastrada. Comece adicionando uma acima.
          </div>
        )}

        {structure?.disciplines.map((discipline, dIndex) => (
          <VerticalEdictItem
            key={discipline.id}
            id={discipline.id}
            name={discipline.name}
            type="discipline"
            isExpanded={expandedItems.includes(discipline.id)}
            onToggleExpand={() => toggleExpand(discipline.id)}
            onRename={(newName) => handleRename('discipline', { disciplineId: discipline.id }, newName)}
            onDelete={() => requestDelete('discipline', { disciplineId: discipline.id }, discipline.name)}
            onAddChild={() => handleAddTopic(discipline.id)}
            onMove={(dir) => handleMove('discipline', { disciplineId: discipline.id }, dIndex, dir)}
            isFirst={dIndex === 0}
            isLast={dIndex === structure.disciplines.length - 1}
          >
            {/* TÓPICOS */}
            {discipline.topics.map((topic, tIndex) => (
              <VerticalEdictItem
                key={topic.id}
                id={topic.id}
                name={topic.name}
                type="topic"
                linkedGoals={topic.linkedGoals}
                metaLookup={metaLookup}
                isExpanded={expandedItems.includes(topic.id)}

                // Pass Level Data
                studyLevels={structure?.studyLevels}
                currentLevelId={topic.studyLevelId}
                onLevelChange={(newLevelId) => handleUpdateTopicLevel(discipline.id, topic.id, newLevelId)}

                onToggleExpand={() => toggleExpand(topic.id)}
                onRename={(newName) => handleRename('topic', { disciplineId: discipline.id, topicId: topic.id }, newName)}
                onUpdateObservation={(newObs) => handleUpdateObservation('topic', { disciplineId: discipline.id, topicId: topic.id }, newObs)}
                onDelete={() => requestDelete('topic', { disciplineId: discipline.id, topicId: topic.id }, topic.name)}
                onAddChild={() => handleAddSubtopic(discipline.id, topic.id)}
                onMove={(dir) => handleMove('topic', { disciplineId: discipline.id }, tIndex, dir)}
                onLinkGoals={() => openLinkModal({ disciplineId: discipline.id, topicId: topic.id }, topic.name)}
                onUnlinkGoal={(goalId, type) => handleUnlinkGoal({ disciplineId: discipline.id, topicId: topic.id }, goalId, type)}
                isFirst={tIndex === 0}
                isLast={tIndex === discipline.topics.length - 1}
                observation={topic.observation}
              >
                {/* SUBTÓPICOS */}
                {topic.subtopics.map((sub, sIndex) => (
                  <VerticalEdictItem
                    key={sub.id}
                    id={sub.id}
                    name={sub.name}
                    type="subtopic"
                    linkedGoals={sub.linkedGoals}
                    metaLookup={metaLookup}
                    onRename={(newName) => handleRename('subtopic', { disciplineId: discipline.id, topicId: topic.id, subtopicId: sub.id }, newName)}
                    onUpdateObservation={(newObs) => handleUpdateObservation('subtopic', { disciplineId: discipline.id, topicId: topic.id, subtopicId: sub.id }, newObs)}
                    onDelete={() => requestDelete('subtopic', { disciplineId: discipline.id, topicId: topic.id, subtopicId: sub.id }, sub.name)}
                    onMove={(dir) => handleMove('subtopic', { disciplineId: discipline.id, topicId: topic.id }, sIndex, dir)}
                    onLinkGoals={() => openLinkModal({ disciplineId: discipline.id, topicId: topic.id, subtopicId: sub.id }, sub.name)}
                    onUnlinkGoal={(goalId, type) => handleUnlinkGoal({ disciplineId: discipline.id, topicId: topic.id, subtopicId: sub.id }, goalId, type)}
                    isFirst={sIndex === 0}
                    isLast={sIndex === topic.subtopics.length - 1}
                    observation={sub.observation}
                  />
                ))}
              </VerticalEdictItem>
            ))}
          </VerticalEdictItem>
        ))}
      </div>

      {/* MODAL CRIAR DISCIPLINA */}
      {isCreatingDiscipline && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200" onMouseDown={() => setIsCreatingDiscipline(false)}>
          <div className="w-full max-w-md bg-zinc-950 border border-zinc-800 rounded-2xl shadow-2xl p-6 animate-in zoom-in-95 duration-200" onMouseDown={e => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-black text-white uppercase tracking-tighter">Nova Disciplina do Edital</h3>
              <button onClick={() => setIsCreatingDiscipline(false)} className="text-zinc-500 hover:text-white transition-colors">
                <X size={20} />
              </button>
            </div>
            <form onSubmit={handleSaveDiscipline}>
              <div className="space-y-4">
                <div>
                  <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest block mb-2">Nome da Disciplina</label>
                  <input
                    value={newDisciplineName}
                    onChange={e => setNewDisciplineName(e.target.value)}
                    autoFocus
                    placeholder="Ex: Direito Constitucional"
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-sm font-bold text-white placeholder-zinc-600 focus:outline-none focus:border-brand-red focus:ring-1 focus:ring-brand-red/20"
                  />
                </div>
                <div className="flex gap-3 pt-2">
                  <button type="button" onClick={() => setIsCreatingDiscipline(false)} className="flex-1 py-3 bg-zinc-900 hover:bg-zinc-800 border border-zinc-800 rounded-xl text-xs font-bold text-zinc-400 hover:text-white uppercase tracking-widest transition-all">
                    Cancelar
                  </button>
                  <button type="submit" disabled={isSubmitting || !newDisciplineName.trim()} className="flex-1 py-3 bg-brand-red hover:bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-red-900/20 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2">
                    {isSubmitting ? <Loader2 className="animate-spin" size={14} /> : 'Salvar'}
                  </button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* MODAL DE SELEÇÃO DE METAS */}
      <GoalSelectorModal 
        isOpen={isLinkModalOpen}
        onClose={() => setIsLinkModalOpen(false)}
        onSave={handleConfirmLink}
        planStructure={planStructureTree}
        globalLinkedIds={globalLinkedIds}
        title={linkTarget?.name || 'Item'}
      />

      {/* MODAL DE NÍVEIS DE ESTUDO */}
      <StudyLevelsModal 
        isOpen={isLevelsModalOpen}
        onClose={() => setIsLevelsModalOpen(false)}
        levels={structure?.studyLevels || []}
        onAdd={handleAddStudyLevel}
        onDelete={handleDeleteStudyLevel}
      />

      {/* MODAL DE CONFIRMAÇÃO (Exclusão) */}
      <ConfirmationModal 
        isOpen={!!deleteData}
        onClose={() => setDeleteData(null)}
        onConfirm={confirmDelete}
        title={`Excluir ${deleteData?.type === 'discipline' ? 'Disciplina' : 'Item'}?`}
        message={`Deseja excluir "${deleteData?.name}"? ${deleteData?.type !== 'subtopic' ? 'Todos os itens internos também serão removidos.' : ''}`}
      />
    </div>
  );
};

export default VerticalEdictManager;

import React, { useState, useEffect, useMemo } from 'react';
import { X, Upload, Check, ChevronDown, ChevronUp, Search } from 'lucide-react';
import { LiveEvent, LiveEventAccessControl } from '../../../types/liveEvent';
import { getPlans } from '../../../services/planService';
import { courseService } from '../../../services/courseService';
import { classService } from '../../../services/classService';
import { getSimulatedClasses } from '../../../services/simulatedService';

interface LiveEventFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (data: LiveEvent, thumbnailFile?: File) => Promise<void>;
  initialData?: LiveEvent | null;
}

export const LiveEventFormModal: React.FC<LiveEventFormModalProps> = ({ isOpen, onClose, onSave, initialData }) => {
  const [title, setTitle] = useState('');
  const [subtitle, setSubtitle] = useState('');
  const [eventDate, setEventDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [timezoneLocation, setTimezoneLocation] = useState('Brasília/DF');
  const [isIsolatedProduct, setIsIsolatedProduct] = useState(false);
  const [thumbnailFile, setThumbnailFile] = useState<File | null>(null);
  const [thumbnailPreview, setThumbnailPreview] = useState<string>('');

  const [accessControl, setAccessControl] = useState<LiveEventAccessControl>({
    plans: [],
    onlineCourses: [],
    presentialClasses: [],
    simulated: []
  });

  const [loading, setLoading] = useState(false);

  // Search states
  const [searchPlan, setSearchPlan] = useState('');
  const [searchCourse, setSearchCourse] = useState('');
  const [searchClass, setSearchClass] = useState('');
  const [searchSimulated, setSearchSimulated] = useState('');
  const [expandedSection, setExpandedSection] = useState<string | null>('plans');

  // Data for selects
  const [plans, setPlans] = useState<any[]>([]);
  const [courses, setCourses] = useState<any[]>([]);
  const [classes, setClasses] = useState<any[]>([]);
  const [simulated, setSimulated] = useState<any[]>([]);

  // Filtered data
  const filteredPlans = useMemo(() => {
    if (!searchPlan) return plans;
    const term = searchPlan.toLowerCase();
    return plans.filter(p => 
      (p.title || p.name || '').toLowerCase().includes(term) ||
      (p.category || '').toLowerCase().includes(term)
    );
  }, [plans, searchPlan]);

  const filteredCourses = useMemo(() => {
    if (!searchCourse) return courses;
    const term = searchCourse.toLowerCase();
    return courses.filter(c => 
      (c.title || c.name || '').toLowerCase().includes(term) ||
      (c.category || '').toLowerCase().includes(term)
    );
  }, [courses, searchCourse]);

  const filteredClasses = useMemo(() => {
    if (!searchClass) return classes;
    const term = searchClass.toLowerCase();
    return classes.filter(c => 
      (c.title || c.name || '').toLowerCase().includes(term) ||
      (c.category || '').toLowerCase().includes(term)
    );
  }, [classes, searchClass]);

  const filteredSimulated = useMemo(() => {
    if (!searchSimulated) return simulated;
    const term = searchSimulated.toLowerCase();
    return simulated.filter(s => 
      (s.title || s.name || '').toLowerCase().includes(term) ||
      (s.category || '').toLowerCase().includes(term)
    );
  }, [simulated, searchSimulated]);

  useEffect(() => {
    if (isOpen) {
      loadData();
      if (initialData) {
        setTitle(initialData.title);
        setSubtitle(initialData.subtitle || '');
        setEventDate(initialData.eventDate);
        setStartTime(initialData.startTime);
        setTimezoneLocation(initialData.timezoneLocation || 'Brasília/DF');
        setIsIsolatedProduct(initialData.isIsolatedProduct);
        setAccessControl(initialData.accessControl);
        setThumbnailPreview(initialData.thumbnailUrl || '');
      } else {
        resetForm();
      }
    }
  }, [isOpen, initialData]);

  const loadData = async () => {
    try {
      const [plansData, coursesData, classesData, simulatedData] = await Promise.all([
        getPlans(),
        courseService.getCourses(),
        classService.getClasses(),
        getSimulatedClasses()
      ]);
      setPlans(plansData);
      setCourses(coursesData);
      setClasses(classesData);
      setSimulated(simulatedData);
    } catch (error) {
      console.error("Error loading access control data:", error);
    }
  };

  const resetForm = () => {
    setTitle('');
    setSubtitle('');
    setEventDate('');
    setStartTime('');
    setTimezoneLocation('Brasília/DF');
    setIsIsolatedProduct(false);
    setThumbnailFile(null);
    setThumbnailPreview('');
    setAccessControl({
      plans: [],
      onlineCourses: [],
      presentialClasses: [],
      simulated: []
    });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setThumbnailFile(file);
      setThumbnailPreview(URL.createObjectURL(file));
    }
  };

  const toggleAccess = (type: keyof LiveEventAccessControl, id: string) => {
    setAccessControl(prev => {
      const currentList = prev[type];
      if (currentList.includes(id)) {
        return { ...prev, [type]: currentList.filter(itemId => itemId !== id) };
      } else {
        return { ...prev, [type]: [...currentList, id] };
      }
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const eventData: LiveEvent = {
        ...(initialData?.id ? { id: initialData.id } : {}),
        title,
        subtitle,
        eventDate,
        startTime,
        timezoneLocation,
        isIsolatedProduct,
        accessControl,
        status: initialData?.status || 'scheduled',
        thumbnailUrl: initialData?.thumbnailUrl || ''
      };

      await onSave(eventData, thumbnailFile || undefined);
      onClose();
    } catch (error) {
      console.error("Error saving live event:", error);
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed top-[120px] inset-x-0 bottom-0 bg-black/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4 sm:p-6 overflow-hidden">
      <div className="bg-zinc-900 border border-zinc-800 rounded-xl w-full max-w-4xl max-h-full flex flex-col shadow-2xl">

        <div className="flex items-center justify-between p-6 border-b border-zinc-800 shrink-0">
          <h2 className="text-xl font-bold text-white">
            {initialData ? 'EDITAR EVENTO AO VIVO' : 'AGENDAR EVENTO AO VIVO'}
          </h2>
          <button onClick={onClose} className="text-zinc-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-6 overflow-y-auto custom-scrollbar flex-1">
          <form id="live-event-form" onSubmit={handleSubmit} className="space-y-8">

            {/* Informações Básicas */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-red-500 border-b border-zinc-800 pb-2">Informações Básicas</h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-sm font-medium text-zinc-400 mb-1">Título do Evento *</label>
                  <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:border-red-500"
                    placeholder="Ex: Aulão de Véspera"
                  />
                </div>

                <div className="col-span-2">
                  <label className="block text-sm font-medium text-zinc-400 mb-1">Subtítulo (Opcional)</label>
                  <input
                    type="text"
                    value={subtitle}
                    onChange={(e) => setSubtitle(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:border-red-500"
                    placeholder="Ex: Revisão Final de Direito Penal"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-zinc-400 mb-1">Data do Evento *</label>
                  <input
                    type="date"
                    required
                    value={eventDate}
                    onChange={(e) => setEventDate(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:border-red-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-zinc-400 mb-1">Horário de Início *</label>
                  <input
                    type="time"
                    required
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:border-red-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-zinc-400 mb-1">Fuso Horário de Referência *</label>
                  <select
                    required
                    value={timezoneLocation}
                    onChange={(e) => setTimezoneLocation(e.target.value)}
                    className="w-full bg-black border border-zinc-800 rounded-lg px-4 py-2.5 text-white focus:outline-none focus:border-red-500"
                  >
                    <option value="Brasília/DF">Brasília/DF (Horário Padrão)</option>
                    <option value="Porto Velho/RO">Porto Velho/RO</option>
                    <option value="Rio Branco/AC">Rio Branco/AC</option>
                  </select>
                </div>
              </div>
            </div>

            {/* Capa do Evento */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-red-500 border-b border-zinc-800 pb-2">Capa do Evento (1920x1080)</h3>
              <div className="flex items-center gap-6">
                <div className="w-64 h-36 bg-black border-2 border-dashed border-zinc-700 rounded-xl overflow-hidden flex items-center justify-center relative group">
                  {thumbnailPreview ? (
                    <>
                      <img src={thumbnailPreview} alt="Preview" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <span className="text-white text-sm font-medium">Trocar Imagem</span>
                      </div>
                    </>
                  ) : (
                    <div className="flex flex-col items-center text-zinc-500">
                      <Upload size={24} className="mb-2" />
                      <span className="text-xs">Fazer Upload</span>
                    </div>
                  )}
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={handleFileChange}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
                <div className="flex-1 text-sm text-zinc-400">
                  <p>A capa será exibida na listagem de eventos e na sala de espera.</p>
                  <p className="mt-2">Recomendamos imagens na proporção 16:9 (1920x1080 pixels) para melhor visualização.</p>
                </div>
              </div>
            </div>

            {/* Configurações de Venda */}
            <div className="space-y-4">
              <h3 className="text-lg font-semibold text-red-500 border-b border-zinc-800 pb-2">Configurações de Produto</h3>
              <label className="flex items-center gap-3 cursor-pointer p-4 bg-black border border-zinc-800 rounded-xl hover:border-zinc-700 transition-colors" onClick={() => setIsIsolatedProduct(!isIsolatedProduct)}>
                <div className={`w-6 h-6 rounded-md border flex items-center justify-center transition-colors ${isIsolatedProduct ? 'bg-red-600 border-red-600' : 'border-zinc-600 bg-zinc-900'}`}>
                  {isIsolatedProduct && <Check size={16} className="text-white" />}
                </div>
                <div>
                  <span className="block text-white font-medium">Vender como Produto Isolado</span>
                  <span className="block text-xs text-zinc-500 mt-0.5">Permite liberar o acesso a este evento individualmente no cadastro do aluno.</span>
                </div>
              </label>
            </div>

            {/* Controle de Acesso */}
            <div className="space-y-6">
              <div className="flex items-center justify-between border-b border-zinc-800 pb-2">
                <h3 className="text-lg font-semibold text-red-500">Controle de Acesso (Recursos Vinculados)</h3>
                <div className="flex gap-2">
                  <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Total Selecionado:</span>
                  <span className="text-[10px] font-bold text-white bg-zinc-800 px-2 py-0.5 rounded">
                    {accessControl.plans.length + accessControl.onlineCourses.length + accessControl.presentialClasses.length + accessControl.simulated.length}
                  </span>
                </div>
              </div>
              <p className="text-sm text-zinc-400">Selecione quais recursos darão acesso automático a este evento ao vivo.</p>

              <div className="space-y-3">
                {/* Planos */}
                <div className="bg-black border border-zinc-800 rounded-xl overflow-hidden">
                  <button
                    type="button"
                    onClick={() => setExpandedSection(expandedSection === 'plans' ? null : 'plans')}
                    className="w-full flex items-center justify-between p-4 hover:bg-zinc-900/50 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                      <span className="text-white font-medium uppercase tracking-wider text-xs">Planos de Estudo</span>
                      <span className="bg-emerald-500/20 text-emerald-500 text-[10px] font-bold px-2 py-0.5 rounded-full">
                        {accessControl.plans.length}
                      </span>
                    </div>
                    {expandedSection === 'plans' ? <ChevronUp size={18} className="text-zinc-500" /> : <ChevronDown size={18} className="text-zinc-500" />}
                  </button>

                  {expandedSection === 'plans' && (
                    <div className="p-4 border-t border-zinc-800 space-y-4 bg-zinc-900/20">
                      <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={14} />
                        <input
                          type="text"
                          value={searchPlan}
                          onChange={(e) => setSearchPlan(e.target.value)}
                          placeholder="Pesquisar planos..."
                          className="w-full bg-black border border-zinc-800 rounded-lg pl-9 pr-4 py-2 text-xs text-white focus:outline-none focus:border-emerald-500/50"
                        />
                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 max-h-60 overflow-y-auto custom-scrollbar pr-2">
                        {filteredPlans.map(plan => (
                          <label key={plan.id} className="flex items-center gap-3 cursor-pointer group p-2 rounded-lg hover:bg-zinc-800/50 transition-colors" onClick={(e) => { e.preventDefault(); toggleAccess('plans', plan.id); }}>
                            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors shrink-0 ${accessControl.plans.includes(plan.id) ? 'bg-red-600 border-red-600' : 'border-zinc-600 bg-zinc-900 group-hover:border-zinc-500'}`}>
