                    <div className="space-y-2">
                        <label className="text-[10px] font-black text-zinc-500 tracking-widest flex items-center gap-1">
                            <Clock size={12} /> Tempo Estimado (min)
                        </label>
                        <input 
                            type="number"
                            value={estimatedTime}
                            onChange={(e) => setEstimatedTime(Number(e.target.value))}
