import React from 'react';
import { Repeat } from 'lucide-react';
import { SpacedReviewConfig } from '../../../../services/metaService';

interface ReviewSystemConfigProps {
  config: SpacedReviewConfig;
  onChange: (config: SpacedReviewConfig) => void;
  customColor?: string;
}

const ReviewSystemConfig: React.FC<ReviewSystemConfigProps> = ({ 
  config, 
  onChange,
  customColor = '#22c55e'
}) => {

  const updateConfig = (key: keyof SpacedReviewConfig, value: any) => {
    onChange({ ...config, [key]: value });
  };

  return (
    <div 
        className="p-4 rounded-xl border transition-all"
        style={{ 
            backgroundColor: config.active ? `${customColor}10` : 'rgba(24, 24, 27, 0.2)', // zinc-900/20
            borderColor: config.active ? `${customColor}40` : '#27272a' // zinc-800
        }}
    >
        <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-3">
                <div 
                    className="p-2 rounded-full"
                    style={{ 
                        backgroundColor: config.active ? customColor : '#27272a',
                        color: config.active ? '#000' : '#71717a'
                    }}
                >
                    <Repeat size={16} />
                </div>
                <div>
                    <h4 className="text-sm font-black text-white uppercase tracking-tight">Sistema de Revisão Espaçada</h4>
                    <p className="text-[10px] text-zinc-500">Agendar revisões automáticas desta meta.</p>
                </div>
            </div>

            <button
                type="button"
                onClick={() => updateConfig('active', !config.active)}
                className="relative w-12 h-6 rounded-full transition-colors"
                style={{ backgroundColor: config.active ? customColor : '#27272a' }}
            >
                <div className={`absolute top-1 left-1 w-4 h-4 bg-white rounded-full transition-transform ${config.active ? 'translate-x-6' : 'translate-x-0'}`}></div>
            </button>
        </div>

        {config.active && (
            <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Intervalos (em dias)</label>
                    <input 
                        value={config.intervals}
                        onChange={(e) => {
                            if (/^[\d,\s]*$/.test(e.target.value)) {
                                updateConfig('intervals', e.target.value);
                            }
                        }}
                        placeholder="1, 7, 15, 30"
                        className="w-full bg-zinc-950 border border-zinc-800 rounded-lg px-4 py-3 text-xs text-white placeholder-zinc-700 outline-none font-mono tracking-widest"
                        onFocus={(e) => e.target.style.borderColor = customColor}
                        onBlur={(e) => e.target.style.borderColor = '#27272a'}
                    />
                    <p className="text-[9px] text-zinc-600">Separe os dias por vírgula. Ex: 1 dia depois, 7 dias depois, etc.</p>
                </div>

                <div className="flex items-center gap-2">
                    <input 
                        type="checkbox" 
                        id={`repeatLast`}
                        checked={config.repeatLast}
                        onChange={(e) => updateConfig('repeatLast', e.target.checked)}
                        className="w-4 h-4 rounded bg-zinc-950 border-zinc-800 focus:ring-0 cursor-pointer"
                        style={{ accentColor: customColor }}
                    />
                    <label htmlFor={`repeatLast`} className="text-xs text-zinc-300 font-bold uppercase select-none cursor-pointer">
                        Repetir último intervalo indefinidamente?
                    </label>
                </div>
            </div>
        )}
    </div>
  );
};

export default ReviewSystemConfig;

import React, { useState } from 'react';
import { Wand2, Maximize2, BrainCircuit, Loader2, Sparkles, CheckCircle2, Trash2, AlertTriangle } from 'lucide-react';
import { MindMapNode } from '../../../../../services/metaService';
import MindMapFullscreen from './MindMapFullscreen';
import MetaFilesUploader, { FileItem } from '../../shared/MetaFilesUploader';
import { generateMindMapStructure, AIMindMapNode } from '../../../../../services/aiService';

interface MindMapManagerProps {
  nodes: MindMapNode[];
  onChange: (nodes: MindMapNode[]) => void;
  planId?: string;
}

type ViewState = 'idle' | 'processing' | 'done' | 'error';

const MindMapManager: React.FC<MindMapManagerProps> = ({ nodes, onChange, planId }) => {
  const hasNodes = nodes && nodes.length > 0;
  const [viewState, setViewState] = useState<ViewState>(hasNodes ? 'done' : 'idle');
  const [isFullscreenOpen, setIsFullscreenOpen] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');

  // Local state for "Knowledge Sources"
  const [sourceFiles, setSourceFiles] = useState<FileItem[]>([]);

  // Confirmation Modal State
  const [showResetConfirm, setShowResetConfirm] = useState(false);

  // Processing Animation State
  const [processStep, setProcessStep] = useState(0);
  const processMessages = [
    "Enviando arquivos para o Gemini...",
    "Analisando contexto semântico...",
    "Estruturando hierarquia de conceitos...",
    "Finalizando árvore de conhecimento..."
  ];

  // Helper: Flatten Recursive JSON to Flat List with UUIDs
  const flattenAIResponse = (root: AIMindMapNode): MindMapNode[] => {
    const flatList: MindMapNode[] = [];

    // Função recursiva para percorrer e achatar a árvore
    const traverse = (node: AIMindMapNode, parentId?: string, level: number = 0) => {
      const currentId = crypto.randomUUID(); // Gera ID único real

      // Define cores baseadas no nível (apenas para inicialização, o VisualNode recalcula)
      let color = '#a855f7'; // Root (Purple)
      if (level === 1) color = '#ec4899'; // Pink
      if (level === 2) color = '#3b82f6'; // Blue
      if (level >= 3) color = '#10b981'; // Emerald

      const newNode: MindMapNode = {
        id: currentId,
        label: node.label.replace(/<[^>]*>?/gm, ''), // Remove HTML tags for raw label (VisualNode can re-apply if needed)
        // Mantém as tags HTML dentro de uma propriedade customizada se quisermos renderizar rich text no futuro, 
        // mas por enquanto o VisualNode usa contentEditable text. 
        // Vamos passar o label limpo e usar styles array se detectarmos <b>
        styles: node.label.includes('<b>') ? ['bold'] : [],
        x: 0, // Posição será gerenciada pelo Flexbox/VisualNode
        y: 0,
        color: color,
        type: level === 0 ? 'root' : 'child',
        parentId: parentId
      };

      flatList.push(newNode);

      if (node.children && node.children.length > 0) {
        node.children.forEach(child => traverse(child, currentId, level + 1));
      }
    };

    traverse(root);
    return flatList;
  };

  const handleGenerateAI = async () => {
    if (sourceFiles.length === 0) return;

    setViewState('processing');
    setProcessStep(0);
    setErrorMessage('');

    try {
      // Simulation of progress steps while waiting for promise
      const interval = setInterval(() => {
        setProcessStep(prev => prev < processMessages.length - 1 ? prev + 1 : prev);
      }, 2500);

      // Extract raw JS Files from FileItems
      const filesToProcess = sourceFiles
        .map(f => f.file)
        .filter((f): f is File => f !== undefined);

      if (filesToProcess.length === 0) {
        throw new Error("Nenhum arquivo válido encontrado para processar.");
      }

      // Call AI Service (Now accepts a single file for better reliability in this version)
      const aiRootNode = await generateMindMapStructure(filesToProcess[0]);

      clearInterval(interval);
      setProcessStep(3); // Final step

      // Parse and Update
      const flatNodes = flattenAIResponse(aiRootNode);
      onChange(flatNodes);

      // Small delay for UX
      setTimeout(() => {
        setViewState('done');
      }, 500);

    } catch (error: any) {
      console.error("AI Generation Error:", error);
      setViewState('error');
      setErrorMessage(error.message || "Falha ao gerar mapa mental.");
    }
  };

  const handleResetRequest = () => {
    setShowResetConfirm(true);
  };

  const confirmReset = () => {
    onChange([]);
    setViewState('idle');
    setSourceFiles([]);
    setErrorMessage('');
    setShowResetConfirm(false);
  };

  // Sync view state if props change externally (e.g. load from DB)
  if (hasNodes && viewState === 'idle') {
      setViewState('done');
  } else if (!hasNodes && viewState === 'done') {
      setViewState('idle');
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
          <label className="flex items-center gap-2 text-[10px] font-black text-purple-500 uppercase tracking-widest">
              <BrainCircuit size={14} /> Mapa Mental (IA)
          </label>
      </div>

      <div className="relative w-full bg-zinc-950 rounded-xl border border-zinc-800 overflow-hidden group min-h-[250px] flex flex-col">

        {/* === STATE: IDLE (Upload & Start) === */}
        {viewState === 'idle' && (
            <div className="p-6 flex flex-col gap-6 animate-in fade-in duration-500">
                <div className="text-center space-y-2">
                    <div className="w-12 h-12 bg-purple-900/20 border border-purple-500/30 rounded-full flex items-center justify-center mx-auto mb-2">
                        <Sparkles size={20} className="text-purple-400" />
                    </div>
                    <h3 className="text-sm font-black text-white uppercase tracking-tight">NotebookLM Generator</h3>
                    <p className="text-[10px] text-zinc-500 max-w-xs mx-auto">
                        A IA irá ler seus PDFs e estruturar automaticamente todo o conhecimento em tópicos hierárquicos.
                    </p>
                </div>

                <div className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800">
                    <MetaFilesUploader 
                        files={sourceFiles} 
                        onChange={setSourceFiles} 
                        colorClass="text-purple-500"
                    />
                </div>

                <button 
                    type="button"
                    onClick={handleGenerateAI}
                    disabled={sourceFiles.length === 0}
                    className="w-full py-4 bg-purple-600 hover:bg-purple-500 disabled:bg-zinc-800 disabled:text-zinc-600 disabled:cursor-not-allowed text-white rounded-xl shadow-[0_0_20px_rgba(168,85,247,0.3)] hover:shadow-[0_0_30px_rgba(168,85,247,0.5)] transition-all font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2"
                >
                    <Wand2 size={16} /> Gerar Estrutura com IA
                </button>
            </div>
        )}

        {/* === STATE: PROCESSING === */}
        {viewState === 'processing' && (
            <div className="flex-1 flex flex-col items-center justify-center p-8 gap-6 animate-in fade-in duration-300">
                <div className="relative">
                    <div className="absolute inset-0 bg-purple-500/20 blur-xl rounded-full"></div>
                    <Loader2 size={48} className="text-purple-500 animate-spin relative z-10" />
                </div>

                <div className="text-center space-y-2">
                    <h3 className="text-lg font-black text-white uppercase tracking-tighter animate-pulse">
                        Analisando Documentos...
                    </h3>
                    <p className="text-xs text-purple-400 font-mono">
                        {processMessages[processStep]}
                    </p>
                </div>

                {/* Progress Bar */}
                <div className="w-64 h-1 bg-zinc-900 rounded-full overflow-hidden">
                    <div 
                        className="h-full bg-purple-500 transition-all duration-700 ease-out"
                        style={{ width: `${((processStep + 1) / processMessages.length) * 100}%` }}
                    ></div>
                </div>
            </div>
        )}

        {/* === STATE: ERROR === */}
        {viewState === 'error' && (
            <div className="flex-1 flex flex-col items-center justify-center p-8 gap-6 animate-in fade-in duration-300">
                <div className="w-16 h-16 bg-red-900/20 border border-red-500/30 rounded-full flex items-center justify-center mb-2">
                    <AlertTriangle size={32} className="text-red-500" />
                </div>

                <div className="text-center space-y-2 max-w-xs">
                    <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                        Erro na Geração
                    </h3>
                    <p className="text-xs text-red-400 font-mono break-words">
                        {errorMessage}
                    </p>
                </div>

                <button 
                    type="button"
                    onClick={() => setViewState('idle')}
                    className="px-6 py-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg text-xs font-bold uppercase"
                >
                    Tentar Novamente
                </button>
            </div>
        )}

        {/* === STATE: DONE (Preview & Actions) === */}
        {viewState === 'done' && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900/30 backdrop-blur-md p-6 gap-6 animate-in zoom-in-95 duration-300">

                <div className="relative bg-zinc-950 border border-purple-500/30 p-6 rounded-2xl shadow-2xl flex flex-col items-center text-center max-w-sm w-full">

                    {/* Botão de Exclusão / Reset */}
                    <button 
                        type="button"
                        onClick={handleResetRequest}
                        className="absolute top-4 right-4 rounded-full p-2 text-zinc-400 hover:bg-red-500/20 hover:text-red-500 transition-colors"
                        title="Excluir Mapa e Reiniciar"
                    >
                        <Trash2 size={18} />
                    </button>

                    <div className="w-16 h-16 bg-green-500/10 rounded-full flex items-center justify-center mb-4 border border-green-500/20">
                        <CheckCircle2 size={32} className="text-green-500" />
                    </div>

                    <h3 className="text-xl font-black text-white uppercase tracking-tighter mb-1">
                        Mapa Gerado com Sucesso
                    </h3>
                    <p className="text-[10px] text-zinc-400 uppercase tracking-widest mb-6">
                        {nodes?.length || 0} tópicos estruturados hierarquicamente.
                    </p>

                    <button 
                        type="button"
                        onClick={() => setIsFullscreenOpen(true)}
                        className="w-full px-6 py-3 bg-white hover:bg-zinc-200 text-black rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 mb-3 shadow-[0_0_15px_rgba(255,255,255,0.1)]"
                    >
                        <Maximize2 size={14} /> Visualizar & Editar
                    </button>
                </div>
            </div>
        )}
      </div>

      {isFullscreenOpen && (
        <MindMapFullscreen 
            nodes={nodes} 
            onChange={onChange} 
            onClose={() => setIsFullscreenOpen(false)} 
        />
      )}

      {/* MODAL DE CONFIRMAÇÃO DE RESET */}
      {showResetConfirm && (
        <div 
            className="fixed inset-0 z-[200] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200"
            onMouseDown={(e) => e.stopPropagation()}
        >
            <div 
                className="w-[400px] bg-zinc-900 border border-zinc-700 rounded-xl shadow-2xl p-6 animate-in zoom-in-95 duration-200"
                onMouseDown={(e) => e.stopPropagation()}
            >
                <div className="flex flex-col items-center text-center gap-4">
                    <div className="p-3 rounded-full bg-red-500/10 text-red-500 border border-red-500/20">
                        <AlertTriangle size={32} />
                    </div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter">Excluir Mapa Mental?</h3>
                    <p className="text-zinc-400 text-sm leading-relaxed">
                        Todo o mapa mental gerado e suas edições serão perdidos. Deseja continuar?
                    </p>
                    <div className="flex gap-3 w-full mt-2">
                        <button 
                            onClick={() => setShowResetConfirm(false)} 
                            className="flex-1 py-3 rounded-lg border border-zinc-600 text-zinc-300 hover:bg-zinc-800 font-bold uppercase text-xs tracking-widest transition-colors"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmReset} 
                            className="flex-1 py-3 rounded-lg bg-red-600 text-white font-black uppercase text-xs tracking-widest hover:bg-red-700 transition-all shadow-lg shadow-red-900/40"
                        >
                            Sim, Excluir
                        </button>
                    </div>
                </div>
            </div>
        </div>
       )}
    </div>
  );
};

export default MindMapManager;

import React, { useState, useRef, useEffect } from 'react';
import { 
  X, Save, Trash2, Edit2, Plus, 
  Bold, Italic, Underline, Strikethrough, 
  Highlighter, Eraser, Type 
} from 'lucide-react';

// Cores de Fundo do Post-It (Papel)
const PAPER_COLORS = [
  '#fef3c7', // Amarelo (Padrão)
  '#dbeafe', // Azul
  '#dcfce7', // Verde
  '#fce7f3', // Rosa
  '#f3e8ff', // Lilás
  '#27272a', // Dark Mode (Preto Suave)
];

export interface PostItNote {
  id: string;
  text: string;
  color: string;
  date: string;
}

interface PostItEditorProps {
  initialNote?: PostItNote;
  onSave: (note: PostItNote) => void;
  onCancel: () => void;
}

// --- COMPONENTE 1: EDITOR DE POST-IT (CORRIGIDO) ---
export function PostItEditor({ initialNote, onSave, onCancel }: PostItEditorProps) {
  const [paperColor, setPaperColor] = useState(initialNote?.color || '#fef3c7');
  const [hiliteColor, setHiliteColor] = useState('#facc15'); // Amarelo marca-texto
  const editorRef = useRef<HTMLDivElement>(null);

  // Inicialização do conteúdo
  useEffect(() => {
    if (editorRef.current && initialNote?.text) {
      editorRef.current.innerHTML = initialNote.text;
    }
  }, [initialNote]);

  // Aplicação de Formato Segura (Sem perder seleção)
  const applyFormat = (command: string, value: string | undefined = undefined) => {
    document.execCommand(command, false, value);
    // Mantém o foco no editor
    if (editorRef.current) editorRef.current.focus();
  };

  const handleSave = () => {
    if (!editorRef.current) return;
    const html = editorRef.current.innerHTML;
    if (!html.trim()) return alert("A nota não pode estar vazia.");

    onSave({
      id: initialNote?.id || crypto.randomUUID(),
      text: html,
      color: paperColor,
      date: new Date().toISOString()
    });
  };

  // Previne propagação de teclas (especialmente Enter) para o form pai
  const handleKeyDown = (e: React.KeyboardEvent) => {
    e.stopPropagation(); 
    // O Enter natural do contentEditable já cria divs/br, não precisamos interceptar
    // a menos que quiséssemos comportamento específico.
  };

  // Helper para Botões de Formatação (Evita perda de foco com onMouseDown)
  const FormatBtn = ({ icon: Icon, cmd, val, title, className = "" }: any) => (
    <button
      type="button" // CRÍTICO
      onMouseDown={(e) => {
        e.preventDefault(); // Impede perda de foco
        applyFormat(cmd, val);
      }}
      className={`p-1.5 rounded hover:bg-black/10 dark:hover:bg-white/10 text-zinc-600 dark:text-zinc-300 transition-colors ${className}`}
      title={title}
    >
      <Icon size={16} />
    </button>
  );

  const isDarkPaper = paperColor === '#27272a';

  return (
    <div 
      className="fixed inset-0 z-[150] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200"
      onClick={onCancel} // Fecha ao clicar no backdrop
    >
      <div 
        className="w-[450px] bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()} // Impede fechamento ao clicar no conteúdo
      >

        {/* Header */}
        <div className="flex items-center justify-between p-3 border-b border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-900">
          <span className="font-bold text-zinc-700 dark:text-zinc-200 text-xs uppercase tracking-wider flex items-center gap-2">
            <Edit2 size={12} /> {initialNote ? 'Editar Nota' : 'Nova Nota'}
          </span>
          <button type="button" onClick={onCancel} className="text-zinc-400 hover:text-red-500"><X size={18}/></button>
        </div>

        {/* Toolbar de Formatação */}
        <div className="flex flex-wrap items-center gap-1 p-2 bg-zinc-100 dark:bg-zinc-950 border-b border-zinc-200 dark:border-zinc-800">
          <FormatBtn icon={Bold} cmd="bold" title="Negrito" />
          <FormatBtn icon={Italic} cmd="italic" title="Itálico" />
          <FormatBtn icon={Underline} cmd="underline" title="Sublinhado" />
          <FormatBtn icon={Strikethrough} cmd="strikeThrough" title="Taxado" />

          <div className="w-px h-5 bg-zinc-300 dark:bg-zinc-700 mx-1" />

          {/* Cor da Fonte */}
          <div className="relative w-7 h-7 flex items-center justify-center group">
             <Type size={16} className="text-zinc-600 dark:text-zinc-300 pointer-events-none" />
             <input 
               type="color" 
               className="absolute inset-0 opacity-0 cursor-pointer"
               onChange={(e) => applyFormat('foreColor', e.target.value)}
               title="Cor do Texto"
             />
          </div>

          <div className="w-px h-5 bg-zinc-300 dark:bg-zinc-700 mx-1" />

          {/* Marca Texto */}
          <div className="flex items-center gap-1 bg-black/5 dark:bg-white/5 rounded px-1">
             <FormatBtn 
               icon={Highlighter} 
               cmd="hiliteColor" 
               val={hiliteColor} 
               title="Aplicar Marca-Texto"
               className="text-yellow-600 dark:text-yellow-400"
             />
             <div className="relative w-4 h-4 rounded-full border border-zinc-300 overflow-hidden">
                <input 
                  type="color" 
                  value={hiliteColor}
                  onChange={(e) => setHiliteColor(e.target.value)}
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                />
                <div className="w-full h-full" style={{ backgroundColor: hiliteColor }} />
             </div>
             <FormatBtn 
               icon={Eraser} 
               cmd="hiliteColor" 
               val="transparent" 
               title="Remover Marcação"
               className="hover:text-red-500"
             />
          </div>
        </div>

        {/* Área de Edição (O Papel) */}
        <div className="flex-1 bg-zinc-200 dark:bg-zinc-950 p-6 overflow-y-auto">
          <div 
            className="w-full min-h-[300px] shadow-lg rounded p-5 text-sm leading-relaxed outline-none transition-colors duration-300"
            style={{ 
              backgroundColor: paperColor,
              color: isDarkPaper ? '#e4e4e7' : '#18181b' // Texto claro se papel escuro
            }}
          >
            <div 
              ref={editorRef}
              contentEditable
              suppressContentEditableWarning
              onKeyDown={handleKeyDown} // BLINDAGEM CONTRA FECHAMENTO
              className="w-full h-full min-h-[250px] outline-none whitespace-pre-wrap break-words rich-editor-content"
              style={{ minHeight: '250px' }}
            />
          </div>
        </div>

        {/* Footer: Cores do Papel e Salvar */}
        <div className="p-4 bg-zinc-50 dark:bg-zinc-900 border-t border-zinc-200 dark:border-zinc-800 flex flex-col gap-4">

          <div className="flex items-center justify-between">
            <span className="text-[10px] font-bold uppercase text-zinc-400">Cor do Papel:</span>
            <div className="flex gap-2">
              {PAPER_COLORS.map(c => (
                <button
                  key={c}
                  type="button"
                  onClick={() => setPaperColor(c)}
                  className={`w-6 h-6 rounded-full border transition-transform hover:scale-110 ${paperColor === c ? 'border-zinc-500 scale-110 ring-1 ring-zinc-400' : 'border-transparent'}`}
                  style={{ backgroundColor: c }}
                  title={c}
                />
              ))}
              {/* Custom Hex Paper */}
              <div className="relative w-6 h-6 rounded-full border border-zinc-300 overflow-hidden group">
                 <input type="color" value={paperColor} onChange={e => setPaperColor(e.target.value)} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
                 <div className="w-full h-full flex items-center justify-center bg-zinc-200 text-[8px] text-zinc-500">+</div>
                 <div className="absolute inset-0 pointer-events-none" style={{ backgroundColor: !PAPER_COLORS.includes(paperColor) ? paperColor : 'transparent' }} />
              </div>
            </div>
          </div>

          <button 
            type="button" // CRÍTICO
            onClick={handleSave}
            className="w-full py-3 bg-zinc-900 dark:bg-white hover:bg-zinc-800 dark:hover:bg-zinc-200 text-white dark:text-black font-bold rounded-lg transition-all shadow-lg active:scale-95"
          >
            SALVAR NOTA
          </button>
        </div>
      </div>
    </div>
  );
}

interface PostItViewerProps {
  notes: PostItNote[];
  nodeLabel: string;
  onClose: () => void;
  onEdit: (note: PostItNote) => void;
  onDelete: (id: string) => void;
  onAdd: () => void;
  readOnly?: boolean;
}

// --- COMPONENTE 2: VISUALIZADOR (LIGHTBOX) ---
export function PostItViewer({ notes, nodeLabel, onClose, onEdit, onDelete, onAdd, readOnly }: PostItViewerProps) {
  return (
    <div 
      className="fixed inset-0 z-[140] flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in duration-300"
      onClick={onClose} // Fecha ao clicar no backdrop (ou em espaços vazios do layout)
    >
      <div 
        className="relative w-full max-w-6xl h-[85vh] flex flex-col"
        // NOTA: Removido stopPropagation daqui para permitir fechar clicando nos gaps
      >
        {/* Header Flutuante */}
        <div 
            className="text-center mb-6 animate-in slide-in-from-top-10 duration-500 z-10"
            onClick={e => e.stopPropagation()} // Protege o header de fechar o modal
        >
           <div className="inline-flex items-center gap-4 bg-zinc-900/80 backdrop-blur rounded-full px-6 py-2 border border-zinc-700 shadow-xl">
              <h2 className="text-lg font-bold text-white">Notas de:</h2>
              <span className="text-purple-300 font-mono text-sm truncate max-w-[300px]" dangerouslySetInnerHTML={{ __html: nodeLabel }} />
              <button onClick={onClose} className="ml-4 p-1 rounded-full hover:bg-white/10 text-zinc-400 hover:text-white"><X size={16}/></button>
           </div>
        </div>

        {/* Grid Scrollável */}
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          <div className="flex flex-wrap justify-center gap-8 pb-20">

            {/* Card de Nova Nota */}
            {!readOnly && (
              <button 
                type="button"
                onClick={(e) => {
                    e.stopPropagation(); // Protege o botão
                    onAdd();
                }}
                className="group w-[260px] h-[260px] rounded-lg border-2 border-dashed border-zinc-700 bg-zinc-900/30 hover:bg-zinc-900/60 flex flex-col items-center justify-center gap-3 transition-all hover:scale-105 active:scale-95"
              >
                <div className="p-4 rounded-full bg-zinc-800 group-hover:bg-purple-600 text-zinc-400 group-hover:text-white transition-colors shadow-lg">
                  <Plus size={32} />
                </div>
                <span className="text-zinc-500 font-medium group-hover:text-purple-300 uppercase tracking-widest text-xs">Adicionar Nota</span>
              </button>
            )}

            {/* Lista de Notas */}
            {notes.map((note, index) => {
              const isDark = note.color === '#27272a';
              return (
                <div 
                  key={note.id}
                  onClick={(e) => e.stopPropagation()} // Protege o card da nota
                  className="relative group w-[260px] min-h-[260px] p-6 shadow-2xl flex flex-col justify-between transition-all hover:-translate-y-2 hover:shadow-[0_20px_40px_-15px_rgba(0,0,0,0.5)] animate-in zoom-in duration-500 cursor-default"
                  style={{ 
                    backgroundColor: note.color,
                    color: isDark ? '#e4e4e7' : '#18181b',
                    animationDelay: `${index * 50}ms`,
                    transform: `rotate(${index % 2 === 0 ? '-1deg' : '1deg'})` 
                  }}
                >
                  {/* Conteúdo HTML */}
                  <div 
                    className="text-sm leading-relaxed font-medium break-words mb-4 whitespace-pre-wrap"
                    dangerouslySetInnerHTML={{ __html: note.text }}
                  />

                  {/* Rodapé */}
                  <div className={`border-t pt-2 flex justify-between items-center ${isDark ? 'border-white/10' : 'border-black/10'}`}>
                    <span className={`text-[10px] font-mono ${isDark ? 'text-white/40' : 'text-black/40'}`}>
                      {new Date(note.date).toLocaleDateString()}
                    </span>
                  </div>

                  {/* Ações (Hover) */}
                  {!readOnly && (
                    <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button type="button" onClick={() => onEdit(note)} className="p-1.5 bg-white/20 hover:bg-white/80 rounded-full text-zinc-700 shadow-sm backdrop-blur-sm transition-colors">
                        <Edit2 size={14} />
                      </button>
                      <button type="button" onClick={() => onDelete(note.id)} className="p-1.5 bg-white/20 hover:bg-red-500 rounded-full text-red-600 hover:text-white shadow-sm backdrop-blur-sm transition-colors">
                        <Trash2 size={14} />
                      </button>
                    </div>
                  )}

                  {/* Tape Effect */}
                  <div className="absolute -top-3 left-1/2 -translate-x-1/2 w-16 h-8 bg-white/20 rotate-1 blur-[1px]" />
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Settings } from 'lucide-react';
import { MentorshipModule, MentorshipLesson, MentorshipContent } from '../../../../types/mentorship';
import { MentorshipContentModal } from './MentorshipContentModal';
import { ConfirmationModal } from '../../ui/ConfirmationModal';

// Função auxiliar simples para gerar ID
const generateId = () => Date.now().toString(36) + Math.random().toString(36).substr(2);

// Tipo auxiliar para itens mistos na lista
type MixedItem = 
  | { type: 'submodule'; data: any; order: number }
  | { type: 'lesson'; data: MentorshipLesson; order: number };

interface MentorshipModuleDetailProps {
  planId: string;
  module: MentorshipModule;
  onBack: () => void;
  onEdit: () => void; // NOVO PROP
  onUpdateModule: (updatedModule: MentorshipModule) => Promise<void>;
}

export function MentorshipModuleDetail({ planId, module, onBack, onEdit, onUpdateModule }: MentorshipModuleDetailProps) {
  // --- NAVEGAÇÃO (Breadcrumbs) ---
  const [navigationPath, setNavigationPath] = useState<{id: string, title: string}[]>([]);

  // --- CONTROLE DE ACORDEÃO (Pastas Abertas) ---
  // Armazena quais pastas estão expandidas visualmente (Key: ID da pasta, Value: true)
  const [expandedFolders, setExpandedFolders] = useState<Record<string, boolean>>({});

  // --- ESTADOS DE CRIAÇÃO ---
  const [isCreatingLesson, setIsCreatingLesson] = useState(false);
  const [isCreatingSubmodule, setIsCreatingSubmodule] = useState(false);
  const [newItemTitle, setNewItemTitle] = useState('');

  // --- ESTADOS DE EDIÇÃO (RENOMEAR) ---
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitleTemp, setEditTitleTemp] = useState('');

  // --- ESTADOS DE EXCLUSÃO ---
  const [itemToDelete, setItemToDelete] = useState<{id: string, type: 'lesson' | 'submodule'} | null>(null);

  // --- MODAL DE CONTEÚDOS ---
  const [selectedLessonForContent, setSelectedLessonForContent] = useState<MentorshipLesson | null>(null);

  // --- HELPER: ENCONTRAR CONTAINER ATUAL (Recursividade) ---
  const getCurrentContainer = () => {
    let current: any = module;
    for (const pathItem of navigationPath) {
        if (current.subModules) {
            current = current.subModules.find((sub: any) => sub.id === pathItem.id);
        }
    }
    return current;
  };

  const currentContainer = getCurrentContainer();

  // --- HELPER: ATUALIZAR ÁRVORE DE DADOS ---
  const updateTree = (root: MentorshipModule, targetId: string | null, updateFn: (node: any) => any): MentorshipModule => {
    if (targetId === null && navigationPath.length === 0) return updateFn(root);
    if (root.id === targetId) return updateFn(root);

    if (root.subModules) {
        return {
            ...root,
            subModules: root.subModules.map(sub => 
                (sub.id === targetId || isNodeInPath(sub.id)) 
                    ? updateTree(sub, targetId, updateFn)
                    : sub
            )
        } as MentorshipModule;
    }
    return root;
  };

  const isNodeInPath = (id: string) => {
     // Otimização simples: se o ID está no path atual, precisamos descer nele
     return navigationPath.some(p => p.id === id) || id === navigationPath[navigationPath.length - 1]?.id;
  };

  const handleSaveTree = async (updatedNode: any) => {
    const targetId = navigationPath.length > 0 ? navigationPath[navigationPath.length - 1].id : module.id;
    // Se targetId for igual ao module.id, passamos null para indicar raiz
    const newRoot = updateTree(module, targetId === module.id ? null : targetId, () => updatedNode);
    await onUpdateModule(newRoot);
  };

  // --- HELPER: MIXAR E ORDENAR LISTA ---
  const getSortedMixedItems = (container: any): MixedItem[] => {
    const lessons = (container.lessons || []).map((l: any) => ({ type: 'lesson', data: l, order: l.order || 0 }));
    const submodules = (container.subModules || []).map((s: any) => ({ type: 'submodule', data: s, order: s.order || 0 }));

    return [...lessons, ...submodules].sort((a, b) => a.order - b.order) as MixedItem[];
  };

  // --- AÇÕES DE CRIAÇÃO ---
  const handleCreateItem = async () => {
    if (!newItemTitle.trim()) return;

    // Pega o maior order atual para adicionar no final
    const currentItems = getSortedMixedItems(currentContainer);
    const maxOrder = currentItems.length > 0 ? Math.max(...currentItems.map(i => i.order)) : -1;
    const newOrder = maxOrder + 1;

    const updatedContainer = { ...currentContainer };

    if (isCreatingSubmodule) {
        const newSub = {
            id: generateId(),
            title: newItemTitle,
            lessons: [],
            subModules: [],
            order: newOrder
        };
        updatedContainer.subModules = [...(updatedContainer.subModules || []), newSub];
    } else {
        const newLesson = {
            id: generateId(),
            title: newItemTitle,
            contents: [],
            order: newOrder
        };
        updatedContainer.lessons = [...(updatedContainer.lessons || []), newLesson];
    }

    await handleSaveTree(updatedContainer);
    setNewItemTitle('');
    setIsCreatingLesson(false);
    setIsCreatingSubmodule(false);
  };

  // --- AÇÕES DE REORDENAÇÃO (MOVER CIMA/BAIXO) ---
  const handleMoveItem = async (index: number, direction: 'up' | 'down') => {
    const items = getSortedMixedItems(currentContainer);
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === items.length - 1) return;

    const targetIndex = direction === 'up' ? index - 1 : index + 1;

    const itemA = items[index];
    const itemB = items[targetIndex];
// Troca os orders
    const tempOrder = itemA.order;
    itemA.order = itemB.order;
    itemB.order = tempOrder;

    // Atualiza o container
    const updatedContainer = { ...currentContainer };

    // Atualiza arrays originais com os novos orders
    const updateOrderInList = (list: any[], item: MixedItem) => {
        return list.map(x => x.id === item.data.id ? { ...x, order: item.order } : x);
    };

    if (itemA.type === 'lesson') updatedContainer.lessons = updateOrderInList(updatedContainer.lessons, itemA);
    else updatedContainer.subModules = updateOrderInList(updatedContainer.subModules, itemA);

    if (itemB.type === 'lesson') updatedContainer.lessons = updateOrderInList(updatedContainer.lessons, itemB);
    else updatedContainer.subModules = updateOrderInList(updatedContainer.subModules, itemB);

    await handleSaveTree(updatedContainer);
  };

  // --- OUTRAS AÇÕES (Renomear, Excluir, Navegar) ---
  const handleRename = async () => {
    if (!editTitleTemp.trim() || !editingId) return;
    const updatedContainer = { ...currentContainer };

    // Procura nas aulas
    if (updatedContainer.lessons) {
        updatedContainer.lessons = updatedContainer.lessons.map((l:any) => l.id === editingId ? {...l, title: editTitleTemp} : l);
    }
    // Procura nas pastas
    if (updatedContainer.subModules) {
        updatedContainer.subModules = updatedContainer.subModules.map((s:any) => s.id === editingId ? {...s, title: editTitleTemp} : s);
    }

    await handleSaveTree(updatedContainer);
    setEditingId(null);
  };

  const handleExecuteDelete = async () => {
    if (!itemToDelete) return;
    const updatedContainer = { ...currentContainer };

    if (itemToDelete.type === 'submodule') {
        updatedContainer.subModules = updatedContainer.subModules.filter((s:any) => s.id !== itemToDelete.id);
    } else {
        updatedContainer.lessons = updatedContainer.lessons.filter((l:any) => l.id !== itemToDelete.id);
    }

    await handleSaveTree(updatedContainer);
    setItemToDelete(null);
  };

  // Callback para atualização de conteúdos da aula
  const handleUpdateLessonContents = async (updatedLesson: MentorshipLesson) => {
    // Aqui precisamos percorrer a árvore para achar a aula, pois ela pode estar
    // dentro de um submódulo que não é o currentContainer se viermos via expansão de acordeão.
    // Porem, para simplificar e dado que o modal bloqueia a tela, podemos assumir que
    // só editamos aulas visíveis. 
    // Melhor: usar a função updateTree global buscando pelo ID da aula.

    // Função recursiva para achar e atualizar a aula em qualquer lugar da árvore
    const updateLessonInTree = (node: MentorshipModule): MentorshipModule => {
        const newNode = { ...node };

        // Tenta atualizar na lista de lições deste nó
        if (newNode.lessons) {
            newNode.lessons = newNode.lessons.map(l => l.id === updatedLesson.id ? updatedLesson : l);
        }

        // Recursividade para subpastas
        if (newNode.subModules) {
            newNode.subModules = newNode.subModules.map(sub => updateLessonInTree(sub as MentorshipModule));
        }

        return newNode;
    };

    const newRoot = updateLessonInTree(module);
    await onUpdateModule(newRoot);
    setSelectedLessonForContent(updatedLesson);
  };

  const toggleFolder = (folderId: string) => {
    setExpandedFolders(prev => ({
        ...prev,
        [folderId]: !prev[folderId]
    }));
  };

  // --- NAVEGAÇÃO HANDLERS ---
  const handleBreadcrumbClick = (index: number) => {
    setNavigationPath(prev => prev.slice(0, index + 1));
  };

  const handleNavigateUp = () => {
    if (navigationPath.length > 0) {
        setNavigationPath(prev => prev.slice(0, -1));
    } else {
        onBack();
    }
  };

  // --- RENDERIZADOR DA LISTA MISTA ---
  const renderMixedList = (container: any) => {
    const items = getSortedMixedItems(container);

    if (items.length === 0) {
        return (
            <div className="text-center py-8 border border-dashed border-gray-800 rounded bg-black/20 text-gray-500 text-sm">
                Esta pasta está vazia. Adicione aulas ou subpastas.
            </div>
        );
    }

    return (
        <div className="space-y-3">
            {items.map((item, index) => {
                const isFirst = index === 0;
                const isLast = index === items.length - 1;
                const isEditing = editingId === item.data.id;

                // --- RENDERIZAR PASTA (SUBMÓDULO) ---
                if (item.type === 'submodule') {
                    const isOpen = expandedFolders[item.data.id];
                    return (
                        <div key={item.data.id} className="border border-gray-800 rounded-lg overflow-hidden bg-[#15171b] transition-all hover:border-gray-700">
                            {/* Cabeçalho da Pasta */}
                            <div 
                                className="p-3 flex items-center justify-between cursor-pointer hover:bg-[#1a1d24]"
                                onClick={() => toggleFolder(item.data.id)}
                            >
                                <div className="flex items-center gap-3 flex-1">
                                    {/* Ícone Chevron */}
                                    <div className={`text-gray-500 transition-transform duration-200 ${isOpen ? 'rotate-90' : ''}`}>
                                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                                    </div>

                                    {/* Ícone Pasta */}
                                    <svg className="w-6 h-6 text-yellow-600" fill="currentColor" viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>

                                    {/* Título ou Input de Edição */}
                                    {isEditing ? (
                                        <div className="flex items-center gap-2 flex-1 mr-4" onClick={e => e.stopPropagation()}>
                                            <input value={editTitleTemp} onChange={e => setEditTitleTemp(e.target.value)} className="w-full bg-black border border-yellow-600 rounded px-2 py-1 text-white text-sm focus:outline-none" autoFocus />
                                            <button onClick={handleRename} className="text-green-500 hover:text-green-400"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg></button>
                                            <button onClick={() => setEditingId(null)} className="text-gray-500 hover:text-gray-300"><svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                                        </div>
                                    ) : (
                                        <div className="flex-1">
                                            <h4 className="text-white font-bold text-sm">{item.data.title}</h4>
                                            <p className="text-[10px] text-gray-500">{(item.data.lessons?.length || 0) + (item.data.subModules?.length || 0)} itens</p>
                                        </div>
                                    )}
                                </div>

                                {/* Botões de Ação (Só aparecem se não estiver editando) */}
                                {!isEditing && (
                                    <div className="flex items-center gap-1" onClick={e => e.stopPropagation()}>
                                        {/* Ordenação */}
                                        <div className="flex flex-col mr-2">
                                            <button disabled={isFirst} onClick={() => handleMoveItem(index, 'up')} className={`text-gray-600 hover:text-white ${isFirst ? 'opacity-30 cursor-not-allowed' : ''}`}><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg></button>
                                            <button disabled={isLast} onClick={() => handleMoveItem(index, 'down')} className={`text-gray-600 hover:text-white ${isLast ? 'opacity-30 cursor-not-allowed' : ''}`}><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7 7" /></svg></button>
                                        </div>

                                        <button onClick={() => { setEditingId(item.data.id); setEditTitleTemp(item.data.title); }} className="p-2 text-gray-500 hover:text-white hover:bg-gray-700 rounded transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg></button>
                                        <button onClick={() => setItemToDelete({id: item.data.id, type: 'submodule'})} className="p-2 text-gray-500 hover:text-red-500 hover:bg-red-500/10 rounded transition-colors"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg></button>

                                        {/* Entrar na Pasta (Drill-down) */}
                                        <button 
                                            onClick={() => setNavigationPath([...navigationPath, { id: item.data.id, title: item.data.title }])}
                                            className="ml-2 px-3 py-1 bg-gray-800 text-xs font-bold text-gray-300 rounded border border-gray-600 hover:bg-gray-700 hover:border-gray-500 transition-colors"
                                        >
                                            ENTRAR
                                        </button>
                                    </div>
                                )}
                            </div>

                            {/* Conteúdo do Acordeão (Recursivo) */}
                            {isOpen && (
                                <div className="p-4 border-t border-gray-800 bg-black/30 ml-4 border-l pl-4 relative">
                                    {/* Linha guia visual */}
                                    <div className="absolute left-0 top-0 bottom-0 w-0.5 bg-gray-800"></div>
                                    {/* Renderiza a lista de dentro da pasta. 
                                        Nota: Aqui apenas visualizamos. Para reordenar itens DENTRO da pasta, 
                                        o ideal é "Entrar" nela via breadcrumb para ter o contexto do currentContainer correto. 
                                        Mas podemos listar para visualização rápida. */}
                                    <div className="text-xs text-gray-500 mb-2 italic flex justify-between">
                                        <span>Conteúdo de: {item.data.title}</span>
                                        <button 
                                            onClick={() => setNavigationPath([...navigationPath, { id: item.data.id, title: item.data.title }])}
                                            className="text-yellow-600 hover:underline"
                                        >
                                            Gerenciar esta pasta &rarr;
                                        </button>
                                    </div>

                                    {/* Lista simplificada apenas para leitura rápida */}
                                    <div className="space-y-2 opacity-75">
                                        {(item.data.subModules || []).map((s:any) => (
                                            <div key={s.id} className="flex items-center gap-2 text-gray-400 pl-2">
                                                <svg className="w-4 h-4 text-yellow-600" fill="currentColor" viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>
                                                <span>{s.title}</span>
                                            </div>
                                        ))}
                                        {(item.data.lessons || []).map((l:any) => (
                                            <div key={l.id} className="flex items-center gap-2 text-gray-300 pl-2">
                                                 <span className="w-1.5 h-1.5 bg-gray-600 rounded-full"></span>
                                                <span>{l.title}</span>
                                            </div>
                                        ))}
                                        {(!item.data.subModules?.length && !item.data.lessons?.length) && (
                                            <span className="text-gray-600">Pasta vazia.</span>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                }
// --- RENDERIZAR AULA ---
                if (item.type === 'lesson') {
                    return (
                        <div key={item.data.id} className={`bg-[#1a1d24] border rounded-lg p-3 flex items-center justify-between transition-all group ${isEditing ? 'border-red-500' : 'border-gray-800 hover:border-gray-600'}`}>
                            <div className="flex items-center gap-3 flex-1">
                                {/* Marcador de Aula */}
                                <div className="w-8 h-8 rounded bg-gray-800 flex items-center justify-center text-gray-500 shrink-0">
                                    <span className="font-bold text-xs">{index + 1}</span>
                                </div>

                                {isEditing ? (
                                    <div className="flex items-center gap-2 flex-1 mr-4">
                                        <input value={editTitleTemp} onChange={e => setEditTitleTemp(e.target.value)} className="w-full bg-black border border-red-500 rounded px-2 py-1 text-white text-sm focus:outline-none" autoFocus />
                                        <button onClick={handleRename} className="p-2 bg-green-600 hover:bg-green-500 rounded text-white"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg></button>
                                        <button onClick={() => setEditingId(null)} className="p-2 bg-gray-700 hover:bg-gray-600 rounded text-gray-300"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                                    </div>
                                ) : (
                                    <div className="flex-1">
                                        <h4 className="text-white font-bold text-lg">{item.data.title}</h4>
                                        <div className="flex gap-2 mt-1">
                                            {item.data.contents?.some(c => c.type === 'video') && <span className="text-[9px] bg-red-900/30 text-red-500 px-1.5 py-0.5 rounded border border-red-900/50">VÍDEO</span>}
                                            {item.data.contents?.some(c => c.type === 'pdf') && <span className="text-[9px] bg-blue-900/30 text-blue-500 px-1.5 py-0.5 rounded border border-blue-900/50">PDF</span>}
                                            <span className="text-xs text-gray-500">{item.data.contents?.length || 0} itens</span>
                                        </div>
                                    </div>
                                )}
                            </div>

                            {!isEditing && (
                                <div className="flex items-center gap-2">
                                     {/* Ordenação */}
                                     <div className="flex flex-col mr-2">
                                        <button disabled={isFirst} onClick={() => handleMoveItem(index, 'up')} className={`text-gray-600 hover:text-white ${isFirst ? 'opacity-30 cursor-not-allowed' : ''}`}><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg></button>
                                        <button disabled={isLast} onClick={() => handleMoveItem(index, 'down')} className={`text-gray-600 hover:text-white ${isLast ? 'opacity-30 cursor-not-allowed' : ''}`}><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7 7" /></svg></button>
                                    </div>

                                    <button onClick={() => setSelectedLessonForContent(item.data)} className="px-3 py-1 bg-gray-800 hover:bg-gray-700 text-gray-200 text-xs font-bold uppercase rounded border border-gray-700 hover:border-white transition-all flex items-center gap-2 mr-2">
                                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                                        Gerenciar
                                    </button>
