        cancelText="Cancelar"
        isDanger={true}
        onConfirm={handleExecuteDelete}
        onCancel={() => setItemToDelete(null)}
      />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { X, Search, BookOpen, Folder } from 'lucide-react';
import { courseService } from '../../../services/courseService';

interface SelectionData {
  moduleId: string;
  moduleName: string;
  folderId: string;
  folderName: string;
}

interface TeachingAreaSelectorModalProps {
  isOpen: boolean;
  classId: string;
  onClose: () => void;
  onSelect: (data: SelectionData) => void;
}

export const TeachingAreaSelectorModal: React.FC<TeachingAreaSelectorModalProps> = ({ isOpen, classId, onClose, onSelect }) => {
  const [teachingModules, setTeachingModules] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    if (isOpen && classId) {
      loadTeachingArea();
    } else {
      setSearchTerm('');
    }
  }, [isOpen, classId]);

  const loadTeachingArea = async () => {
    setLoading(true);
    try {
      // Buscamos a estrutura da Área de Ensino vinculada a esta turma
      // Por padrão, usamos o classId como identificador da área de ensino
      const data = await courseService.getCourseStructure(classId);
      setTeachingModules(data);
    } catch (error) {
      console.error("Erro ao carregar Área de Ensino:", error);
    } finally {
      setLoading(false);
    }
  };

  const filteredModules = teachingModules.filter(module => {
    const moduleMatch = (module.title || module.name || '').toLowerCase().includes(searchTerm.toLowerCase());
    const folderMatch = module.folders?.some((f: any) => 
      (f.title || f.name || '').toLowerCase().includes(searchTerm.toLowerCase())
    );
    return moduleMatch || folderMatch;
  });

  const handleSelectFolder = (moduleItem: any, folderItem: any) => {
    onSelect({
      moduleId: moduleItem.id,
      moduleName: moduleItem.title || moduleItem.name,
      folderId: folderItem.id,
      folderName: folderItem.title || folderItem.name
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-gray-900 border border-gray-800 rounded-xl w-full max-w-2xl flex flex-col shadow-2xl overflow-hidden h-[80vh]">

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-gray-800 bg-gray-900/50">
          <h2 className="text-lg font-bold text-white flex items-center gap-2">
            <BookOpen size={20} className="text-red-500" />
            Vincular à Área de Ensino
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition">
            <X size={24} />
          </button>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-hidden flex flex-col">

          {/* Barra de Pesquisa */}
          <div className="p-4 border-b border-gray-800">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
              <input 
                type="text" 
                placeholder="Buscar módulo ou pasta..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-gray-800 border border-gray-700 text-white rounded-lg pl-10 pr-4 py-2 focus:outline-none focus:border-red-500 transition"
              />
            </div>
          </div>

          {/* Navegação Estrutural */}
          <div className="flex-1 overflow-y-auto p-2">
            {loading ? (
              <div className="flex justify-center items-center h-full text-gray-400">Carregando estrutura...</div>
            ) : (
              <div className="flex flex-col gap-2 p-2">
                {filteredModules.length > 0 ? (
                  filteredModules.map((module: any) => (
                    <div key={module.id} className="bg-gray-800/50 rounded-lg border border-gray-700/50 overflow-hidden mb-3">
                      <div className="bg-gray-800 px-4 py-2 border-b border-gray-700/50">
                        <span className="font-semibold text-gray-200 text-sm uppercase tracking-tight">{module.title || module.name}</span>
                      </div>
                      <div className="p-2 flex flex-col gap-1">
                        {module.folders && module.folders.length > 0 ? (
                          module.folders.map((folder: any) => (
                            <button
                              key={folder.id}
                              onClick={() => handleSelectFolder(module, folder)}
                              className="flex items-center gap-3 p-2 rounded hover:bg-gray-700 transition text-left group"
                            >
                              <Folder size={16} className="text-amber-500 opacity-70 group-hover:opacity-100" />
                              <span className="text-gray-400 text-sm group-hover:text-white transition">{folder.title || folder.name}</span>
                            </button>
                          ))
                        ) : (
                          <div className="px-4 py-2 text-xs text-gray-500 italic">Nenhuma pasta neste módulo.</div>
                        )}
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="p-8 text-center text-gray-500 text-sm">
                    {searchTerm ? 'Nenhum resultado para sua busca.' : 'Nenhum módulo encontrado nesta Área de Ensino.'}
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { X, ChevronRight, ChevronLeft, Check, Save, Loader2 } from 'lucide-react';
import { Class } from '../../../../types/class';
import { classService } from '../../../../services/classService';
import { ClassIdentityForm } from './forms/ClassIdentityForm';
import { ClassStructureForm } from './forms/ClassStructureForm';
import { ClassScheduleForm } from './forms/ClassScheduleForm';
import { ClassroomSelectionForm } from './forms/ClassroomSelectionForm';

interface ClassFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  classToEdit?: Class | null;
}

const INITIAL_DATA: Partial<Class> = {
  name: '',
  type: 'PRE_EDITAL',
  modality: 'REGULAR',
  hasRecordings: false,
  totalMeetings: 0,
  meetingDuration: 0,
  classesPerMeeting: 0,
  hasBreak: false,
  breakDuration: 0,
  shift: 'MORNING',
  startTime: '',
  daysOfWeek: [],
  allowWeekend: false,
  weekendConfigs: [],
  startDate: '',
  holidaysOff: true,
  status: 'SALES_OPEN',
  category: '',
  subcategory: '',
  organization: ''
};

const STEPS = [
  { id: 1, title: 'Identidade' },
  { id: 2, title: 'Estrutura' },
  { id: 3, title: 'Cronograma' },
  { id: 4, title: 'Alocação' }
];

export const ClassFormModal: React.FC<ClassFormModalProps> = ({ isOpen, onClose, onSuccess, classToEdit }) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<Partial<Class>>(INITIAL_DATA);
  const [loading, setLoading] = useState(false);
  const [breakCount, setBreakCount] = useState(1); // Auxiliary state for structure form

  // States for banner files
  const [bannerDesktopFile, setBannerDesktopFile] = useState<File | undefined>(undefined);
  const [bannerTabletFile, setBannerTabletFile] = useState<File | undefined>(undefined);
  const [bannerMobileFile, setBannerMobileFile] = useState<File | undefined>(undefined);

  React.useEffect(() => {
    if (isOpen) {
      if (classToEdit) {
        setFormData(classToEdit);
        // Calculate break count if needed, though it's not stored directly in Class interface as a count, 
        // but derived from logic. For now, we default to 1 if hasBreak is true.
        if (classToEdit.hasBreak) {
           setBreakCount(1); // Ideally this should be calculated or stored if variable
        }
      } else {
        setFormData(INITIAL_DATA);
        setBreakCount(1);
      }
      setCurrentStep(1);
      setBannerDesktopFile(undefined);
      setBannerTabletFile(undefined);
      setBannerMobileFile(undefined);
    }
  }, [isOpen, classToEdit]);

  const updateFormData = (updates: Partial<Class>) => {
    setFormData(prev => ({ ...prev, ...updates }));
  };

  const validateStep = (step: number): boolean => {
    switch (step) {
      case 1: // Identity
        if (!formData.name?.trim()) {
          alert('Por favor, informe o nome da turma.');
          return false;
        }
        return true;
      case 2: // Structure
        if (!formData.totalMeetings || formData.totalMeetings <= 0) {
          alert('Informe o total de encontros.');
          return false;
        }
        if (!formData.meetingDuration || formData.meetingDuration <= 0) {
          alert('Informe a duração do encontro.');
          return false;
        }
        if (!formData.classesPerMeeting || formData.classesPerMeeting <= 0) {
          alert('Informe a quantidade de aulas por encontro.');
          return false;
        }
        return true;
      case 3: // Schedule
        if (!formData.startTime) {
          alert('Informe o horário de início.');
          return false;
        }
        if (!formData.daysOfWeek || formData.daysOfWeek.length === 0) {
          alert('Selecione pelo menos um dia da semana.');
          return false;
        }
        if (!formData.startDate) {
          alert('Informe a data de início.');
          return false;
        }
        if (formData.type === 'POS_EDITAL' && !formData.hardDeadline) {
          alert('Para turmas Pós-Edital, a Data Limite (Hard Deadline) é obrigatória.');
          return false;
        }
        return true;
      case 4: // Room
        if (!formData.classroomId) {
          alert('Selecione uma sala de aula.');
          return false;
        }
        return true;
      default:
        return true;
    }
  };

  const handleNext = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(prev => Math.min(prev + 1, STEPS.length));
    }
  };

  const handleBack = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  };

  const handleSubmit = async () => {
    if (!validateStep(currentStep)) return;

    try {
      setLoading(true);
      if (classToEdit && classToEdit.id) {
        await classService.updateClass(classToEdit.id, formData, bannerDesktopFile, bannerMobileFile, bannerTabletFile);
      } else {
        await classService.createClass(formData as Omit<Class, 'id'>, bannerDesktopFile, bannerMobileFile, bannerTabletFile);
      }
      onSuccess();
      onClose();
    } catch (error) {
      console.error('Error saving class:', error);
      alert('Erro ao salvar turma. Tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-zinc-900 border border-zinc-800 w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
          <div>
            <h2 className="text-lg font-bold text-white uppercase tracking-tight">
              {classToEdit ? 'Editar Turma' : 'Nova Turma Presencial'}
            </h2>
            <p className="text-xs text-zinc-500">Passo {currentStep} de {STEPS.length}: {STEPS[currentStep - 1].title}</p>
          </div>
          <button onClick={onClose} className="text-zinc-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Stepper */}
        <div className="flex w-full h-1 bg-zinc-800">
          {STEPS.map((step) => (
            <div
              key={step.id}
              className={`h-full transition-all duration-500 ${
                step.id <= currentStep ? 'bg-brand-red' : 'bg-transparent'
              }`}
              style={{ width: `${100 / STEPS.length}%` }}
            />
          ))}
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 scrollbar-thin scrollbar-thumb-zinc-700">
          {currentStep === 1 && (
            <ClassIdentityForm 
              data={formData} 
              onChange={updateFormData} 
              onBannerDesktopChange={setBannerDesktopFile}
              onBannerTabletChange={setBannerTabletFile}
              onBannerMobileChange={setBannerMobileFile}
            />
          )}
          {currentStep === 2 && (
            <ClassStructureForm 
              data={formData} 
              onChange={updateFormData} 
              breakCount={breakCount}
              setBreakCount={setBreakCount}
            />
          )}
          {currentStep === 3 && (
            <ClassScheduleForm data={formData} onChange={updateFormData} />
          )}
          {currentStep === 4 && (
            <ClassroomSelectionForm 
              data={formData} 
              onChange={updateFormData}
              hasRecordings={formData.hasRecordings || false}
            />
          )}
        </div>

        {/* Footer / Actions */}
        <div className="p-4 border-t border-zinc-800 bg-zinc-900/50 flex justify-between items-center">
          <button
            onClick={handleBack}
            disabled={currentStep === 1 || loading}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold uppercase transition-colors ${
              currentStep === 1 
                ? 'text-zinc-600 cursor-not-allowed' 
                : 'text-zinc-400 hover:text-white hover:bg-zinc-800'
            }`}
          >
            <ChevronLeft className="w-4 h-4" />
            Voltar
          </button>

          {currentStep < STEPS.length ? (
            <button
              onClick={handleNext}
              className="flex items-center gap-2 px-6 py-2 bg-zinc-100 hover:bg-white text-zinc-900 rounded-lg font-bold uppercase text-xs tracking-wider transition-colors"
            >
              Próximo
              <ChevronRight className="w-4 h-4" />
            </button>
          ) : (
            <button
              onClick={handleSubmit}
              disabled={loading}
              className="flex items-center gap-2 px-6 py-2 bg-brand-red hover:bg-red-600 text-white rounded-lg font-bold uppercase text-xs tracking-wider shadow-lg shadow-brand-red/20 transition-colors disabled:opacity-50"
            >
              {loading ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin" />
                  Salvando...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4" />
                  Salvar Turma
                </>
              )}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Upload, Video, FileText, Type, X, Filter, Layers, Building2, Image as ImageIcon, Smartphone, Monitor } from 'lucide-react';
import { Class } from '../../../../../types/class';
import { classMetadataService, MetadataItem } from '../../../../../services/classMetadataService';

interface ClassIdentityFormProps {
  data: Partial<Class>;
  onChange: (updates: Partial<Class>) => void;
  onBannerDesktopChange?: (file: File) => void;
  onBannerTabletChange?: (file: File) => void;
  onBannerMobileChange?: (file: File) => void;
}

export const ClassIdentityForm: React.FC<ClassIdentityFormProps> = ({ 
  data, 
  onChange,
  onBannerDesktopChange,
  onBannerTabletChange,
  onBannerMobileChange
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const bannerDesktopRef = useRef<HTMLInputElement>(null);
  const bannerTabletRef = useRef<HTMLInputElement>(null);
  const bannerMobileRef = useRef<HTMLInputElement>(null);

  const [categories, setCategories] = useState<MetadataItem[]>([]);
  const [subcategories, setSubcategories] = useState<MetadataItem[]>([]);
  const [organizations, setOrganizations] = useState<MetadataItem[]>([]);

  useEffect(() => {
    const fetchMetadata = async () => {
      try {
        const [cats, subs, orgs] = await Promise.all([
          classMetadataService.getCategories(),
          classMetadataService.getSubcategories(),
          classMetadataService.getOrganizations()
        ]);
        setCategories(cats);
        setSubcategories(subs);
        setOrganizations(orgs);
      } catch (error) {
        console.error("Error fetching metadata:", error);
      }
    };
    fetchMetadata();
  }, []);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
