import React from 'react';
import { Calendar, Clock, AlertTriangle, CalendarDays, Sun, Moon, Sunset } from 'lucide-react';
import { Class, ClassShift } from '../../../../../types/class';

interface ClassScheduleFormProps {
  data: Partial<Class>;
  onChange: (updates: Partial<Class>) => void;
}

const DAYS_OF_WEEK = [
  { value: 1, label: 'Segunda' },
  { value: 2, label: 'Terça' },
  { value: 3, label: 'Quarta' },
  { value: 4, label: 'Quinta' },
  { value: 5, label: 'Sexta' },
];

const WEEKEND_DAYS = [
  { value: 6, label: 'Sábado' },
  { value: 0, label: 'Domingo' },
];

export const ClassScheduleForm: React.FC<ClassScheduleFormProps> = ({ data, onChange }) => {

  const toggleDay = (day: number) => {
    const currentDays = data.daysOfWeek || [];
    const newDays = currentDays.includes(day)
      ? currentDays.filter(d => d !== day)
      : [...currentDays, day].sort();
    onChange({ daysOfWeek: newDays });
  };

  const updateRegularWeekendConfig = (dayOfWeek: number, shift: ClassShift, checked: boolean, time?: string) => {
    const currentConfigs = data.regularWeekendConfigs || [];
    const dayConfigIndex = currentConfigs.findIndex(c => c.dayOfWeek === dayOfWeek);

    let newConfigs = [...currentConfigs];

    if (dayConfigIndex === -1) {
        if (checked) {
            // Add new day config with the shift
            newConfigs.push({
                dayOfWeek,
                shifts: [{ shift, startTime: time || '08:00' }]
            });
        }
    } else {
        const dayConfig = { ...newConfigs[dayConfigIndex] };
        const shiftIndex = dayConfig.shifts.findIndex(s => s.shift === shift);

        if (checked) {
            if (shiftIndex === -1) {
                // Add shift
                dayConfig.shifts = [...dayConfig.shifts, { shift, startTime: time || '08:00' }];
            } else if (time !== undefined) {
                // Update time
                const newShifts = [...dayConfig.shifts];
                newShifts[shiftIndex] = { ...newShifts[shiftIndex], startTime: time };
                dayConfig.shifts = newShifts;
            }
        } else {
            // Remove shift
            if (shiftIndex !== -1) {
                dayConfig.shifts = dayConfig.shifts.filter(s => s.shift !== shift);
            }
        }

        if (dayConfig.shifts.length === 0) {
            newConfigs = newConfigs.filter((_, i) => i !== dayConfigIndex);
        } else {
            newConfigs[dayConfigIndex] = dayConfig;
        }
    }

    onChange({ regularWeekendConfigs: newConfigs });
  };

  const updateWeekendConfig = (dayOfWeek: number, shift: ClassShift, checked: boolean, time?: string) => {
    const currentConfigs = data.weekendConfigs || [];
    const dayConfigIndex = currentConfigs.findIndex(c => c.dayOfWeek === dayOfWeek);

    let newConfigs = [...currentConfigs];

    if (dayConfigIndex === -1) {
        if (checked) {
            // Add new day config with the shift
            newConfigs.push({
                dayOfWeek,
                shifts: [{ shift, startTime: time || '08:00' }]
            });
        }
    } else {
        const dayConfig = { ...newConfigs[dayConfigIndex] };
        const shiftIndex = dayConfig.shifts.findIndex(s => s.shift === shift);

        if (checked) {
            if (shiftIndex === -1) {
                // Add shift
                dayConfig.shifts = [...dayConfig.shifts, { shift, startTime: time || '08:00' }];
            } else if (time !== undefined) {
                // Update time
                const newShifts = [...dayConfig.shifts];
                newShifts[shiftIndex] = { ...newShifts[shiftIndex], startTime: time };
                dayConfig.shifts = newShifts;
            }
        } else {
            // Remove shift
            if (shiftIndex !== -1) {
                dayConfig.shifts = dayConfig.shifts.filter(s => s.shift !== shift);
            }
        }

        if (dayConfig.shifts.length === 0) {
            newConfigs = newConfigs.filter((_, i) => i !== dayConfigIndex);
        } else {
            newConfigs[dayConfigIndex] = dayConfig;
        }
    }

    onChange({ weekendConfigs: newConfigs });
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-500">
      <div className="flex items-center gap-2 mb-4 pb-2 border-b border-zinc-800">
        <CalendarDays className="w-5 h-5 text-brand-red" />
        <h3 className="text-lg font-bold text-white uppercase">Cronograma e Prazos</h3>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Turno */}
        <div>
          <label className="block text-xs font-bold text-zinc-400 uppercase mb-1">Turno *</label>
          <div className="grid grid-cols-3 gap-2 bg-zinc-800 p-1 rounded-lg border border-zinc-700">
            {[
              { value: 'MORNING', label: 'Manhã', icon: Sun },
              { value: 'AFTERNOON', label: 'Tarde', icon: Sunset },
              { value: 'NIGHT', label: 'Noite', icon: Moon },
            ].map((option) => (
              <button
                key={option.value}
                type="button"
                onClick={() => onChange({ shift: option.value as ClassShift })}
                className={`flex flex-col items-center justify-center py-2 rounded-md text-[10px] font-bold uppercase transition-all ${
                  data.shift === option.value
                    ? 'bg-zinc-600 text-white shadow-lg'
                    : 'text-zinc-400 hover:text-white hover:bg-zinc-700'
                }`}
              >
                <option.icon className="w-3 h-3 mb-1" />
                {option.label}
              </button>
            ))}
          </div>
        </div>

        {/* Horário de Início */}
        <div>
          <label className="block text-xs font-bold text-zinc-400 uppercase mb-1">Horário de Início *</label>
          <div className="relative">
            <Clock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
            <input
              type="time"
              value={data.startTime || ''}
              onChange={(e) => onChange({ startTime: e.target.value })}
              className="w-full bg-zinc-800 border border-zinc-700 rounded-lg pl-10 pr-4 py-3 text-white focus:outline-none focus:border-brand-red transition-colors"
            />
          </div>
        </div>

        {/* Dias da Semana */}
        <div className="col-span-2">
          <label className="block text-xs font-bold text-zinc-400 uppercase mb-2">Dias de Aula (Semana) *</label>
          <div className="flex flex-wrap gap-2">
            {DAYS_OF_WEEK.map((day) => (
              <button
                key={day.value}
                type="button"
                onClick={() => toggleDay(day.value)}
                className={`px-4 py-2 rounded-lg text-xs font-bold uppercase transition-all border ${
                  data.daysOfWeek?.includes(day.value)
                    ? 'bg-brand-red text-white border-brand-red shadow-lg shadow-red-900/20'
                    : 'bg-zinc-800 text-zinc-400 border-zinc-700 hover:border-zinc-600'
                }`}
              >
                {day.label}
              </button>
            ))}
          </div>
        </div>

        {/* Datas Início e Fim */}
        <div>
          <label className="block text-xs font-bold text-zinc-400 uppercase mb-1">Data de Início *</label>
          <input
            type="date"
            value={data.startDate || ''}
            onChange={(e) => onChange({ startDate: e.target.value })}
            className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-brand-red transition-colors"
          />
        </div>

        <div>
          <label className="block text-xs font-bold text-zinc-400 uppercase mb-1">Término Previsto (Desejado)</label>
          <input
            type="date"
            value={data.endDate || ''}
            onChange={(e) => onChange({ endDate: e.target.value })}
            className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-brand-red transition-colors"
          />
        </div>

        {/* Gatilhos Condicionais de Prazo */}
        <div className="col-span-2 bg-zinc-900/50 border border-zinc-800 p-4 rounded-xl">
          {data.type === 'POS_EDITAL' ? (
            <div className="animate-in fade-in slide-in-from-top-2">
              <div className="flex items-center gap-2 mb-2 text-red-500">
                <AlertTriangle className="w-4 h-4" />
                <label className="text-xs font-bold uppercase">Data Limite Inegociável (Hard Deadline) *</label>
              </div>
              <input
                type="date"
                value={data.hardDeadline || ''}
                onChange={(e) => onChange({ hardDeadline: e.target.value })}
                className="w-full bg-red-900/10 border border-red-900/30 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-red-500 transition-colors"
                required
              />
              <p className="text-[10px] text-zinc-500 mt-1">
                Nenhum encontro será agendado automaticamente após esta data.
              </p>
            </div>
          ) : (
            <div className="animate-in fade-in slide-in-from-top-2">
              <label className="block text-xs font-bold text-zinc-400 uppercase mb-1">Margem de Tolerância de Prazo (%)</label>
              <input
                type="number"
                min="0"
                max="100"
                value={data.softDeadlineMargin || ''}
                onChange={(e) => onChange({ softDeadlineMargin: Number(e.target.value) })}
                className="w-full bg-zinc-800 border border-zinc-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-brand-red transition-colors"
                placeholder="Ex: 10%"
              />
              <p className="text-[10px] text-zinc-500 mt-1">
                Percentual de tempo extra tolerado além da data de término prevista.
              </p>
            </div>
          )}
        </div>

        {/* Configuração de Finais de Semana (REGULAR) */}
        <div className="col-span-2 space-y-4 pt-4 border-t border-zinc-800">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <label className="text-sm font-bold text-white uppercase">
                Aulas Regulares aos Finais de Semana
              </label>
            </div>
          </div>

          <div className="bg-zinc-800/30 p-4 rounded-xl border border-zinc-700/50 space-y-4 animate-in fade-in slide-in-from-top-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {WEEKEND_DAYS.map((day) => {
                  const dayConfig = data.regularWeekendConfigs?.find(c => c.dayOfWeek === day.value);

                  return (
                      <div key={day.value} className="bg-zinc-900/50 p-4 rounded-lg border border-zinc-800">
                          <h4 className="text-sm font-bold text-white uppercase mb-3">{day.label}</h4>
                          <div className="space-y-3">
                              {[
                                  { value: 'MORNING', label: 'Manhã' },
                                  { value: 'AFTERNOON', label: 'Tarde' },
                                  { value: 'NIGHT', label: 'Noite' },
                              ].map((shiftOption) => {
                                  const shift = shiftOption.value as ClassShift;
                                  const shiftConfig = dayConfig?.shifts.find(s => s.shift === shift);
                                  const isChecked = !!shiftConfig;

                                  return (
                                      <div key={shift} className="flex flex-col gap-2">
                                          <div className="flex items-center gap-2">
                                              <input
                                                  type="checkbox"
                                                  id={`regular-weekend-${day.value}-${shift}`}
                                                  checked={isChecked}
                                                  onChange={(e) => updateRegularWeekendConfig(day.value, shift, e.target.checked)}
                                                  className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-brand-red focus:ring-brand-red"
                                              />
                                              <label htmlFor={`regular-weekend-${day.value}-${shift}`} className="text-xs font-medium text-zinc-300 cursor-pointer select-none">
                                                  {shiftOption.label}
                                              </label>
                                          </div>

                                          {isChecked && (
                                              <div className="ml-6 animate-in fade-in slide-in-from-top-1">
                                                  <input
                                                      type="time"
                                                      value={shiftConfig?.startTime || ''}
                                                      onChange={(e) => updateRegularWeekendConfig(day.value, shift, true, e.target.value)}
                                                      className="w-full bg-zinc-800 border border-zinc-700 rounded px-2 py-1 text-xs text-white focus:border-brand-red"
                                                  />
                                              </div>
                                          )}
                                      </div>
                                  );
                              })}
                          </div>
                      </div>
                  );
              })}
            </div>
          </div>
        </div>

        {/* Configuração de Finais de Semana (Reserva) */}
        <div className="col-span-2 space-y-4 pt-4 border-t border-zinc-800">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="allowWeekend"
                checked={data.allowWeekend || false}
                onChange={(e) => onChange({ allowWeekend: e.target.checked, weekendConfigs: e.target.checked ? data.weekendConfigs : [] })}
                className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-brand-red focus:ring-brand-red"
              />
              <label htmlFor="allowWeekend" className="text-sm font-medium text-white cursor-pointer select-none">
                Permitir aulas aos Finais de Semana (Reserva)?
              </label>
            </div>
          </div>

          {data.allowWeekend && (
            <div className="bg-zinc-800/30 p-4 rounded-xl border border-zinc-700/50 space-y-4 animate-in fade-in slide-in-from-top-2">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {WEEKEND_DAYS.map((day) => {
                    const dayConfig = data.weekendConfigs?.find(c => c.dayOfWeek === day.value);

                    return (
                        <div key={day.value} className="bg-zinc-900/50 p-4 rounded-lg border border-zinc-800">
                            <h4 className="text-sm font-bold text-white uppercase mb-3">{day.label}</h4>
                            <div className="space-y-3">
                                {[
                                    { value: 'MORNING', label: 'Manhã' },
                                    { value: 'AFTERNOON', label: 'Tarde' },
                                    { value: 'NIGHT', label: 'Noite' },
                                ].map((shiftOption) => {
                                    const shift = shiftOption.value as ClassShift;
                                    const shiftConfig = dayConfig?.shifts.find(s => s.shift === shift);
                                    const isChecked = !!shiftConfig;

                                    // Check if this slot is already taken by Regular Schedule
                                    const isRegularlyScheduled = data.regularWeekendConfigs?.some(
                                        c => c.dayOfWeek === day.value && c.shifts.some(s => s.shift === shift)
                                    );

                                    return (
                                        <div key={shift} className="flex flex-col gap-2">
                                            <div className="flex items-center gap-2">
                                                <input
                                                    type="checkbox"
                                                    id={`weekend-${day.value}-${shift}`}
                                                    checked={isChecked}
                                                    disabled={isRegularlyScheduled}
                                                    onChange={(e) => updateWeekendConfig(day.value, shift, e.target.checked)}
                                                    className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-brand-red focus:ring-brand-red disabled:opacity-50 disabled:cursor-not-allowed"
                                                />
                                                <label 
                                                    htmlFor={`weekend-${day.value}-${shift}`} 
                                                    className={`text-xs font-medium cursor-pointer select-none ${isRegularlyScheduled ? 'text-zinc-600 line-through' : 'text-zinc-300'}`}
                                                >
                                                    {shiftOption.label} {isRegularlyScheduled && '(Regular)'}
                                                </label>
                                            </div>

                                            {isChecked && (
                                                <div className="ml-6 animate-in fade-in slide-in-from-top-1">
                                                    <input
                                                        type="time"
                                                        value={shiftConfig?.startTime || ''}
                                                        onChange={(e) => updateWeekendConfig(day.value, shift, true, e.target.value)}
                                                        className="w-full bg-zinc-800 border border-zinc-700 rounded px-2 py-1 text-xs text-white focus:border-brand-red"
                                                    />
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
              </div>
            </div>
          )}
        </div>

        {/* Feriados */}
        <div className="col-span-2 pt-2">
          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              id="holidaysOff"
              checked={data.holidaysOff || false}
              onChange={(e) => onChange({ holidaysOff: e.target.checked })}
              className="w-4 h-4 rounded border-zinc-600 bg-zinc-700 text-brand-red focus:ring-brand-red"
            />
            <label htmlFor="holidaysOff" className="text-sm font-medium text-zinc-300 cursor-pointer select-none">
              Dar folga nos Feriados Vermelhos?
            </label>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Class } from '../../../../../types/class';
import { Topic, Subject, Module } from '../../../../../types/curriculum';
import { Teacher } from '../../../../../types/teacher';
import { ClassScheduleEvent, ScheduleGap, ScheduleException, ScheduleAlert } from '../../../../../types/schedule';
import { buildSchedule } from '../../../../../utils/scheduler/ScheduleBuilder';
import { resolveManualSchedule } from '../../../../../utils/scheduler/ContentResolver';
import { generateEmptySlots } from '../../../../../utils/scheduler/TimeSlotGenerator';
import { SchedulePreview } from './schedule/SchedulePreview';
import { classScheduleService } from '../../../../../services/classScheduleService';
import { holidayService } from '../../../../../services/holidayService';
import { sanitizeSchedule } from '../../../../../utils/scheduler/ScheduleSynchronizer';
import { Calendar, RefreshCw, Save, Loader2, CheckCircle, AlertTriangle, AlertOctagon, Trash2 } from 'lucide-react';

interface ScheduleTabProps {
  cls: Class;
  topics: Topic[];
  subjects: Subject[];
  teachers: Teacher[];
  onUpdate?: () => void;
}

export const ScheduleTab: React.FC<ScheduleTabProps> = ({ cls, topics, subjects, teachers, onUpdate }) => {
  const [generatedEvents, setGeneratedEvents] = useState<ClassScheduleEvent[]>([]);
  const [generatedGaps, setGeneratedGaps] = useState<ScheduleGap[]>([]);
  const [alert, setAlert] = useState<ScheduleAlert | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [holidays, setHolidays] = useState<string[]>([]);
  const [manualAppointments, setManualAppointments] = useState<any[]>([]);
  const [saveMessage, setSaveMessage] = useState('');
  const [instructionMessage, setInstructionMessage] = useState<string | null>(null);
  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [isManualMode, setIsManualMode] = useState(false);
  const [isClearModalOpen, setIsClearModalOpen] = useState(false);
  const [isClearing, setIsClearing] = useState(false);

  useEffect(() => {
    const fetchHolidays = async () => {
      try {
        const fetchedHolidays = await holidayService.getHolidays();
        setHolidays(fetchedHolidays);
      } catch (error) {
        console.error("Error fetching holidays:", error);
      }
    };
    fetchHolidays();
  }, []);

  useEffect(() => {
    if (isPreviewMode) return;

    const loadAndSanitize = async () => {
      try {
        const originalEvents = await classScheduleService.getScheduleEventsByClass(cls.id);
        setManualAppointments(originalEvents);
      } catch (error) {
        console.error("Error loading schedule:", error);
      }
    };

    loadAndSanitize();
  }, [cls.id, isPreviewMode]);

  useEffect(() => {
    if (manualAppointments.length > 0) {
      const resolved = resolveManualSchedule(manualAppointments, subjects, topics);
      setGeneratedEvents(resolved);
    } else {
      setGeneratedEvents([]);
    }
  }, [manualAppointments, subjects, topics]);

  const handleGenerateSchedule = async () => {
    setIsGenerating(true);
    setSaveMessage('');
    setAlert(null);
    setInstructionMessage(null);

    // 1. HARD RESET: Limpa a memória de eventos antigos
    setManualAppointments([]);

    // 2. Trava a intromissão do banco de dados
    setIsPreviewMode(true);
    setIsManualMode(false);

    // 3. Aguarda um pequeno delay para o React limpar a tela
    await new Promise(resolve => setTimeout(resolve, 100));

    try {
      // 4. CHAMA O MOTOR DE AGENDAMENTO COM AS EXCEÇÕES ZERADAS
      const { events, gaps, alert: generatedAlert } = buildSchedule(cls, topics, teachers, holidays, [], subjects);
      setManualAppointments(events);
      setGeneratedGaps(gaps);
      setAlert(generatedAlert);
    } catch (error) {
      console.error("Error generating schedule:", error);
      window.alert("Erro ao gerar cronograma. Verifique o console para mais detalhes.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAddException = (newException: ScheduleException) => {
    setManualAppointments(prev => {
      // Encontra o evento original na lista resolvida para pegar os metadados (data, turno, disciplina)
      const originalEvent = generatedEvents.find(e => e.id === newException.eventId);

      if (!originalEvent) {
        // Fallback for missing originalEvent (e.g. if generatedEvents is out of sync)
        const eventIndex = prev.findIndex(e => 
          (e.id && e.id === newException.eventId) || 
          (e.date === newException.date && (e.meetingNumber === newException.meetingNumber || e.periodNumber === newException.meetingNumber))
        );

        if (eventIndex !== -1) {
          const updated = [...prev];
          if (newException.type === 'CANCELLATION') {
            updated.splice(eventIndex, 1);
          } else {
            updated[eventIndex] = {
              ...updated[eventIndex],
              teacherId: newException.substituteTeacherId || updated[eventIndex].teacherId,
              isSubstitute: newException.type === 'SUBSTITUTION',
              originalTeacherId: newException.type === 'SUBSTITUTION' ? newException.originalTeacherId : undefined
            };
          }
          return updated;
        }
        return prev;
      }

      if (newException.type === 'CANCELLATION') {
        // Remove all events that match the same date, shift, and subject
        return prev.filter(e => !(e.date === originalEvent.date && e.shift === originalEvent.shift && e.subjectId === originalEvent.subjectId));
      } else {
        // Update all events that match the same date, shift, and subject
        return prev.map(e => {
          if (e.date === originalEvent.date && e.shift === originalEvent.shift && e.subjectId === originalEvent.subjectId) {
            return {
              ...e,
              teacherId: newException.substituteTeacherId || e.teacherId,
              isSubstitute: newException.type === 'SUBSTITUTION',
              originalTeacherId: newException.type === 'SUBSTITUTION' ? newException.originalTeacherId : undefined
            };
          }
          return e;
        });
      }
    });
  };

  const handleDeleteAppointment = (eventId: string) => {
    setManualAppointments(prev => {
      // Encontra o evento na lista resolvida para pegar os metadados
      const eventToDelete = generatedEvents.find(ge => ge.id === eventId);

      if (eventToDelete) {
        // Remove todos os eventos que compartilham a mesma data, turno e disciplina
        return prev.filter(e => 
          !(e.date === eventToDelete.date && e.shift === eventToDelete.shift && e.subjectId === eventToDelete.subjectId)
        );
      }

      // Fallback: tenta remover pelo ID
      return prev.filter(e => e.id !== eventId);
    });
  };

  const handleSaveSchedule = async () => {
    if (alert?.type === 'RED') return;

    setIsSaving(true);
    setSaveMessage('');
    try {
      await classScheduleService.saveScheduleEvents(cls.id, generatedEvents);
      setSaveMessage('Cronograma salvo e sincronizado com sucesso!');
      setIsPreviewMode(false);
      if (onUpdate) onUpdate();
      setTimeout(() => setSaveMessage(''), 3000);
    } catch (error) {
      console.error("Error saving schedule:", error);
      window.alert("Erro ao salvar cronograma. Tente novamente.");
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdateEventStatus = async (eventIds: string[], status: 'COMPLETED' | 'SCHEDULED') => {
    try {
      await classScheduleService.updateAppointmentsStatus(eventIds, status);

      // Atualiza o estado local para refletir a mudança imediatamente
      setManualAppointments(prev => prev.map(event => {
        if (eventIds.includes(event.id)) {
          return { ...event, status };
        }
        return event;
      }));

      if (onUpdate) onUpdate();
    } catch (error) {
      console.error("Error updating event status:", error);
      window.alert("Erro ao atualizar status das aulas.");
    }
  };

  const handleClearSchedule = async () => {
    setIsClearing(true);
    try {
      // 1. Apaga do banco de dados
      await classScheduleService.clearClassSchedule(cls.id); 

      // 2. Limpa o estado visual da tela
      setGeneratedEvents([]); 
      setManualAppointments([]);

      // 3. Fecha o modal
      setIsClearModalOpen(false);

      // 4. Se quiser, pode voltar para o modo inicial
      setIsPreviewMode(false);
      setIsManualMode(false);
    } catch (error) {
      console.error("Erro ao limpar cronograma:", error);
      window.alert("Erro ao limpar cronograma. Tente novamente.");
    } finally {
      setIsClearing(false);
    }
  };

  const handleCreateManually = () => {
    // 1. Limpa qualquer evento fantasma anterior
    setGeneratedEvents([]);
    setManualAppointments([]);

    // 2. FORÇA a geração da estrutura vazia do calendário (Gaps)
    if (cls) {
      const emptySlots = generateEmptySlots(cls, holidays);
      const emptyGaps: ScheduleGap[] = emptySlots.map(slot => ({
        date: slot.date,
        startTime: slot.startTime,
        endTime: slot.endTime,
        reason: 'NO_TEACHER',
        description: 'Disponível para Agendamento'
      }));

      // Adiciona os feriados aos gaps também
      holidays.forEach(h => {
        if (!emptyGaps.some(g => g.date === h && g.reason === 'HOLIDAY')) {
          emptyGaps.push({ date: h, reason: 'HOLIDAY', description: 'Feriado / Recesso' });
        }
      });

      setGeneratedGaps(emptyGaps);
    }

    // 3. Ativa a visualização do calendário
    setIsPreviewMode(true);
    setIsManualMode(true);
  };

  return (
    <div className="space-y-6">
      {generatedEvents.length === 0 && !isPreviewMode ? (
        <div className="flex flex-col items-center justify-center p-12 bg-zinc-900 rounded-xl border border-dashed border-zinc-800 shadow-sm animate-in fade-in">
          <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mb-4">
            <Calendar className="w-8 h-8 text-zinc-400" />
          </div>
          <h3 className="text-xl font-semibold text-white mb-2">Cronograma de Aulas</h3>
          <p className="text-zinc-400 text-center max-w-md mb-8">
            Inicie a montagem do cronograma para organizar os encontros e aulas desta turma.
          </p>

          <div className="flex gap-4">
            <button
              onClick={handleCreateManually}
              className="flex items-center gap-2 px-8 py-4 bg-brand-red text-white rounded-lg hover:bg-red-600 transition-colors font-bold shadow-lg shadow-brand-red/20 uppercase tracking-wider"
            >
              <Calendar className="w-5 h-5" />
              INICIAR MONTAGEM MANUAL
            </button>
          </div>
        </div>
      ) : (
        <div className="space-y-6 animate-in fade-in">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-zinc-900 p-4 rounded-xl border border-zinc-800 shadow-sm">
            <div>
              <h3 className="text-lg font-semibold text-white">Configuração do Cronograma</h3>
              <p className="text-sm text-zinc-400">
                {generatedEvents.length} aulas agendadas. Verifique os detalhes abaixo antes de salvar.
              </p>
            </div>

            <div className="flex flex-col sm:flex-row items-end sm:items-center gap-3 w-full sm:w-auto">
              {saveMessage && (
                <div className="flex items-center gap-2 text-emerald-500 bg-emerald-950/30 px-3 py-2 rounded-lg border border-emerald-900/50 text-sm font-medium animate-in slide-in-from-right-5 fade-in">
                  <CheckCircle className="w-4 h-4" />
                  {saveMessage}
                </div>
              )}

              <div className="flex items-center gap-3 w-full sm:w-auto">
                <button
                  onClick={() => setIsClearModalOpen(true)}
                  className="flex items-center gap-2 px-4 py-2 border border-red-500/50 text-red-500 hover:bg-red-500 hover:text-white rounded-lg transition text-sm font-medium"
                >
                  <Trash2 size={16} />
                  Limpar Cronograma
                </button>

                <button
                  onClick={handleSaveSchedule}
