import React, { useState, useEffect, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import { ChevronDown, ChevronRight, FileText, Link as LinkIcon, CheckCircle, Clock, AlertCircle, Globe, Video, CheckCircle2 } from 'lucide-react';
import { Subject, Topic, Module } from '../../../../../../types/curriculum';
import { ClassScheduleEvent } from '../../../../../../types/schedule';
import { Teacher } from '../../../../../../types/teacher';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';
import { useAuth } from '../../../../../../contexts/AuthContext';
import { openWatermarkedPdf } from '../../../../../../utils/pdfSecurityService';

interface PedagogicalPlanningProps {
  subjects: Subject[];
  topics: Topic[];
  modules: Module[];
  events: ClassScheduleEvent[];
  teachers: Teacher[];
  totalMeetings?: number;
}

export function PedagogicalPlanning({ subjects, topics, modules, events, teachers, totalMeetings = 0 }: PedagogicalPlanningProps) {
  const { currentUser, userData } = useAuth();
  const [searchParams] = useSearchParams();
  const [expandedSubjects, setExpandedSubjects] = useState<Set<string>>(new Set());
  const [expandedTopics, setExpandedTopics] = useState<Set<string>>(new Set());
  const [expandedModules, setExpandedModules] = useState<Set<string>>(new Set());

  // Deep Linking: Auto-expand and scroll
  useEffect(() => {
    const urlSubjectId = searchParams.get('subjectId');
    const urlTopicId = searchParams.get('topicId');
    const urlModuleId = searchParams.get('moduleId');

    if (urlSubjectId || urlTopicId || urlModuleId) {
      if (urlSubjectId) setExpandedSubjects(prev => new Set([...prev, urlSubjectId]));
      if (urlTopicId) setExpandedTopics(prev => new Set([...prev, urlTopicId]));
      if (urlModuleId) setExpandedModules(prev => new Set([...prev, urlModuleId]));

      // Scroll to module after expansion
      if (urlModuleId) {
        setTimeout(() => {
          const element = document.getElementById(`module-${urlModuleId}`);
          if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
            element.classList.add('highlight-pulse');
            setTimeout(() => element.classList.remove('highlight-pulse'), 3000);
          }
        }, 500);
      }
    }
  }, [searchParams]);

  const onlineModuleIds = new Set(modules.filter(m => m.isOnline).map(m => m.id));

  const handleOpenPdf = async (url: string, title: string) => {
    try {
      await openWatermarkedPdf(url, {
        email: currentUser?.email || 'admin@insanus.com',
        cpf: userData?.cpf || '000.000.000-00'
      });
    } catch (error) {
      console.error('Error opening PDF:', error);
      window.open(url, '_blank');
    }
  };

  const toggleSubject = (id: string) => {
    const newSet = new Set(expandedSubjects);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedSubjects(newSet);
  };

  const toggleTopic = (id: string) => {
    const newSet = new Set(expandedTopics);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedTopics(newSet);
  };

  const toggleModule = (id: string) => {
    const newSet = new Set(expandedModules);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedModules(newSet);
  };

  // Filter subjects that have topics
  const activeSubjects = subjects.filter(subject => 
    topics.some(topic => topic.subjectId === subject.id)
  );

  // Calculate global progression
  const globalStats = useMemo(() => {
    let totalRequired = 0;
    let totalCompleted = 0;

    subjects.forEach(subject => {
      const subjectTopics = topics.filter(t => t.subjectId === subject.id);
      const subjectRequired = subjectTopics.reduce((acc, topic) => {
        const topicPresentialClasses = (topic.modules || []).reduce((mAcc, m) => {
          if (!m.isOnline) return mAcc + (m.classesCount || 0);
          return mAcc;
        }, 0);

        if (topicPresentialClasses === 0 && (!topic.modules || topic.modules.length === 0)) {
          return acc + (topic.requiredClasses || 0);
        }
        return acc + topicPresentialClasses;
      }, 0);

      const subjectCompleted = events.filter(e => 
        e.subjectId === subject.id && 
        e.status === 'COMPLETED' && 
        !onlineModuleIds.has(e.moduleId)
      ).length;

      totalRequired += subjectRequired;
      totalCompleted += subjectCompleted;
    });

    // Calculate completed meetings
    const meetingsMap = new Map<number, ClassScheduleEvent[]>();
    events.forEach(e => {
      if (e.meetingNumber) {
        if (!meetingsMap.has(e.meetingNumber)) {
          meetingsMap.set(e.meetingNumber, []);
        }
        meetingsMap.get(e.meetingNumber)?.push(e);
      }
    });

    let completedMeetingsCount = 0;
    meetingsMap.forEach((meetingEvents) => {
      if (meetingEvents.length > 0 && meetingEvents.every(e => e.status === 'COMPLETED')) {
        completedMeetingsCount++;
      }
    });

    return {
      totalRequired,
      totalCompleted,
      completedMeetingsCount,
      percentage: totalRequired > 0 ? Math.round((totalCompleted / totalRequired) * 100) : 0
    };
  }, [subjects, topics, events, onlineModuleIds]);

  return (
    <div className="space-y-6">
      {/* Global Progression Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
        <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex flex-col justify-between">
          <div className="flex justify-between items-start mb-2">
            <div>
              <h3 className="text-zinc-400 text-xs font-bold uppercase tracking-wider">Progresso Geral de Aulas</h3>
              <p className="text-2xl font-black text-white">{globalStats.totalCompleted} / {globalStats.totalRequired}</p>
            </div>
            <span className="text-brand-red font-black text-xl">{globalStats.percentage}%</span>
          </div>
          <div className="w-full bg-zinc-800 h-2 rounded-full overflow-hidden">
            <div 
              className="bg-brand-red h-full transition-all duration-500" 
              style={{ width: `${globalStats.percentage}%` }}
            />
          </div>
        </div>

        <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex items-center justify-between">
          <div>
            <h3 className="text-zinc-400 text-xs font-bold uppercase tracking-wider">Contador de Encontros</h3>
            <p className="text-3xl font-black text-white">
              {globalStats.completedMeetingsCount} <span className="text-zinc-500 text-xl">/ {totalMeetings}</span>
            </p>
          </div>
          <div className="w-12 h-12 rounded-full border-2 border-zinc-800 flex items-center justify-center">
            <CheckCircle2 className={clsx(
              "w-6 h-6",
              globalStats.completedMeetingsCount === totalMeetings && totalMeetings > 0 ? "text-emerald-500" : "text-zinc-600"
            )} />
          </div>
        </div>
      </div>

      <div className="space-y-4">
      {activeSubjects.map(subject => {
        const subjectTopics = topics.filter(t => t.subjectId === subject.id);

        // Calculate total required presential classes from curriculum
        const totalRequiredClasses = subjectTopics.reduce((acc, topic) => {
          const topicPresentialClasses = (topic.modules || []).reduce((mAcc, m) => {
            if (!m.isOnline) return mAcc + (m.classesCount || 0);
            return mAcc;
          }, 0);

          // If no modules are defined, use the topic's requiredClasses (assuming they are presential)
          if (topicPresentialClasses === 0 && (!topic.modules || topic.modules.length === 0)) {
            return acc + (topic.requiredClasses || 0);
          }

          return acc + topicPresentialClasses;
        }, 0);

        const completedEvents = events.filter(e => 
          e.subjectId === subject.id && 
          e.status === 'COMPLETED' && 
          !onlineModuleIds.has(e.moduleId)
        );

        const isExpanded = expandedSubjects.has(subject.id);

        // Sort topics for this subject
        const sortedTopics = [...subjectTopics].sort((a, b) => (a.order || 0) - (b.order || 0));

        return (
          <div key={subject.id} className="border border-zinc-800 rounded-lg overflow-hidden bg-zinc-900/50">
            {/* Subject Header */}
            <button
              onClick={() => toggleSubject(subject.id)}
              className="w-full flex items-center justify-between p-4 hover:bg-zinc-800/50 transition-colors"
            >
              <div className="flex items-center gap-3">
                {isExpanded ? <ChevronDown className="w-5 h-5 text-zinc-400" /> : <ChevronRight className="w-5 h-5 text-zinc-400" />}
                <div 
                  className="w-3 h-3 rounded-full" 
                  style={{ backgroundColor: subject.color }}
                />
                <span className="font-medium text-zinc-100">{subject.name}</span>
              </div>
              <div className="flex items-center gap-4 text-sm">
                <span className="text-zinc-400">
                  {completedEvents.length} / {totalRequiredClasses} aulas concluídas
                </span>
                <div className="w-24 h-2 bg-zinc-800 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-emerald-500 transition-all duration-500"
                    style={{ 
                      width: `${totalRequiredClasses > 0 ? (completedEvents.length / totalRequiredClasses) * 100 : 0}%` 
                    }}
                  />
                </div>
              </div>
            </button>

            {/* Subject Content (Topics) */}
            {isExpanded && (
              <div className="border-t border-zinc-800 bg-zinc-900/30">
                {sortedTopics.map(topic => {
                  const isTopicExpanded = expandedTopics.has(topic.id);
                  const topicModules = topic.modules || [];

                  return (
                    <div key={topic.id} className="border-b border-zinc-800 last:border-0">
                      {/* Topic Header */}
                      <button
                        onClick={() => toggleTopic(topic.id)}
                        className="w-full flex items-center justify-between p-3 pl-8 hover:bg-zinc-800/30 transition-colors"
                      >
                        <div className="flex items-center gap-3">
                          {isTopicExpanded ? <ChevronDown className="w-4 h-4 text-zinc-500" /> : <ChevronRight className="w-4 h-4 text-zinc-500" />}
                          <span className="text-sm font-medium text-zinc-300">{topic.name}</span>
                        </div>
                        <span className="text-xs text-zinc-500">
                          {topicModules.length} módulos
                        </span>
                      </button>

                      {/* Topic Content (Modules) */}
                      {isTopicExpanded && (
                        <div className="bg-zinc-950/30 pl-12 pr-4 py-2 space-y-2">
                          {topicModules.map(module => {
                            const isModuleExpanded = expandedModules.has(module.id);
                            const moduleEvents = events.filter(e => e.moduleId === module.id)
                              .sort((a, b) => new Date(`${a.date}T${a.startTime}`).getTime() - new Date(`${b.date}T${b.startTime}`).getTime());

                            const moduleContents = module.contents || [];

                            return (
                              <div 
                                key={module.id} 
                                id={`module-${module.id}`}
                                className="border border-zinc-800 rounded-md overflow-hidden bg-zinc-900 transition-all duration-500"
                              >
                                {/* Module Header */}
                                  <button
                                    onClick={() => toggleModule(module.id)}
                                    className="w-full flex items-center justify-between p-3 hover:bg-zinc-800/50 transition-colors"
                                  >
                                    <div className="flex items-center gap-3">
                                      {isModuleExpanded ? <ChevronDown className="w-4 h-4 text-zinc-500" /> : <ChevronRight className="w-4 h-4 text-zinc-500" />}
                                      <div className="flex items-center gap-2">
                                        <span className="text-sm text-zinc-300">{module.name}</span>
                                        {module.isOnline && (
                                          <span className="px-1.5 py-0.5 rounded bg-blue-500/10 text-blue-500 border border-blue-500/20 text-[10px] font-bold uppercase">
                                            Online
                                          </span>
                                        )}
                                      </div>
                                    </div>
                                    <div className="flex items-center gap-3 text-xs text-zinc-500">
                                      <span className="flex items-center gap-1">
                                        <FileText className="w-3 h-3" />
                                        {moduleContents.length}
                                      </span>
                                      {!module.isOnline && (
                                        <span className="flex items-center gap-1">
                                          <Clock className="w-3 h-3" />
                                          {moduleEvents.filter(e => e.status === 'COMPLETED').length} / {module.classesCount} aulas
                                        </span>
                                      )}
                                      {module.isOnline && (
                                        <span className="flex items-center gap-1">
                                          {module.onlineStatus === 'EM_GRAVACAO' ? (
                                            <Video className="w-3 h-3 text-amber-500" />
                                          ) : (
                                            <CheckCircle2 className="w-3 h-3 text-emerald-500" />
                                          )}
                                          {module.onlineStatus === 'EM_GRAVACAO' ? 'Em Gravação' : 'Publicado'}
                                        </span>
                                      )}
                                    </div>
                                  </button>

                                {/* Module Content (Materials & Classes) */}
                                {isModuleExpanded && (
                                  <div className="p-4 space-y-6 border-t border-zinc-800 bg-zinc-950/50">

                                    {/* Online Info Section */}
                                    {module.isOnline && (
                                      <div className="p-4 rounded-lg bg-zinc-900 border border-zinc-800 space-y-4">
                                        <div className="flex items-center justify-between">
                                          <div className="flex items-center gap-3">
                                            <div className={twMerge(
                                              "w-10 h-10 rounded-full flex items-center justify-center border",
                                              module.onlineStatus === 'PUBLICADO' 
                                                ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-500"
                                                : "bg-amber-500/10 border-amber-500/30 text-amber-500"
                                            )}>
                                              {module.onlineStatus === 'PUBLICADO' ? <CheckCircle2 className="w-5 h-5" /> : <Video className="w-5 h-5" />}
                                            </div>
                                            <div>
                                              <h4 className="text-sm font-bold text-white">Módulo Online</h4>
                                              <p className="text-xs text-zinc-500 uppercase font-bold tracking-wider">
                                                Status: {module.onlineStatus === 'EM_GRAVACAO' ? 'Em Gravação' : 'Publicado'}
                                              </p>
                                            </div>
                                          </div>

                                          {module.onlineStatus === 'EM_GRAVACAO' && module.publicationDate && (
                                            <div className="text-right">
                                              <p className="text-[10px] text-zinc-500 uppercase font-bold">Previsão de Publicação</p>
                                              <p className="text-sm font-bold text-amber-500">
                                                {format(new Date(module.publicationDate + 'T00:00:00'), "dd/MM/yyyy")}
                                              </p>
                                            </div>
                                          )}
                                        </div>

                                        {module.onlineStatus === 'PUBLICADO' && module.teachingAreaLink && (
                                          <button 
                                            onClick={() => {
                                              console.log('Redirecting to teaching area:', module.teachingAreaLink);
                                            }}
                                            className="w-full flex items-center justify-between p-3 rounded-lg bg-zinc-950 border border-zinc-800 hover:border-brand-red/50 transition-all group"
                                          >
                                            <div className="flex items-center gap-3">
                                              <div className="w-8 h-8 rounded bg-zinc-900 flex items-center justify-center border border-zinc-800 group-hover:border-brand-red/30">
                                                <Globe className="w-4 h-4 text-brand-red" />
                                              </div>
                                              <div className="text-left">
                                                <p className="text-xs font-bold text-zinc-300 group-hover:text-white">Acessar na Área de Ensino</p>
                                                <p className="text-[10px] text-zinc-500">Módulo: {module.teachingAreaLink.moduleId} | Pasta: {module.teachingAreaLink.folderId}</p>
                                              </div>
                                            </div>
                                            <ChevronRight className="w-4 h-4 text-zinc-600 group-hover:text-brand-red" />
                                          </button>
                                        )}
                                      </div>
                                    )}

                                    {/* Materials Section */}
                                    {moduleContents.length > 0 && (
                                      <div className="space-y-3">
                                        <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">Materiais de Apoio</h4>
                                        <div className="grid gap-2">
                                          {moduleContents.map(content => (
                                            <button 
                                              key={content.id}
                                              onClick={() => {
                                                if (content.type === 'PDF') {
                                                  handleOpenPdf(content.url, content.title);
                                                } else {
                                                  window.open(content.url, '_blank');
                                                }
                                              }}
                                              className="w-full text-left flex items-center gap-3 p-3 rounded-md bg-zinc-900 border border-zinc-800 hover:border-zinc-700 hover:bg-zinc-800 transition-all group"
                                            >
                                              <div className="p-2 rounded-md bg-zinc-950 border border-zinc-800 group-hover:border-zinc-700">
                                                {content.type === 'PDF' ? (
                                                  <FileText className="w-4 h-4 text-red-400" />
                                                ) : (
                                                  <LinkIcon className="w-4 h-4 text-blue-400" />
                                                )}
                                              </div>
                                              <div className="flex-1">
                                                <p className="text-sm text-zinc-300 group-hover:text-white transition-colors">{content.title}</p>
                                                <p className="text-xs text-zinc-500">Adicionado em {new Date(content.createdAt).toLocaleDateString('pt-BR')}</p>
                                              </div>
                                            </button>
                                          ))}
                                        </div>
                                      </div>
                                    )}

                                    {/* Classes Section */}
                                    {!module.isOnline && (
                                      <div className="space-y-3">
                                        <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">
                                          Cronograma de Aulas ({moduleEvents.length})
                                        </h4>

                                        {moduleEvents.length === 0 ? (
                                          <div className="text-center py-8 border border-dashed border-zinc-800 rounded-lg">
                                            <p className="text-sm text-zinc-500">Nenhuma aula agendada para este módulo.</p>
                                          </div>
                                        ) : (
                                          <div className="grid gap-2">
                                            {moduleEvents.map(event => {
                                              const teacher = teachers.find(t => t.id === event.teacherId);
                                              const isCompleted = event.status === 'COMPLETED';

                                              return (
                                                <div 
                                                  key={event.id}
                                                  className={twMerge(
                                                    "flex items-center justify-between p-3 rounded-md border transition-all",
                                                    isCompleted 
                                                      ? "bg-emerald-950/10 border-emerald-900/30" 
                                                      : "bg-zinc-900 border-zinc-800"
                                                  )}
                                                >
                                                  <div className="flex items-center gap-4">
                                                    <div className={twMerge(
                                                      "w-10 h-10 rounded-full flex items-center justify-center border",
                                                      isCompleted
                                                        ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-500"
                                                        : "bg-zinc-800 border-zinc-700 text-zinc-400"
                                                    )}>
                                                      {isCompleted ? <CheckCircle className="w-5 h-5" /> : <Clock className="w-5 h-5" />}
                                                    </div>
                                                    <div>
                                                      <div className="flex items-center gap-2 mb-1">
                                                        <span className={twMerge(
                                                          "text-sm font-medium",
                                                          isCompleted ? "text-emerald-400" : "text-zinc-200"
                                                        )}>
                                                          {format(new Date(event.date + 'T00:00:00'), "dd 'de' MMMM", { locale: ptBR })}
                                                        </span>
                                                        <span className="text-xs text-zinc-500">
                                                          {event.startTime} - {event.endTime}
                                                        </span>
                                                      </div>
                                                      <div className="flex items-center gap-2 text-xs text-zinc-500">
                                                        <span>Prof. {teacher?.name || 'Não definido'}</span>
                                                        {event.isSubstitute && (
                                                          <span className="px-1.5 py-0.5 rounded bg-amber-500/10 text-amber-500 border border-amber-500/20">
                                                            Substituto
                                                          </span>
                                                        )}
                                                      </div>
                                                    </div>
                                                  </div>

                                                  <div className="flex items-center gap-2">
                                                    <span className={twMerge(
                                                      "text-xs px-2 py-1 rounded-full border",
                                                      event.status === 'COMPLETED' && "bg-emerald-500/10 text-emerald-500 border-emerald-500/20",
                                                      event.status === 'SCHEDULED' && "bg-blue-500/10 text-blue-500 border-blue-500/20",
                                                      event.status === 'CANCELED' && "bg-red-500/10 text-red-500 border-red-500/20",
                                                      event.status === 'RESCHEDULED' && "bg-amber-500/10 text-amber-500 border-amber-500/20",
                                                    )}>
                                                      {event.status === 'COMPLETED' && 'Concluída'}
                                                      {event.status === 'SCHEDULED' && 'Agendada'}
                                                      {event.status === 'CANCELED' && 'Cancelada'}
                                                      {event.status === 'RESCHEDULED' && 'Reagendada'}
                                                    </span>
                                                  </div>
                                                </div>
                                              );
                                            })}
                                          </div>
                                        )}
                                      </div>
                                    )}
                                  </div>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}

      {activeSubjects.length === 0 && (
        <div className="text-center py-12 border border-dashed border-zinc-800 rounded-lg bg-zinc-900/30">
          <AlertCircle className="w-8 h-8 text-zinc-600 mx-auto mb-3" />
          <h3 className="text-zinc-400 font-medium">Nenhuma disciplina encontrada</h3>
          <p className="text-zinc-500 text-sm mt-1">Cadastre disciplinas e tópicos para visualizar o planejamento.</p>
        </div>
      )}
      </div>
    </div>
  );
}

import React, { useState, useMemo } from 'react';
import { X, Check, Clock, AlertCircle } from 'lucide-react';
import { Class } from '../../../../../../types/class';
import { Teacher } from '../../../../../../types/teacher';
import { Subject, Topic } from '../../../../../../types/curriculum';
import { checkTeacherAvailability } from '../../../../../../utils/scheduler/ResourceValidator';
import { calculateMultiPeriodTimes } from '../../../../../../utils/scheduler/TimeCalculator';

interface AddManualAppointmentModalProps {
  selectedDate: string;
  classData: Class;
  teachers: Teacher[];
  subjects: Subject[];
  topics: Topic[];
  isHoliday?: boolean;
  onClose: () => void;
  onSave: (appointments: any[]) => void;
}

const normalizeText = (text: string | undefined | null) => {
  if (!text) return '';
  // Remove acentos, converte para minúsculo e remove espaços em branco extras
  return text.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
};

export const AddManualAppointmentModal: React.FC<AddManualAppointmentModalProps> = ({
  selectedDate,
  classData,
  teachers,
  subjects,
  topics,
  isHoliday = false,
  onClose,
  onSave
}) => {
  const dateObj = new Date(selectedDate + 'T12:00:00');
  const dayOfWeek = dateObj.getDay();
  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6 || isHoliday;

  const [startTime, setStartTime] = useState(isWeekend ? '' : classData.startTime);
  const [shift, setShift] = useState(isWeekend ? '' : classData.shift);

  const [numberOfPeriods, setNumberOfPeriods] = useState(1);
  const [isSameSubject, setIsSameSubject] = useState(true);

  const [globalSelection, setGlobalSelection] = useState({ subjectId: '', teacherId: '' });
  const [periodSelections, setPeriodSelections] = useState<Array<{ subjectId: string, teacherId: string }>>(
    Array(4).fill({ subjectId: '', teacherId: '' })
  );

  const intervalMinutes = classData.hasBreak ? classData.breakDuration : 0;
  const classDurationMinutes = useMemo(() => {
    const totalMinutes = classData.meetingDuration * 60;
    // O tempo total de encontro (ensino) é dividido pela quantidade de tempos selecionada
    return Math.floor(totalMinutes / numberOfPeriods);
  }, [classData.meetingDuration, numberOfPeriods]);

  const getAvailableTeachers = (subjectId: string) => {
    if (!shift || !subjectId) return { availableTeachers: [], unavailableTeachers: [] };

    const available: Teacher[] = [];
    const unavailable: { teacher: Teacher, details: string }[] = [];

    const selectedSubject = subjects.find(s => s.id === subjectId);

    // Normaliza os dados alvo
    const normTargetId = normalizeText(subjectId);
    const normTargetName = normalizeText(selectedSubject?.name);

    // Robust filtering for qualified teachers
    const qualifiedTeachers = teachers.filter(t => {
      // 1. Check if teacher is linked to this subject in the class curriculum (Pedagogical Planning)
      // Check both topic-level links and subject-level default teacher
      const isLinkedInCurriculum = 
        (selectedSubject?.defaultTeacherId === t.id) ||
        topics.some(topic => topic.subjectId === subjectId && topic.teacherId === t.id);

      if (isLinkedInCurriculum) return true;

      // 2. Fallback: Check if teacher has this subject in their profile (Flexible matching)
      const professorSubjects = (t as any).subjects || (t as any).materiasLecionadas || [];

      if (!professorSubjects || !Array.isArray(professorSubjects) || professorSubjects.length === 0) {
        return false;
      }

      // Helper for flexible matching
      const isMatch = (target: string, candidate: string) => {
        if (!target || !candidate) return false;
        return target === candidate || target.includes(candidate) || candidate.includes(target);
      };

      // Busca Bidirecional com Normalização
      return professorSubjects.some((sub: any) => {
        if (typeof sub === 'string') {
          const normSub = normalizeText(sub);
          return isMatch(normTargetId, normSub) || isMatch(normTargetName, normSub);
        }

        if (typeof sub === 'object' && sub !== null) {
          const normSubId = normalizeText(sub.id);
          const normSubName = normalizeText(sub.name || sub.title || sub.materia);

          // Cruza tudo: Testa o ID e Nome da aula contra o ID e Nome do professor, e vice-versa
          return isMatch(normTargetId, normSubId) || 
                 isMatch(normTargetId, normSubName) ||
                 isMatch(normTargetName, normSubId) ||
                 isMatch(normTargetName, normSubName);
        }

        return false;
      });
    });

    qualifiedTeachers.forEach(t => {
      const mockClassData = { ...classData, shift: shift as any };
      const availability = checkTeacherAvailability(t, selectedDate, mockClassData);

      if (availability.isAvailable) {
        available.push(t);
      } else {
        unavailable.push({ teacher: t, details: availability.details || 'Indisponível' });
      }
    });

    return { availableTeachers: available, unavailableTeachers: unavailable, hasQualifiedTeachers: qualifiedTeachers.length > 0 };
  };

  const handleSave = () => {
    if (!startTime || !shift) return;

    if (isSameSubject) {
      if (!globalSelection.subjectId || !globalSelection.teacherId) return;
    } else {
      for (let i = 0; i < numberOfPeriods; i++) {
        if (!periodSelections[i].subjectId || !periodSelections[i].teacherId) return;
      }
    }

    const periodsTimes = calculateMultiPeriodTimes(
      startTime, 
      numberOfPeriods, 
      classDurationMinutes,
      intervalMinutes
    );

    const appointmentsToSave = periodsTimes.map((period, index) => {
      const selection = isSameSubject ? globalSelection : periodSelections[index]; 

      return {
        id: Math.random().toString(36).substring(2, 15),
        date: selectedDate,
        startTime: period.startTime,
        endTime: period.endTime,
        shift: shift,
        teacherId: selection.teacherId,
        subjectId: selection.subjectId,
        periodNumber: period.periodNumber,
        isManual: true
      };
    });

    onSave(appointmentsToSave);
  };

  const renderSelectionFields = (index: number, isGlobal: boolean) => {
    const selection = isGlobal ? globalSelection : periodSelections[index];
    const setSelection = (newSelection: Partial<{ subjectId: string, teacherId: string }>) => {
      if (isGlobal) {
        setGlobalSelection(prev => ({ ...prev, ...newSelection }));
      } else {
        setPeriodSelections(prev => {
          const newArr = [...prev];
          newArr[index] = { ...newArr[index], ...newSelection };
          return newArr;
        });
      }
    };

    const { availableTeachers, unavailableTeachers, hasQualifiedTeachers } = getAvailableTeachers(selection.subjectId);

    return (
      <div className="space-y-4 p-4 bg-zinc-950/50 rounded-lg border border-zinc-800">
        {!isGlobal && <h4 className="text-sm font-bold text-white mb-2">{index + 1}º Tempo</h4>}
        <div>
          <label className="text-xs font-bold text-zinc-500 uppercase block mb-1">Disciplina</label>
          <select
            value={selection.subjectId}
            onChange={(e) => {
              setSelection({ subjectId: e.target.value, teacherId: '' });
            }}
            className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-2 text-white text-sm focus:border-brand-red focus:ring-1 focus:ring-brand-red outline-none"
          >
            <option value="">Selecione a disciplina...</option>
            {subjects.map(s => (
              <option key={s.id} value={s.id}>{s.name}</option>
            ))}
          </select>
        </div>

        {shift && selection.subjectId && (
          <div className="space-y-2 pt-2 border-t border-zinc-800">
            <label className="text-sm font-medium text-zinc-300 block">Professor</label>

            <div className="border border-zinc-700 p-2 rounded bg-zinc-900">
              {!hasQualifiedTeachers ? (
                <div className="text-zinc-500 text-xs text-center py-4 italic">
                  Nenhum professor cadastrado e habilitado para esta disciplina.
                </div>
              ) : (
                <>
                  {availableTeachers.length > 0 && (
                    <div className="mb-3">
                      <div className="text-xs font-bold text-emerald-500 uppercase mb-1 flex items-center gap-1">
                        ✅ Professores Disponíveis
                      </div>
                      <div className="space-y-1">
                        {availableTeachers.map(teacher => (
                          <button
                            key={teacher.id}
                            onClick={() => setSelection({ teacherId: teacher.id })}
                            className={`w-full text-left px-2 py-1.5 rounded text-sm transition-colors flex items-center justify-between ${
                              selection.teacherId === teacher.id 
                                ? 'bg-emerald-900/30 text-emerald-200 border border-emerald-800' 
                                : 'text-zinc-300 hover:bg-zinc-800'
                            }`}
                          >
                            <span>{teacher.name}</span>
                            {selection.teacherId === teacher.id && <Check className="w-3 h-3" />}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}

                  {unavailableTeachers.length > 0 && (
                    <div>
                      <div className="text-xs font-bold text-red-500 uppercase mb-1 flex items-center gap-1">
                        ❌ Professores Indisponíveis
                      </div>
                      <div className="space-y-1">
                        {unavailableTeachers.map(({ teacher, details }) => (
                          <div
                            key={teacher.id}
                            className="w-full text-left px-2 py-1.5 rounded text-sm flex items-center justify-between opacity-75 bg-zinc-950/50 border border-zinc-800"
                          >
                            <span className="text-zinc-400">{teacher.name}</span>
                            <span className="text-[10px] text-red-400 max-w-[50%] text-right truncate" title={details}>{details}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </>
              )}
            </div>
          </div>
        )}
      </div>
    );
  };

  const isSaveDisabled = () => {
    if (!startTime || !shift) return true;
    if (isSameSubject) {
      return !globalSelection.subjectId || !globalSelection.teacherId;
    } else {
      for (let i = 0; i < numberOfPeriods; i++) {
        if (!periodSelections[i].subjectId || !periodSelections[i].teacherId) return true;
      }
      return false;
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50">
          <h3 className="text-lg font-bold text-white flex items-center gap-2">
            Adicionar Agendamento
          </h3>
          <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 space-y-6 max-h-[75vh] overflow-y-auto scrollbar-thin scrollbar-thumb-zinc-700">
          <div className="space-y-4">
            <div>
              <label className="text-xs font-bold text-zinc-500 uppercase block mb-1">Data</label>
              <div className="text-sm font-medium text-white bg-zinc-800/50 p-2 rounded border border-zinc-700">
                {dateObj.toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase block mb-1">Turno</label>
                {isWeekend ? (
                  <select
                    value={shift}
                    onChange={(e) => setShift(e.target.value)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-2 text-white text-sm focus:border-brand-red focus:ring-1 focus:ring-brand-red outline-none"
                  >
                    <option value="">Selecione...</option>
                    <option value="MORNING">Manhã</option>
                    <option value="AFTERNOON">Tarde</option>
                    <option value="NIGHT">Noite</option>
                  </select>
                ) : (
                  <div className="text-sm font-medium text-zinc-300 bg-zinc-800/30 p-2 rounded border border-zinc-800">
                    {shift === 'MORNING' ? 'Manhã' : shift === 'AFTERNOON' ? 'Tarde' : 'Noite'}
                  </div>
                )}
              </div>
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase block mb-1">Horário de Início</label>
                {isWeekend ? (
                  <input
                    type="time"
                    value={startTime}
                    onChange={(e) => setStartTime(e.target.value)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-2 text-white text-sm focus:border-brand-red focus:ring-1 focus:ring-brand-red outline-none"
                  />
                ) : (
                  <div className="text-sm font-medium text-zinc-300 bg-zinc-800/30 p-2 rounded border border-zinc-800 flex items-center gap-2">
                    <Clock className="w-4 h-4" />
                    {startTime}
                  </div>
                )}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs font-bold text-zinc-500 uppercase block mb-1">Quantos tempos de aula?</label>
                <input
                  type="number"
                  min="1"
                  max="4"
                  value={numberOfPeriods}
                  onChange={(e) => setNumberOfPeriods(Math.max(1, Math.min(4, parseInt(e.target.value) || 1)))}
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-lg p-2 text-white text-sm focus:border-brand-red focus:ring-1 focus:ring-brand-red outline-none"
                />
              </div>
            </div>

            <div className="flex items-start gap-2 text-xs text-zinc-400 bg-zinc-950/50 p-3 rounded-lg border border-zinc-800">
              <AlertCircle className="w-4 h-4 text-brand-red shrink-0 mt-0.5" />
              <p>O sistema aplicará os intervalos de acordo com a configuração da turma ({intervalMinutes} minutos de intervalo).</p>
            </div>

            {numberOfPeriods > 1 && (
              <div className="flex items-center gap-3 p-3 bg-zinc-800/30 rounded-lg border border-zinc-700">
                <label className="text-sm font-medium text-white flex-1 cursor-pointer">
                  Usar a mesma disciplina/professor para todos os tempos?
                </label>
                <div className="flex items-center gap-2">
                  <button
                    onClick={() => setIsSameSubject(true)}
                    className={`px-3 py-1 text-xs font-medium rounded-md transition-colors ${isSameSubject ? 'bg-brand-red text-white' : 'bg-zinc-800 text-zinc-400 hover:text-white'}`}
                  >
                    Sim
                  </button>
                  <button
                    onClick={() => setIsSameSubject(false)}
                    className={`px-3 py-1 text-xs font-medium rounded-md transition-colors ${!isSameSubject ? 'bg-brand-red text-white' : 'bg-zinc-800 text-zinc-400 hover:text-white'}`}
                  >
                    Não
                  </button>
                </div>
              </div>
            )}

            <div className="space-y-4">
              {isSameSubject ? (
                renderSelectionFields(0, true)
              ) : (
                Array.from({ length: numberOfPeriods }).map((_, index) => (
                  <React.Fragment key={index}>
                    {renderSelectionFields(index, false)}
                  </React.Fragment>
                ))
              )}
            </div>

          </div>
        </div>

        <div className="p-4 border-t border-zinc-800 bg-zinc-950/50 flex justify-end gap-3">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-zinc-400 hover:text-white transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={handleSave}
            disabled={isSaveDisabled()}
            className="flex items-center gap-2 px-4 py-2 bg-brand-red text-white rounded-lg hover:bg-red-600 font-medium shadow-lg shadow-brand-red/20 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Check className="w-4 h-4" />
            Salvar Agendamento
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { ClassScheduleEvent, ScheduleGap, ScheduleException, ExceptionType } from '../../../../../../types/schedule';
import { Teacher } from '../../../../../../types/teacher';
import { Subject, Topic } from '../../../../../../types/curriculum';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Clock, User, AlertTriangle, ChevronDown, ChevronUp, LayoutGrid, List, Edit2, X, Check, CheckCircle, Loader2, BookOpen } from 'lucide-react';

import { checkTeacherAvailability } from '../../../../../../utils/scheduler/ResourceValidator';

import { Class } from '../../../../../../types/class';

import { AddManualAppointmentModal } from './AddManualAppointmentModal';

interface SchedulePreviewProps {
  classData: Class;
  events: ClassScheduleEvent[];
  gaps: ScheduleGap[];
  teachers: Teacher[];
  subjects: Subject[];
  topics: Topic[];
  onAddException?: (exception: ScheduleException) => void;
  onAddManualAppointment?: (appointment: any) => void;
  onDeleteAppointment?: (eventId: string) => void;
  onUpdateEventStatus?: (eventIds: string[], status: 'COMPLETED' | 'SCHEDULED') => void;
}

const normalizeText = (text: string | undefined | null) => {
  if (!text) return '';
  // Remove acentos, converte para minúsculo e remove espaços em branco extras
  return text.normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
};

export const SchedulePreview: React.FC<SchedulePreviewProps> = ({ classData, events, gaps, teachers, subjects, topics, onAddException, onAddManualAppointment, onDeleteAppointment, onUpdateEventStatus }) => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'month' | 'week'>('month');
  const [expandedEventId, setExpandedEventId] = useState<string | null>(null);
  const [editingEvent, setEditingEvent] = useState<ClassScheduleEvent | null>(null);
  const [selectedSubstituteId, setSelectedSubstituteId] = useState('');
  const [actionType, setActionType] = useState<ExceptionType>('SUBSTITUTION');
  const [forceConfirmData, setForceConfirmData] = useState<{ teacherId: string, details: string } | null>(null);
  const [selectedDateForManual, setSelectedDateForManual] = useState<string | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

  const [completionModalData, setCompletionModalData] = useState<{ shift: string, events: ClassScheduleEvent[] } | null>(null);
  const [selectedEventIds, setSelectedEventIds] = useState<string[]>([]);
  const [isUpdatingStatus, setIsUpdatingStatus] = useState(false);

  const todayString = new Date(new Date().getTime() - new Date().getTimezoneOffset() * 60000).toISOString().split('T')[0];

  // Sync selected substitute when editing event changes
  useEffect(() => {
    if (editingEvent) {
      setSelectedSubstituteId(editingEvent.teacherId || '');
      setActionType('SUBSTITUTION'); // Reset to default
      setForceConfirmData(null);
    }
  }, [editingEvent]);

  // Group teachers by availability
  const { availableTeachers, unavailableTeachers, hasQualifiedTeachers } = useMemo(() => {
    if (!editingEvent) return { availableTeachers: [], unavailableTeachers: [], hasQualifiedTeachers: false };

    const available: Teacher[] = [];
    const unavailable: { teacher: Teacher, details: string }[] = [];

    // 1. CAPTURA AS INFORMAÇÕES DA AULA QUE ESTÁ SENDO EDITADA
    const targetSubjectId = editingEvent.subjectId || '';
    const targetSubject = subjects.find(s => s.id === targetSubjectId);
    const targetSubjectName = (editingEvent as any).subjectName || (editingEvent as any).title || (editingEvent as any).subject?.name || targetSubject?.name || '';

    // 2. Normaliza os dados alvo
    const normTargetId = normalizeText(targetSubjectId);
    const normTargetName = normalizeText(targetSubjectName);

    // 3. VERIFICAÇÃO DE SEGURANÇA
    if (!normTargetId && !normTargetName) return { availableTeachers: [], unavailableTeachers: [], hasQualifiedTeachers: false };

    // Robust filtering for qualified teachers
    const qualifiedTeachers = teachers.filter(t => {
      const professorSubjects = (t as any).subjects || (t as any).materiasLecionadas || [];

      if (!professorSubjects || !Array.isArray(professorSubjects) || professorSubjects.length === 0) {
        return false;
      }

      // 4. BUSCA BIDIRECIONAL COM NORMALIZAÇÃO
      return professorSubjects.some((sub: any) => {
        if (typeof sub === 'string') {
          const normSub = normalizeText(sub);
          return (normTargetId && normSub === normTargetId) || 
                 (normTargetName && normSub === normTargetName) ||
                 (normTargetId && normSub.includes(normTargetId)) ||
                 (normTargetName && normSub.includes(normTargetName));
        }

        if (typeof sub === 'object' && sub !== null) {
           const normSubId = normalizeText(sub.id);
           const normSubName = normalizeText(sub.name || sub.title || sub.materia);

           // Cruza tudo: Testa o ID da aula contra o ID e Nome do professor, e vice-versa
           return (normTargetId && (normSubId === normTargetId || normSubName === normTargetId || normSubId.includes(normTargetId) || normSubName.includes(normTargetId))) || 
                  (normTargetName && (normSubId === normTargetName || normSubName === normTargetName || normSubId.includes(normTargetName) || normSubName.includes(normTargetName)));
        }

        return false;
      });
    });

    qualifiedTeachers.forEach(t => {
      // Use the event's shift if available, otherwise fallback to classData.shift
      const effectiveClassData = {
        ...classData,
        shift: editingEvent.shift || classData.shift
      };
      const availability = checkTeacherAvailability(t, editingEvent.date, effectiveClassData);
      if (availability.isAvailable) {
        available.push(t);
      } else {
        unavailable.push({ teacher: t, details: availability.details || 'Indisponível' });
      }
    });

    return { availableTeachers: available, unavailableTeachers: unavailable, hasQualifiedTeachers: qualifiedTeachers.length > 0 };
  }, [teachers, editingEvent, subjects, classData]);

  const handleSelectTeacher = (teacherId: string, isAvailable?: boolean, details?: string) => {
    if (!teacherId) {
      setSelectedSubstituteId('');
      setForceConfirmData(null);
      return;
    }

    // If it's the current teacher (if any), just select it
    if (teacherId === editingEvent?.teacherId) {
      setSelectedSubstituteId(teacherId);
      setForceConfirmData(null);
      return;
    }

    // Optimization: use passed values if present
    if (isAvailable !== undefined) {
      if (isAvailable) {
        setSelectedSubstituteId(teacherId);
        setForceConfirmData(null);
      } else {
        setForceConfirmData({ 
          teacherId, 
          details: details || 'Indisponível' 
        });
      }
      return;
    }

    const teacher = teachers.find(t => t.id === teacherId);
    if (!teacher || !editingEvent) return;

    const effectiveClassData = {
      ...classData,
      shift: editingEvent.shift || classData.shift
    };
    const availability = checkTeacherAvailability(teacher, editingEvent.date, effectiveClassData);

    if (availability.isAvailable) {
      setSelectedSubstituteId(teacherId);
      setForceConfirmData(null);
    } else {
      setForceConfirmData({ 
        teacherId, 
        details: availability.details || 'Indisponível' 
      });
    }
  };

  const confirmForceTeacher = () => {
    if (forceConfirmData) {
      setSelectedSubstituteId(forceConfirmData.teacherId);
      setForceConfirmData(null);
    }
  };

  // Determine the initial date based on the first event or current date
  const initialDate = useMemo(() => {
    if (events.length > 0) {
      const sortedDates = [...events].sort((a, b) => a.date.localeCompare(b.date));
      const firstDate = new Date(sortedDates[0].date + 'T00:00:00');
      return new Date(firstDate.getFullYear(), firstDate.getMonth(), 1);
    }
    return new Date();
  }, [events]);

  const [currentDate, setCurrentDate] = useState(initialDate);

  // Helper to get days in month
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month + 1, 0).getDate();
  };

  // Helper to get day of week for the 1st of the month (0-6, 0 is Sunday)
  const getFirstDayOfMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month, 1).getDay();
  };

  // Helper to get start of the week for the current date
  const getStartOfWeek = (date: Date) => {
    const day = date.getDay();
    const diff = date.getDate() - day; // Adjust when day is Sunday
    return new Date(date.getFullYear(), date.getMonth(), diff);
  };

  const handlePrev = () => {
    if (viewMode === 'month') {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    } else {
      const newDate = new Date(currentDate);
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const handleNext = () => {
    if (viewMode === 'month') {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    } else {
      const newDate = new Date(currentDate);
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    }
  };

  const formatHeaderDate = (date: Date) => {
    if (viewMode === 'month') {
      return date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    } else {
      const start = getStartOfWeek(date);
      const end = new Date(start);
      end.setDate(end.getDate() + 6);
      const startStr = start.toLocaleDateString('pt-BR', { day: 'numeric', month: 'short' });
      const endStr = end.toLocaleDateString('pt-BR', { day: 'numeric', month: 'short', year: 'numeric' });
      return `${startStr} - ${endStr}`;
    }
  };

  // Data Getters
  const getTeacherName = (teacherId: string) => {
    const teacher = teachers.find(t => t.id === teacherId);
    return teacher ? teacher.name : 'Professor não atribuído';
  };

  const getSubject = (subjectId: string) => {
    return subjects.find(s => s.id === subjectId);
  };

  const getModuleName = (topicId: string, moduleId: string) => {
    const topic = topics.find(t => t.id === topicId);
    if (!topic) return 'Tópico desconhecido';
    const module = topic.modules?.find(m => m.id === moduleId);
    return module ? module.name : 'Módulo desconhecido';
  };

  const handleSaveCompletion = async () => {
    if (!completionModalData || !onUpdateEventStatus) return;
    setIsUpdatingStatus(true);
    try {
      const allIds = completionModalData.events.map(e => e.id);
      const idsToComplete = selectedEventIds;
      const idsToRevert = allIds.filter(id => !selectedEventIds.includes(id));

      if (idsToComplete.length) onUpdateEventStatus(idsToComplete, 'COMPLETED');
      if (idsToRevert.length) onUpdateEventStatus(idsToRevert, 'SCHEDULED');

      setCompletionModalData(null);
    } catch (error) {
      console.error("Erro ao atualizar status:", error);
    } finally {
      setIsUpdatingStatus(false);
    }
  };

  const handleSaveEdit = () => {
    if (editingEvent && onAddException) {
      const newException: ScheduleException = {
        id: Date.now().toString(),
        eventId: editingEvent.id,
        date: editingEvent.date,
        meetingNumber: editingEvent.meetingNumber,
        originalTeacherId: editingEvent.teacherId,
        substituteTeacherId: actionType === 'CANCELLATION' ? undefined : selectedSubstituteId,
        type: actionType
      };
      onAddException(newException);
      setEditingEvent(null);
      setSelectedSubstituteId('');
      setActionType('SUBSTITUTION');
    } else {
        // If no change or no handler, just close
        setEditingEvent(null);
    }
  };

  // Generate Grid Cells
  const calendarCells = useMemo(() => {
    const cells = [];

    if (viewMode === 'month') {
      const year = currentDate.getFullYear();
      const month = currentDate.getMonth();
      const daysInMonth = getDaysInMonth(currentDate);
      const firstDay = getFirstDayOfMonth(currentDate);

      // Empty cells for previous month
      for (let i = 0; i < firstDay; i++) {
        cells.push({ type: 'empty', key: `empty-${i}` });
      }

      // Days of current month
      for (let day = 1; day <= daysInMonth; day++) {
        const dateString = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        const dayEvents = events.filter(e => e.date === dateString);
        const dayGaps = gaps.filter(g => g.date === dateString);

        cells.push({
          type: 'day',
          day,
          dateString,
          events: dayEvents,
          gaps: dayGaps,
          key: dateString
        });
      }
    } else {
      // Week View
      const startOfWeek = getStartOfWeek(currentDate);
      for (let i = 0; i < 7; i++) {
        const date = new Date(startOfWeek);
        date.setDate(date.getDate() + i);
        const year = date.getFullYear();
        const month = date.getMonth() + 1;
        const day = date.getDate();
        const dateString = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        const dayEvents = events.filter(e => e.date === dateString);
        const dayGaps = gaps.filter(g => g.date === dateString);

        cells.push({
          type: 'day',
          day,
          dateString,
          events: dayEvents,
          gaps: dayGaps,
          key: dateString
        });
      }
    }

    return cells;
  }, [currentDate, events, gaps, viewMode]);

  return (
    <>
      <div className="bg-zinc-900 border border-zinc-800 rounded-xl overflow-hidden shadow-sm animate-in fade-in duration-500">
        {/* Header */}
        <div className="flex flex-col sm:flex-row items-center justify-between p-4 border-b border-zinc-800 bg-zinc-900 gap-4">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-bold text-white capitalize flex items-center gap-2">
              <CalendarIcon className="w-5 h-5 text-brand-red" />
              {formatHeaderDate(currentDate)}
            </h2>
            <div className="flex items-center gap-1 bg-zinc-800 rounded-lg p-1 border border-zinc-700">
              <button
                onClick={() => {
                  if (viewMode === 'week') {
                    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth(), 1));
                    setViewMode('month');
                  }
                }}
                className={`p-1.5 rounded-md transition-all ${viewMode === 'month' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-zinc-200'}`}
                title="Visualização Mensal"
              >
                <LayoutGrid className="w-4 h-4" />
              </button>
              <button
                onClick={() => {
                  if (viewMode === 'month') {
                    const today = new Date();
                    if (currentDate.getMonth() === today.getMonth() && currentDate.getFullYear() === today.getFullYear()) {
                      setCurrentDate(today);
                    }
                    setViewMode('week');
                  }
                }}
                className={`p-1.5 rounded-md transition-all ${viewMode === 'week' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-400 hover:text-zinc-200'}`}
                title="Visualização Semanal"
              >
                <List className="w-4 h-4" />
              </button>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={handlePrev}
              className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-400 hover:text-white transition-colors border border-transparent hover:border-zinc-700"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <button 
              onClick={() => setCurrentDate(new Date())}
              className="px-3 py-1.5 text-xs font-bold uppercase tracking-wider text-zinc-400 hover:text-white border border-zinc-800 hover:border-zinc-600 rounded-lg transition-colors"
            >
              Hoje
            </button>
            <button 
              onClick={handleNext}
              className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-400 hover:text-white transition-colors border border-transparent hover:border-zinc-700"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* Weekday Headers */}
        <div className="grid grid-cols-7 border-b border-zinc-800 bg-zinc-950">
          {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(day => (
            <div key={day} className="py-3 text-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
              {day}
            </div>
          ))}
        </div>

        {/* Calendar Grid */}
        <div className={`grid grid-cols-7 bg-zinc-900 ${viewMode === 'month' ? 'auto-rows-fr' : 'h-[600px]'}`}>
          {calendarCells.map((cell: any) => {
            if (cell.type === 'empty') {
              return <div key={cell.key} className="min-h-[140px] border-b border-r border-zinc-800/50 bg-zinc-950/30"></div>;
            }

            const isToday = new Date().toISOString().split('T')[0] === cell.dateString;
            const dayGaps = cell.gaps || [];
            const dayEvents = cell.events || [];
            const holidayGap = dayGaps.find((g: ScheduleGap) => g.reason === 'HOLIDAY');

            // Timeline construction
            const timeline = holidayGap 
              ? [] 
              : [
                  ...dayEvents.map((e: ClassScheduleEvent) => ({ type: 'event' as const, data: e, startTime: e.startTime, shift: e.shift || classData?.shift || 'MORNING' })),
                  ...dayGaps.filter((g: ScheduleGap) => {
                    if (!g.startTime || !g.endTime) return false;
                    // Oculta o gap se houver um evento que se sobreponha a ele (mesmo horário ou dentro do intervalo)
                    const hasOverlappingEvent = dayEvents.some(e => 
                      (e.startTime < g.endTime! && e.endTime > g.startTime!)
                    );
                    return !hasOverlappingEvent;
                  }).map((g: ScheduleGap) => ({ type: 'gap' as const, data: g, startTime: g.startTime!, shift: classData?.shift || 'MORNING' }))
                ].sort((a, b) => a.startTime.localeCompare(b.startTime));

            const eventsByShift = timeline.reduce((acc, item) => {
              const shiftName = item.shift === 'MORNING' ? 'Manhã' : item.shift === 'AFTERNOON' ? 'Tarde' : 'Noite';
              if (!acc[shiftName]) acc[shiftName] = [];
              acc[shiftName].push(item);
              return acc;
            }, {} as Record<string, any[]>);

            const hasEvents = dayEvents.length > 0;

            return (
              <div 
                key={cell.key} 
                className={`
                  p-2 border-b border-r border-zinc-800 transition-colors relative group overflow-y-auto scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent
                  ${viewMode === 'month' ? 'min-h-[140px]' : 'h-full'}
                  ${isToday ? 'bg-brand-red/5' : 'hover:bg-zinc-800/30'}
                `}
              >
                <div className="flex justify-between items-start mb-2 sticky top-0 bg-inherit z-10 pb-1">
                  <span 
                    className={`
                      text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full
                      ${isToday ? 'bg-brand-red text-white' : 'text-zinc-400 group-hover:text-zinc-200'}
                    `}
                  >
                    {cell.day}
                  </span>
                </div>

                <div className="space-y-2">
                  {/* Holiday Display */}
                  {holidayGap && (
                    <div className="h-full flex flex-col items-center justify-center py-4">
                      <div className="w-full p-3 rounded-lg border border-dashed border-zinc-700 bg-zinc-800/30 text-zinc-500 flex flex-col items-center justify-center text-center gap-2">
                        <CalendarIcon className="w-5 h-5 opacity-50" />
                        <span className="text-xs font-medium">{holidayGap.description}</span>
                      </div>
                    </div>
                  )}

                  {/* Timeline Display (Events + Gaps) grouped by shift */}
                  {!holidayGap && Object.entries(eventsByShift).map(([shiftName, shiftItems], shiftIndex) => {
                    const shiftEvents = shiftItems.filter(i => i.type === 'event').map(i => i.data as ClassScheduleEvent);
                    const firstEvent = shiftEvents[0];
                    const meetingNumber = firstEvent?.meetingNumber;
                    const isOverflow = firstEvent?.isOverflow;
                    const isShiftCompleted = shiftEvents.length > 0 && shiftEvents.every(e => e.status === 'COMPLETED');

                    return (
                      <div key={shiftName} className="mb-4">
                        {/* Divisor Visual para múltiplos turnos no mesmo dia */}
                        {shiftIndex > 0 && <div className="border-t border-dashed border-zinc-700 my-3"></div>}

                        {/* Cabeçalho do Turno com o Número do Encontro */}
                        <div className="flex justify-between items-center mb-2">
                          <span className="text-xs font-bold text-zinc-500 uppercase">{shiftName}</span>
                          <div className="flex items-center gap-2">
                            {meetingNumber && (
                              <span className={`
                                text-[10px] font-bold px-1.5 py-0.5 rounded border uppercase tracking-wide
                                ${isShiftCompleted 
                                  ? 'bg-emerald-600 text-white border-emerald-500' 
                                  : isOverflow 
                                    ? 'bg-red-600 text-white border-red-500' 
                                    : 'text-brand-red bg-brand-red/10 border-brand-red/20'}
                              `}>
                                {isOverflow 
                                  ? `Encontro #${meetingNumber} (EXTRA)` 
                                  : `Encontro #${meetingNumber}`}
                              </span>
                            )}
                            {onUpdateEventStatus && (
                              <button 
                                onClick={(e) => {
                                  e.stopPropagation();
                                  setCompletionModalData({ shift: shiftName, events: shiftEvents });
                                  setSelectedEventIds(shiftEvents.filter(e => e.status === 'COMPLETED').map(e => e.id));
                                }}
                                className={`${isShiftCompleted ? 'text-emerald-500' : 'text-zinc-500'} hover:text-emerald-500 transition-colors`}
                                title="Concluir Aulas"
                              >
                                <CheckCircle className="w-4 h-4" />
                              </button>
                            )}
                          </div>
                        </div>

                        {/* Renderiza os eventos deste turno */}
                        <div className="space-y-2">
                          {shiftItems.map((item, index) => {
                            if (item.type === 'event') {
                              const event = item.data as ClassScheduleEvent;
                              const subject = getSubject(event.subjectId);
                              const isExpanded = expandedEventId === event.id;
                              const borderColor = subject?.color || '#52525b';

                              const isOverflow = event.isOverflow;

                              return (
                                <React.Fragment key={event.id}>
                                  <div 
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setExpandedEventId(isExpanded ? null : event.id);
                                    }}
                                    className={`
                                      rounded-lg border-l-4 transition-all cursor-pointer overflow-hidden
                                      ${isExpanded ? 'bg-zinc-800 shadow-lg ring-1 ring-zinc-700 z-20 relative' : 'bg-zinc-800/50 hover:bg-zinc-800'}
                                      ${isOverflow ? 'border-red-500 bg-red-900/20' : ''}
                                      ${event.status === 'COMPLETED' ? 'border-emerald-500 bg-emerald-900/10 opacity-80' : ''}
                                    `}
                                    style={{ borderLeftColor: event.status === 'COMPLETED' ? '#10b981' : borderColor }}
                                  >
                                    {/* Card Header */}
                                    <div className="p-2">
                                      <div className="flex justify-between items-center mb-1">
                                        <div className="text-[9px] font-bold text-zinc-500 uppercase tracking-wider">
                                          {index + 1}º Tempo
                                        </div>
                                        <div className="flex gap-1">
                                          {event.status === 'COMPLETED' && (
                                            <span className="text-[8px] font-bold text-emerald-500 bg-emerald-950/50 px-1 py-0.5 rounded border border-emerald-900/50 uppercase tracking-wider flex items-center gap-1">
                                              <CheckCircle className="w-2 h-2" />
                                              CONCLUÍDO
                                            </span>
                                          )}
                                          {event.isSubstitute && (
                                            <span className="text-[8px] font-bold text-black bg-yellow-500 px-1 py-0.5 rounded border border-yellow-600 uppercase tracking-wider flex items-center gap-1">
                                              SUBSTITUIÇÃO
                                            </span>
                                          )}
                                          {isOverflow && (
                                            <span className="text-[8px] font-bold text-red-400 bg-red-950/50 px-1 py-0.5 rounded border border-red-900/50 uppercase tracking-wider flex items-center gap-1">
                                              <AlertTriangle className="w-2 h-2" />
                                              ⚠️ Além do limite da turma
                                            </span>
                                          )}
                                        </div>
                                      </div>
                                      <div className="flex justify-between items-start gap-2">
                                        <div className="flex-1 min-w-0">
                                          <div className="flex items-center gap-1.5 text-[10px] font-bold text-zinc-400 mb-0.5">
                                            <Clock className="w-3 h-3" />
                                            <span>{event.startTime} - {event.endTime}</span>
                                          </div>
                                          <div className="font-bold text-xs text-zinc-200 truncate leading-tight">
                                            {subject?.name || 'Disciplina Desconhecida'}
                                          </div>
                                        </div>
                                        <div className="flex items-center gap-1">
                                          <button
                                            onClick={(e) => {
                                              e.stopPropagation();
                                              const newParams = new URLSearchParams(searchParams);
                                              newParams.set('tab', 'PLANNING');
                                              if (event.subjectId) newParams.set('subjectId', event.subjectId);
                                              if (event.topicId) newParams.set('topicId', event.topicId);
                                              if (event.moduleId) newParams.set('moduleId', event.moduleId);
                                              setSearchParams(newParams);
                                            }}
                                            className="p-1 text-zinc-500 hover:text-brand-red transition-colors"
                                            title="Ver materiais no Planejamento"
                                          >
                                            <BookOpen className="w-3 h-3" />
                                          </button>
                                          <div className="text-zinc-500">
                                            {isExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                                          </div>
                                        </div>
                                      </div>
                                    </div>

                                    {/* Card Details */}
                                    {isExpanded && (
                                      <div className="px-2 pb-2 pt-0 space-y-2 animate-in slide-in-from-top-1 duration-200">
                                        <div className="h-px bg-zinc-700/50 w-full my-1" />

                                        <div>
                                          <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-0.5">Módulo</span>
                                          <p className="text-[11px] text-zinc-300 leading-tight">
                                            {getModuleName(event.topicId, event.moduleId)}
                                          </p>
                                        </div>

                                        <div>
                                          <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-0.5">Professor</span>
                                          <div className="flex items-center gap-1.5 text-[11px] text-zinc-300">
                                            <User className="w-3 h-3 text-zinc-500" />
                                            <span>{getTeacherName(event.teacherId)}</span>
                                          </div>
                                        </div>

                                        {!event.teacherId && (
                                          <div className="flex items-center gap-1.5 text-[10px] text-yellow-500 bg-yellow-900/20 p-1.5 rounded border border-yellow-700/30 mt-1">
                                            <AlertTriangle className="w-3 h-3" />
                                            <span>Professor não alocado</span>
                                          </div>
                                        )}

                                        <button
                                          onClick={(e) => {
                                            e.stopPropagation();
                                            setEditingEvent(event);
                                          }}
                                          className="w-full flex items-center justify-center gap-1.5 mt-2 py-1.5 bg-zinc-700 hover:bg-zinc-600 text-zinc-200 text-[10px] font-bold uppercase rounded transition-colors"
                                        >
                                          <Edit2 className="w-3 h-3" />
                                          Gerenciar Encontro
                                        </button>
                                      </div>
                                    )}
                                  </div>

                                  {/* Interval Divider */}
                                  {index === 0 && shiftItems.length > 1 && (
                                    <div className="flex items-center gap-2 my-2 opacity-50">
                                      <div className="h-px bg-zinc-700 border-t border-dashed border-zinc-600 flex-1"></div>
                                      <span className="text-[9px] text-zinc-500 font-medium whitespace-nowrap">Intervalo (15 min)</span>
                                      <div className="h-px bg-zinc-700 border-t border-dashed border-zinc-600 flex-1"></div>
                                    </div>
                                  )}
                                </React.Fragment>
                              );
                            } else {
                              // Gap Rendering
                              const gap = item.data as ScheduleGap;
                              return (
                                <React.Fragment key={`gap-${index}`}>
                                  <div className="rounded-lg border border-dashed border-zinc-700 bg-zinc-800/30 p-2">
                                    <div className="text-[9px] font-bold text-zinc-500 uppercase tracking-wider mb-1">
                                      {index + 1}º Tempo
                                    </div>
                                    <div className="flex flex-col gap-1">
                                      <div className="flex items-center gap-1.5 text-[10px] font-bold text-zinc-500">
                                        <Clock className="w-3 h-3" />
                                        <span>{gap.startTime} - {gap.endTime}</span>
                                      </div>
                                      <div className="flex items-center gap-1.5 text-[10px] text-zinc-400">
                                        <AlertTriangle className="w-3 h-3" />
                                        <span className="leading-tight">{gap.description}</span>
                                      </div>
                                    </div>
                                  </div>

                                  {/* Interval Divider */}
                                  {index === 0 && shiftItems.length > 1 && (
                                    <div className="flex items-center gap-2 my-2 opacity-50">
                                      <div className="h-px bg-zinc-700 border-t border-dashed border-zinc-600 flex-1"></div>
                                      <span className="text-[9px] text-zinc-500 font-medium whitespace-nowrap">Intervalo (15 min)</span>
                                      <div className="h-px bg-zinc-700 border-t border-dashed border-zinc-600 flex-1"></div>
                                    </div>
                                  )}
                                </React.Fragment>
                              );
                            }
                          })}
                        </div>
                      </div>
                    );
                  })}

                  {/* Add Manual Appointment Button */}
                  {!hasEvents && (
                    <button
                      onClick={() => setSelectedDateForManual(cell.dateString)}
                      className="w-full mt-2 flex items-center justify-center gap-1.5 py-2 bg-zinc-800/50 hover:bg-zinc-700/80 text-zinc-400 hover:text-white text-[10px] font-bold uppercase tracking-wider rounded border border-dashed border-zinc-700 transition-colors"
                    >
                      + Adicionar Agendamento
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Edit Modal */}
      {editingEvent && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50">
              <h3 className="text-lg font-bold text-white flex items-center gap-2">
                <Edit2 className="w-5 h-5 text-brand-red" />
                Gerenciar Encontro
              </h3>
              <button 
                onClick={() => setEditingEvent(null)}
                className="text-zinc-500 hover:text-white transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <div className="p-6 space-y-6">
              {/* Event Details */}
              <div className="bg-zinc-800/50 rounded-lg p-4 space-y-3 border border-zinc-800">
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-zinc-500 uppercase">Data</span>
                  <span className="text-sm font-medium text-white">
                    {new Date(editingEvent.date + 'T00:00:00').toLocaleDateString('pt-BR', { weekday: 'long', day: 'numeric', month: 'long' })}
                  </span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-zinc-500 uppercase">Horário</span>
                  <span className="text-sm font-medium text-white flex items-center gap-1.5">
                    <Clock className="w-4 h-4 text-zinc-400" />
                    {editingEvent.startTime} - {editingEvent.endTime}
                  </span>
                </div>
                <div className="flex justify-between items-center">
                  <span className="text-xs font-bold text-zinc-500 uppercase">Disciplina</span>
                  <span className="text-sm font-medium text-white text-right">
                    {getSubject(editingEvent.subjectId)?.name}
                  </span>
                </div>
                <div className="pt-2 border-t border-zinc-700/50 mt-2">
                  <p className="text-[10px] text-zinc-400 italic text-center">
                    * Atenção: Esta alteração será aplicada a todas as aulas (tempos) deste encontro.
                  </p>
                </div>
              </div>

              {/* Action Type Selection */}
              <div className="space-y-3">
                <label className="text-xs font-bold text-zinc-500 uppercase block">Ação</label>
                <div className="grid grid-cols-1 gap-2">
                  <button
                    onClick={() => setActionType('SUBSTITUTION')}
                    className={`p-3 rounded-lg border text-left transition-all ${actionType === 'SUBSTITUTION' ? 'bg-zinc-800 border-brand-red ring-1 ring-brand-red' : 'bg-zinc-900 border-zinc-800 hover:bg-zinc-800'}`}
                  >
                    <div className="font-medium text-sm text-white">Substituir (Apenas Hoje)</div>
                    <div className="text-xs text-zinc-500">Gera custo adicional. Disponível apenas no dia da aula.</div>
                  </button>

                  <button
                    onClick={() => setActionType('CANCELLATION')}
                    className={`p-3 rounded-lg border text-left transition-all ${actionType === 'CANCELLATION' ? 'bg-zinc-800 border-brand-red ring-1 ring-brand-red' : 'bg-zinc-900 border-zinc-800 hover:bg-zinc-800'}`}
                  >
                    <div className="font-medium text-sm text-white">Cancelar Aula</div>
                    <div className="text-xs text-zinc-500">Remove a aula e reajusta o cronograma.</div>
                  </button>
                </div>
              </div>

              {/* Teacher Selection */}
              {actionType !== 'CANCELLATION' && (
                <div className="space-y-2 pt-2 border-t border-zinc-800">
                  <label className="text-sm font-medium text-zinc-300 block">
                    Professor Substituto
                  </label>

                  <div className="max-h-48 overflow-y-auto border border-zinc-700 p-2 rounded bg-zinc-950/50">
                    {!hasQualifiedTeachers ? (
                      <div className="text-zinc-500 text-xs text-center py-4 italic">
                        Nenhum professor cadastrado e habilitado para esta disciplina.
                      </div>
                    ) : (
                      <>
                        {/* Available Teachers */}
                        {availableTeachers.length > 0 && (
                          <div className="mb-3">
                            <div className="text-xs font-bold text-emerald-500 uppercase mb-1 flex items-center gap-1">
                              ✅ Professores Disponíveis
                            </div>
                            <div className="space-y-1">
                              {availableTeachers.map(teacher => (
                                <button
                                  key={teacher.id}
                                  onClick={() => handleSelectTeacher(teacher.id, true)}
                                  className={`w-full text-left px-2 py-1.5 rounded text-sm transition-colors flex items-center justify-between ${
                                    selectedSubstituteId === teacher.id 
                                      ? 'bg-emerald-900/30 text-emerald-200 border border-emerald-800' 
                                      : 'text-zinc-300 hover:bg-zinc-800'
                                  }`}
                                >
                                  <span>{teacher.name}</span>
                                  {selectedSubstituteId === teacher.id && <Check className="w-3 h-3" />}
                                </button>
                              ))}
                            </div>
                          </div>
                        )}

                        {/* Unavailable Teachers */}
                        {unavailableTeachers.length > 0 && (
                          <div>
                            <div className="text-xs font-bold text-red-500 uppercase mb-1 flex items-center gap-1">
                              ❌ Professores Indisponíveis
                            </div>
                            <div className="space-y-1">
                              {unavailableTeachers.map(({ teacher, details }) => (
                                <button
                                  key={teacher.id}
                                  onClick={() => handleSelectTeacher(teacher.id, false, details)}
                                  className={`w-full text-left px-2 py-1.5 rounded text-sm transition-colors flex items-center justify-between opacity-75 hover:opacity-100 ${
                                    selectedSubstituteId === teacher.id 
                                      ? 'bg-red-900/30 text-red-200 border border-red-800' 
                                      : 'text-zinc-400 hover:bg-zinc-800'
                                  }`}
                                >
                                  <span>{teacher.name}</span>
                                  {selectedSubstituteId === teacher.id && <Check className="w-3 h-3" />}
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </>
                    )}
                  </div>

                  {/* Force Schedule Alert */}
                  {forceConfirmData && (
                    <div className="bg-red-900/20 border border-red-500/50 p-3 rounded-lg animate-in slide-in-from-top-2">
                      <div className="flex items-start gap-2 mb-3">
                        <AlertTriangle className="w-4 h-4 text-red-500 shrink-0 mt-0.5" />
                        <div className="text-xs text-red-200">
                          <span className="font-bold block mb-0.5">Atenção: Este professor está indisponível.</span>
                          Motivo: {forceConfirmData.details}
                        </div>
                      </div>
                      <div className="flex gap-2 justify-end">
                        <button
                          onClick={() => setForceConfirmData(null)}
                          className="px-3 py-1.5 text-xs font-medium text-zinc-400 hover:text-white bg-zinc-800 hover:bg-zinc-700 rounded transition-colors"
                        >
                          Cancelar
                        </button>
                        <button
                          onClick={confirmForceTeacher}
                          className="px-3 py-1.5 text-xs font-bold text-white bg-red-600 hover:bg-red-500 rounded shadow-sm transition-colors"
                        >
                          FORÇAR AGENDAMENTO
                        </button>
                      </div>
                    </div>
                  )}

                  <p className="text-xs text-zinc-500 mt-1">
                    * Ao alterar o professor manualmente, esta aula será marcada como substituição.
                  </p>
                </div>
              )}
            </div>

            <div className="p-4 border-t border-zinc-800 bg-zinc-950/50 flex justify-between items-center gap-3">
              {onDeleteAppointment ? (
                <button
                  onClick={() => setShowDeleteConfirm(true)}
                  className="px-4 py-2 text-sm font-medium text-red-400 hover:text-red-300 transition-colors"
                >
                  Remover
                </button>
              ) : (
                <div></div>
              )}
              <div className="flex gap-3">
                <button
                  onClick={() => setEditingEvent(null)}
                  className="px-4 py-2 text-sm font-medium text-zinc-400 hover:text-white transition-colors"
                >
                  Cancelar
                </button>
                <button
                  onClick={handleSaveEdit}
                  className="flex items-center gap-2 px-4 py-2 bg-brand-red text-white rounded-lg hover:bg-red-600 font-medium shadow-lg shadow-brand-red/20 transition-all"
                >
                  <Check className="w-4 h-4" />
                  Salvar Ajuste
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {showDeleteConfirm && editingEvent && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 text-center">
              <div className="w-16 h-16 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-4">
                <AlertTriangle className="w-8 h-8 text-red-500" />
              </div>
              <h3 className="text-lg font-bold text-white mb-2">Remover Agendamento?</h3>
              <p className="text-zinc-400 text-sm mb-6">
                Tem certeza que deseja remover este agendamento? Esta ação não pode ser desfeita e o cronograma será reajustado.
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowDeleteConfirm(false)}
                  className="flex-1 px-4 py-2 bg-zinc-800 text-zinc-300 rounded-lg hover:bg-zinc-700 font-medium transition-colors"
                >
                  Cancelar
                </button>
                <button
                  onClick={() => {
                    if (onDeleteAppointment && editingEvent) {
                      onDeleteAppointment(editingEvent.id);
                      setEditingEvent(null);
                      setShowDeleteConfirm(false);
                    }
                  }}
                  className="flex-1 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium shadow-lg shadow-red-600/20 transition-colors"
                >
                  Remover
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Completion Modal */}
      {completionModalData && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
          <div className="bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <div className="flex items-center gap-3 mb-6">
                <div className="w-12 h-12 bg-emerald-900/30 rounded-full flex items-center justify-center">
