              onAddManualAppointment(appointment);
            }
            setSelectedDateForManual(null);
          }}
        />
      )}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { CourseModule } from '../../../../../../types/course';
import { courseService } from '../../../../../../services/courseService';
import { CourseModuleCard } from '../../../../courses/modules/CourseModuleCard';
import { CourseModuleModal } from '../../../../courses/modules/CourseModuleModal';
import { ModuleContentManager } from '../../../../courses/modules/ModuleContentManager';
import { ConfirmationModal } from '../../../../ui/ConfirmationModal';

interface TeachingEnvironmentProps {
  classId: string;
}

export function TeachingEnvironment({ classId }: TeachingEnvironmentProps) {
  // --- ESTADOS DE MÓDULOS ---
  const [modules, setModules] = useState<CourseModule[]>([]);
  const [loading, setLoading] = useState(true);

  const [isModuleModalOpen, setIsModuleModalOpen] = useState(false);
  const [editingModule, setEditingModule] = useState<CourseModule | null>(null);
  const [moduleToDelete, setModuleToDelete] = useState<CourseModule | null>(null);

  // Estado para controlar se o usuário está vendo a lista ou o conteúdo de um módulo
  // Armazena o objeto completo do módulo selecionado
  const [selectedModule, setSelectedModule] = useState<CourseModule | null>(null);

  // Carregar Módulos
  const loadModules = async () => {
    setLoading(true);
    try {
      // Polimorfismo: Usamos classId como se fosse courseId
      const data = await courseService.getModules(classId);
      setModules(data);
    } catch (error) {
      console.error("Erro ao carregar módulos da turma:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadModules();
  }, [classId]);

  // CRUD Módulos
  const handleSaveModule = async (data: Partial<CourseModule>) => {
    if (editingModule) {
      await courseService.updateModule(editingModule.id, data);
    } else {
      await courseService.createModule({
        ...data,
        courseId: classId, // Polimorfismo: Salvamos com o ID da turma
        order: 999 
      } as any);
    }
    await loadModules();
    setEditingModule(null);
  };

  const handleDeleteModule = async () => {
    if (moduleToDelete) {
      await courseService.deleteModule(moduleToDelete.id);
      await loadModules();
      setModuleToDelete(null);
    }
  };

  const handleReorder = async (index: number, direction: 'left' | 'right') => {
    const newModules = [...modules];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newModules.length) return;

    [newModules[index], newModules[targetIndex]] = [newModules[targetIndex], newModules[index]];
    setModules(newModules);
    await courseService.reorderModules(newModules);
  };

  // Se um módulo estiver selecionado, renderiza o gerenciador de conteúdo interno
  if (selectedModule) {
    return (
      <ModuleContentManager 
        module={selectedModule} 
        onBack={() => setSelectedModule(null)} 
      />
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in flex flex-col h-full">

      {/* Header com Título e Botão Novo Módulo */}
      <div className="flex items-center justify-between border-b border-gray-800 pb-4 shrink-0">
          <div>
            <span className="text-red-500 font-bold text-xs uppercase tracking-wider">Turma Presencial</span>
            <h2 className="text-2xl font-black text-white uppercase">Ambiente de Ensino (Recursos Online)</h2>
          </div>

          <button 
            onClick={() => { setEditingModule(null); setIsModuleModalOpen(true); }}
            className="px-6 py-2 bg-red-600 hover:bg-red-500 text-white font-bold uppercase text-xs rounded shadow-lg shadow-red-900/20 flex items-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
            Novo Módulo
          </button>
      </div>

      {/* Lista de Módulos */}
      <div className="flex-1 overflow-hidden">
         <div className="space-y-6 h-full overflow-y-auto custom-scrollbar p-1">
            {loading ? (
            <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-red-600"></div></div>
            ) : modules.length === 0 ? (
            <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                <p className="text-gray-500">Nenhum módulo cadastrado nesta turma.</p>
                <button 
                    onClick={() => { setEditingModule(null); setIsModuleModalOpen(true); }}
                    className="mt-4 text-red-500 hover:text-red-400 text-sm font-bold uppercase"
                >
                    Criar Primeiro Módulo
                </button>
            </div>
            ) : (
            <div className="flex gap-6 overflow-x-auto pb-6 scrollbar-thin scrollbar-thumb-red-900 scrollbar-track-transparent px-1">
                {modules.map((module, index) => (
                <CourseModuleCard 
                    key={module.id}
                    module={module}
                    onEdit={(m) => { setEditingModule(m); setIsModuleModalOpen(true); }}
                    onDelete={setModuleToDelete}
                    onMoveLeft={() => { handleReorder(index, 'left'); }}
                    onMoveRight={() => { handleReorder(index, 'right'); }}
                    onManageContent={(m) => setSelectedModule(m)}
                    isFirst={index === 0}
                    isLast={index === modules.length - 1}
                />
                ))}
            </div>
            )}
         </div>
      </div>

      {/* Modais */}
      <CourseModuleModal 
        isOpen={isModuleModalOpen}
        onClose={() => setIsModuleModalOpen(false)}
        onSave={handleSaveModule}
        initialData={editingModule}
      />

      <ConfirmationModal 
        isOpen={!!moduleToDelete}
        title="Excluir Módulo?"
        message={`Deseja excluir "${moduleToDelete?.title}"? Todo o conteúdo interno será perdido.`}
        onConfirm={handleDeleteModule}
        onCancel={() => setModuleToDelete(null)}
        isDanger
      />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { X, Plus, Trash2, Settings, Loader2, AlertTriangle, Check } from 'lucide-react';
import { Equipment } from '../../../../types/equipment';
import { equipmentService } from '../../../../services/equipmentService';

interface EquipmentManagerModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export const EquipmentManagerModal: React.FC<EquipmentManagerModalProps> = ({ isOpen, onClose }) => {
  const [equipments, setEquipments] = useState<Equipment[]>([]);
  const [newEquipmentName, setNewEquipmentName] = useState('');
  const [loading, setLoading] = useState(false);
  const [adding, setAdding] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  const fetchEquipments = async () => {
    try {
      setLoading(true);
      const data = await equipmentService.getEquipments();
      setEquipments(data);
    } catch (error) {
      console.error("Error fetching equipments:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      fetchEquipments();
    }
  }, [isOpen]);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEquipmentName.trim()) return;

    try {
      setAdding(true);
      await equipmentService.createEquipment({ name: newEquipmentName.trim() });
      setNewEquipmentName('');
      await fetchEquipments();
    } catch (error) {
      console.error("Error adding equipment:", error);
      alert("Erro ao adicionar equipamento.");
    } finally {
      setAdding(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      setDeletingId(id);
      await equipmentService.deleteEquipment(id);
      await fetchEquipments();
      setConfirmDeleteId(null);
    } catch (error) {
      console.error("Error deleting equipment:", error);
      alert("Erro ao excluir equipamento.");
    } finally {
      setDeletingId(null);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-zinc-900 border border-zinc-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-300 flex flex-col max-h-[80vh]">
        <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-zinc-900/50">
          <div className="flex items-center gap-2">
            <Settings className="w-5 h-5 text-brand-red" />
            <h2 className="text-lg font-bold text-white uppercase tracking-tight">
              Gerenciar Equipamentos
            </h2>
          </div>
          <button onClick={onClose} className="text-zinc-400 hover:text-white transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="p-6 flex-1 overflow-hidden flex flex-col">
          <form onSubmit={handleAdd} className="flex gap-2 mb-6">
            <input
              type="text"
              value={newEquipmentName}
              onChange={(e) => setNewEquipmentName(e.target.value)}
              placeholder="Nome do equipamento..."
              className="flex-1 bg-zinc-800 border border-zinc-700 rounded-lg px-4 py-2 text-white focus:outline-none focus:border-brand-red transition-colors text-sm"
            />
            <button
              type="submit"
              disabled={adding || !newEquipmentName.trim()}
              className="bg-brand-red hover:bg-red-600 disabled:opacity-50 disabled:cursor-not-allowed text-white px-3 py-2 rounded-lg transition-colors flex items-center justify-center min-w-[40px]"
            >
              {adding ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
            </button>
          </form>

          <div className="flex-1 overflow-y-auto pr-2 space-y-2 scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent">
            {loading ? (
              <div className="text-center py-8 text-zinc-500 text-sm">Carregando...</div>
            ) : equipments.length === 0 ? (
              <div className="text-center py-8 text-zinc-500 text-sm italic border border-dashed border-zinc-800 rounded-lg">
                Nenhum equipamento cadastrado.
              </div>
            ) : (
              equipments.map((item) => (
                <div key={item.id} className={`flex items-center justify-between p-3 border rounded-lg transition-all ${confirmDeleteId === item.id ? 'bg-red-900/10 border-red-900/30' : 'bg-zinc-800/30 border-zinc-800 hover:border-zinc-700'}`}>
                  {confirmDeleteId === item.id ? (
                    <div className="flex items-center justify-between w-full animate-in fade-in duration-200">
                      <span className="text-xs font-bold text-red-400 uppercase flex items-center gap-2">
                        <AlertTriangle className="w-3 h-3" />
                        Confirmar exclusão?
                      </span>
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => setConfirmDeleteId(null)}
                          className="px-2 py-1 rounded bg-zinc-800 text-zinc-400 text-xs font-bold uppercase hover:text-white transition-colors"
                        >
                          Cancelar
                        </button>
                        <button
                          onClick={() => handleDelete(item.id)}
                          disabled={deletingId === item.id}
                          className="px-2 py-1 rounded bg-red-600 text-white text-xs font-bold uppercase hover:bg-red-700 transition-colors flex items-center gap-1"
                        >
                          {deletingId === item.id ? (
                            <Loader2 className="w-3 h-3 animate-spin" />
                          ) : (
                            <>
                              <Trash2 className="w-3 h-3" />
                              Excluir
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  ) : (
                    <>
                      <span className="text-sm text-zinc-300 font-medium">{item.name}</span>
                      <button
                        onClick={() => setConfirmDeleteId(item.id)}
                        className="text-zinc-500 hover:text-red-500 p-1.5 rounded-md hover:bg-red-500/10 transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </>
                  )}
                </div>
              ))
            )}
          </div>
        </div>

        <div className="p-4 border-t border-zinc-800 bg-zinc-900/50">
          <p className="text-[10px] text-zinc-500 text-center">
            Estes equipamentos estarão disponíveis para seleção no cadastro de salas.
          </p>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { Check, Info } from 'lucide-react';
import { Teacher, DayOfWeek, Shift, TeacherArea, TeacherSchedulePreference } from '../../../../types/teacher';

interface TeacherAvailabilityProps {
  data: Partial<Teacher>;
  onChange: (data: Partial<Teacher>) => void;
}

const DAYS: { value: DayOfWeek; label: string }[] = [
  { value: 'MONDAY', label: 'Segunda' },
  { value: 'TUESDAY', label: 'Terça' },
  { value: 'WEDNESDAY', label: 'Quarta' },
  { value: 'THURSDAY', label: 'Quinta' },
  { value: 'FRIDAY', label: 'Sexta' },
];

const SHIFTS: { value: Shift; label: string }[] = [
  { value: 'MORNING', label: 'Manhã' },
  { value: 'AFTERNOON', label: 'Tarde' },
  { value: 'NIGHT', label: 'Noite' },
];

export const TeacherAvailability: React.FC<TeacherAvailabilityProps> = ({ data, onChange }) => {
  const preferences = data.schedulePreferences || [];
  const areas = data.areas || [];

  const handlePreferenceToggle = (day: DayOfWeek, shift: Shift, area: TeacherArea) => {
    // Check if already selected
    const existingIndex = preferences.findIndex(
      p => p.day === day && p.shift === shift && p.area === area
    );

    const newPreferences = [...preferences];

    if (existingIndex >= 0) {
      // Remove if exists
      newPreferences.splice(existingIndex, 1);
    } else {
      // Add new preference
      // Check limit: Max 3 preferences total? Or just collect them all and rank later?
      // PRD says: "Escolher três horários em ordem hierárquica de preferência."
      // For now, let's allow selecting them, and we assign priority based on selection order or just count.

      // Simple logic: Add to list with next priority
      const nextPriority = (newPreferences.length % 3) + 1; 

      newPreferences.push({
        day,
        shift,
        area,
        priority: nextPriority as 1 | 2 | 3
      });
    }

    onChange({ ...data, schedulePreferences: newPreferences });
  };

  const getPreference = (day: DayOfWeek, shift: Shift, area: TeacherArea) => {
    return preferences.find(p => p.day === day && p.shift === shift && p.area === area);
  };

  const handleWeekendChange = (day: 'saturday' | 'sunday') => {
    onChange({
      ...data,
      availableWeekends: {
        ...data.availableWeekends,
        [day]: !data.availableWeekends?.[day],
      } as any
    });
  };

  if (areas.length === 0) {
    return (
      <div className="p-8 text-center border border-dashed border-zinc-800 rounded-xl">
        <p className="text-zinc-500">Selecione as Áreas de Atuação na etapa de Dados Profissionais para configurar a disponibilidade.</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-bold text-white">Preferência de Horários</h3>
        <div className="flex items-center gap-2 text-xs text-zinc-500 bg-zinc-900 px-3 py-1 rounded-full border border-zinc-800">
          <Info className="w-3 h-3" />
          <span>Selecione os horários titulares de preferência</span>
        </div>
      </div>

      {areas.map(area => (
        <div key={area} className="space-y-4">
          <div className="flex items-center gap-2">
            <span className={`text-xs font-bold px-2 py-1 rounded ${
              area === 'CONCURSO' ? 'bg-blue-500/10 text-blue-500' : 'bg-brand-red/10 text-brand-red'
            }`}>
              {area === 'CONCURSO' ? 'CONCURSO PÚBLICO' : 'ENEM'}
            </span>
            <div className="h-px bg-zinc-800 flex-1"></div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr>
                  <th className="p-2 text-left text-[10px] font-bold text-zinc-500 uppercase">Turno / Dia</th>
                  {DAYS.map(day => (
                    <th key={day.value} className="p-2 text-center text-[10px] font-bold text-zinc-500 uppercase bg-zinc-900/50 border border-zinc-800 min-w-[80px]">
                      {day.label}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {SHIFTS.map(shift => (
                  <tr key={shift.value}>
                    <td className="p-3 text-[11px] font-bold text-zinc-400 uppercase bg-zinc-900/30 border border-zinc-800">
                      {shift.label}
                    </td>
                    {DAYS.map(day => {
                      const pref = getPreference(day.value, shift.value, area);
                      const isSelected = !!pref;

                      return (
                        <td key={`${day.value}-${shift.value}`} className="p-1 border border-zinc-800 text-center">
                          <button
                            onClick={() => handlePreferenceToggle(day.value, shift.value, area)}
                            className={`w-full h-10 rounded transition-all flex items-center justify-center gap-1 ${
                              isSelected 
                                ? area === 'CONCURSO' 
                                  ? 'bg-blue-600 text-white shadow-[0_0_10px_rgba(37,99,235,0.3)]' 
                                  : 'bg-brand-red text-white shadow-[0_0_10px_rgba(220,38,38,0.3)]'
                                : 'hover:bg-zinc-800 text-zinc-600'
                            }`}
                          >
                            {isSelected && <Check className="w-3 h-3" />}
                            <span className="text-[10px] font-bold">{isSelected ? 'TITULAR' : '-'}</span>
                          </button>
                        </td>
                      );
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      ))}

      <div className="pt-6 border-t border-zinc-800">
        <h4 className="text-sm font-bold text-white mb-4 uppercase">Disponibilidade Finais de Semana</h4>
        <div className="flex gap-6">
          <label className="flex items-center gap-3 cursor-pointer group p-3 bg-zinc-900 rounded-lg border border-zinc-800 hover:border-zinc-600 transition-colors">
            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${
              data.availableWeekends?.saturday ? 'bg-brand-red border-brand-red' : 'border-zinc-600 bg-zinc-800'
            }`}>
              {data.availableWeekends?.saturday && <Check className="w-3 h-3 text-white" />}
            </div>
            <span className="text-sm font-medium text-zinc-300">Sábado</span>
            <input 
              type="checkbox" 
              className="hidden" 
              checked={data.availableWeekends?.saturday || false}
              onChange={() => handleWeekendChange('saturday')}
            />
          </label>

          <label className="flex items-center gap-3 cursor-pointer group p-3 bg-zinc-900 rounded-lg border border-zinc-800 hover:border-zinc-600 transition-colors">
            <div className={`w-5 h-5 rounded border flex items-center justify-center transition-colors ${
              data.availableWeekends?.sunday ? 'bg-brand-red border-brand-red' : 'border-zinc-600 bg-zinc-800'
            }`}>
              {data.availableWeekends?.sunday && <Check className="w-3 h-3 text-white" />}
            </div>
            <span className="text-sm font-medium text-zinc-300">Domingo</span>
            <input 
              type="checkbox" 
              className="hidden" 
              checked={data.availableWeekends?.sunday || false}
              onChange={() => handleWeekendChange('sunday')}
            />
          </label>
        </div>
      </div>
    </div>
  );
};

