// 2. DISCIPLINAS (WRAPPER)
// ==========================================
function StudentDisciplineAccordion({ discipline, courseId, completedLessons, completedTopics, onToggleTopic, focusTopicId }: any) {
    // NOVA LÓGICA: Verifica se o tópico focado está escondido dentro desta disciplina
    const hasFocusedTopic = useMemo(() => {
      if (!focusTopicId) return false;
      const check = (topics: any[]): boolean => {
          if (!topics) return false;
          for (const t of topics) {
              if (String(t.id) === String(focusTopicId)) return true;
              if (t.subtopics && check(t.subtopics)) return true;
          }
          return false;
      };
      return check(discipline.topics);
    }, [discipline, focusTopicId]);

    // Se tiver, o estado inicial de isOpen será true
    const [isOpen, setIsOpen] = useState(hasFocusedTopic);

    // Monitora mudanças para abrir automaticamente
    useEffect(() => {
        if (hasFocusedTopic) setIsOpen(true);
    }, [hasFocusedTopic]);

    // --- CÁLCULO RECURSIVO DA BARRA DE PROGRESSO DA DISCIPLINA ---
    const countDisciplineTopics = (topics: any[]): number => {
        let count = 0;
        topics.forEach(t => {
            count++;
            if (t.subtopics) count += countDisciplineTopics(t.subtopics);
        });
        return count;
    };

    const countDisciplineCompleted = (topics: any[]): number => {
        let count = 0;
        topics.forEach(t => {
            if (completedTopics.includes(String(t.id))) count++;
            if (t.subtopics) count += countDisciplineCompleted(t.subtopics);
        });
        return count;
    };

    const discTotal = countDisciplineTopics(discipline.topics || []);
    const discCompleted = countDisciplineCompleted(discipline.topics || []);
    const discProgress = discTotal > 0 ? Math.round((discCompleted / discTotal) * 100) : 0;

    return (
      <div className={`border rounded-xl bg-[#1a1d24] overflow-hidden transition-all ${discProgress === 100 ? 'border-green-900/50' : 'border-gray-800'}`}>
        <div 
          onClick={() => setIsOpen(!isOpen)}
          className="flex flex-col sm:flex-row sm:items-center justify-between p-4 hover:bg-[#202329] transition-colors cursor-pointer select-none group gap-4"
        >
          <div className="flex items-center gap-3">
            <ChevronRight size={18} className={`text-gray-500 transition-transform ${isOpen ? 'rotate-90' : 'group-hover:text-white'}`} />
            <BookOpen size={20} className={discProgress === 100 ? 'text-green-500' : 'text-red-500'} />
            <h3 className="text-white font-black text-sm uppercase">{discipline.name}</h3>
          </div>

          <div className="flex items-center gap-4 ml-7 sm:ml-0">
              <div className="flex flex-col items-end hidden sm:flex w-32">
                  <span className="text-[9px] font-bold text-gray-500 uppercase">{discProgress}% Concluído</span>
                  <div className="w-full bg-black rounded-full h-1.5 overflow-hidden mt-1">
                      <div className="bg-green-500 h-full rounded-full transition-all duration-500" style={{ width: `${discProgress}%` }}></div>
                  </div>
              </div>
              <span className="text-[10px] font-bold text-gray-500 bg-black/50 px-3 py-1 rounded-full border border-gray-800">
                {discTotal} Tópicos
              </span>
          </div>
        </div>

        {/* Progress Bar Mobile */}
        <div className="sm:hidden w-full bg-black h-1">
           <div className="bg-green-500 h-full transition-all duration-500" style={{ width: `${discProgress}%` }}></div>
        </div>

        {isOpen && discipline.topics && (
          <div className="p-4 pt-0 border-t border-gray-800/50 bg-black/20">
            <div className="pl-4 border-l-2 border-gray-800 mt-4 space-y-3">
              {discipline.topics.map((topic: any) => (
                <StudentTopicAccordion 
                   key={topic.id} 
                   topic={topic} 
                   courseId={courseId}
                   disciplineId={discipline.id} 
                   disciplineName={discipline.name} // <-- CAPTURANDO E ENVIANDO O NOME
                   completedLessons={completedLessons}
                   completedTopics={completedTopics}
                   onToggleTopic={onToggleTopic}
                   focusTopicId={focusTopicId}
                />
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }

// ==========================================
// 3. COMPONENTE PRINCIPAL (MANAGER)
// ==========================================
export function StudentCourseEdital({ courseId, focusTopicId }: { courseId: string, focusTopicId?: string | null }) {
    const { currentUser: user } = useAuth();
    const [structure, setStructure] = useState<CourseEditalStructure | null>(null);
    const [loading, setLoading] = useState(true);
    const [completedTopics, setCompletedTopics] = useState<string[]>([]);

    // Novas vars
    const [completedLessons, setCompletedLessons] = useState<string[]>([]);

    useEffect(() => {
        const loadData = async () => {
            if (!user) return;
            setLoading(true);
            try {
                const [editalData, topicsDone, lessonsDone] = await Promise.all([
                    courseService.getCourseEdital(courseId),
                    courseService.getCompletedTopics(user.uid, courseId),
                    courseService.getCompletedLessons(user.uid, courseId)
                ]);
                setStructure(editalData);
                // Garante que todos os IDs de tópicos sejam strings
                setCompletedTopics((topicsDone || []).map(String));
                setCompletedLessons(lessonsDone || []);
            } catch (error) {
                console.error(error);
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, [courseId, user]);

    // Função Blindada para Marcar/Desmarcar o Tópico (Optimistic UI)
    const handleToggleTopic = (topicId: string | number) => {
        if (!user) return;
        const safeId = String(topicId);

        // setCompletedTopics com 'prev' garante que NUNCA usaremos dados obsoletos
        setCompletedTopics(prev => {
            const isAlreadyCompleted = prev.includes(safeId);
            const newStatus = !isAlreadyCompleted;

            // 1. Dispara o salvamento pro banco em segundo plano (não trava a tela)
            courseService.toggleTopicCompletion(user.uid, courseId, safeId, newStatus)
                .catch(err => console.error("Erro ao salvar progresso no banco:", err));

            // 2. Atualiza a interface instantaneamente (o Check fica verde na mesma hora)
            if (newStatus) {
                return [...prev, safeId];
            } else {
                return prev.filter(id => String(id) !== safeId);
            }
        });
    };

    if (loading) return <div className="flex justify-center p-20"><Loader2 className="animate-spin text-red-500" /></div>;

    if (!structure || !structure.disciplines || structure.disciplines.length === 0) {
        return (
            <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                <BookOpen className="w-12 h-12 text-gray-600 mx-auto mb-4" />
                <p className="text-gray-500 uppercase font-bold text-sm">Edital não disponível.</p>
                <p className="text-gray-600 text-xs mt-1">O professor ainda não publicou o edital verticalizado.</p>
            </div>
        );
    }

    // --- CÁLCULO DA BARRA DE PROGRESSO GERAL ---
    const countTotalTopics = (items: any[]): number => {
        let count = 0;
        items.forEach(item => {
            count++; 
            if (item.subtopics && item.subtopics.length > 0) {
                count += countTotalTopics(item.subtopics); 
            }
        });
        return count;
    };

    const totalTopics = structure.disciplines.reduce((acc: number, disc: any) => acc + countTotalTopics(disc.topics || []), 0);
    const overallProgress = totalTopics > 0 ? Math.round((completedTopics.length / totalTopics) * 100) : 0;

    return (
        <div className="space-y-6 pb-20 animate-in fade-in">
            {/* Header / Resumo */}
            <div className="flex flex-col md:flex-row justify-between items-end gap-4 border-b border-gray-800 pb-6">
                <div>
                    <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Edital Verticalizado</h2>
                    <p className="text-gray-500 text-sm font-medium mt-1">Acompanhe seu progresso tópico por tópico.</p>
                </div>

                {/* BARRA DE PROGRESSO GERAL */}
                <div className="bg-[#1a1d24] border border-gray-800 rounded-xl p-3 flex flex-col gap-1 w-full md:w-64">
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider block">Progresso Geral</span>
                        <span className="text-sm font-black text-white">{overallProgress}%</span>
                    </div>
                    <div className="w-full bg-black rounded-full h-2 overflow-hidden border border-gray-800">
                        <div className="bg-green-500 h-full rounded-full transition-all duration-700 ease-out" style={{ width: `${overallProgress}%` }}></div>
                    </div>
                </div>
            </div>

            {/* Lista de Disciplinas */}
            <div className="space-y-4">
                {structure.disciplines.map(discipline => (
                    <StudentDisciplineAccordion 
                        key={discipline.id} 
                        discipline={discipline} 
                        courseId={courseId}
                        completedLessons={completedLessons}
                        completedTopics={completedTopics} 
                        onToggleTopic={handleToggleTopic}
                        focusTopicId={focusTopicId} // PASSANDO O ID DE FOCO PARA BAIXO
                    />
                ))}
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { FileText, FileQuestion, Layers, Download } from 'lucide-react';
import { CourseLesson, CourseContent } from '../../../../types/course';
import { courseService } from '../../../../services/courseService';
import { useAuth } from '../../../../contexts/AuthContext';
import { openWatermarkedPdf } from '../../../../utils/pdfSecurityService';
import { AlternativeYouTubePlayer } from '../../../shared/AlternativeYouTubePlayer';

interface CoursePlayerContentProps {
  lesson: CourseLesson;
}

export function CoursePlayerContent({ lesson }: CoursePlayerContentProps) {
  const { currentUser, userData } = useAuth();
  const [contents, setContents] = useState<CourseContent[]>([]);
  const [loading, setLoading] = useState(true);

  // Estado para controlar o loading específico de cada PDF
  const [openingPdfId, setOpeningPdfId] = useState<string | null>(null);

  useEffect(() => {
    const loadContents = async () => {
        setLoading(true);
        try {
            const data = await courseService.getContents(lesson.id);
            setContents(data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };
    loadContents();
  }, [lesson.id]);

  // Função para abrir PDF com marca d'água
  const handleOpenPdf = async (url: string, contentId: string) => {
    if (!url || !currentUser) return;
    if (openingPdfId) return; // Evita múltiplos cliques

    setOpeningPdfId(contentId);

    try {
        await openWatermarkedPdf(url, {
            email: currentUser.email || 'usuario@insanus.com',
            cpf: userData?.cpf || '000.000.000-00'
        });
    } catch (error: any) {
        console.error("Erro ao abrir PDF:", error);
        alert(`Erro ao gerar documento seguro: ${error.message}`);
    } finally {
        setOpeningPdfId(null);
    }
  };

  // Helper para renderizar o ícone do PDF baseado na classificação
  const renderPdfIcon = (classification?: string) => {
    switch (classification) {
      case 'QUESTÕES':
        return <FileQuestion size={24} />;
      case 'TEORIA_QUESTÕES':
        return <Layers size={24} />;
      case 'TEORIA':
      default:
        return <FileText size={24} />;
    }
  };

  // Helper para renderizar o helper do YouTube
  function getYouTubeID(url: string) {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  }

  if (loading) return <div className="flex items-center justify-center py-20"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-red-600"></div></div>;

  if (contents.length === 0) {
      return (
          <div className="flex flex-col items-center justify-center py-20 text-gray-500">
              <svg className="w-16 h-16 mb-4 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
              <p>Esta aula ainda não possui conteúdo.</p>
          </div>
      );
  }

  return (
    <div className="w-full flex flex-col animate-in fade-in">

        {contents.map((item, index) => {

            // --- BLOCO DE VÍDEO ---
            if (item.type === 'video') {
                return (
                    <div key={item.id} className="w-full bg-[#0a0c10] border-b border-gray-900 shadow-2xl relative z-10 py-6 md:py-10 px-4 md:px-10">
                        <div className="w-full max-w-4xl aspect-video mx-auto rounded-xl overflow-hidden border border-gray-800 shadow-[0_0_50px_rgba(0,0,0,0.5)]"> 
                            {item.videoPlatform === 'youtube' ? (
                                <div className="w-full h-full bg-black">
                                    <AlternativeYouTubePlayer videoId={getYouTubeID(item.videoUrl || '') || ''} />
                                </div>
                            ) : (
                                <iframe src={item.videoUrl} className="w-full h-full" frameBorder="0" allowFullScreen />
                            )}
                        </div>
                    </div>
                );
            }

            // --- OUTROS CONTEÚDOS ---
            return (
                <div key={item.id} className="w-full max-w-6xl mx-auto px-6 lg:px-10 mt-8">

                    {/* Exibe o Título da Aula apenas acima do primeiro conteúdo não-vídeo */}
                    {((index === 0 && item.type !== 'video') || (index === 1 && contents[0].type === 'video')) && (
                         <div className="border-b border-gray-800 pb-4 mb-6">
                            <h1 className="text-2xl font-bold text-white">{lesson.title}</h1>
                        </div>
                    )}

                    {/* Texto Rico */}
                    {item.type === 'text' && (
                        <div className="prose prose-invert max-w-none bg-[#1a1d24] p-6 rounded-xl border border-gray-800" dangerouslySetInnerHTML={{ __html: item.textContent || '' }} />
                    )}

                    {/* PDF (COM SEGURANÇA) */}
                    {item.type === 'pdf' && (
                        <div 
                            onClick={() => handleOpenPdf(item.fileUrl || '', item.id)}
                            className={`
                                flex items-center gap-4 p-4 bg-[#1a1d24] border border-gray-800 rounded-xl transition-all group mb-4 cursor-pointer
                                ${openingPdfId === item.id ? 'opacity-75 pointer-events-none' : 'hover:border-red-600/50 hover:bg-[#202329]'}
                            `}
                        >
                            <div className="w-10 h-10 rounded bg-red-900/20 flex items-center justify-center text-red-500 group-hover:scale-110 transition-transform shrink-0">
                                {openingPdfId === item.id ? (
                                    <div className="animate-spin h-5 w-5 border-2 border-red-500 border-t-transparent rounded-full"></div>
                                ) : (
                                    renderPdfIcon(item.pdfClassification)
                                )}
                            </div>
                            <div className="flex-1">
                                <h4 className="text-white font-bold text-sm">{item.title}</h4>
                                <span className={`text-[10px] uppercase transition-colors ${openingPdfId === item.id ? 'text-red-400 animate-pulse' : 'text-gray-500 group-hover:text-gray-400'}`}>
                                    {openingPdfId === item.id ? 'Gerando documento seguro...' : `Material em PDF • ${item.pdfClassification || 'TEORIA'} • Clique para acessar`}
                                </span>
                            </div>
                            {openingPdfId !== item.id && (
                                <Download className="w-5 h-5 text-gray-500 group-hover:text-white" />
                            )}
                        </div>
                    )}

                    {/* Link */}
                    {item.type === 'link' && (
                        <a href={item.linkUrl} target="_blank" rel="noreferrer" className="flex items-center gap-4 p-4 bg-[#1a1d24] border border-gray-800 rounded-xl hover:border-blue-500/50 hover:bg-[#202329] transition-all group mb-4">
                            <div className="w-10 h-10 rounded bg-blue-900/20 flex items-center justify-center text-blue-500 group-hover:scale-110 transition-transform shrink-0">
                                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
                            </div>
                            <div className="flex-1">
                                <h4 className="text-white font-bold text-sm">{item.title}</h4>
                                <span className="text-[10px] text-gray-500 uppercase">Link Externo</span>
                            </div>
                        </a>
                    )}

                    {/* Embed */}
                    {item.type === 'embed' && (
                        <div className="w-full overflow-hidden rounded-xl border border-gray-800 mb-4" dangerouslySetInnerHTML={{ __html: item.embedCode || '' }} />
                    )}
                </div>
            );
        })}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { courseReviewService, CourseReview } from '../../../../services/courseReviewService';
import { courseService } from '../../../../services/courseService';
import { useAuth } from '../../../../contexts/AuthContext';
import { AlertCircle, CalendarClock, CheckCircle2, ChevronRight, ChevronDown } from 'lucide-react';

export function CourseReviewDashboard({ courseId, onReviewNow }: { courseId: string, onReviewNow: (topicId: string) => void }) {
    const { currentUser: user } = useAuth();
    const [reviews, setReviews] = useState<CourseReview[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchReviews = async () => {
        if (!user) return;
        try {
            const [reviewsData, editalData] = await Promise.all([
                courseReviewService.getPendingReviews(user.uid, courseId),
                courseService.getCourseEdital(courseId)
            ]);

            // Mapeamento de Tópicos Ativos para Filtro de Registros Órfãos
            const activeTopicIds = new Set<string>();
            if (editalData) {
                editalData.disciplines.forEach(discipline => {
                    const collectIds = (topics: any[]) => {
                        topics.forEach(topic => {
                            activeTopicIds.add(topic.id);
                            if (topic.subtopics && topic.subtopics.length > 0) {
                                collectIds(topic.subtopics);
                            }
                        });
                    };
                    collectIds(discipline.topics);
                });
            }

            // Filtragem em Tempo de Leitura: Remove revisões de tópicos excluídos
            const validReviews = reviewsData.filter(review => activeTopicIds.has(review.topicId));

            setReviews(validReviews);
        } catch (error) {
            console.error("Erro ao buscar revisões:", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReviews();
    }, [courseId, user]);

    const handleComplete = async (review: CourseReview) => {
        if (!user) return;
        // Atualização Otimista: Desaparece do ecrã na hora em que clica
        setReviews(prev => prev.filter(r => r.id !== review.id));
        try {
            await courseReviewService.completeReview(user.uid, review);
        } catch (error) {
            console.error("Erro ao concluir revisão:", error);
            fetchReviews(); // Reverte caso dê erro no banco de dados
        }
    };

    if (loading || reviews.length === 0) return null;

    // Garante a formatação da data baseada no fuso horário local do utilizador (YYYY-MM-DD)
    const getLocalDateStr = () => {
        const d = new Date();
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    };
    const todayStr = getLocalDateStr();

    const overdueReviews = reviews.filter(r => r.scheduledDate < todayStr);
    const todayReviews = reviews.filter(r => r.scheduledDate === todayStr);

    if (overdueReviews.length === 0 && todayReviews.length === 0) return null;

    return (
        <div className="flex flex-col gap-4 mb-6 animate-in fade-in slide-in-from-top-4">
            {/* Secção de Revisões Atrasadas */}
            <ReviewSection 
                title="Revisões em Atraso" 
                count={overdueReviews.length} 
                theme="red" 
                icon={AlertCircle}
                defaultOpen={true}
            >
                {overdueReviews.map(review => (
                    <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={true} />
                ))}
            </ReviewSection>

            {/* Secção de Revisões de Hoje */}
            <ReviewSection 
                title="Revisões Agendadas para Hoje" 
                count={todayReviews.length} 
                theme="yellow" 
                icon={CalendarClock}
                defaultOpen={true}
            >
                {todayReviews.map(review => (
                    <ReviewCard key={review.id} review={review} onReviewNow={onReviewNow} onComplete={handleComplete} isOverdue={false} />
                ))}
            </ReviewSection>
        </div>
    );
}

// ====================================================
// COMPONENTE: Acordeão Inteligente (ReviewSection)
// ====================================================
function ReviewSection({ title, count, theme, defaultOpen = true, icon: Icon, children }: any) {
    const [isOpen, setIsOpen] = useState(defaultOpen);
    const isRed = theme === 'red';

    // Configuração de cores baseada no tema
    const bgHeader = isRed ? 'bg-red-900/20' : 'bg-yellow-900/20';
    const borderColor = isRed ? 'border-red-900/50' : 'border-yellow-900/50';
    const textColor = isRed ? 'text-red-500' : 'text-yellow-500';
    const badgeBg = isRed ? 'bg-red-500/20 text-red-400' : 'bg-yellow-500/20 text-yellow-500';

    if (count === 0) return null;

    return (
        <div className={`border rounded-xl overflow-hidden shadow-lg transition-all ${borderColor}`}>
            {/* Cabeçalho Clicável do Acordeão */}
            <div 
                onClick={() => setIsOpen(!isOpen)}
                className={`w-full flex items-center justify-between p-4 ${bgHeader} hover:opacity-80 transition-opacity cursor-pointer select-none`}
            >
                <div className="flex items-center gap-3">
                    <Icon size={18} className={textColor} />
                    <h3 className={`${textColor} font-black uppercase text-sm`}>{title}</h3>
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${badgeBg}`}>
                        {count}
                    </span>
                </div>
                <ChevronDown size={18} className={`${textColor} transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} />
            </div>

            {/* Corpo do Acordeão */}
            {isOpen && (
                <div className={`p-4 bg-[#121418] flex flex-col gap-2 border-t ${borderColor} animate-in fade-in slide-in-from-top-2`}>
                    {children}
                </div>
            )}
        </div>
    );
}

