import React, { useState, useEffect } from 'react';
import { useAuth } from '../../../contexts/AuthContext'; 
import { SimuladoDashboardCard as SimuladoGoalCard } from '../SimuladoDashboardCard';
import { SimuladoFocusMode } from '../goals/SimuladoFocusMode'; 
import { scheduleUserSimulado } from '../../../services/scheduleService';
import { collection, query, where, getDocs, documentId, doc, updateDoc } from 'firebase/firestore';
import { db } from '../../../services/firebase';

interface ComputedSimulado {
    id: string;
    title: string;
    duration: number;
    status: 'blocked' | 'released' | 'scheduled';
    date?: Date;
    pdfUrl?: string; 
}

export const StudentDailyGoals = ({ planData, userData }: { planData: any, userData: any }) => {
    const { currentUser: user } = useAuth();
    const [schedule, setSchedule] = useState<any[]>([]); 
    const [computedSimulados, setComputedSimulados] = useState<{ blocked: ComputedSimulado[], released: ComputedSimulado[] }>({ blocked: [], released: [] });
    const [showScheduleModal, setShowScheduleModal] = useState<string | null>(null);
    const [simuladosDetails, setSimuladosDetails] = useState<Record<string, any>>({}); 

    // Estados do Modo Foco e Acordeão
    const [isExamMode, setIsExamMode] = useState(false);
    const [activeSimulado, setActiveSimulado] = useState<any>(null);
    const [expandedSimulado, setExpandedSimulado] = useState<string | null>(null);

    // SOLICITAÇÃO 2: ESTADO PARA O POPUP DE CONFIRMAÇÃO
    const [showStartConfirmation, setShowStartConfirmation] = useState<any>(null);

    // 1. BUSCA AGENDAMENTO REAL
    useEffect(() => {
        const fetchSchedule = async () => {
            if (!user || !planData?.id) return;
            // CORREÇÃO: Usa a subcoleção correta do usuário
            const schedulesRef = collection(db, 'users', user.uid, 'schedules');
            const snap = await getDocs(schedulesRef);

            // Achata todos os itens de todos os dias em um único array
            const allItems: any[] = [];
            snap.docs.forEach(docSnap => {
                const data = docSnap.data();
                const items = (data.items || []) as any[];
                // Filtra apenas os itens deste plano
                const planItems = items.filter(i => i.planId === planData.id);
                allItems.push(...planItems.map(i => ({ ...i, date: data.date })));
            });

            setSchedule(allItems);
        };
        fetchSchedule();
    }, [user, planData]);

    // 2. BUSCA DETALHES REAIS (Incluindo PDF)
    useEffect(() => {
        const fetchSimuladoDetails = async () => {
            if (!planData || !planData.cycles) return;
            const ids = new Set<string>();
            planData.cycles.forEach((c: any) => c.items?.forEach((i: any) => {
                if (i.type === 'simulado') ids.add(i.simuladoId || i.id);
            }));
            if (ids.size === 0) return;

            try {
                // Adaptação para chunks de 10
                const idsArray = Array.from(ids);
                const chunks = [];
                for (let i = 0; i < idsArray.length; i += 10) {
                    chunks.push(idsArray.slice(i, i + 10));
                }

                const details: Record<string, any> = {};
                for (const chunk of chunks) {
                    const q = query(collection(db, 'simulados_exams'), where(documentId(), 'in', chunk));
                    const snap = await getDocs(q);
                    snap.forEach(doc => details[doc.id] = doc.data());
                }
                setSimuladosDetails(details);
            } catch (error) {
                console.error("Erro ao buscar detalhes:", error);
            }
        };
        fetchSimuladoDetails();
    }, [planData]);

    // 3. CÁLCULO DE STATUS
    useEffect(() => {
        if (!planData || !planData.cycles) return;

        const blocked: ComputedSimulado[] = [];
        const released: ComputedSimulado[] = [];
        const completedMetaIds = new Set(
            schedule.filter((s: any) => s.status === 'completed').map((s: any) => s.metaId)
        );
        let accumulatedPrerequisites: string[] = [];

        planData.cycles.forEach((cycle: any, cIndex: number) => {
            if (!cycle.items) return;
            cycle.items.forEach((item: any) => {
                if (item.type === 'simulado') {
                    const simuladoId = item.simuladoId || item.id;
                    const realData = simuladosDetails[simuladoId];
                    const realDuration = realData?.duration ? Number(realData.duration) : (item.duration ? Number(item.duration) : 240);
                    const realPdfUrl = realData?.arquivoProvaUrl || realData?.pdfUrl;
                    const scheduledItem = schedule.find((s: any) => s.metaId === simuladoId && s.type === 'simulado' && s.status !== 'completed');
                    const allPrerequisitesMet = accumulatedPrerequisites.every(id => completedMetaIds.has(id));

                    const simuladoObj: ComputedSimulado = {
                        id: simuladoId,
                        title: item.simuladoTitle || item.title || 'Simulado Oficial',
                        duration: realDuration,
                        status: 'blocked',
                        pdfUrl: realPdfUrl,
                        date: scheduledItem ? (scheduledItem.date.toDate ? scheduledItem.date.toDate() : new Date(scheduledItem.date)) : undefined
                    };

                    if (scheduledItem) {
                        simuladoObj.status = 'scheduled';
                        released.push(simuladoObj); 
                    } else if (allPrerequisitesMet) {
                        simuladoObj.status = 'released';
                        released.push(simuladoObj);
                    } else {
                        simuladoObj.status = 'blocked';
                        blocked.push(simuladoObj);
                    }
                } else {
                    const metasInItem = extractMetaIdsFromItem(item);
                    accumulatedPrerequisites = [...accumulatedPrerequisites, ...metasInItem];
                }
            });
        });
        released.sort((a, b) => (a.status === 'scheduled' ? -1 : 1));
        setComputedSimulados({ blocked, released });
    }, [planData, schedule, simuladosDetails, userData]);

    const extractMetaIdsFromItem = (item: any): string[] => {
        const ids: string[] = [];
        if (!planData?.disciplines) return ids;

        let targetDisciplines = [];
        if (item.type === 'discipline') {
            targetDisciplines = planData.disciplines.filter((d: any) => d.id === item.referenceId);
        } else if (item.type === 'folder') {
            targetDisciplines = planData.disciplines.filter((d: any) => d.folderId === item.referenceId);
        }

        targetDisciplines.forEach((disc: any) => {
            disc.topics?.forEach((topic: any) => {
                topic.metas?.forEach((meta: any) => {
                    ids.push(meta.id);
                });
            });
        });

        return ids;
    };

    const handleScheduleSimulado = async (date: Date) => {
        if (!showScheduleModal || !user || !planData) return;
        const simuladoToSchedule = computedSimulados.released.find(s => s.id === showScheduleModal);
        if (!simuladoToSchedule) return;
        try {
            await scheduleUserSimulado(user.uid, planData.id, simuladoToSchedule, date);
            window.location.reload(); 
        } catch (error) {
            console.error("Erro ao agendar:", error);
            alert("Erro ao agendar simulado.");
        }
    };

    const handleCompleteSimulado = async (docId: string) => {
        try {
            const goalRef = doc(db, 'student_schedule', docId);
            await updateDoc(goalRef, { status: 'completed', completedAt: new Date() });
            setSchedule(prev => prev.map((item: any) => item.docId === docId ? { ...item, status: 'completed' } : item));
            setIsExamMode(false);
            setActiveSimulado(null);
        } catch (error) {
            console.error("Erro ao concluir:", error);
        }
    };

    // NOVA FUNÇÃO: Iniciar Prova (Após confirmação)
    const confirmStartExam = () => {
        if (showStartConfirmation) {
            setActiveSimulado(showStartConfirmation);
            setIsExamMode(true);
            setShowStartConfirmation(null);
        }
    };

    return (
        <div className="w-full max-w-7xl mx-auto p-4 md:p-8">

            {/* --- MODO FOCO --- */}
            {isExamMode && activeSimulado && (
                <SimuladoFocusMode 
                    simulado={{
                        id: activeSimulado.docId, 
                        title: activeSimulado.title,
                        duration: activeSimulado.duration || 60,
                        pdfUrl: activeSimulado.pdfUrl // Passando PDF para o modo foco
                    }}
                    onClose={() => setIsExamMode(false)}
                    onComplete={() => handleCompleteSimulado(activeSimulado.docId)}
                />
            )}

            {/* SEÇÃO DE SIMULADOS (DISPONÍVEIS/BLOQUEADOS) */}
            {(computedSimulados.released.length > 0 || computedSimulados.blocked.length > 0) && (
                <div className="mb-10 space-y-8 border-b border-gray-800 pb-8">
                    {computedSimulados.released.length > 0 && (
                        <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                            <div className="flex items-center gap-3 mb-4">
                                <span className="w-1.5 h-6 bg-yellow-500 rounded-full shadow-[0_0_15px_rgba(234,179,8,0.6)]"></span>
                                <h2 className="text-white font-black text-2xl uppercase tracking-wider">Simulados</h2>
                            </div>
                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
                                {computedSimulados.released.map(sim => (
                                    <SimuladoGoalCard key={sim.id} simulado={sim} onSchedule={(id) => setShowScheduleModal(id)} />
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* --- METAS AGENDADAS PARA HOJE (LAYOUT CORRIGIDO) --- */}
            <div className="mb-8">
                {schedule.some((s:any) => s.type === 'simulado' && s.status === 'pending') && (
                    <h3 className="text-gray-400 font-bold text-sm uppercase tracking-wider mb-4 flex items-center gap-2">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        Metas de Prova (Hoje)
                    </h3>
                )}

                <div className="space-y-6">
                    {schedule.filter((s: any) => s.type === 'simulado' && s.status === 'pending').map((simulado: any, idx) => {
                        // Resgata o PDF
                        const pdfFile = simulado.files?.[0];
                        const pdfUrl = pdfFile?.url || simuladosDetails[simulado.metaId]?.pdfUrl;

                        return (
                            <div key={idx} className="bg-black border border-yellow-600/50 rounded-xl overflow-hidden shadow-[0_0_20px_rgba(234,179,8,0.1)]">

                                {/* CONTEÚDO PRINCIPAL */}
                                <div className="p-6 md:p-8 relative">
                                    <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-yellow-500"></div>

                                    <div className="flex flex-col md:flex-row items-start md:items-center gap-6">
                                        <div className="p-4 bg-yellow-500/10 rounded-xl text-yellow-500 border border-yellow-500/20 shrink-0">
                                            <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>
                                        </div>
                                        <div className="flex-1">
                                            <div className="flex items-center gap-3 mb-2">
                                                <h4 className="text-yellow-500 font-black text-xs uppercase tracking-widest">META DE SIMULADO</h4>
                                                <span className="bg-gray-800 text-gray-400 text-[10px] px-2 py-0.5 rounded border border-gray-700 font-mono">ID: {simulado.metaId.slice(0,6)}</span>
                                            </div>
                                            <h3 className="text-white font-bold text-2xl leading-tight">{simulado.title}</h3>
                                            <div className="flex items-center gap-4 mt-3">
                                                <span className="text-gray-400 text-sm flex items-center gap-1.5">
                                                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                                    {Math.floor(simulado.duration / 60)}h Duração
                                                </span>
                                                <span className={`text-sm flex items-center gap-1.5 ${pdfUrl ? 'text-green-500' : 'text-red-500'}`}>
                                                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                                    {pdfUrl ? 'Caderno Disponível' : 'Caderno Pendente'}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* SOLICITAÇÃO 1: RODAPÉ COM BOTÕES CENTRALIZADOS */}
                                <div className="bg-[#15171b] p-4 border-t border-gray-800 flex flex-col sm:flex-row justify-center items-center gap-4">
                                    <button 
                                        onClick={() => setExpandedSimulado(expandedSimulado === simulado.metaId ? null : simulado.metaId)}
                                        className={`w-full sm:w-auto px-6 py-3 rounded-lg font-bold text-xs uppercase tracking-wider border transition-all flex justify-center items-center gap-2
                                            ${expandedSimulado === simulado.metaId ? 'bg-gray-800 border-gray-600 text-white' : 'bg-transparent border-gray-700 text-gray-400 hover:text-white hover:border-gray-500'}
                                        `}
                                    >
                                        {expandedSimulado === simulado.metaId ? 'Ocultar Materiais' : 'Ver Materiais'}
                                        <svg className={`w-4 h-4 transition-transform ${expandedSimulado === simulado.metaId ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7 7" /></svg>
                                    </button>

                                    {/* SOLICITAÇÃO 2: ABRE POPUP DE CONFIRMAÇÃO AO INVÉS DE INICIAR DIRETO */}
                                    <button 
                                        onClick={() => setShowStartConfirmation({ ...simulado, pdfUrl })}
                                        className="w-full sm:w-auto px-10 py-3 bg-yellow-500 hover:bg-yellow-400 text-black font-black text-sm rounded-lg uppercase tracking-wider transition-all shadow-lg shadow-yellow-900/30 flex justify-center items-center gap-2 transform hover:scale-105"
                                    >
                                        <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                                        INICIAR PROVA
                                    </button>
                                </div>

                                {/* ACORDEÃO INTELIGENTE (PDF) */}
                                {expandedSimulado === simulado.metaId && (
                                    <div className="border-t border-gray-800 bg-[#0f1115] p-6 animate-in slide-in-from-top-2">
                                        <h4 className="text-gray-400 font-bold text-xs uppercase mb-3">Material de Apoio</h4>

                                        {pdfUrl ? (
                                            <div className="flex items-center justify-between p-4 rounded-lg bg-[#1a1d24] border border-gray-700 hover:border-gray-500 transition-colors group">
                                                <div className="flex items-center gap-3">
                                                    <div className="p-2 bg-red-500/10 text-red-500 rounded">
                                                        <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
                                                    </div>
                                                    <div>
                                                        <p className="text-white font-bold text-sm">Caderno de Questões Oficial</p>
                                                        <p className="text-gray-500 text-xs">PDF • Clique para abrir</p>
                                                    </div>
                                                </div>
                                                <a href={pdfUrl} target="_blank" rel="noopener noreferrer" className="px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white text-xs font-bold rounded uppercase transition-colors">
                                                    Abrir PDF
                                                </a>
                                            </div>
                                        ) : (
                                            <div className="text-gray-600 text-sm italic p-4 text-center border border-gray-800 border-dashed rounded">
                                                Nenhum caderno PDF encontrado.
                                            </div>
                                        )}

                                        <div className="mt-4 p-4 bg-yellow-900/10 border border-yellow-500/20 rounded-lg flex gap-3">
                                            <svg className="w-5 h-5 text-yellow-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                            <p className="text-xs text-yellow-200/80 leading-relaxed">
                                                <strong>Dica:</strong> Abra o PDF antes de iniciar a prova. O modo foco bloqueará outras ações na tela.
                                            </p>
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Modal de Agendamento */}
            {showScheduleModal && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 p-4 backdrop-blur-sm">
                    <div className="bg-[#1a1d24] p-8 rounded-2xl w-full max-w-md border border-gray-700 shadow-2xl">
                        <div className="text-center mb-6">
                            <h3 className="text-white font-black text-xl uppercase">Agendar Simulado</h3>
                            <p className="text-gray-400 text-sm mt-2">Escolha um dia exclusivo.</p>
                        </div>
                        <input type="date" className="w-full bg-black text-white p-4 rounded-xl border border-gray-600 mb-6 focus:border-yellow-500 outline-none text-center font-bold" onChange={(e) => handleScheduleSimulado(new Date(e.target.value))} />
                        <button onClick={() => setShowScheduleModal(null)} className="w-full py-3 text-gray-500 hover:text-white text-sm font-bold uppercase tracking-wider">Cancelar</button>
                    </div>
                </div>
            )}

            {/* SOLICITAÇÃO 2: POPUP DE CONFIRMAÇÃO DE INÍCIO */}
            {showStartConfirmation && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/95 p-4 backdrop-blur-md animate-in fade-in duration-200">
                    <div className="bg-[#1a1d24] p-8 rounded-2xl w-full max-w-lg border border-red-600/30 shadow-[0_0_50px_rgba(220,38,38,0.2)]">
                        <div className="flex flex-col items-center text-center">
                            <div className="w-16 h-16 bg-red-600/10 rounded-full flex items-center justify-center mb-6 text-red-500 border border-red-500/20">
                                <svg className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            </div>
                            <h3 className="text-white font-black text-2xl uppercase mb-2">Atenção!</h3>
                            <p className="text-gray-300 text-sm leading-relaxed mb-6">
                                Você está prestes a iniciar o simulado <strong>{showStartConfirmation.title}</strong>.
                                <br/><br/>
                                <span className="text-red-400 font-bold block bg-red-900/10 p-2 rounded">
                                    O cronômetro iniciará imediatamente e NÃO poderá ser pausado.
                                </span>
                            </p>

                            <div className="flex flex-col w-full gap-3">
                                <button 
                                    onClick={confirmStartExam}
                                    className="w-full py-4 bg-red-600 hover:bg-red-500 text-white font-black text-sm rounded-xl uppercase tracking-wider transition-all shadow-lg"
                                >
                                    Estou pronto, Iniciar Agora
                                </button>
                                <button 
                                    onClick={() => setShowStartConfirmation(null)}
                                    className="w-full py-3 bg-transparent border border-gray-700 hover:border-gray-500 text-gray-400 hover:text-white font-bold text-sm rounded-xl uppercase tracking-wider transition-all"
                                >
                                    Cancelar
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { 
  CheckCircle2, ChevronDown, PlayCircle, FileText, 
  ListChecks, Book, Edit3, RefreshCw, ExternalLink, Download, 
  Play, Plus, Trash2, Eye, Pencil, BrainCircuit, Layers, X, Loader2,
  AlertTriangle, TextCursor, BookOpen, Lock, Trophy
} from 'lucide-react';
import { Meta, MetaType, MindMapNode } from '../../../services/metaService';
import { isPandaVideo } from '../../../utils/videoHelpers';
import { openWatermarkedPdf } from '../../../utils/pdfSecurityService';
import { useAuth } from '../../../contexts/AuthContext';
import { 
  getUserContent, 
  createUserContent, 
  deleteUserContent, 
  updateUserContent,
  UserContentType, 
  UserContentItem 
} from '../../../services/userContentService';
import MindMapViewerModal from '../MindMapViewerModal';
import FlashcardPlayerModal from '../FlashcardPlayerModal';
import MindMapFullscreen from '../../admin/metas/tools/mindmap/MindMapFullscreen';
import FlashcardFullscreenEditor from '../../admin/metas/tools/FlashcardFullscreenEditor';
import NotebookEditorModal from '../tools/NotebookEditorModal';

interface LinkedGoalItemProps {
  goal: Meta;
  isCompleted: boolean;
  activeUserMode: boolean;
  planId?: string; // Required for User Content
  onToggleComplete: (goal: Meta) => void;
  onPlayVideo?: (url: string) => void;
}

const TYPE_CONFIG: Record<MetaType, { label: string; color: string; icon: any }> = {
  lesson: { label: 'AULA', color: '#3b82f6', icon: PlayCircle },
  material: { label: 'PDF', color: '#f97316', icon: FileText },
  questions: { label: 'QUESTÕES', color: '#10b981', icon: ListChecks },
  law: { label: 'LEI SECA', color: '#eab308', icon: Book },
  review: { label: 'REVISÃO', color: '#ec4899', icon: RefreshCw },
  summary: { label: 'RESUMO', color: '#a855f7', icon: Edit3 },
  simulado: { label: 'SIMULADO', color: '#EAB308', icon: Trophy },
};

const LinkedGoalItem: React.FC<LinkedGoalItemProps> = ({ 
  goal, 
  isCompleted, 
  activeUserMode, 
  planId,
  onToggleComplete,
  onPlayVideo
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const { currentUser, userData } = useAuth();
  const [loadingPdf, setLoadingPdf] = useState(false);

  // User Content State
  const [userItems, setUserItems] = useState<UserContentItem[]>([]);
  const [loadingContent, setLoadingContent] = useState(false);

  // Creation Modal State
  const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);
  const [newItemTitle, setNewItemTitle] = useState('');
  const [isCreating, setIsCreating] = useState(false);

  // Rename Modal State
  const [itemToRename, setItemToRename] = useState<UserContentItem | null>(null);
  const [renameTitle, setRenameTitle] = useState('');
  const [isRenaming, setIsRenaming] = useState(false);

  // Deletion Modal State
  const [itemToDelete, setItemToDelete] = useState<UserContentItem | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Confirmation Modal State
  const [showConfirmModal, setShowConfirmModal] = useState(false);

  // Admin Content Viewers State
  const [isAdminMapOpen, setIsAdminMapOpen] = useState(false);
  const [isAdminFlashcardOpen, setIsAdminFlashcardOpen] = useState(false);

  // User Content Editor State
  const [activeUserItem, setActiveUserItem] = useState<UserContentItem | null>(null);
  const [userEditorMode, setUserEditorMode] = useState<'VIEW' | 'EDIT'>('VIEW');
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'success'>('idle');

  const config = TYPE_CONFIG[goal.type] || TYPE_CONFIG.lesson;
  const GoalIcon = config.icon;
  const metaColor = goal.color || config.color || '#71717a';

  const isSummary = goal.type === 'summary';
  const isReview = goal.type === 'review';
  const isQuestions = goal.type === 'questions';
  const supportsUserContent = isSummary || isReview || isQuestions;

  // Check for Admin Content
  const hasAdminMindMap = isSummary && goal.summaryConfig?.mindMap && goal.summaryConfig.mindMap.length > 0;
  const hasAdminFlashcards = isReview && goal.flashcardConfig?.cards && goal.flashcardConfig.cards.length > 0;

  // --- HELPER: GET CONTENT TYPE & UI CONFIG ---
  const getUserContentType = (): UserContentType | null => {
    if (isSummary) return 'MAP';
    if (isReview) return 'FLASHCARD';
    if (isQuestions) return 'NOTEBOOK';
    return null;
  };

  const getUserContentUI = () => {
    if (isSummary) return { label: 'Meus Mapas Mentais', itemLabel: 'Mapa', btnLabel: 'NOVO MAPA', icon: BrainCircuit, color: '#a855f7' }; // Purple
    if (isReview) return { label: 'Meus Flashcards', itemLabel: 'Deck', btnLabel: 'NOVO DECK', icon: Layers, color: '#ec4899' }; // Pink
    if (isQuestions) return { label: 'Meus Cadernos', itemLabel: 'Caderno', btnLabel: 'NOVO CADERNO', icon: BookOpen, color: '#eab308' }; // Yellow
    return null;
  };

  const uiConfig = getUserContentUI();

  // --- EFFECT: LOAD USER CONTENT ---
  useEffect(() => {
    if (isOpen && supportsUserContent && currentUser && planId && goal.id) {
        loadUserContent();
    }
  }, [isOpen, currentUser, planId]);

  const loadUserContent = async () => {
    if (!currentUser || !planId || !goal.id) return;
    const type = getUserContentType();
    if (!type) return;

    setLoadingContent(true);
    try {
        const items = await getUserContent(currentUser.uid, planId, goal.id, type);
        setUserItems(items);
    } catch (error) {
        console.error("Failed to load user content", error);
    } finally {
        setLoadingContent(false);
    }
  };

  // --- HELPER: INITIAL MAP DATA ---
  const getInitialMapData = (title: string): MindMapNode[] => {
    return [{
      id: crypto.randomUUID(),
      label: title,
      x: 0,
      y: 0,
      color: '#a855f7',
      type: 'root'
    }];
  };

  // --- CONTENT HANDLERS ---

  const handleCreateConfirm = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !planId || !goal.id || !newItemTitle.trim()) return;

    const type = getUserContentType();
    if (!type) return;

    setIsCreating(true);
    try {
        await createUserContent(currentUser.uid, planId, goal.id, type, newItemTitle);
        await loadUserContent(); // Refresh list
        setIsCreateModalOpen(false);
        setNewItemTitle('');
    } catch (error: any) {
        alert(error.message);
    } finally {
        setIsCreating(false);
    }
  };

  const handleOpenUserItem = (item: UserContentItem, mode: 'VIEW' | 'EDIT') => {
    setActiveUserItem(item);
    setUserEditorMode(mode);
  };

  const handleSaveUserContent = async (contentData: any) => {
    if (!currentUser || !planId || !activeUserItem) return;

    setSaveStatus('saving');

    try {
        // 1. Update Firestore
        // FIXED: Now we pass { data: contentData } explicitly because the service is generic
        await updateUserContent(currentUser.uid, planId, activeUserItem.id, { data: contentData });

        // 2. Update Active Item State (Critical for Editor persistence without closing)
        setActiveUserItem(prev => prev ? { ...prev, data: contentData } : null);

        // 3. Update List State (Background refresh)
        await loadUserContent();

        setSaveStatus('success');
        setTimeout(() => setSaveStatus('idle'), 3000);

        // Auto-close if editing flashcards (matches Admin behavior)
        if (activeUserItem.type === 'FLASHCARD' && userEditorMode === 'EDIT') {
             setActiveUserItem(null);
        }
        // NOTEBOOK does not auto-close to allow continuous editing
    } catch (error) {
        console.error("Failed to save user content", error);
        alert("Erro ao salvar conteúdo.");
        setSaveStatus('idle');
    }
  };

  const handleRenameConfirm = async () => {
    if (!currentUser || !planId || !itemToRename || !renameTitle.trim()) return;

    setIsRenaming(true);
    try {
        await updateUserContent(currentUser.uid, planId, itemToRename.id, { title: renameTitle.toUpperCase() });
        await loadUserContent();
        setItemToRename(null);
        setRenameTitle('');
    } catch (error) {
        console.error("Failed to rename", error);
        alert("Erro ao renomear.");
    } finally {
        setIsRenaming(false);
    }
  };

  const handleConfirmDelete = async () => {
    if (!currentUser || !planId || !itemToDelete) return;
    setIsDeleting(true);
    try {
        await deleteUserContent(currentUser.uid, planId, itemToDelete.id);
        setUserItems(prev => prev.filter(i => i.id !== itemToDelete.id));
        setItemToDelete(null); // Fecha modal
    } catch (error) {
        console.error(error);
        alert("Erro ao excluir.");
    } finally {
        setIsDeleting(false);
    }
  };

  const handleOpenPdf = async (url: string) => {
    if (!currentUser || loadingPdf) return;
    setLoadingPdf(true);
    try {
      await openWatermarkedPdf(url, {
        email: currentUser.email || '',
        cpf: userData?.cpf || '000.000.000-00'
      });
    } catch (error) {
      console.error(error);
      alert("Erro ao abrir documento protegido.");
    } finally {
      setLoadingPdf(false);
    }
  };

  const handleCheckClick = (e: React.MouseEvent) => {
    e.stopPropagation();

    // TRAVA DO USUÁRIO ATIVO
    if (!activeUserMode) {
      alert("A conclusão manual está desativada para este plano. Siga o cronograma ou ative o 'Usuário Ativo'.");
      return;
    }

    // Se já estiver concluído, executa direto (undo). Se não, abre modal.
    if (!isCompleted) {
        setShowConfirmModal(true);
    } else {
        onToggleComplete(goal);
    }
  };

  const confirmCompletion = () => {
      onToggleComplete(goal);
      setShowConfirmModal(false);
  };

  const getReviewCount = () => {
    if (!goal.reviewConfig?.active) return null;

    const intervals = goal.reviewConfig.intervals.split(',').filter(i => i.trim());
    const total = intervals.length;

    if (total === 0) return null;

    // Recupera progresso se disponível, senão 0
    const completed = (goal as any).completedReviewsCount || (goal as any).completedReviews || 0;
    const isAllDone = total > 0 && completed >= total;

    return (
      <span 
        className={`
            text-[9px] font-mono px-1.5 py-0.5 rounded ml-2 flex items-center gap-1 border
            ${isAllDone 
                ? 'text-emerald-400 bg-emerald-950/30 border-emerald-500/30' 
                : 'text-zinc-500 bg-zinc-900 border-zinc-700'}
        `}
        title={`${completed} de ${total} revisões concluídas`}
      >
        <RefreshCw size={8} className={isAllDone ? 'text-emerald-500' : ''} />
        {completed}/{total} Rev
      </span>
    );
  };

  return (
    <>
    <div 
      className="border-l-2 ml-5 pl-4 mb-2 relative group transition-colors"
      style={{ borderColor: metaColor }}
    >
      {/* HEADER */}
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className={`
          flex items-center justify-between p-3 rounded-xl border cursor-pointer transition-all
          ${isCompleted 
            ? 'bg-zinc-950/30 border-zinc-800/50 opacity-70 hover:opacity-100' 
            : 'bg-zinc-900/40 border-zinc-800 hover:bg-zinc-900 hover:border-zinc-700'}
        `}
      >
        <div className="flex items-center gap-3 overflow-hidden">
          <button
            onClick={handleCheckClick}
            className={`
              shrink-0 w-5 h-5 rounded-md flex items-center justify-center border transition-all
              ${isCompleted 
                ? 'bg-emerald-500 border-emerald-500 text-black' 
                : !activeUserMode 
                    ? 'bg-zinc-900 border-zinc-700 text-zinc-600 cursor-not-allowed opacity-50' 
                    : 'bg-transparent border-zinc-600 text-transparent hover:border-zinc-400 cursor-pointer'}
            `}
            title={activeUserMode ? "Marcar como concluído" : "A conclusão manual está desativada neste plano"}
          >
            {isCompleted ? (
                <CheckCircle2 size={14} strokeWidth={3} />
            ) : !activeUserMode ? (
                <Lock size={12} />
            ) : (
                <CheckCircle2 size={14} strokeWidth={3} />
            )}
          </button>

          <div 
            className="shrink-0 p-1.5 rounded-md flex items-center justify-center border border-white/5"
            style={{ 
              color: metaColor, 
              backgroundColor: `${metaColor}1A`
            }}
          >
             <GoalIcon size={16} />
          </div>

          <div className="flex flex-col min-w-0">
            <div className="flex items-center gap-2">
              <span className={`text-xs font-bold truncate ${isCompleted ? 'text-zinc-500 line-through' : 'text-zinc-200'}`}>
                {goal.title}
              </span>
            </div>

            <div className="flex items-center gap-2 mt-1 flex-wrap">
              <span 
                className="text-[9px] font-black uppercase px-1.5 py-0.5 rounded border tracking-wide"
                style={{ 
                    color: metaColor, 
                    borderColor: `${metaColor}40`, 
                    backgroundColor: `${metaColor}10` 
                }}
              >
                {config.label}
              </span>
              {getReviewCount()}
              {(goal.videos?.length || 0) > 0 && <span className="text-[9px] text-zinc-600 font-medium">• {goal.videos?.length} Aulas</span>}
              {(goal.files?.length || 0) > 0 && <span className="text-[9px] text-zinc-600 font-medium">• {goal.files?.length} PDFs</span>}
            </div>
          </div>
        </div>

        <div className={`text-zinc-600 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}>
          <ChevronDown size={16} />
        </div>
      </div>

      {/* CONTENT BODY */}
      {isOpen && (
        <div className="mt-2 space-y-2 animate-in slide-in-from-top-1 duration-200 pl-2">

          {/* 1. VIDEOS */}
          {goal.type === 'lesson' && goal.videos?.map((video, idx) => (
            <div 
                key={idx} 
                className="flex items-start justify-between p-3 bg-zinc-900/50 rounded-lg border border-zinc-800/50 hover:bg-zinc-900 transition-colors group/video"
            >
                <div className="flex items-start gap-3 w-full">
                    <button 
                        onClick={() => isPandaVideo(video.link) && onPlayVideo ? onPlayVideo(video.link) : window.open(video.link, '_blank')}
                        className="w-8 h-8 rounded-full bg-red-600/20 text-red-500 flex items-center justify-center group-hover/video:bg-red-600 group-hover/video:text-white transition-all shrink-0 mt-0.5"
                    >
                        <Play size={12} className="ml-0.5" fill="currentColor" />
                    </button>

                    <div className="flex flex-col min-w-0 flex-1">
                        <span className="text-xs text-zinc-300 font-medium whitespace-normal break-words leading-tight">
                            {video.title || `Aula ${idx + 1}`}
                        </span>
                        <span className="text-[9px] text-zinc-600 font-mono flex items-center gap-1 mt-1">
                            {isPandaVideo(video.link) ? 'Player Interno' : 'Link Externo'} • {video.duration} min
                        </span>
                    </div>
                </div>
            </div>
          ))}

          {/* 2. FILES (Dynamic Color) */}
          {goal.files?.map((file, idx) => (
            <button
              key={idx}
              onClick={() => handleOpenPdf(file.url)}
              disabled={loadingPdf}
              className="w-full flex items-center justify-between p-2.5 rounded-lg border transition-all text-left group/file mb-1 hover:border-white/10"
              style={{ backgroundColor: `${metaColor}0D`, borderColor: 'transparent' }}
            >
              <div className="flex items-center gap-3">
                <div 
                    className="p-1.5 rounded"
                    style={{ backgroundColor: `${metaColor}1A`, color: metaColor }}
                >
                  <FileText size={14} />
                </div>
                <span className="text-xs font-medium text-zinc-300 group-hover/file:text-white transition-colors">{file.name}</span>
              </div>
              {loadingPdf ? (
                 <span className="text-[9px] animate-pulse" style={{ color: metaColor }}>Abrindo...</span>
              ) : (
                 <Download size={14} className="text-zinc-600 group-hover/file:text-white transition-colors" />
              )}
            </button>
          ))}

          {/* 3. LINKS (Dynamic Color) */}
          {goal.links?.map((link, idx) => (
            <a
              key={idx}
              href={link.url}
              target="_blank"
              rel="noreferrer"
              className="flex items-center gap-3 p-2.5 rounded-lg border transition-all group/link mb-1 hover:border-white/10"
              style={{ backgroundColor: `${metaColor}0D`, borderColor: 'transparent' }}
            >
              <div 
                className="p-1.5 rounded"
                style={{ backgroundColor: `${metaColor}1A`, color: metaColor }}
              >
                <ExternalLink size={14} />
              </div>
              <div className="flex flex-col min-w-0">
                <span className="text-xs font-medium truncate transition-colors" style={{ color: metaColor }}>{link.name}</span>
                <span className="text-[9px] text-zinc-600 truncate">{link.url}</span>
              </div>
            </a>
          ))}

          {/* 4. ADMIN CONTENT (Dynamic Color) */}
          {(hasAdminMindMap || hasAdminFlashcards) && (
             <div 
                className="mt-2 mb-2 p-2 border rounded-lg flex items-center justify-between group/admin transition-colors"
                style={{ 
                    borderColor: `${metaColor}30`, 
                    backgroundColor: `${metaColor}10` 
                }}
             >
                <div className="flex items-center gap-2">
                    {hasAdminMindMap ? (
                        <BrainCircuit size={16} style={{ color: metaColor }} />
                    ) : (
                        <Layers size={16} style={{ color: metaColor }} />
                    )}
                    <div className="flex flex-col">
                        <span className="text-[10px] font-black uppercase tracking-wider" style={{ color: metaColor }}>
                            {hasAdminMindMap ? 'Mapa Mental' : 'Flashcards'}
                        </span>
                        <span className="text-[9px] font-medium" style={{ color: metaColor, opacity: 0.7 }}>
                            Material Oficial do Curso
                        </span>
                    </div>
                </div>
                <button 
                    onClick={() => hasAdminMindMap ? setIsAdminMapOpen(true) : setIsAdminFlashcardOpen(true)}
                    className="px-3 py-1.5 text-white text-[9px] font-bold uppercase rounded transition-colors flex items-center gap-1.5 hover:brightness-110 shadow-sm"
                    style={{ backgroundColor: metaColor }}
                >
                    {hasAdminMindMap ? <Eye size={10} /> : <Play size={10} />}
                    Visualizar
                </button>
             </div>
          )}

          {/* 5. USER CONTENT SECTION (My Maps / My Flashcards / My Notebooks) */}
          {supportsUserContent && uiConfig && (
            <div className="mt-4 pt-3 border-t border-zinc-800/50">
               <div className="flex items-center justify-between mb-3">
                  <span className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2" style={{ color: uiConfig.color }}>
                     <uiConfig.icon size={12} />
                     {uiConfig.label}
                  </span>
                  <span className={`text-[9px] font-mono ${userItems.length >= 5 ? 'text-red-500' : 'text-zinc-600'}`}>
                     {userItems.length}/5 Criados
                  </span>
               </div>

               <div className="space-y-2">
                  {userItems.map(item => (
                     <div key={item.id} className="flex items-center justify-between p-2.5 bg-zinc-900 rounded-lg border border-zinc-800 group hover:border-zinc-700 transition-colors">
                        <span className="text-xs font-medium text-zinc-300 uppercase truncate max-w-[150px]">
                           {item.title}
                        </span>
                        <div className="flex items-center gap-1 opacity-60 group-hover:opacity-100 transition-opacity">
                           <button 
                              onClick={() => handleOpenUserItem(item, 'VIEW')}
                              className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-colors" 
                              title="Visualizar"
                           >
                              <Eye size={12} />
                           </button>
                           <button 
                              onClick={() => handleOpenUserItem(item, 'EDIT')}
                              className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-colors" 
                              title="Editar Conteúdo"
                           >
                              <Pencil size={12} />
                           </button>

                           {/* Rename Button - UPDATED ICON */}
                           <button 
                              onClick={(e) => { 
                                  e.stopPropagation(); 
                                  setItemToRename(item); 
                                  setRenameTitle(item.title); 
                              }}
                              className="p-1.5 hover:bg-zinc-800 rounded text-zinc-400 hover:text-white transition-colors" 
                              title="Renomear"
                           >
                              <TextCursor size={12} />
                           </button>

                           <button 
                              onClick={(e) => { e.stopPropagation(); setItemToDelete(item); }}
                              className="p-1.5 hover:bg-red-900/20 rounded text-zinc-400 hover:text-red-500 transition-colors" 
                              title="Excluir"
                           >
                              <Trash2 size={12} />
                           </button>
                        </div>
                     </div>
                  ))}

                  {/* Create Button */}
                  {userItems.length < 5 && (
                     <button 
                        onClick={() => setIsCreateModalOpen(true)}
                        className="w-full py-2.5 border border-dashed border-zinc-800 hover:border-zinc-600 rounded-lg text-[10px] font-bold text-zinc-500 hover:text-white hover:bg-zinc-900 transition-all flex items-center justify-center gap-2"
                     >
                        <Plus size={12} />
                        {uiConfig.btnLabel}
                     </button>
                  )}
               </div>
            </div>
          )}

          {/* EMPTY STATE */}
          {(!goal.videos?.length && !goal.files?.length && !goal.links?.length && !supportsUserContent && !hasAdminMindMap && !hasAdminFlashcards) && (
             <div className="p-3 text-center border border-dashed border-zinc-800 rounded-lg">
                <p className="text-[10px] text-zinc-600 uppercase font-bold">Sem conteúdo anexado</p>
             </div>
          )}

        </div>
      )}
    </div>

    {/* --- MODAL: CREATE USER CONTENT --- */}
    {isCreateModalOpen && createPortal(
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
        <div 
            className="w-full max-w-sm bg-zinc-950 border border-zinc-800 rounded-2xl shadow-2xl p-6 animate-in zoom-in-95 duration-200"
            onClick={e => e.stopPropagation()}
        >
            <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                    Novo {uiConfig?.itemLabel}
                </h3>
                <button onClick={() => setIsCreateModalOpen(false)} className="text-zinc-500 hover:text-white"><X size={20}/></button>
            </div>

            <form onSubmit={handleCreateConfirm}>
                <div className="space-y-4">
                    <div>
                        <label className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest block mb-1">Título do Material</label>
                        <input 
                            value={newItemTitle}
                            onChange={e => setNewItemTitle(e.target.value)}
                            placeholder={`Ex: Meu ${uiConfig?.itemLabel} 01`}
                            autoFocus
                            className="w-full bg-zinc-900 border border-zinc-800 rounded-xl px-4 py-3 text-sm text-white placeholder-zinc-700 focus:outline-none focus:border-brand-red font-bold uppercase"
                        />
                    </div>
                    <button 
                        type="submit" 
                        disabled={isCreating || !newItemTitle.trim()}
                        className="w-full py-3 bg-brand-red hover:bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg flex items-center justify-center gap-2 disabled:opacity-50"
                    >
                        {isCreating ? <Loader2 size={14} className="animate-spin" /> : <CheckCircle2 size={14} />}
                        Criar Material
                    </button>
                </div>
            </form>
        </div>
      </div>,
      document.body
    )}

    {/* --- MODAL: RENAME USER CONTENT --- */}
    {itemToRename && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setItemToRename(null)}>
            <div 
                className="bg-zinc-950 border border-zinc-800 p-6 rounded-xl w-full max-w-sm shadow-2xl animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                    <TextCursor className="w-5 h-5 text-blue-500" />
                    Renomear Material
                </h3>

                <input 
                    type="text"
                    value={renameTitle}
                    onChange={(e) => setRenameTitle(e.target.value)}
                    className="w-full bg-zinc-900 border border-zinc-800 text-white rounded-xl p-3 mb-6 focus:border-blue-500 outline-none font-bold uppercase"
                    autoFocus
                    placeholder="Novo Título"
                />

                <div className="flex justify-end gap-3">
                    <button 
                        onClick={() => setItemToRename(null)}
                        className="px-4 py-2 text-zinc-400 hover:text-white text-xs font-bold uppercase tracking-widest bg-transparent border border-zinc-800 hover:bg-zinc-900 rounded-lg transition-colors"
                        disabled={isRenaming}
                    >
                        Cancelar
                    </button>
                    <button 
                        onClick={handleRenameConfirm}
                        disabled={isRenaming || !renameTitle.trim()}
                        className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg text-xs font-bold uppercase tracking-widest shadow-lg flex items-center gap-2 disabled:opacity-50"
                    >
                        {isRenaming ? <Loader2 size={12} className="animate-spin" /> : 'Salvar'}
                    </button>
                </div>
            </div>
        </div>
    )}

    {/* --- MODAL: CONFIRM DELETE USER CONTENT --- */}
    {itemToDelete && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setItemToDelete(null)}>
            <div 
                className="bg-zinc-950 border border-zinc-800 p-6 rounded-xl w-full max-w-sm shadow-2xl border-l-4 border-l-red-600 animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                <h3 className="text-lg font-bold text-white mb-2 flex items-center gap-2">
                    <AlertTriangle className="w-5 h-5 text-red-500" />
                    Excluir Material
                </h3>

                <p className="text-zinc-400 text-sm mb-6 leading-relaxed">
                    Tem certeza que deseja excluir permanentemente o item <span className="text-white font-bold uppercase">&quot;{itemToDelete.title}&quot;</span>?
                    <br/>
                    <span className="text-red-400 text-xs font-bold mt-2 block">Esta ação não pode ser desfeita.</span>
                </p>

                <div className="flex justify-end gap-3">
                    <button 
                        onClick={() => setItemToDelete(null)}
                        className="px-4 py-2 text-zinc-400 hover:text-white text-xs font-bold uppercase tracking-widest transition-colors rounded-lg hover:bg-zinc-900"
                        disabled={isDeleting}
                    >
                        Cancelar
                    </button>
                    <button 
                        onClick={handleConfirmDelete}
                        disabled={isDeleting}
                        className="px-4 py-2 bg-red-600 hover:bg-red-500 text-white rounded-lg text-xs font-bold uppercase tracking-widest shadow-lg shadow-red-900/20 flex items-center gap-2 transition-all disabled:opacity-50"
                    >
                        {isDeleting ? <Loader2 size={12} className="animate-spin"/> : <Trash2 size={12} />}
                        {isDeleting ? 'Excluindo...' : 'Sim, Excluir'}
                    </button>
                </div>
            </div>
        </div>
    )}

    {/* --- ADMIN CONTENT VIEWERS --- */}
    {hasAdminMindMap && (
        <MindMapViewerModal 
            isOpen={isAdminMapOpen}
            onClose={() => setIsAdminMapOpen(false)}
            nodes={goal.summaryConfig?.mindMap || []}
            edges={[]}
            title={`Mapa Mental: ${goal.title}`}
            timerState={{ status: 'idle', formattedTime: '00:00' }} // No timer needed in static view
        />
    )}

    {hasAdminFlashcards && (
        <FlashcardPlayerModal 
            isOpen={isAdminFlashcardOpen}
            onClose={() => setIsAdminFlashcardOpen(false)}
            flashcards={goal.flashcardConfig?.cards || []}
            title={`Flashcards: ${goal.title}`}
            timerState={{ status: 'idle', formattedTime: '00:00' }}
            accentColor={metaColor}
        />
    )}

    {/* --- USER CONTENT EDITORS/VIEWERS --- */}

    {/* MAPA MENTAL */}
    {activeUserItem && activeUserItem.type === 'MAP' && createPortal(
        <div className="fixed inset-0 z-[200] w-screen h-screen bg-zinc-950">
            {saveStatus === 'success' && (
                <div className="absolute bottom-24 left-1/2 transform -translate-x-1/2 z-[210] bg-emerald-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 animate-in slide-in-from-bottom-4 fade-in duration-300 border border-emerald-400/50 backdrop-blur-md pointer-events-none">
                    <div className="bg-white/20 p-1 rounded-full">
                        <CheckCircle2 size={16} strokeWidth={3} />
                    </div>
                    <span className="font-bold text-xs tracking-widest uppercase">Mapa Salvo com Sucesso!</span>
                </div>
            )}
            <MindMapFullscreen 
                nodes={(activeUserItem.data && activeUserItem.data.length > 0) ? activeUserItem.data : getInitialMapData(activeUserItem.title)}
                onChange={handleSaveUserContent}
                onClose={() => setActiveUserItem(null)}
                readOnly={userEditorMode === 'VIEW'}
            />
        </div>,
        document.body
    )}

    {/* FLASHCARD EDITOR */}
    {activeUserItem && activeUserItem.type === 'FLASHCARD' && userEditorMode === 'EDIT' && createPortal(
        <div className="fixed inset-0 z-[200] w-screen h-screen bg-zinc-950 flex flex-col animate-in fade-in duration-200">
            <FlashcardFullscreenEditor 
                cards={activeUserItem.data || []}
                onChange={handleSaveUserContent}
                onClose={() => setActiveUserItem(null)}
                accentColor={metaColor}
            />
        </div>,
        document.body
    )}

    {/* FLASHCARD VIEWER */}
    {activeUserItem && activeUserItem.type === 'FLASHCARD' && userEditorMode === 'VIEW' && (
        <FlashcardPlayerModal 
            isOpen={true}
            onClose={() => setActiveUserItem(null)}
            flashcards={activeUserItem.data || []}
            title={activeUserItem.title}
            timerState={{ status: 'idle', formattedTime: '00:00' }} 
            accentColor={metaColor}
        />
    )}

    {/* NOTEBOOK EDITOR (Fullscreen via Portal) */}
    {activeUserItem && activeUserItem.type === 'NOTEBOOK' && createPortal(
        <NotebookEditorModal
            initialData={activeUserItem.data}
            title={activeUserItem.title}
            onSave={handleSaveUserContent}
            onClose={() => setActiveUserItem(null)}
            readOnly={userEditorMode === 'VIEW'}
        />,
        document.body
    )}

    {/* MODAL DE CONFIRMAÇÃO DE CONCLUSÃO MANUAL */}
    {showConfirmModal && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setShowConfirmModal(false)}>
            <div 
                className="bg-zinc-900 border border-zinc-800 p-6 rounded-xl w-full max-w-sm shadow-2xl animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                <div className="flex flex-col items-center text-center gap-4">
                    <div className="p-3 rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 shadow-[0_0_15px_rgba(16,185,129,0.2)]">
                        <CheckCircle2 size={32} />
                    </div>

                    <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                        Concluir Meta?
                    </h3>

                    <div className="text-sm text-zinc-400 leading-relaxed">
                        <p>Você está prestes a marcar a meta <strong>&quot;{goal.title}&quot;</strong> como concluída.</p>
                        <p className="mt-2 text-xs bg-zinc-950 p-2 rounded border border-zinc-800 text-zinc-500">
                            Isso removerá quaisquer agendamentos futuros desta meta do seu calendário.
                        </p>
                    </div>

                    <div className="flex gap-3 w-full mt-2">
                        <button 
                            onClick={() => setShowConfirmModal(false)}
                            className="flex-1 py-3 rounded-lg border border-zinc-700 hover:bg-zinc-800 text-zinc-300 font-bold uppercase text-xs tracking-widest transition-colors"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmCompletion}
                            className="flex-1 py-3 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white font-black uppercase text-xs tracking-widest transition-all shadow-lg shadow-emerald-900/20 flex items-center justify-center gap-2"
                        >
                            Confirmar
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
    )}
    </>
  );
};

export default LinkedGoalItem;

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { 
  ChevronRight, ChevronDown, CheckCircle2, Circle, Folder, Lock, AlertTriangle, Loader2, StickyNote
} from 'lucide-react';
import { EdictTopic, EdictSubtopic, EdictStudyLevel } from '../../../services/edictService';
import { Meta, MetaType } from '../../../services/metaService';
import { useAuth } from '../../../contexts/AuthContext';
import { editalProgressService } from '../../../services/editalProgressService';
import LinkedGoalItem from './LinkedGoalItem';

interface TopicItemProps {
  item: EdictTopic | EdictSubtopic;
  depth?: number;
  completedMetaIds: Set<string>;
  activeUserMode?: boolean;
  metaLookup?: Record<string, Meta>;
  planId?: string;
  studyLevels?: EdictStudyLevel[];
  onToggleGoal?: (goal: Meta) => void;
  onBatchToggle?: (ids: string[], status: boolean) => void; // NEW PROP FOR BATCH UPDATE
  onPlayVideo?: (url: string) => void;
}

const TopicItem: React.FC<TopicItemProps> = ({ 
  item, 
  depth = 0, 
  completedMetaIds, 
  activeUserMode = false,
  metaLookup = {},
  planId,
  studyLevels,
  onToggleGoal,
  onBatchToggle,
  onPlayVideo
}) => {
  const { currentUser } = useAuth();
  const [isExpanded, setIsExpanded] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // --- LOCAL STATE FOR OPTIMISTIC UI ---
  const [localCompletedIds, setLocalCompletedIds] = useState<Set<string>>(new Set());

  // --- STATE VERSIONING FORCED REMOUNT ---
  // Incremented to force React to destroy and recreate child components
  // ensuring they pick up the new "completed" style immediately.
  const [remountToken, setRemountToken] = useState(0);

  // Reset local state if props change (e.g. parent refresh)
  useEffect(() => {
    setLocalCompletedIds(new Set());
    setRemountToken(prev => prev + 1); // Ensure children refresh if parent data changes
  }, [completedMetaIds]);

  // Merge Prop Data + Local Optimistic Data
  const effectiveCompletedIds = useMemo(() => {
    if (localCompletedIds.size === 0) return completedMetaIds;
    const merged = new Set(completedMetaIds);
    localCompletedIds.forEach(id => merged.add(id));
    return merged;
  }, [completedMetaIds, localCompletedIds]);

  // Check for children
  const hasSubtopics = item.subtopics && item.subtopics.length > 0;

  // Check for observation
  const observation = item.observation;
  const hasObservation = !!observation && observation.trim() !== '' && observation.trim() !== '<p><br></p>';

  // Level Logic
  const levelId = item.studyLevelId;
  const levelName = levelId && studyLevels ? studyLevels.find(l => l.id === levelId)?.name : null;

  const getLevelStyle = (name: string) => {
    const norm = name?.toLowerCase() || '';
    if (norm.includes('alta') || norm.includes('muito') || norm.includes('difícil')) 
        return 'border-red-500/30 text-red-400 bg-red-500/10';
    if (norm.includes('média') || norm.includes('media') || norm.includes('médio')) 
        return 'border-yellow-500/30 text-yellow-400 bg-yellow-500/10';
    if (norm.includes('baixa') || norm.includes('fácil') || norm.includes('facil')) 
        return 'border-emerald-500/30 text-emerald-400 bg-emerald-500/10';
    return 'border-zinc-700 text-zinc-400 bg-zinc-800';
  };

  // --- PROGRESS CALCULATION & META GATHERING ---
  const { progressStats, allMetaIds } = useMemo(() => {
    let totalGoals = 0;
    let completedGoals = 0;
    const ids: string[] = [];

    const countGoals = (linkedGoals: any) => {
      if (!linkedGoals) return;
      Object.values(linkedGoals).forEach((idList: any) => {
        if (Array.isArray(idList)) {
          totalGoals += idList.length;
          idList.forEach(id => {
            ids.push(id);
            // Use EFFECTIVE IDs for calculation
            if (effectiveCompletedIds.has(id)) completedGoals++;
          });
        }
      });
    };

    // 1. Count own goals
    countGoals(item.linkedGoals);

    // 2. Recursively count subtopics goals (to show aggregate status on parent)
    const traverse = (t: EdictTopic | EdictSubtopic) => {
        if (t.subtopics) {
            t.subtopics.forEach(sub => {
                countGoals(sub.linkedGoals);
            });
        }
    };
    if (hasSubtopics) traverse(item);

    return { 
        progressStats: { total: totalGoals, completed: completedGoals },
        allMetaIds: ids
    };
  }, [item, hasSubtopics, effectiveCompletedIds]);

  const percentage = progressStats.total > 0 
    ? Math.round((progressStats.completed / progressStats.total) * 100) 
    : 0;

  const isFullyComplete = progressStats.total > 0 && progressStats.completed === progressStats.total;

  // --- HANDLERS ---

  const handleStatusClick = (e: React.MouseEvent) => {
    e.stopPropagation();

    // 1. Active User Guard
    if (!activeUserMode) {
       return; // Lock icon shows this is disabled
    }

    // 2. Logic: Only allow COMPLETING via bulk action.
    if (!isFullyComplete && allMetaIds.length > 0) {
        setShowConfirmModal(true);
    }
  };

  const confirmCompletion = async () => {
    if (!currentUser || !planId) return;
    setIsProcessing(true);
    try {
        // 1. Call Service (Persistence)
        await editalProgressService.completeTopicManually(currentUser.uid, planId, allMetaIds);

        // 2. Optimistic UI Update (Immediate Green Check)
        const newLocal = new Set(localCompletedIds);
        allMetaIds.forEach(id => newLocal.add(id));
        setLocalCompletedIds(newLocal);

        // 3. FORCE VISUAL UPDATE ON CHILDREN
        setRemountToken(prev => prev + 1);

        // 4. Trigger Batch State Update on Parent (Visual Sync Fix)
        if (onBatchToggle) {
             onBatchToggle(allMetaIds, true);
        } else if (onToggleGoal && allMetaIds.length > 0 && metaLookup && metaLookup[allMetaIds[0]]) {
             // Fallback single trigger (Deprecated but safe)
             onToggleGoal(metaLookup[allMetaIds[0]]); 
        }

        setShowConfirmModal(false);
    } catch (error) {
        console.error("Erro ao concluir em lote", error);
        alert("Erro ao salvar progresso.");
    } finally {
        setIsProcessing(false);
    }
  };

  // --- RENDER LINKED GOALS ---
  const renderLinkedGoals = () => {
    if (!item.linkedGoals) return null;

    // Flatten all linked IDs into a list of Meta objects
    const metasToRender: Meta[] = [];
    const types: MetaType[] = ['lesson', 'material', 'questions', 'law', 'summary', 'review'];

    types.forEach(type => {
        const ids = item.linkedGoals[type] || [];
        ids.forEach(id => {
            if (metaLookup[id]) {
                metasToRender.push(metaLookup[id]);
            }
        });
    });

    if (metasToRender.length === 0) return null;

    return (
        <div className="flex flex-col gap-2 mt-2 mb-2 animate-in slide-in-from-left-2 duration-300">
            {metasToRender.map(meta => {
                const isDone = effectiveCompletedIds.has(meta.id!);
                return (
                    <LinkedGoalItem 
                        // FORCE REMOUNT on status change OR manual trigger (remountToken)
                        // This guarantees the component is fresh and green instantly
                        key={`${meta.id}-v${remountToken}-${isDone ? 'done' : 'pending'}`}
                        goal={meta}
                        isCompleted={isDone}
                        activeUserMode={activeUserMode}
                        planId={planId}
                        onToggleComplete={onToggleGoal || (() => {})}
                        onPlayVideo={onPlayVideo}
                    />
                );
            })}
        </div>
    );
  };

  // --- STYLES ---
  const paddingLeft = `${depth * 1.5 + 1}rem`;
  const isTopic = depth === 0;

  return (
    <div className="flex flex-col">
      {/* HEADER ROW */}
      <div 
        className={`
          flex items-center gap-3 p-3 border-b border-zinc-800/50 transition-colors cursor-pointer select-none
          ${isExpanded ? 'bg-zinc-900/50' : 'hover:bg-zinc-900/30'}
          ${isTopic ? 'border-l-2 border-l-transparent hover:border-l-brand-red' : ''}
        `}
        style={{ paddingLeft }}
        onClick={() => setIsExpanded(!isExpanded)}
      >
        {/* Expand Icon */}
        <div className={`text-zinc-500 transition-transform duration-200 ${hasSubtopics ? '' : (progressStats.total > 0 || hasObservation ? '' : 'opacity-0')}`}>
           {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
        </div>

        {/* Title */}
        <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
                <h4 className={`text-sm font-medium truncate ${isFullyComplete ? 'text-zinc-500 line-through' : 'text-zinc-200'}`}>
                    {item.name}
                </h4>
            </div>

            {/* Progress Micro-Bar (Mobile/Desktop) */}
            {progressStats.total > 0 && (
                <div className="flex items-center gap-2 mt-1.5 w-full max-w-[200px]">
                    <div className="h-1 flex-1 bg-zinc-800 rounded-full overflow-hidden">
                        <div 
                            className={`h-full rounded-full transition-all duration-500 ${isFullyComplete ? 'bg-emerald-500' : 'bg-brand-red'}`} 
                            style={{ width: `${percentage}%` }}
                        />
                    </div>
                    <span className={`text-[9px] font-bold ${isFullyComplete ? 'text-emerald-500' : 'text-zinc-500'}`}>
                        {percentage}%
                    </span>
                </div>
            )}
        </div>

        {/* Observation Badge (Collapsed) */}
        {!isExpanded && hasObservation && (
            <div className="mr-2 text-yellow-500/50 flex items-center gap-1" title="Possui observação">
                <StickyNote size={12} />
            </div>
        )}

        {/* Level Badge (Aligned Right, Before Status) */}
        {levelName && (
            <span className={`text-[9px] font-bold uppercase px-2 py-0.5 rounded border tracking-wider shrink-0 ${getLevelStyle(levelName)}`}>
                {levelName}
            </span>
        )}

        {/* Status Icon */}
        <button
            onClick={handleStatusClick}
            disabled={!activeUserMode || isFullyComplete} // Disable if mode off OR already done
            className={`shrink-0 transition-colors ${!activeUserMode ? 'cursor-not-allowed' : (isFullyComplete ? 'cursor-default' : 'cursor-pointer hover:scale-110')}`}
            title={!activeUserMode ? "Modo Automático (Conclusão Manual Bloqueada)" : (isFullyComplete ? "Tópico Concluído" : "Marcar Tópico como Concluído")}
        >
            {isFullyComplete ? (
                <CheckCircle2 size={18} className="text-emerald-500" />
            ) : !activeUserMode ? (
                <Lock size={16} className="text-zinc-700" />
            ) : (
                <Circle size={18} className="text-zinc-600 hover:text-zinc-400" />
            )}
        </button>
      </div>

      {/* BODY (Subtopics + Linked Goals + Observation) */}
      {isExpanded && (
        <div className="animate-in slide-in-from-top-1 duration-200">

            {/* 1. Observation Block (NEW) */}
            {hasObservation && (
                <div 
                    className="mb-2 mt-2 mr-2 p-3 bg-yellow-900/10 border-l-2 border-yellow-600 text-sm text-zinc-300 rich-content"
                    style={{ marginLeft: `${(depth + 1) * 1.5 + 0.5}rem` }}
                >
                    <div className="flex items-center gap-2 text-yellow-500 mb-1 text-[10px] font-bold uppercase tracking-widest">
                        <StickyNote size={12} /> Observação
                    </div>
                    <div 
                        dangerouslySetInnerHTML={{ __html: observation }} 
                        className="prose prose-invert prose-sm max-w-none text-zinc-400 text-xs"
                    />
                    <style>{`
                        .rich-content ul { list-style-type: disc; padding-left: 1.5em; }
                        .rich-content ol { list-style-type: decimal; padding-left: 1.5em; }
                    `}</style>
                </div>
            )}

            {/* 2. Goals attached to THIS item */}
            {renderLinkedGoals()}

            {/* 3. Subtopics Recursive Render */}
            {hasSubtopics && item.subtopics?.map(sub => (
                <TopicItem 
                    key={sub.id} 
                    item={sub} 
                    depth={depth + 1} 
                    // Pass EFFECTIVE IDs down to children to maintain visual state
                    completedMetaIds={effectiveCompletedIds}
                    activeUserMode={activeUserMode}
                    metaLookup={metaLookup}
                    planId={planId}
                    studyLevels={studyLevels}
                    onToggleGoal={onToggleGoal}
                    onBatchToggle={onBatchToggle} // PROPAGATE BATCH TOGGLE DOWN
                    onPlayVideo={onPlayVideo}
                />
            ))}

            {/* 4. Empty State Check */}
            {progressStats.total === 0 && !hasSubtopics && !hasObservation && (
                <div 
                    className="py-3 pr-4 border-b border-zinc-800/30 bg-zinc-950/30 text-zinc-600 text-xs italic"
                    style={{ paddingLeft: `${(depth + 1) * 1.5 + 2.5}rem` }}
                >
                    Sem conteúdo vinculado.
                </div>
            )}
        </div>
      )}

      {/* MODAL DE CONFIRMAÇÃO DE CONCLUSÃO DO TÓPICO */}
      {showConfirmModal && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setShowConfirmModal(false)}>
            <div 
                className="bg-zinc-900 border border-zinc-800 p-6 rounded-xl w-full max-w-sm shadow-2xl animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                <div className="flex flex-col items-center text-center gap-4">
                    <div className="p-3 rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 shadow-[0_0_15px_rgba(16,185,129,0.2)]">
                        <CheckCircle2 size={32} />
                    </div>

                    <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                        Concluir Tópico?
                    </h3>

                    <div className="text-sm text-zinc-400 leading-relaxed">
                        <p>Você está prestes a marcar <strong>todas as {progressStats.total} metas</strong> deste tópico como concluídas.</p>
                        <p className="mt-2 text-xs bg-zinc-950 p-2 rounded border border-zinc-800 text-zinc-500">
                            Isso removerá quaisquer agendamentos futuros dessas metas do seu calendário.
                        </p>
                    </div>

                    <div className="flex gap-3 w-full mt-2">
                        <button 
                            onClick={() => setShowConfirmModal(false)}
                            disabled={isProcessing}
                            className="flex-1 py-3 rounded-lg border border-zinc-700 hover:bg-zinc-800 text-zinc-300 font-bold uppercase text-xs tracking-widest transition-colors"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmCompletion}
                            disabled={isProcessing}
                            className="flex-1 py-3 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white font-black uppercase text-xs tracking-widest transition-all shadow-lg shadow-emerald-900/20 flex items-center justify-center gap-2"
                        >
                            {isProcessing ? <Loader2 size={14} className="animate-spin" /> : 'Confirmar'}
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
      )}
    </div>
  );
};

