import React, { useState } from 'react';
import { Download, PlayCircle } from 'lucide-react';
import { AlternativeYouTubePlayer } from '../../../shared/AlternativeYouTubePlayer';

export const StudentLiveRecording = ({ event }: { event: any }) => {
  const [activeVideoIndex, setActiveVideoIndex] = useState(0);
  const recordings = event.recordings || [];
  const materials = event.materials || [];

  const getYouTubeID = (url: string) => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const parseRecordingData = (data: string) => {
    if (!data) return { isYouTube: false, videoId: null, rawEmbed: '' };

    // Se for um link direto ou iframe do YouTube
    const isYouTube = data.includes('youtube.com') || data.includes('youtu.be');
    const videoId = isYouTube ? getYouTubeID(data) : null;

    return { isYouTube, videoId, rawEmbed: data };
  };

  if (recordings.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-gray-400 p-8 text-center">
        <PlayCircle size={48} className="mb-4 opacity-50" />
        <h3 className="text-xl font-bold text-white mb-2">Gravação em Processamento</h3>
        <p>A gravação deste evento estará disponível em breve. Aguarde a publicação pelo administrador.</p>
      </div>
    );
  }

  const activeVideo = recordings[activeVideoIndex];
  const { isYouTube, videoId, rawEmbed } = parseRecordingData(activeVideo.url);

  return (
    <div className="flex flex-col gap-6 p-4">
      {/* Player de Vídeo da Gravação */}
      <div className="w-full aspect-video bg-black rounded-lg overflow-hidden border border-gray-800 relative">
        {isYouTube && videoId ? (
          <AlternativeYouTubePlayer 
            videoId={videoId} 
            hideControls={true}
            preventSharing={true}
            customMask={true}
          />
        ) : (
          <div 
            className="w-full h-full panda-player-container" 
            dangerouslySetInnerHTML={{ __html: rawEmbed }} 
          />
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Lista de Aulas Gravadas */}
        <div className="md:col-span-2 flex flex-col gap-3">
          <h3 className="text-lg font-bold text-white">Conteúdo da Gravação</h3>
          <div className="flex flex-col gap-2">
            {recordings.map((rec: any, idx: number) => (
              <button 
                key={rec.id || idx}
                onClick={() => setActiveVideoIndex(idx)}
                className={`flex items-center gap-3 p-3 rounded-lg border text-left transition ${activeVideoIndex === idx ? 'border-red-500 bg-red-900/20' : 'border-gray-800 bg-gray-900 hover:border-gray-600'}`}
              >
                <PlayCircle size={20} className={activeVideoIndex === idx ? 'text-red-500' : 'text-gray-400'} />
                <span className="text-white font-medium">{rec.title}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Lista de Materiais PDF */}
        <div className="flex flex-col gap-3">
          <h3 className="text-lg font-bold text-white">Materiais (PDF)</h3>
          {materials.length === 0 ? (
            <p className="text-sm text-gray-400">Nenhum material disponibilizado.</p>
          ) : (
            <div className="flex flex-col gap-2">
              {materials.map((mat: any, idx: number) => (
                <a 
                  key={mat.id || idx}
                  href={mat.url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-3 p-3 rounded-lg border border-gray-800 bg-gray-900 hover:border-gray-600 transition"
                >
                  <Download size={18} className="text-gray-400" />
                  <span className="text-sm text-white font-medium truncate">{mat.title}</span>
                </a>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { MentorshipModule, MentorshipLesson } from '../../../types/mentorship';
import { mentorshipService } from '../../../services/mentorshipService';
import { useAuth } from '../../../contexts/AuthContext';

// Ícones
const PlayIcon = () => <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>;
const CheckCircleIcon = () => <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const CheckSolidIcon = () => <svg className="w-4 h-4 text-green-500" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>;
const ChevronDown = () => <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>;
const FileIcon = () => <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>;

interface StudentLessonPlayerProps {
  module: MentorshipModule;
  planId: string; // Novo Prop obrigatório
  onBack: () => void;
}

export function StudentLessonPlayer({ module, planId, onBack }: StudentLessonPlayerProps) {
  const { currentUser: user } = useAuth(); // Pegar ID do usuário logado (useAuth returns currentUser)
  const [activeLesson, setActiveLesson] = useState<MentorshipLesson | null>(null);
  const [expandedFolders, setExpandedFolders] = useState<Record<string, boolean>>({});

  // ESTADO DE PROGRESSO: Lista de IDs das aulas concluídas
  const [completedLessons, setCompletedLessons] = useState<string[]>([]);
  const [isLoadingProgress, setIsLoadingProgress] = useState(false);

  // 1. Carregar aula inicial e expandir pastas
  useEffect(() => {
    if (module) {
        const firstLesson = module.lessons?.[0] || module.subModules?.[0]?.lessons?.[0];
        if (firstLesson) setActiveLesson(firstLesson);

        const initialExpanded: Record<string, boolean> = {};
        module.subModules?.forEach(sub => initialExpanded[sub.id] = true);
        setExpandedFolders(initialExpanded);
    }
  }, [module]);

  // 2. Carregar Progresso do Banco de Dados
  useEffect(() => {
    const loadProgress = async () => {
        if (user && planId) {
            const progress = await mentorshipService.getStudentProgress(user.uid, planId);
            setCompletedLessons(progress);
        }
    };
    loadProgress();
  }, [user, planId]);

  // 3. Função para Marcar/Desmarcar Conclusão
  const handleToggleComplete = async () => {
    if (!user || !activeLesson) return;

    // Atualização Otimista (Muda na hora visualmente)
    const isCurrentlyCompleted = completedLessons.includes(activeLesson.id);
    let newCompletedList;

    if (isCurrentlyCompleted) {
        newCompletedList = completedLessons.filter(id => id !== activeLesson.id);
    } else {
        newCompletedList = [...completedLessons, activeLesson.id];
    }
    setCompletedLessons(newCompletedList); // Atualiza estado local

    // Atualiza no Banco
    setIsLoadingProgress(true);
    try {
        await mentorshipService.toggleLessonCompletion(user.uid, planId, activeLesson.id);
    } catch (error) {
        console.error("Erro ao salvar progresso", error);
        // Reverte se der erro (opcional)
    } finally {
        setIsLoadingProgress(false);
    }
  };

  const renderContent = () => {
    if (!activeLesson) return <div className="text-center py-20 text-gray-500">Selecione uma aula para começar.</div>;

    const videoContent = activeLesson.contents?.find(c => c.type === 'video');
    const pdfContent = activeLesson.contents?.find(c => c.type === 'pdf');
    const downloads = activeLesson.contents?.filter(c => c.type === 'pdf' || c.type === 'link') || [];
    const contentCount = activeLesson.contents?.length || 0;

    // Verifica se a aula atual está concluída
    const isCompleted = completedLessons.includes(activeLesson.id);

    return (
      <div className="flex flex-col h-full">
        {/* PLAYER */}
        <div className="aspect-video bg-black rounded-xl overflow-hidden border border-gray-800 shadow-2xl relative mb-6">
            {videoContent ? (
                <iframe 
                    src={videoContent.videoUrl} 
                    className="w-full h-full" 
                    frameBorder="0" 
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                    allowFullScreen
                    title={videoContent.title}
                />
            ) : pdfContent ? (
                <div className="w-full h-full flex items-center justify-center bg-[#15171b]">
                    <div className="text-center">
                        <FileIcon />
                        <p className="mt-2 text-gray-400">Esta aula é um material de leitura.</p>
                        <a href={pdfContent.fileUrl} target="_blank" rel="noreferrer" className="mt-4 inline-block px-6 py-2 bg-red-600 text-white rounded hover:bg-red-500 transition-colors">
                            Ler PDF
                        </a>
                    </div>
                </div>
            ) : (
                <div className="w-full h-full flex items-center justify-center bg-[#15171b] text-gray-500">
                    Selecione um conteúdo.
                </div>
            )}
        </div>

        {/* BARRA DE TÍTULO E AÇÕES */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 border-b border-gray-800 pb-6">
            <div>
                <h1 className="text-2xl font-bold text-white mb-2">{activeLesson.title}</h1>
                <div className="flex items-center gap-2 text-sm text-gray-400">
                    <span className="bg-gray-800 px-2 py-0.5 rounded text-xs uppercase tracking-wider text-white">AULA</span>
                    <span>{contentCount} {contentCount === 1 ? 'CONTEÚDO' : 'CONTEÚDOS'}</span>
                </div>
            </div>

            {/* BOTÃO INTELIGENTE DE CONCLUSÃO */}
            <button 
                onClick={handleToggleComplete}
                disabled={isLoadingProgress}
                className={`flex items-center gap-2 px-6 py-3 rounded-lg font-bold uppercase text-xs tracking-wider transition-all border
                    ${isCompleted 
                        ? 'bg-green-600/10 border-green-500 text-green-500 hover:bg-green-600/20' 
                        : 'bg-[#1a1d24] border-gray-700 text-gray-400 hover:text-white hover:border-gray-500'
                    }
                `}
            >
                {isCompleted ? <CheckSolidIcon /> : <div className="w-4 h-4 rounded-full border-2 border-current"></div>}
                {isCompleted ? 'AULA CONCLUÍDA' : 'MARCAR COMO CONCLUÍDA'}
            </button>
        </div>

        {/* DOWNLOADS */}
        {downloads.length > 0 && (
            <div className="mb-12">
                <h3 className="text-white font-bold text-lg mb-4 flex items-center gap-2">
                    <svg className="w-5 h-5 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    Arquivos e Links
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {downloads.map(item => (
                        <a 
                            key={item.id} 
                            href={item.type === 'pdf' ? item.fileUrl : item.linkUrl} 
                            target="_blank" 
                            rel="noreferrer"
                            className="flex items-center gap-3 p-4 bg-[#1a1d24] hover:bg-[#202329] border border-gray-800 rounded-lg transition-colors group"
                        >
                            <div className="p-2 bg-black rounded text-gray-400 group-hover:text-white transition-colors">
                                {item.type === 'pdf' ? <FileIcon /> : <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>}
                            </div>
                            <div className="flex-1 min-w-0">
                                <p className="text-sm font-bold text-gray-200 truncate group-hover:text-white">{item.title}</p>
                                <p className="text-xs text-gray-500 uppercase">{item.type}</p>
                            </div>
                            <svg className="w-4 h-4 text-gray-600 group-hover:text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                        </a>
                    ))}
                </div>
            </div>
        )}
      </div>
    );
  };

  // Helper para renderizar item da lista com ícone de check
  const renderLessonItem = (lesson: MentorshipLesson) => {
    const isCompleted = completedLessons.includes(lesson.id);
    const isActive = activeLesson?.id === lesson.id;

    return (
        <div 
            key={lesson.id}
            onClick={() => setActiveLesson(lesson)}
            className={`
                flex items-start gap-3 cursor-pointer transition-colors border-l-4 py-3 pr-4
                ${isActive 
                    ? 'border-red-600 bg-[#1a1d24]' 
                    : 'border-transparent hover:bg-[#1a1d24]'
                }
                ${isCompleted ? 'opacity-70 hover:opacity-100' : ''}
            `}
            style={{ paddingLeft: '1rem' }} // Padding fixo para alinhar
        >
            <div className="mt-0.5 shrink-0">
                {/* ÍCONE DINÂMICO: CHECK OU PLAY */}
                {isCompleted ? (
                    <div className="text-green-500"><CheckSolidIcon /></div>
                ) : (
                    <div className={isActive ? 'text-red-500' : 'text-gray-600'}>
                        <PlayIcon />
                    </div>
                )}
            </div>
            <div>
                <span className={`text-sm leading-snug block ${isActive || isCompleted ? 'text-white font-medium' : 'text-gray-400'}`}>
                    {lesson.title}
                </span>
                <span className="text-[10px] text-gray-600 uppercase mt-1 block">Videoaula</span>
            </div>
        </div>
    );
  };

  return (
    <div className="fixed top-[120px] left-0 right-0 bottom-0 bg-[#0f1115] z-40 flex flex-col md:flex-row overflow-hidden animate-in fade-in">

      {/* --- HEADER MOBILE (SÓ APARECE EM TELAS PEQUENAS) --- */}
      <div className="md:hidden p-4 bg-[#121418] border-b border-gray-800 flex justify-between items-center shrink-0">
        <button onClick={onBack} className="text-gray-400 text-sm">Voltar</button>
        <span className="font-bold text-white truncate max-w-[200px] text-sm">{module.title}</span>
        <div className="w-8"></div>
      </div>

      {/* --- COLUNA ESQUERDA: PLAYER (CONTEÚDO) --- */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8 bg-black/50">
        <div className="max-w-5xl mx-auto">

            {/* Breadcrumb Desktop */}
            <button 
                onClick={onBack}
                className="hidden md:flex items-center gap-2 text-gray-500 hover:text-white mb-6 transition-colors text-sm uppercase font-bold tracking-widest"
            >
                &larr; Voltar para o Portal
            </button>

            {renderContent()}
        </div>
      </div>

      {/* --- COLUNA DIREITA: SIDEBAR (LISTA DE AULAS) --- */}
      <div className="w-full md:w-[400px] bg-[#121418] border-l border-gray-800 flex flex-col h-full shrink-0">

        {/* Cabeçalho da Sidebar */}
        <div className="p-6 border-b border-gray-800">
            <h2 className="text-white font-bold text-lg leading-tight mb-2">{module.title}</h2>

            {/* Barra de Progresso Real */}
            <div className="flex items-center gap-2">
                <div className="h-1 flex-1 bg-gray-800 rounded-full overflow-hidden">
                    <div 
                        className="h-full bg-green-500 transition-all duration-500"
                        style={{ 
                            width: `${(completedLessons.length / Math.max(1, (module.lessons?.length || 0) + (module.subModules?.reduce((acc, sub) => acc + (sub.lessons?.length || 0), 0) || 0))) * 100}%` 
                        }}
                    ></div>
                </div>
                <span className="text-xs text-gray-500 font-mono">
                    {Math.round((completedLessons.length / Math.max(1, (module.lessons?.length || 0) + (module.subModules?.reduce((acc, sub) => acc + (sub.lessons?.length || 0), 0) || 0))) * 100)}%
                </span>
            </div>
        </div>

        {/* Lista Scrollável */}
        <div className="flex-1 overflow-y-auto custom-scrollbar">

            {/* 1. LISTA DE AULAS SOLTAS (FORA DE PASTAS) */}
            {module.lessons && module.lessons.length > 0 && (
                <div className="border-b border-gray-800/50">
                    {module.lessons.map(lesson => renderLessonItem(lesson))}
                </div>
            )}

            {/* 2. LISTA DE SUBMÓDULOS (PASTAS) */}
            {module.subModules?.map((subModule) => {
                const isOpen = expandedFolders[subModule.id];
                return (
                    <div key={subModule.id} className="border-b border-gray-800/50">
                        {/* Header do Acordeão */}
                        <div 
                            onClick={() => setExpandedFolders(prev => ({...prev, [subModule.id]: !prev[subModule.id]}))}
                            className="p-4 flex justify-between items-center cursor-pointer hover:bg-[#1a1d24] transition-colors group"
                        >
                            <span className="text-sm font-bold text-gray-300 group-hover:text-white uppercase tracking-wide">
                                {subModule.title}
                            </span>
                            <div className={`text-gray-500 transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`}>
                                <ChevronDown />
                            </div>
                        </div>

                        {/* Conteúdo do Acordeão (Aulas) */}
                        {isOpen && (
                            <div className="bg-black/20">
                                {subModule.lessons?.map(lesson => renderLessonItem(lesson))}
                                {(!subModule.lessons || subModule.lessons.length === 0) && (
                                    <div className="pl-8 py-3 text-xs text-gray-600 italic">Pasta vazia</div>
                                )}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { MentorshipModule, MentorshipLesson } from '../../../types/mentorship';

// Ícones
const FolderIcon = () => <svg className="w-5 h-5 text-yellow-500" fill="currentColor" viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>;
const PlayIcon = () => <svg className="w-4 h-4 text-red-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const ChevronRight = () => <svg className="w-4 h-4 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>;

interface StudentModuleViewProps {
  module: MentorshipModule;
  onBack: () => void;
  onLessonSelect: (lesson: MentorshipLesson) => void;
}

export function StudentModuleView({ module, onBack, onLessonSelect }: StudentModuleViewProps) {
  // Navegação interna (Breadcrumbs)
  const [navigationPath, setNavigationPath] = useState<{id: string, title: string}[]>([]);

  // Estado para pastas expandidas (Acordeão)
  const [expandedFolders, setExpandedFolders] = useState<Record<string, boolean>>({});

  // Helper para encontrar o container atual (Raiz ou Subpasta)
  const getCurrentContainer = () => {
    let current: any = module;
    for (const pathItem of navigationPath) {
        if (current.subModules) {
            current = current.subModules.find((sub: any) => sub.id === pathItem.id);
        }
    }
    return current;
  };

  const currentContainer = getCurrentContainer();

  // Toggle Acordeão
  const toggleFolder = (folderId: string) => {
    setExpandedFolders(prev => ({ ...prev, [folderId]: !prev[folderId] }));
  };

  // Helper para ordenar itens (Pastas e Aulas)
  const getSortedItems = (container: any) => {
    const lessons = (container.lessons || []).map((l: any) => ({ type: 'lesson', data: l, order: l.order || 0 }));
    const submodules = (container.subModules || []).map((s: any) => ({ type: 'submodule', data: s, order: s.order || 0 }));
    return [...lessons, ...submodules].sort((a: any, b: any) => a.order - b.order);
  };

  const items = getSortedItems(currentContainer);

  return (
    <div className="animate-in slide-in-from-right duration-300">

      {/* --- HEADER DO MÓDULO --- */}
      <div className="mb-8 border-b border-gray-800 pb-4">
        {/* Botão Voltar */}
        <button 
            onClick={() => {
                if (navigationPath.length > 0) {
                    setNavigationPath(prev => prev.slice(0, -1));
                } else {
                    onBack();
                }
            }}
            className="flex items-center gap-2 text-gray-400 hover:text-white transition-colors mb-4 text-sm font-bold uppercase tracking-wider"
        >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
            {navigationPath.length > 0 ? 'Voltar' : 'Voltar para Mentoria'}
        </button>

        <h2 className="text-2xl md:text-3xl font-black text-white flex items-center gap-3">
            {navigationPath.length === 0 && (
                <img src={module.coverUrl} className="w-10 h-14 object-cover rounded border border-gray-700" alt="Capa" />
            )}
            {navigationPath.length > 0 ? currentContainer.title : module.title}
        </h2>

        {/* Breadcrumbs */}
        <div className="flex items-center gap-2 mt-2 text-sm text-gray-500">
            <span className={`cursor-pointer hover:text-white ${navigationPath.length === 0 ? 'text-white font-bold' : ''}`} onClick={() => setNavigationPath([])}>
                Início
            </span>
            {navigationPath.map((item, idx) => (
                <React.Fragment key={item.id}>
                    <span>/</span>
                    <span 
                        className={`cursor-pointer hover:text-white ${idx === navigationPath.length - 1 ? 'text-white font-bold' : ''}`}
                        onClick={() => setNavigationPath(prev => prev.slice(0, idx + 1))}
                    >
                        {item.title}
                    </span>
                </React.Fragment>
            ))}
        </div>
      </div>

      {/* --- LISTA DE CONTEÚDO --- */}
      <div className="space-y-3 max-w-5xl">
        {items.length === 0 && (
            <div className="p-8 text-center border border-dashed border-gray-800 rounded-lg text-gray-500">
                Esta pasta está vazia.
            </div>
        )}

        {items.map((item: any) => {
            // --- RENDERIZAÇÃO DE PASTA ---
            if (item.type === 'submodule') {
                const isOpen = expandedFolders[item.data.id];
                return (
                    <div key={item.data.id} className="border border-gray-800 rounded-lg bg-[#15171b] overflow-hidden">
                        <div 
                            onClick={() => toggleFolder(item.data.id)}
                            className="p-4 flex items-center justify-between cursor-pointer hover:bg-[#1a1d24] transition-colors"
                        >
                            <div className="flex items-center gap-3">
                                <div className={`transition-transform duration-200 ${isOpen ? 'rotate-90' : ''}`}>
                                    <ChevronRight />
                                </div>
                                <FolderIcon />
                                <span className="text-white font-bold">{item.data.title}</span>
                                <span className="text-xs text-gray-600 ml-2">{(item.data.lessons?.length || 0) + (item.data.subModules?.length || 0)} itens</span>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); setNavigationPath([...navigationPath, { id: item.data.id, title: item.data.title }]); }}
                                className="px-3 py-1 text-xs font-bold text-gray-400 border border-gray-700 rounded hover:text-white hover:border-gray-500"
                            >
                                ABRIR PASTA
                            </button>
                        </div>

                        {/* Conteúdo da Pasta (Preview) */}
                        {isOpen && (
                            <div className="bg-black/20 border-t border-gray-800 p-2 pl-8">
                                {(item.data.lessons || []).map((l: any) => (
                                    <div 
                                        key={l.id} 
                                        onClick={() => onLessonSelect(l)}
                                        className="p-2 flex items-center gap-3 hover:bg-white/5 rounded cursor-pointer text-gray-300 hover:text-white"
                                    >
                                        <PlayIcon />
                                        <span className="text-sm">{l.title}</span>
                                    </div>
                                ))}
                                {(!item.data.lessons?.length && !item.data.subModules?.length) && <p className="text-xs text-gray-600 p-2">Vazio</p>}
                            </div>
                        )}
                    </div>
                );
            }

            // --- RENDERIZAÇÃO DE AULA ---
            if (item.type === 'lesson') {
                return (
                    <div 
                        key={item.data.id}
                        onClick={() => onLessonSelect(item.data)}
                        className="p-4 rounded-lg bg-[#1a1d24] border border-gray-800 hover:border-red-600/50 hover:bg-[#202329] transition-all cursor-pointer flex justify-between items-center group"
                    >
                        <div className="flex items-center gap-4">
                            <div className="w-8 h-8 rounded-full bg-black flex items-center justify-center border border-gray-700 group-hover:border-red-500 transition-colors">
                                <PlayIcon />
                            </div>
                            <div>
                                <h4 className="text-white font-bold text-sm md:text-base group-hover:text-red-500 transition-colors">
                                    {item.data.title}
                                </h4>
                                <div className="flex gap-2 mt-1">
                                    {item.data.contents?.some((c:any) => c.type === 'video') && <span className="text-[10px] bg-red-900/20 text-red-500 px-1.5 rounded border border-red-900/30">VÍDEO</span>}
                                    {item.data.contents?.some((c:any) => c.type === 'pdf') && <span className="text-[10px] bg-blue-900/20 text-blue-500 px-1.5 rounded border border-blue-900/30">PDF</span>}
                                </div>
                            </div>
                        </div>

                        <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                            <button className="px-4 py-2 bg-red-600 text-white text-xs font-bold uppercase rounded shadow-lg hover:bg-red-500">
                                Acessar
                            </button>
                        </div>
                    </div>
                );
            }
            return null;
        })}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import { classScheduleService } from '../../../services/classScheduleService';
import { curriculumService } from '../../../services/curriculumService';
import { teacherService } from '../../../services/teacherService';
import { holidayService } from '../../../services/holidayService';
import { ClassScheduleEvent } from '../../../types/schedule';
import { Subject, Topic } from '../../../types/curriculum';
import { Teacher } from '../../../types/teacher';
import { 
  Calendar as CalendarIcon, 
  Clock, 
  User, 
  BookOpen, 
  AlertTriangle, 
  ChevronLeft, 
  ChevronRight, 
  LayoutGrid, 
  List,
  ChevronDown,
  ChevronUp,
  CheckCircle
} from 'lucide-react';

interface StudentClassScheduleProps {
  classId: string;
}

export const StudentClassSchedule: React.FC<StudentClassScheduleProps> = ({ classId }) => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [events, setEvents] = useState<ClassScheduleEvent[]>([]);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [topics, setTopics] = useState<Topic[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [holidays, setHolidays] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);

  // View State
  const [viewMode, setViewMode] = useState<'month' | 'week'>('week');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [expandedEventId, setExpandedEventId] = useState<string | null>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [eventsData, subjectsData, topicsData, teachersData, holidaysData] = await Promise.all([
          classScheduleService.getScheduleEventsByClass(classId),
          curriculumService.getSubjectsByClass(classId),
          curriculumService.getTopicsByClass(classId),
          teacherService.getTeachers(),
          holidayService.getHolidays()
        ]);

        setEvents(eventsData);
        setSubjects(subjectsData);
        setTopics(topicsData);
        setTeachers(teachersData);
        setHolidays(holidaysData);
      } catch (error) {
        console.error("Error loading schedule data:", error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [classId]);

  // Helpers
  const getSubject = (id: string) => subjects.find(s => s.id === id);
  const getTopicName = (id: string) => topics.find(t => t.id === id)?.name || 'Assunto não encontrado';
  const getTeacherName = (id: string) => teachers.find(t => t.id === id)?.name || 'Professor não atribuído';
  const getModuleName = (topicId: string, moduleId: string) => {
    const topic = topics.find(t => t.id === topicId);
    if (!topic) return 'Tópico desconhecido';
    const module = topic.modules?.find(m => m.id === moduleId);
    return module ? module.name : 'Módulo desconhecido';
  };

  // Calendar Logic
  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month + 1, 0).getDate();
  };

  const getFirstDayOfMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    return new Date(year, month, 1).getDay();
  };

  const getStartOfWeek = (date: Date) => {
    const day = date.getDay();
    const diff = date.getDate() - day;
    return new Date(date.getFullYear(), date.getMonth(), diff);
  };

  const handlePrev = () => {
    if (viewMode === 'month') {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
    } else {
      const newDate = new Date(currentDate);
      newDate.setDate(newDate.getDate() - 7);
      setCurrentDate(newDate);
    }
  };

  const handleNext = () => {
    if (viewMode === 'month') {
      setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
    } else {
      const newDate = new Date(currentDate);
      newDate.setDate(newDate.getDate() + 7);
      setCurrentDate(newDate);
    }
  };

  const formatHeaderDate = (date: Date) => {
    if (viewMode === 'month') {
      return date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    } else {
      const start = getStartOfWeek(date);
      const end = new Date(start);
      end.setDate(end.getDate() + 6);
      const startStr = start.toLocaleDateString('pt-BR', { day: 'numeric', month: 'short' });
      const endStr = end.toLocaleDateString('pt-BR', { day: 'numeric', month: 'short', year: 'numeric' });
      return `${startStr} - ${endStr}`;
    }
  };

  const calendarCells = useMemo(() => {
    const cells = [];

    if (viewMode === 'month') {
      const year = currentDate.getFullYear();
      const month = currentDate.getMonth();
      const daysInMonth = getDaysInMonth(currentDate);
      const firstDay = getFirstDayOfMonth(currentDate);

      // Empty cells for previous month
      for (let i = 0; i < firstDay; i++) {
        cells.push({ type: 'empty', key: `empty-${i}` });
      }

      // Days of current month
      for (let day = 1; day <= daysInMonth; day++) {
        const dateString = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        const dayEvents = events.filter(e => e.date === dateString)
          .sort((a, b) => a.startTime.localeCompare(b.startTime));
        const isHoliday = holidays.includes(dateString);

        cells.push({
          type: 'day',
          day,
          dateString,
          events: dayEvents,
          isHoliday,
          key: dateString
        });
      }
    } else {
      // Week View
      const startOfWeek = getStartOfWeek(currentDate);
      for (let i = 0; i < 7; i++) {
        const date = new Date(startOfWeek);
        date.setDate(date.getDate() + i);
        const year = date.getFullYear();
        const month = date.getMonth() + 1;
        const day = date.getDate();
        const dateString = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
        const dayEvents = events.filter(e => e.date === dateString)
          .sort((a, b) => a.startTime.localeCompare(b.startTime));
        const isHoliday = holidays.includes(dateString);

        cells.push({
          type: 'day',
          day,
          dateString,
          events: dayEvents,
          isHoliday,
          key: dateString
        });
      }
    }

    return cells;
  }, [currentDate, events, holidays, viewMode]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-red-500"></div>
      </div>
    );
  }

  if (events.length === 0 && holidays.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-gray-500 bg-gray-900/30 rounded-xl border border-gray-800">
        <CalendarIcon size={48} className="mb-4 opacity-50" />
        <p className="text-lg font-medium">Nenhuma aula agendada ainda.</p>
        <p className="text-sm">O cronograma será disponibilizado em breve.</p>
      </div>
    );
  }

  return (
    <div className="bg-black border border-zinc-800 rounded-xl overflow-hidden shadow-sm animate-in fade-in duration-500">
      {/* Header */}
      <div className="flex flex-col sm:flex-row items-center justify-between p-4 border-b border-zinc-800 bg-black gap-4">
        <div className="flex items-center gap-4">
          <h2 className="text-xl font-bold text-white capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-brand-red" />
            {formatHeaderDate(currentDate)}
          </h2>
          <div className="flex items-center gap-1 bg-zinc-900 rounded-lg p-1 border border-zinc-800">
            <button
              onClick={() => setViewMode('month')}
              className={`p-1.5 rounded-md transition-all ${viewMode === 'month' ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-400 hover:text-zinc-200'}`}
              title="Visualização Mensal"
            >
              <LayoutGrid className="w-4 h-4" />
            </button>
            <button
              onClick={() => setViewMode('week')}
              className={`p-1.5 rounded-md transition-all ${viewMode === 'week' ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-400 hover:text-zinc-200'}`}
              title="Visualização Semanal"
            >
              <List className="w-4 h-4" />
            </button>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={handlePrev}
            className="p-2 hover:bg-zinc-900 rounded-lg text-zinc-400 hover:text-white transition-colors border border-transparent hover:border-zinc-800"
          >
            <ChevronLeft className="w-5 h-5" />
          </button>
          <button 
            onClick={() => setCurrentDate(new Date())}
            className="px-3 py-1.5 text-xs font-bold uppercase tracking-wider text-zinc-400 hover:text-white border border-zinc-800 hover:border-zinc-700 rounded-lg transition-colors"
          >
            Hoje
          </button>
          <button 
            onClick={handleNext}
            className="p-2 hover:bg-zinc-900 rounded-lg text-zinc-400 hover:text-white transition-colors border border-transparent hover:border-zinc-800"
          >
            <ChevronRight className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* Calendar Container with Horizontal Scroll for Tablets */}
      <div className="overflow-x-auto pb-2 scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent">
        <div className="min-w-full md:min-w-[900px]">
          {/* Weekday Headers */}
          <div className="hidden md:grid grid-cols-7 border-b border-zinc-800 bg-black">
            {['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'].map(day => (
              <div key={day} className="py-3 text-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
                {day}
              </div>
            ))}
          </div>

          {/* Calendar Grid */}
          <div className={`grid grid-cols-1 md:grid-cols-7 bg-black ${viewMode === 'month' ? 'auto-rows-fr' : 'md:h-[600px]'}`}>
            {calendarCells.map((cell: any) => {
              if (cell.type === 'empty') {
                return <div key={cell.key} className="hidden md:block min-h-[140px] border-b border-r border-zinc-800/50 bg-black"></div>;
              }

              const isToday = new Date().toISOString().split('T')[0] === cell.dateString;
              const dayEvents = cell.events || [];
              const isHoliday = cell.isHoliday;
              const hasEvents = dayEvents.length > 0;
              const isDayCompleted = hasEvents && dayEvents.every(e => e.status === 'COMPLETED');

              // Obter o dia da semana abreviado para exibir no mobile
              const dateObj = new Date(cell.dateString + 'T12:00:00');
              const dayOfWeek = dateObj.toLocaleDateString('pt-BR', { weekday: 'short' }).replace('.', '');

              return (
                <div 
                  key={cell.key} 
                  className={`
                    p-2 border-b border-r border-zinc-800 transition-colors relative group overflow-y-auto scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent
                    ${viewMode === 'month' ? 'min-h-[140px]' : 'h-auto md:h-full'}
                    ${isToday ? 'bg-brand-red/5' : 'hover:bg-zinc-900/30'}
                  `}
                >
                  <div className="flex justify-between items-start mb-2 sticky top-0 bg-inherit z-10 pb-1">
                    <div className="flex items-center gap-2">
                      <span 
                        className={`
                          text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full
                          ${isToday ? 'bg-brand-red text-white' : 'text-zinc-400 group-hover:text-zinc-200'}
                        `}
                      >
                        {cell.day}
                      </span>
                      <span className="md:hidden text-xs font-bold text-zinc-500 uppercase tracking-wider">
                        {dayOfWeek}
                      </span>
                    </div>
                    {hasEvents && (
                      <span className={`
                        text-[10px] font-bold px-1.5 py-0.5 rounded border uppercase tracking-wide
                        ${isDayCompleted 
                          ? 'bg-emerald-600 text-white border-emerald-500' 
                          : dayEvents[0].isOverflow 
                            ? 'bg-red-600 text-white border-red-500' 
                            : 'text-brand-red bg-brand-red/10 border-brand-red/20'}
                      `}>
                        {dayEvents[0].isOverflow 
                          ? `Encontro #${dayEvents[0].meetingNumber} (EXTRA)` 
                          : `Encontro #${dayEvents[0].meetingNumber}`}
                      </span>
                    )}
                  </div>

                  <div className="space-y-2">
                    {/* Holiday Display */}
                    {isHoliday && (
                      <div className="h-full flex flex-col items-center justify-center py-4">
                        <div className="w-full p-3 rounded-lg border border-dashed border-zinc-700 bg-zinc-900/30 text-zinc-500 flex flex-col items-center justify-center text-center gap-2">
                          <CalendarIcon className="w-5 h-5 opacity-50" />
                          <span className="text-xs font-medium">Feriado</span>
                        </div>
                      </div>
                    )}

                    {/* Events Display */}
                    {!isHoliday && dayEvents.map((event: ClassScheduleEvent, index: number) => {
                      const subject = getSubject(event.subjectId);
                      const isExpanded = expandedEventId === event.id;
                      const borderColor = subject?.color || '#52525b';
                      const isOverflow = event.isOverflow;

                      return (
                        <React.Fragment key={event.id}>
                          <div 
                            onClick={(e) => {
                              e.stopPropagation();
                              setExpandedEventId(isExpanded ? null : event.id);
                            }}
                            className={`
                              rounded-lg border-l-4 transition-all cursor-pointer overflow-hidden
                              ${isExpanded ? 'bg-zinc-900 shadow-lg ring-1 ring-zinc-800 z-20 relative' : 'bg-zinc-900/50 hover:bg-zinc-900'}
                              ${isOverflow ? 'border-red-500 bg-red-900/20' : ''}
                              ${event.status === 'COMPLETED' ? 'border-emerald-500 bg-emerald-900/10 opacity-80' : ''}
                            `}
                            style={{ borderLeftColor: event.status === 'COMPLETED' ? '#10b981' : borderColor }}
                          >
                            {/* Card Header */}
                            <div className="p-2">
                              <div className="flex justify-between items-center mb-1 flex-wrap gap-1">
                                <div className="text-[9px] font-bold text-zinc-500 uppercase tracking-wider">
                                  {index + 1}º Tempo
                                </div>
                                <div className="flex gap-1 flex-wrap justify-end">
                                  {event.status === 'COMPLETED' && (
                                    <span className="text-[8px] font-bold text-emerald-500 bg-emerald-950/50 px-1 py-0.5 rounded border border-emerald-900/50 uppercase tracking-wider flex items-center gap-1" title="Concluído">
                                      <CheckCircle className="w-2 h-2 shrink-0" />
                                      <span className="hidden lg:inline">CONCLUÍDO</span>
                                    </span>
                                  )}
                                  {event.isSubstitute && (
                                    <span className="text-[8px] font-bold text-black bg-yellow-500 px-1 py-0.5 rounded border border-yellow-600 uppercase tracking-wider flex items-center gap-1" title="Substituição">
                                      SUBST.
                                    </span>
                                  )}
                                  {isOverflow && (
                                    <span className="text-[8px] font-bold text-red-400 bg-red-950/50 px-1 py-0.5 rounded border border-red-900/50 uppercase tracking-wider flex items-center gap-1" title="Aula Extra">
                                      <AlertTriangle className="w-2 h-2 shrink-0" />
                                      <span className="hidden lg:inline">EXTRA</span>
                                    </span>
                                  )}
                                </div>
                              </div>
                              <div className="flex justify-between items-start gap-1">
                                <div className="flex-1 min-w-0">
                                  <div className="flex items-center gap-1 text-[10px] font-bold text-zinc-400 mb-0.5 flex-wrap">
                                    <Clock className="w-3 h-3 shrink-0" />
                                    <span className="whitespace-nowrap">{event.startTime} - {event.endTime}</span>
                                  </div>
                                  <div className="font-bold text-xs text-zinc-200 truncate leading-tight" title={subject?.name}>
                                    {subject?.name || 'Disciplina Desconhecida'}
                                  </div>
                                </div>
                                <div className="flex items-center gap-1 shrink-0">
                                  <button
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      const newParams = new URLSearchParams(searchParams);
                                      newParams.set('tab', 'PLANNING');
                                      if (event.subjectId) newParams.set('subjectId', event.subjectId);
                                      if (event.topicId) newParams.set('topicId', event.topicId);
                                      if (event.moduleId) newParams.set('moduleId', event.moduleId);
                                      setSearchParams(newParams);
                                    }}
                                    className="p-1 text-zinc-500 hover:text-brand-red transition-colors"
                                    title="Ver materiais no Planejamento"
                                  >
                                    <BookOpen className="w-3 h-3" />
                                  </button>
                                  <div className="text-zinc-500">
                                    {isExpanded ? <ChevronUp className="w-3 h-3" /> : <ChevronDown className="w-3 h-3" />}
                                  </div>
                                </div>
                              </div>
                            </div>

                            {/* Card Details */}
                            {isExpanded && (
                              <div className="px-2 pb-2 pt-0 space-y-2 animate-in slide-in-from-top-1 duration-200">
                                <div className="h-px bg-zinc-800 w-full my-1" />

                                <div>
                                  <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-0.5">Módulo</span>
                                  <p className="text-[11px] text-zinc-300 leading-tight">
                                    {getModuleName(event.topicId, event.moduleId)}
                                  </p>
                                </div>

                                <div>
                                  <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-0.5">Assunto</span>
                                  <div className="flex items-center gap-1.5 text-[11px] text-zinc-300">
                                    <BookOpen className="w-3 h-3 text-zinc-500 shrink-0" />
                                    <span>{getTopicName(event.topicId)}</span>
                                  </div>
                                </div>

                                <div>
                                  <span className="text-[10px] text-zinc-500 uppercase font-bold block mb-0.5">Professor</span>
                                  <div className="flex items-center gap-1.5 text-[11px] text-zinc-300">
                                    <User className="w-3 h-3 text-zinc-500 shrink-0" />
                                    <span>{getTeacherName(event.teacherId)}</span>
                                  </div>
                                </div>
                              </div>
                            )}
                          </div>

                          {/* Interval Divider */}
                          {index === 0 && dayEvents.length > 1 && (
                            <div className="flex items-center gap-2 my-2 opacity-50">
                              <div className="h-px bg-zinc-800 border-t border-dashed border-zinc-700 flex-1"></div>
                              <span className="text-[9px] text-zinc-500 font-medium whitespace-nowrap">Intervalo (15 min)</span>
                              <div className="h-px bg-zinc-800 border-t border-dashed border-zinc-700 flex-1"></div>
                            </div>
                          )}
                        </React.Fragment>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { ChevronDown, ChevronRight, FileText, Link as LinkIcon, CheckCircle, Clock, AlertCircle, BookOpen, Video, CheckCircle2, Calendar, PlayCircle } from 'lucide-react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Subject, Topic } from '../../../types/curriculum';
import { ClassScheduleEvent } from '../../../types/schedule';
import { Teacher } from '../../../types/teacher';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { twMerge } from 'tailwind-merge';
import { useAuth } from '../../../contexts/AuthContext';
import { openWatermarkedPdf } from '../../../utils/pdfSecurityService';
import { classScheduleService } from '../../../services/classScheduleService';
import { curriculumService } from '../../../services/curriculumService';
import { teacherService } from '../../../services/teacherService';

interface StudentPedagogicalPlanningProps {
  classId: string;
  totalMeetings?: number;
}

export function StudentPedagogicalPlanning({ classId, totalMeetings = 0 }: StudentPedagogicalPlanningProps) {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { currentUser, userData } = useAuth();
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [topics, setTopics] = useState<Topic[]>([]);
  const [events, setEvents] = useState<ClassScheduleEvent[]>([]);
  const [teachers, setTeachers] = useState<Teacher[]>([]);
  const [loading, setLoading] = useState(true);

  const [expandedSubjects, setExpandedSubjects] = useState<Set<string>>(new Set());
  const [expandedTopics, setExpandedTopics] = useState<Set<string>>(new Set());
  const [expandedModules, setExpandedModules] = useState<Set<string>>(new Set());

  // Deep Linking: Auto-expand and scroll
  useEffect(() => {
    const urlSubjectId = searchParams.get('subjectId');
    const urlTopicId = searchParams.get('topicId');
    const urlModuleId = searchParams.get('moduleId');

    if (urlSubjectId || urlTopicId || urlModuleId) {
      if (urlSubjectId) setExpandedSubjects(prev => new Set([...prev, urlSubjectId]));
      if (urlTopicId) setExpandedTopics(prev => new Set([...prev, urlTopicId]));
      if (urlModuleId) setExpandedModules(prev => new Set([...prev, urlModuleId]));

      // Scroll to module after expansion
      if (urlModuleId) {
        setTimeout(() => {
          const element = document.getElementById(`module-${urlModuleId}`);
          if (element) {
            element.scrollIntoView({ behavior: 'smooth', block: 'center' });
            element.classList.add('highlight-pulse');
            setTimeout(() => element.classList.remove('highlight-pulse'), 3000);
          }
        }, 500);
      }
    }
  }, [searchParams]);

  useEffect(() => {
    const loadData = async () => {
      try {
        const [eventsData, subjectsData, topicsData, teachersData] = await Promise.all([
          classScheduleService.getScheduleEventsByClass(classId),
          curriculumService.getSubjectsByClass(classId),
          curriculumService.getTopicsByClass(classId),
          teacherService.getTeachers()
        ]);

        setEvents(eventsData);
        setSubjects(subjectsData);
        setTopics(topicsData);
        setTeachers(teachersData);
      } catch (error) {
        console.error("Error loading planning data:", error);
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [classId]);

  const handleOpenPdf = async (url: string, title: string) => {
    try {
      await openWatermarkedPdf(url, {
        email: currentUser?.email || 'aluno@insanus.com',
        cpf: userData?.cpf || '000.000.000-00'
      });
    } catch (error) {
      console.error('Error opening PDF:', error);
      window.open(url, '_blank');
    }
  };

  const toggleSubject = (id: string) => {
    const newSet = new Set(expandedSubjects);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedSubjects(newSet);
  };

  const toggleTopic = (id: string) => {
    const newSet = new Set(expandedTopics);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedTopics(newSet);
  };

  const toggleModule = (id: string) => {
    const newSet = new Set(expandedModules);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setExpandedModules(newSet);
  };

  const handleGoToTeachingArea = (teachingAreaLink: any) => {
    if (!teachingAreaLink) return;

    // Para turmas presenciais, o classId é usado como courseId para a Área de Ensino
    const courseId = classId; 

    if (courseId) {
      navigate(`/app/presential/${classId}?module=${teachingAreaLink.moduleId}&folder=${teachingAreaLink.folderId}`);
    } else {
      console.error("ID do curso online não encontrado para realizar o redirecionamento.");
    }
  };

  // Filter subjects that have topics
  const activeSubjects = subjects.filter(subject => 
    topics.some(topic => topic.subjectId === subject.id)
  );

  const onlineModuleIds = React.useMemo(() => {
    return new Set(
      topics.flatMap(t => t.modules || [])
        .filter(m => m.isOnline)
        .map(m => m.id)
    );
  }, [topics]);

  // Calculate global progression
  const globalStats = React.useMemo(() => {
    let totalRequired = 0;
    let totalCompleted = 0;

    subjects.forEach(subject => {
      const subjectTopics = topics.filter(t => t.subjectId === subject.id);
      const subjectRequired = subjectTopics.reduce((acc, topic) => {
        const topicPresentialClasses = (topic.modules || []).reduce((mAcc, m) => {
          if (!m.isOnline) return mAcc + (m.classesCount || 0);
          return mAcc;
        }, 0);

        if (topicPresentialClasses === 0 && (!topic.modules || topic.modules.length === 0)) {
          return acc + (topic.requiredClasses || 0);
        }
        return acc + topicPresentialClasses;
      }, 0);

      const subjectCompleted = events.filter(e => 
        e.subjectId === subject.id && 
        e.status === 'COMPLETED' && 
        !onlineModuleIds.has(e.moduleId)
      ).length;

      totalRequired += subjectRequired;
      totalCompleted += subjectCompleted;
    });

    // Calculate completed meetings
    const meetingsMap = new Map<number, ClassScheduleEvent[]>();
    events.forEach(e => {
      if (e.meetingNumber) {
        if (!meetingsMap.has(e.meetingNumber)) {
          meetingsMap.set(e.meetingNumber, []);
        }
        meetingsMap.get(e.meetingNumber)?.push(e);
      }
    });

    let completedMeetingsCount = 0;
    meetingsMap.forEach((meetingEvents) => {
      if (meetingEvents.length > 0 && meetingEvents.every(e => e.status === 'COMPLETED')) {
        completedMeetingsCount++;
      }
    });

    return {
      totalRequired,
      totalCompleted,
      completedMeetingsCount,
      percentage: totalRequired > 0 ? Math.round((totalCompleted / totalRequired) * 100) : 0
    };
  }, [subjects, topics, events, onlineModuleIds]);

  if (loading) {
    return (
      <div className="flex justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-red-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      {/* Global Progression Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
        <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex flex-col justify-between">
          <div className="flex justify-between items-start mb-2">
            <div>
              <h3 className="text-zinc-400 text-xs font-bold uppercase tracking-wider">Progresso Geral de Aulas</h3>
              <p className="text-2xl font-black text-white">{globalStats.totalCompleted} / {globalStats.totalRequired}</p>
            </div>
            <span className="text-brand-red font-black text-xl">{globalStats.percentage}%</span>
          </div>
          <div className="w-full bg-zinc-800 h-2 rounded-full overflow-hidden">
            <div 
              className="bg-brand-red h-full transition-all duration-500" 
              style={{ width: `${globalStats.percentage}%` }}
            />
          </div>
        </div>

        <div className="bg-zinc-900 border border-zinc-800 p-4 rounded-xl flex items-center justify-between">
          <div>
            <h3 className="text-zinc-400 text-xs font-bold uppercase tracking-wider">Contador de Encontros</h3>
            <p className="text-3xl font-black text-white">
              {globalStats.completedMeetingsCount} <span className="text-zinc-500 text-xl">/ {totalMeetings}</span>
            </p>
          </div>
          <div className="w-12 h-12 rounded-full border-2 border-zinc-800 flex items-center justify-center">
            <CheckCircle2 className={twMerge(
              "w-6 h-6",
              globalStats.completedMeetingsCount === totalMeetings && totalMeetings > 0 ? "text-emerald-500" : "text-zinc-600"
            )} />
          </div>
        </div>
      </div>

      <div className="flex items-center gap-2 mb-6">
        <BookOpen className="w-6 h-6 text-red-500" />
        <h2 className="text-xl font-bold text-white">Planejamento Pedagógico</h2>
      </div>

      {activeSubjects.map(subject => {
        const subjectTopics = topics.filter(t => t.subjectId === subject.id);

        // Calcular o total de aulas presenciais exigidas no currículo
        const totalRequiredClasses = subjectTopics.reduce((acc, topic) => {
          const topicPresentialClasses = (topic.modules || []).reduce((mAcc, m) => {
            if (!m.isOnline) return mAcc + (m.classesCount || 0);
            return mAcc;
          }, 0);

          // Se não houver módulos definidos, usar requiredClasses do tópico (assumindo que são presenciais)
          if (topicPresentialClasses === 0 && (!topic.modules || topic.modules.length === 0)) {
            return acc + (topic.requiredClasses || 0);
          }

          return acc + topicPresentialClasses;
        }, 0);

        const completedEvents = events.filter(e => 
          e.subjectId === subject.id && 
          e.status === 'COMPLETED' && 
          !onlineModuleIds.has(e.moduleId)
        );

        const isExpanded = expandedSubjects.has(subject.id);

        // Ordenar tópicos para esta disciplina
        const sortedTopics = [...subjectTopics].sort((a, b) => (a.order || 0) - (b.order || 0));

        return (
          <div key={subject.id} className="border border-zinc-800 rounded-lg overflow-hidden bg-black">
            {/* Subject Header */}
            <button
              onClick={() => toggleSubject(subject.id)}
              className="w-full flex flex-col md:flex-row md:items-center justify-between p-4 hover:bg-zinc-900 transition-colors gap-3 md:gap-0"
            >
              <div className="flex items-center gap-3 w-full md:w-auto">
                {isExpanded ? <ChevronDown className="w-5 h-5 text-zinc-400 shrink-0" /> : <ChevronRight className="w-5 h-5 text-zinc-400 shrink-0" />}
                <div 
                  className="w-3 h-3 rounded-full shrink-0" 
                  style={{ backgroundColor: subject.color }}
                />
                <span className="font-medium text-zinc-100 text-left">{subject.name}</span>
              </div>
              <div className="flex items-center justify-between md:justify-end gap-4 text-sm w-full md:w-auto pl-11 md:pl-0">
                <span className="text-zinc-400 text-xs md:text-sm whitespace-nowrap">
                  {completedEvents.length} / {totalRequiredClasses} aulas concluídas
                </span>
                <div className="w-20 md:w-24 h-2 bg-zinc-800 rounded-full overflow-hidden shrink-0">
                  <div 
                    className="h-full bg-emerald-500 transition-all duration-500"
                    style={{ 
                      width: `${totalRequiredClasses > 0 ? (completedEvents.length / totalRequiredClasses) * 100 : 0}%` 
                    }}
                  />
                </div>
              </div>
            </button>

            {/* Subject Content (Topics) */}
            {isExpanded && (
              <div className="border-t border-zinc-800 bg-black">
                {sortedTopics.map(topic => {
                  const isTopicExpanded = expandedTopics.has(topic.id);
                  const topicModules = topic.modules || [];

                  return (
                    <div key={topic.id} className="border-b border-zinc-800 last:border-0">
                      {/* Topic Header */}
                      <button
                        onClick={() => toggleTopic(topic.id)}
                        className="w-full flex flex-col md:flex-row md:items-center justify-between p-3 pl-8 hover:bg-zinc-900 transition-colors gap-1 md:gap-0"
                      >
                        <div className="flex items-center gap-3 w-full md:w-auto">
                          {isTopicExpanded ? <ChevronDown className="w-4 h-4 text-zinc-500 shrink-0" /> : <ChevronRight className="w-4 h-4 text-zinc-500 shrink-0" />}
                          <span className="text-sm font-medium text-zinc-300 text-left">{topic.name}</span>
                        </div>
                        <span className="text-xs text-zinc-500 text-left pl-7 md:pl-0 shrink-0">
                          {topicModules.length} módulos
                        </span>
                      </button>

                      {/* Topic Content (Modules) */}
                      {isTopicExpanded && (
                        <div className="bg-black pl-12 pr-4 py-2 space-y-2">
                          {topicModules.map(module => {
                            const isModuleExpanded = expandedModules.has(module.id);
                            const moduleEvents = events.filter(e => e.moduleId === module.id)
                              .sort((a, b) => new Date(`${a.date}T${a.startTime}`).getTime() - new Date(`${b.date}T${b.startTime}`).getTime());

                            const moduleContents = module.contents || [];

                            return (
                              <div 
                                key={module.id} 
                                id={`module-${module.id}`}
                                className="border border-zinc-800 rounded-md overflow-hidden bg-black transition-all duration-500"
                              >
                                {/* Module Header */}
                                <button
                                  onClick={() => toggleModule(module.id)}
                                  className="w-full flex flex-col md:flex-row md:items-center justify-between p-3 hover:bg-zinc-900 transition-colors gap-2 md:gap-0"
                                >
                                  <div className="flex items-center gap-3 w-full md:w-auto">
                                    {isModuleExpanded ? <ChevronDown className="w-4 h-4 text-zinc-500 shrink-0" /> : <ChevronRight className="w-4 h-4 text-zinc-500 shrink-0" />}
                                    <div className="flex items-center gap-2 flex-wrap">
                                      <span className="text-sm text-zinc-300 text-left">{module.name}</span>
                                      {module.isOnline && (
                                        <span className="text-[10px] bg-blue-500/10 text-blue-500 px-2 py-0.5 rounded border border-blue-500/20 font-medium uppercase shrink-0">
                                          Online
                                        </span>
                                      )}
                                    </div>
                                  </div>
                                  <div className="flex items-center justify-between md:justify-end gap-3 text-xs text-zinc-500 w-full md:w-auto pl-7 md:pl-0">
                                    <span className="flex items-center gap-1 shrink-0">
                                      <FileText className="w-3 h-3" />
                                      {moduleContents.length}
                                    </span>
                                    {module.isOnline ? (
                                      <div className={`flex items-center gap-1.5 text-xs shrink-0 ${module.onlineStatus === 'PUBLICADO' ? 'text-green-500' : 'text-amber-500'}`}>
                                        {module.onlineStatus === 'PUBLICADO' ? <CheckCircle2 size={14} /> : <Video size={14} />}
                                        <span className="font-medium whitespace-nowrap">{module.onlineStatus === 'PUBLICADO' ? 'Publicado' : 'Em Gravação'}</span>
                                      </div>
                                    ) : (
                                      <span className="flex items-center gap-1 shrink-0">
                                        <Clock className="w-3 h-3" />
                                        {moduleEvents.filter(e => e.status === 'COMPLETED').length} / {module.classesCount} aulas
                                      </span>
                                    )}
                                  </div>
                                </button>

                                {/* Module Content (Materials & Classes) */}
                                {isModuleExpanded && (
                                  <div className="p-4 space-y-6 border-t border-zinc-800 bg-black">

                                    {module.isOnline && (
                                      <div className="mb-4 bg-gray-800/50 border border-gray-700/50 rounded-lg p-4">
                                        <div className="flex items-start justify-between flex-wrap gap-4">
                                          <div>
                                            <h4 className="text-sm font-medium text-white mb-1">Conteúdo Online</h4>
                                            <p className="text-xs text-gray-400">
                                              {module.onlineStatus === 'PUBLICADO' 
                                                ? 'As aulas deste módulo já estão disponíveis e podem ser assistidas na sua Área de Ensino.' 
                                                : 'Este conteúdo está em fase de produção e será disponibilizado em breve.'}
                                            </p>
                                            {module.onlineStatus === 'EM_GRAVACAO' && module.publicationDate && (
                                              <div className="flex items-center gap-2 mt-3 text-xs text-amber-500 bg-amber-500/10 px-2 py-1.5 rounded w-fit font-medium border border-amber-500/20">
                                                <Calendar size={13} />
                                                <span>Previsão de publicação: {new Date(module.publicationDate).toLocaleDateString('pt-BR')}</span>
                                              </div>
                                            )}
                                          </div>
                                          {module.onlineStatus === 'PUBLICADO' && (
                                            <button 
                                              onClick={() => handleGoToTeachingArea(module.teachingAreaLink)}
                                              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-xs font-medium transition shadow-lg shadow-blue-500/20 shrink-0"
                                            >
                                              <PlayCircle size={16} />
                                              Ir para Área de Ensino
                                            </button>
                                          )}
                                        </div>
                                      </div>
                                    )}

                                    {/* Materials Section */}
                                    {moduleContents.length > 0 && (
                                      <div className="space-y-3">
                                        <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">Materiais de Apoio</h4>
                                        <div className="grid gap-2">
                                          {moduleContents.map(content => (
                                            <button 
                                              key={content.id}
                                              onClick={() => {
                                                if (content.type === 'PDF') {
                                                  handleOpenPdf(content.url, content.title);
                                                } else {
                                                  window.open(content.url, '_blank');
                                                }
                                              }}
                                              className="w-full text-left flex items-center gap-3 p-3 rounded-md bg-zinc-900 border border-zinc-800 hover:border-zinc-700 hover:bg-zinc-800 transition-all group"
                                            >
                                              <div className="p-2 rounded-md bg-black border border-zinc-800 group-hover:border-zinc-700">
                                                {content.type === 'PDF' ? (
                                                  <FileText className="w-4 h-4 text-red-400" />
                                                ) : (
                                                  <LinkIcon className="w-4 h-4 text-blue-400" />
                                                )}
                                              </div>
                                              <div className="flex-1">
                                                <p className="text-sm text-zinc-300 group-hover:text-white transition-colors">{content.title}</p>
                                                <p className="text-xs text-zinc-500">Adicionado em {new Date(content.createdAt).toLocaleDateString('pt-BR')}</p>
                                              </div>
                                            </button>
                                          ))}
                                        </div>
                                      </div>
                                    )}

                                    {/* Classes Section */}
                                    <div className="space-y-3">
                                      <h4 className="text-xs font-semibold text-zinc-500 uppercase tracking-wider">
                                        Cronograma de Aulas ({moduleEvents.length})
                                      </h4>

                                      {moduleEvents.length === 0 ? (
                                        <div className="text-center py-8 border border-dashed border-zinc-800 rounded-lg">
                                          <p className="text-sm text-zinc-500">Nenhuma aula agendada para este módulo.</p>
                                        </div>
                                      ) : (
                                        <div className="grid gap-2">
                                          {moduleEvents.map(event => {
                                            const teacher = teachers.find(t => t.id === event.teacherId);
                                            const isCompleted = event.status === 'COMPLETED';

                                            return (
                                              <div 
                                                key={event.id}
                                                className={twMerge(
                                                  "flex items-center justify-between p-3 rounded-md border transition-all",
                                                  isCompleted 
                                                    ? "bg-emerald-950/10 border-emerald-900/30" 
                                                    : "bg-zinc-900 border-zinc-800"
                                                )}
                                              >
                                                <div className="flex items-center gap-4">
                                                  <div className={twMerge(
                                                    "w-10 h-10 rounded-full flex items-center justify-center border",
                                                    isCompleted
                                                      ? "bg-emerald-500/10 border-emerald-500/30 text-emerald-500"
                                                      : "bg-zinc-800 border-zinc-700 text-zinc-400"
                                                  )}>
                                                    {isCompleted ? <CheckCircle className="w-5 h-5" /> : <Clock className="w-5 h-5" />}
                                                  </div>
                                                  <div>
                                                    <div className="flex items-center gap-2 mb-1">
                                                      <span className={twMerge(
                                                        "text-sm font-medium",
                                                        isCompleted ? "text-emerald-400" : "text-zinc-200"
                                                      )}>
                                                        {format(new Date(event.date + 'T00:00:00'), "dd 'de' MMMM", { locale: ptBR })}
                                                      </span>
                                                      <span className="text-xs text-zinc-500">
                                                        {event.startTime} - {event.endTime}
                                                      </span>
                                                    </div>
                                                    <div className="flex items-center gap-2 text-xs text-zinc-500">
                                                      <span>Prof. {teacher?.name || 'Não definido'}</span>
                                                      {event.isSubstitute && (
                                                        <span className="px-1.5 py-0.5 rounded bg-amber-500/10 text-amber-500 border border-amber-500/20">
                                                          Substituto
                                                        </span>
                                                      )}
                                                    </div>
                                                  </div>
                                                </div>

                                                <div className="flex items-center gap-2">
                                                  <span className={twMerge(
                                                    "text-xs px-2 py-1 rounded-full border",
                                                    event.status === 'COMPLETED' && "bg-emerald-500/10 text-emerald-500 border-emerald-500/20",
                                                    event.status === 'SCHEDULED' && "bg-blue-500/10 text-blue-500 border-blue-500/20",
                                                    event.status === 'CANCELED' && "bg-red-500/10 text-red-500 border-red-500/20",
                                                    event.status === 'RESCHEDULED' && "bg-amber-500/10 text-amber-500 border-amber-500/20",
                                                  )}>
                                                    {event.status === 'COMPLETED' && 'Concluída'}
                                                    {event.status === 'SCHEDULED' && 'Agendada'}
                                                    {event.status === 'CANCELED' && 'Cancelada'}
                                                    {event.status === 'RESCHEDULED' && 'Reagendada'}
                                                  </span>
                                                </div>
                                              </div>
                                            );
                                          })}
                                        </div>
                                      )}
                                    </div>
                                  </div>
                                )}
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        );
      })}

      {activeSubjects.length === 0 && (
        <div className="text-center py-12 border border-dashed border-zinc-800 rounded-lg bg-zinc-900/30">
          <AlertCircle className="w-8 h-8 text-zinc-600 mx-auto mb-3" />
          <h3 className="text-zinc-400 font-medium">Nenhuma disciplina encontrada</h3>
          <p className="text-zinc-500 text-sm mt-1">O planejamento pedagógico será disponibilizado em breve.</p>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Search, Filter, Loader2, GraduationCap } from 'lucide-react';
import { useAuth } from '../../../contexts/AuthContext';
import { classService } from '../../../services/classService';
import { classMetadataService, MetadataItem } from '../../../services/classMetadataService';
import { Class } from '../../../types/class';
import { StudentPresentialCard } from './StudentPresentialCard';

export function StudentPresentialTab() {
  const { userData } = useAuth();

  // Estados de Dados
  const [myClasses, setMyClasses] = useState<Class[]>([]);
  const [filteredClasses, setFilteredClasses] = useState<Class[]>([]);
  const [categories, setCategories] = useState<MetadataItem[]>([]);
  const [subcategories, setSubcategories] = useState<MetadataItem[]>([]);
  const [loading, setLoading] = useState(true);

  // Estados de Filtro
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedSubcategory, setSelectedSubcategory] = useState('');

  // 1. Carregar e Filtrar Dados
  useEffect(() => {
    const loadData = async () => {
        if (!userData || !userData.access) {
            setLoading(false);
            return;
        }

        try {
            // Busca dados do sistema
            const [allClasses, allCategories, allSubcategories] = await Promise.all([
                classService.getClasses(),
                classMetadataService.getCategories(),
                classMetadataService.getSubcategories()
            ]);

            // LÓGICA CRUCIAL: Filtrar apenas turmas que o usuário tem acesso
            // O user.access contém itens { type: 'presential_class', targetId: '...', isActive: true }
            const myAccess = userData.access
                .filter((a: any) => a.type === 'presential_class' && a.isActive);

            const myAccessIds = myAccess.map((a: any) => a.targetId);

            const allowedClasses = allClasses
                .filter(cls => myAccessIds.includes(cls.id))
                .map(cls => {
                    // Descobre o índice original no array de acessos do aluno para espelhar a ordem de cadastro
                    const accessIndex = userData.access.findIndex((a: any) => 
                        a.targetId === cls.id && a.type === 'presential_class' && a.isActive
                    );
                    const access = userData.access[accessIndex];

                    return { 
                        ...cls, 
                        grantedAt: access?.createdAt || access?.grantedAt,
                        orderIndex: access?.orderIndex || 0,
                        accessIndex: accessIndex !== -1 ? accessIndex : 999
                    };
                })
                .sort((a, b) => a.accessIndex - b.accessIndex);

            setMyClasses(allowedClasses);
            setFilteredClasses(allowedClasses);
            setCategories(allCategories);
            setSubcategories(allSubcategories);
        } catch (error) {
            console.error("Erro ao carregar turmas presenciais do aluno:", error);
        } finally {
            setLoading(false);
        }
    };
    loadData();
  }, [userData]);

  // 2. Lógica de Filtragem (Pesquisa/Categoria)
  useEffect(() => {
    const results = myClasses.filter(cls => {
      // Filtro de Texto (Nome ou Órgão)
      const matchesSearch = 
        cls.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (cls.organization && cls.organization.toLowerCase().includes(searchTerm.toLowerCase()));

      // Filtro de Categoria (Comparando ID ou Nome, dependendo de como foi salvo na Class. 
      // Na interface Class, category é string. Assumindo que salva o ID ou Nome. 
      // O Admin salva o ID geralmente. Vamos verificar se bate com o ID da categoria)
      const matchesCategory = selectedCategory ? cls.category === selectedCategory : true;

      // Filtro de Subcategoria
      const matchesSubcategory = selectedSubcategory ? cls.subcategory === selectedSubcategory : true;

      return matchesSearch && matchesCategory && matchesSubcategory;
    });
    setFilteredClasses(results);
  }, [searchTerm, selectedCategory, selectedSubcategory, myClasses]);

  if (loading) {
    return (
        <div className="flex flex-col items-center justify-center min-h-[50vh] gap-4">
            <Loader2 size={40} className="animate-spin text-emerald-600" />
            <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest">Carregando suas turmas...</p>
        </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in pb-20">

      {/* Título */}
      <div className="flex flex-col gap-2">
        <h2 className="text-4xl md:text-5xl font-black text-white tracking-tighter uppercase">
            Turmas <span className="text-emerald-600">Presenciais</span>
        </h2>
        <p className="text-zinc-400 text-sm font-medium">
            Acesse suas turmas presenciais e materiais exclusivos.
        </p>
      </div>

      {/* Barra de Filtros */}
      <div className="bg-[#121418] p-3 rounded-xl border border-zinc-800 flex flex-col md:flex-row gap-3 items-center shadow-lg">

        <div className="flex items-center gap-2 px-3 text-zinc-500 font-bold text-xs uppercase tracking-wider shrink-0">
            <Filter size={16} />
            Filtros:
        </div>

        {/* Select Categoria */}
        <div className="relative w-full md:w-auto min-w-[200px]">
            <select
                value={selectedCategory}
                onChange={(e) => { setSelectedCategory(e.target.value); }}
                className="w-full bg-black border border-zinc-800 rounded-lg px-3 py-2.5 text-xs text-white focus:border-emerald-600 outline-none uppercase font-bold appearance-none cursor-pointer"
            >
                <option value="">Todas as Categorias</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.name}</option>
                ))}
            </select>
            <div className="absolute right-3 top-3 pointer-events-none text-zinc-500">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
        </div>

        {/* Select Subcategoria */}
        <div className="relative w-full md:w-auto min-w-[200px]">
            <select
                value={selectedSubcategory}
                onChange={(e) => setSelectedSubcategory(e.target.value)}
                className="w-full bg-black border border-zinc-800 rounded-lg px-3 py-2.5 text-xs text-white focus:border-emerald-600 outline-none uppercase font-bold appearance-none cursor-pointer"
            >
                <option value="">Todas as Subcategorias</option>
                {subcategories.map(sub => (
                    <option key={sub.id} value={sub.id}>{sub.name}</option>
                ))}
            </select>
            <div className="absolute right-3 top-3 pointer-events-none text-zinc-500">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
        </div>

        {/* Campo de Busca */}
        <div className="flex-1 w-full relative">
            <Search className="w-4 h-4 text-zinc-500 absolute left-3 top-2.5" />
            <input 
                type="text" 
                placeholder="BUSCAR POR NOME OU ÓRGÃO..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full bg-black border border-zinc-800 rounded-lg pl-9 p-2.5 text-xs text-white focus:border-emerald-600 outline-none uppercase font-bold placeholder-zinc-700"
            />
        </div>
      </div>

      {/* Grid de Resultados */}
      {filteredClasses.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-20 border-2 border-dashed border-zinc-800 rounded-2xl bg-zinc-900/20 text-center">
            <div className="bg-zinc-800 p-4 rounded-full mb-4 text-zinc-500">
                <GraduationCap size={32} />
            </div>
            <h3 className="text-zinc-300 font-bold uppercase text-lg">Nenhuma turma encontrada</h3>
            <p className="text-zinc-500 text-xs mt-2 max-w-md">
                {myClasses.length === 0 
                    ? "Você ainda não possui turmas presenciais liberadas em sua conta. Entre em contato com a secretaria." 
                    : "Tente ajustar os filtros de busca para encontrar o que procura."}
            </p>
        </div>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
            {filteredClasses.map(cls => (
                <StudentPresentialCard 
                    key={cls.id} 
                    classData={cls} 
                    // onClick={() => {}} // Futuramente abrirá detalhes
                />
            ))}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { X, Eye, EyeOff, Upload } from 'lucide-react';
import Cropper from 'react-easy-crop';
import getCroppedImg from '../../../utils/cropImage';
// Ajuste os caminhos de importação conforme a estrutura do seu projeto
import { updateStudentProfile, changeUserPassword, checkNicknameExists } from '../../../services/profileService'; 
import { uploadProfilePhoto } from '../../../services/storageService'; 
import { updateProfile } from 'firebase/auth';
import { auth, db } from '../../../services/firebase';
import { doc, getDoc } from 'firebase/firestore';

interface EditProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: any; // Ajuste para a interface do seu usuário
}

export const EditProfileModal: React.FC<EditProfileModalProps> = ({ isOpen, onClose, user }) => {
  const [photoFile, setPhotoFile] = useState<File | null>(null);
  const [isRemovingPhoto, setIsRemovingPhoto] = useState(false);
  const [imageToCrop, setImageToCrop] = useState<string | null>(null);
  const [crop, setCrop] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [croppedAreaPixels, setCroppedAreaPixels] = useState<any>(null);

  // Tenta ler a foto do arquivo ou das possíveis propriedades do banco
  const currentPhoto = !isRemovingPhoto ? (photoFile ? URL.createObjectURL(photoFile) : (user?.photoURL || user?.photo || user?.photoUrl)) : null;

  const [whatsapp, setWhatsapp] = useState(user?.whatsapp || '');
  const [nickname, setNickname] = useState(user?.nickname || '');
  const [isCheckingNickname, setIsCheckingNickname] = useState(false);
  const [nicknameStatus, setNicknameStatus] = useState<'idle' | 'available' | 'taken'>('idle');

  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Busca os dados completos do usuário direto no banco de dados ao abrir o modal
  useEffect(() => {
    const fetchCompleteUserData = async () => {
      if (isOpen && user?.uid) {
        try {
          // Preenchimento otimista (caso a prop user já tenha algo)
          setWhatsapp(user.whatsapp || '');
          setNickname(user.nickname || '');

          // Busca a fonte da verdade no Firestore
          const userDocRef = doc(db, 'users', user.uid);
          const userDocSnap = await getDoc(userDocRef);

          if (userDocSnap.exists()) {
            const userData = userDocSnap.data();
            setWhatsapp(userData.whatsapp || user.whatsapp || '');
            setNickname(userData.nickname || user.nickname || '');
          }

          // Limpeza de segurança
          setPassword('');
          setConfirmPassword('');
          setNicknameStatus('idle');
          setError('');
          setSuccess('');
        } catch (error) {
          console.error("Erro ao buscar dados do usuário no Firestore:", error);
        }
      }
    };

    fetchCompleteUserData();
  }, [isOpen, user]);

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.addEventListener('load', () => setImageToCrop(reader.result?.toString() || null));
      reader.readAsDataURL(file);
    }
  };

  const handleConfirmCrop = async () => {
    try {
      if (!imageToCrop || !croppedAreaPixels) return;
      const croppedFile = await getCroppedImg(imageToCrop, croppedAreaPixels, 'profile.jpg');
      if (croppedFile) {
        setPhotoFile(croppedFile);
        setImageToCrop(null); // Fecha o editor e volta pro formulário
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleCheckNickname = async () => {
    if (!nickname.trim() || nickname === user?.nickname) return;
    setIsCheckingNickname(true);
    try {
      const exists = await checkNicknameExists(nickname, user.uid);
      setNicknameStatus(exists ? 'taken' : 'available');
    } catch (err) {
      console.error("Erro ao verificar apelido:", err);
    } finally {
      setIsCheckingNickname(false);
    }
  };

  if (!isOpen) return null;

  const handleSave = async () => {
    setError('');
    setSuccess('');

    if (nickname && nickname !== user?.nickname && nicknameStatus !== 'available') {
      return setError('Por favor, verifique a disponibilidade do apelido clicando no botão "Verificar".');
    }

    // Validação de Senha
    if (password || confirmPassword) {
      if (password !== confirmPassword) {
        return setError('As senhas digitadas não são idênticas.');
      }
      if (password.length < 6) {
        return setError('A nova senha deve ter no mínimo 6 caracteres.');
      }
    }

    setLoading(true);
    try {
      const updatedData: any = { whatsapp, nickname };

      // 1. Upload ou Remoção de Foto
      if (isRemovingPhoto) {
        updatedData.photoURL = "";
        updatedData.photo = "";

        // Atualiza o Firebase Authentication
        if (auth.currentUser) {
          await updateProfile(auth.currentUser, { photoURL: "" });
        }
      } else if (photoFile) {
        const photoURL = await uploadProfilePhoto(user.uid, photoFile);

        // Aplica o Cache-Buster (Carimbo de tempo) para forçar o navegador a atualizar a imagem visualmente
        const finalPhotoURL = photoURL.includes('?') 
          ? `${photoURL}&t=${Date.now()}` 
          : `${photoURL}?t=${Date.now()}`;

        updatedData.photoURL = finalPhotoURL;
        updatedData.photo = finalPhotoURL;

        // Atualiza o Firebase Authentication com a nova URL
        if (auth.currentUser) {
          await updateProfile(auth.currentUser, { photoURL: finalPhotoURL });
        }
      }

      // 2. Atualizar Senha
      if (password) {
        await changeUserPassword(password);
      }

      // 3. Atualizar Dados no Firestore
      await updateStudentProfile(user.uid, updatedData);

      setSuccess('Perfil atualizado com sucesso!');
      setTimeout(() => {
        onClose();
      }, 1500);

    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro ao atualizar o perfil.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-40 flex justify-center items-start pt-[100px] pb-10 px-4 overflow-y-auto bg-black/80 backdrop-blur-sm sm:items-center sm:pt-4">
      <div className="bg-gray-900 border border-gray-800 rounded-xl w-full max-w-md p-6 relative flex flex-col gap-4 shadow-2xl my-auto shrink-0">

        <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-white transition">
          <X size={24} />
        </button>

        <h2 className="text-2xl font-bold text-white mb-2">Editar Perfil</h2>

        {error && <div className="bg-red-500/20 border border-red-500 text-red-500 p-3 rounded-lg text-sm">{error}</div>}
        {success && <div className="bg-green-500/20 border border-green-500 text-green-500 p-3 rounded-lg text-sm">{success}</div>}

        {/* EDITOR DE IMAGEM CONDICIONAL */}
        {imageToCrop ? (
          <div className="flex flex-col gap-4 animate-in fade-in zoom-in duration-200">
            <div className="relative w-full h-64 bg-black rounded-lg overflow-hidden border border-gray-700">
              <Cropper
                image={imageToCrop}
                crop={crop}
                zoom={zoom}
                aspect={1}
                cropShape="round"
                showGrid={false}
                onCropChange={setCrop}
                onCropComplete={(_, croppedAreaPixels) => setCroppedAreaPixels(croppedAreaPixels)}
                onZoomChange={setZoom}
              />
            </div>
            <div className="flex flex-col gap-2">
              <label className="text-gray-400 text-sm">Ajustar Zoom</label>
              <input
                type="range"
                value={zoom}
                min={1}
                max={3}
                step={0.1}
                onChange={(e) => setZoom(Number(e.target.value))}
                className="w-full accent-red-500"
              />
            </div>
            <div className="flex justify-end gap-3 mt-2 border-t border-gray-800 pt-4">
              <button type="button" onClick={() => setImageToCrop(null)} className="px-4 py-2 bg-gray-800 text-white rounded-lg hover:bg-gray-700 transition">Cancelar</button>
              <button type="button" onClick={handleConfirmCrop} className="px-4 py-2 bg-red-600 text-white font-medium rounded-lg hover:bg-red-700 transition shadow-lg shadow-red-500/20">Confirmar Corte</button>
            </div>
          </div>
        ) : (
          <>
            {/* Formulário Padrão com Avatar Aumentado */}
            <div className="flex flex-col gap-2">
              <label className="text-gray-400 text-sm">Foto de Perfil</label>
              <div className="flex items-center gap-6">
                <div className="w-28 h-28 rounded-full bg-gray-800 flex items-center justify-center overflow-hidden border-2 border-gray-700 shrink-0 shadow-lg relative group">
                  {currentPhoto ? (
                    <img src={currentPhoto} alt="Perfil" className="w-full h-full object-cover" />
                  ) : (
                    <span className="text-gray-500 text-4xl font-bold">{user?.name?.charAt(0) || 'U'}</span>
                  )}
                  {/* Overlay escuro que aparece ao passar o mouse */}
                  <label className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center cursor-pointer transition-opacity duration-200">
                    <Upload size={24} className="text-white drop-shadow-md" />
                    <input type="file" accept="image/*" className="hidden" onChange={onFileChange} />
                  </label>
                </div>

                <div className="flex flex-col gap-3 items-start">
                  <label className="flex items-center gap-2 cursor-pointer bg-gray-800 hover:bg-gray-700 text-white py-2.5 px-5 rounded-lg transition border border-gray-700 font-medium text-sm">
                    <Upload size={18} />
                    <span>{currentPhoto ? 'Alterar Foto' : 'Escolher Foto'}</span>
                    <input type="file" accept="image/*" className="hidden" onChange={onFileChange} />
                  </label>

                  {currentPhoto && (
                    <button
                      type="button"
                      onClick={() => { setPhotoFile(null); setImageToCrop(null); setIsRemovingPhoto(true); }}
                      className="text-red-500 hover:text-red-400 text-sm font-medium transition ml-1"
                    >
                      Remover Foto
                    </button>
                  )}
                </div>
              </div>
            </div>

            {/* WhatsApp e Apelido */}
            <div className="flex flex-col gap-2 mt-2">
              <label className="text-gray-400 text-sm">WhatsApp</label>
              <input type="text" value={whatsapp} onChange={(e) => setWhatsapp(e.target.value)} placeholder="(00) 00000-0000" className="w-full bg-gray-800 border border-gray-700 text-white rounded-lg p-3 focus:outline-none focus:border-red-500 transition" />
            </div>

            <div className="flex flex-col gap-2">
              <label className="text-gray-400 text-sm">Apelido (Para o Ranking de Simulados)</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={nickname}
                  onChange={(e) => {
                    setNickname(e.target.value);
                    setNicknameStatus('idle'); // Reseta o status se o usuário começar a digitar de novo
                  }}
                  placeholder={user?.nickname ? `Atual: ${user.nickname}` : "Seu apelido..."}
                  className="w-full bg-gray-800 border border-gray-700 text-white rounded-lg p-3 focus:outline-none focus:border-red-500 transition"
                />
                <button
                  type="button"
                  onClick={handleCheckNickname}
                  disabled={isCheckingNickname || !nickname.trim() || nickname === user?.nickname}
                  className="px-4 py-2 bg-gray-800 border border-gray-700 hover:bg-gray-700 text-white font-medium rounded-lg transition disabled:opacity-50 whitespace-nowrap"
                >
                  {isCheckingNickname ? 'Verificando...' : 'Verificar'}
                </button>
              </div>
              {nicknameStatus === 'available' && <span className="text-green-500 text-xs font-medium ml-1">✓ Apelido disponível!</span>}
              {nicknameStatus === 'taken' && <span className="text-red-500 text-xs font-medium ml-1">✕ Este apelido já está em uso. Escolha outro.</span>}
            </div>

            {/* Redefinição de Senha */}
            <div className="flex flex-col gap-2 mt-2 pt-4 border-t border-gray-800">
              <h3 className="text-white font-medium text-sm">Redefinir Senha</h3>

              <div className="relative">
                <input type={showPassword ? 'text' : 'password'} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="Nova senha (mín. 6 caracteres)" className="w-full bg-gray-800 border border-gray-700 text-white rounded-lg p-3 pr-10 focus:outline-none focus:border-red-500 transition" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-3 text-gray-400 hover:text-white transition">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>

              <div className="relative mt-2">
                <input type={showPassword ? 'text' : 'password'} value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="Confirme a nova senha" className="w-full bg-gray-800 border border-gray-700 text-white rounded-lg p-3 pr-10 focus:outline-none focus:border-red-500 transition" />
              </div>
            </div>
          </>
        )}

        <button onClick={handleSave} disabled={loading} className="w-full mt-4 bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-lg transition disabled:opacity-50">
          {loading ? 'SALVANDO...' : 'SALVAR ALTERAÇÕES'}
        </button>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { doc, updateDoc } from 'firebase/firestore';
import { db } from '../../../services/firebase';
