                    <div className="h-px w-full bg-white/5 mb-3"></div>
                    <p className="text-[10px] font-bold text-gray-600 uppercase mb-2">Assuntos Identificados:</p>
                    {topics && topics.length > 0 ? (
                        <ul className="grid grid-cols-1 gap-1.5">
