            </div>

            {/* 2. GRÁFICO DE EVOLUÇÃO */}
            <div className="bg-[#1a1d24] p-6 rounded-2xl border border-gray-800 shadow-xl">
                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
