interface SimulatedExamRunnerProps {
  exam: SimulatedExam;
  onClose: () => void;
  onComplete: (result: SimulatedAttempt) => void;
  classId?: string;
}

const SimulatedExamRunner: React.FC<SimulatedExamRunnerProps> = ({ exam, onClose, onComplete, classId }) => {
  const { currentUser, userData } = useAuth();

  // States
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [missingQuestions, setMissingQuestions] = useState<number[]>([]);

  // Modal States
  const [showIncompleteModal, setShowIncompleteModal] = useState(false);
  const [showFinishModal, setShowFinishModal] = useState(false); // PASSO 1: Estado do Modal

  // Handlers
  const handleOptionSelect = (questionIndex: number, option: string) => {
    setAnswers(prev => {
        const current = prev[questionIndex];
        // Toggle logic: Desmarcar se clicar na mesma (útil para provas estilo Cespe/Penalidade)
        if (current === option && exam.hasPenalty) {
            const next = { ...prev };
            delete next[questionIndex];
            return next;
        }
        return { ...prev, [questionIndex]: option };
    });

    // Remove da lista de erros visualmente assim que marca uma opção
    if (missingQuestions.includes(questionIndex)) {
        setMissingQuestions(prevMissing => prevMissing.filter(q => q !== questionIndex));
    }
  };

  // PASSO 2 (PARTE A): Validação e Abertura do Modal
  const handleFinish = () => {
    console.log("%c 🚀 INICIANDO VALIDAÇÃO", "color: green; font-weight: bold;");

    // 0. VERIFICAÇÃO DE INTEGRIDADE
    if (!exam.questions || exam.questions.length === 0) {
        alert("ERRO TÉCNICO: Este simulado está em modo RASCUNHO ou não possui gabarito cadastrado.");
        return;
    }

    // 1. VALIDAÇÃO DE OBRIGATORIEDADE (Regra: Sem penalidade = Obrigatório preencher tudo)
    if (!exam.hasPenalty) {
        const missing: number[] = [];

        for (let i = 1; i <= exam.questionCount; i++) {
            const val = answers[i] || answers[String(i)];
            const hasAnswer = val !== undefined && val !== null && val !== "";
            if (!hasAnswer) missing.push(i);
        }

        if (missing.length > 0) {
            console.warn(`⛔ BLOQUEIO: Faltam ${missing.length} questões.`);
            setMissingQuestions(missing); 
            setShowIncompleteModal(true); 
            return; 
        }
    }

    // 2. TUDO CERTO -> ABRE O MODAL (Não usa mais window.confirm)
    setShowFinishModal(true);
  };

  // PASSO 2 (PARTE B): Envio Real
  const handleConfirmSubmission = async () => {
    if (!currentUser) return;

    // Fecha o modal visualmente mas mantém loading no botão se necessário, 
    // ou podemos manter o modal aberto com estado de loading (melhor UX)
    setIsSubmitting(true);

    try {
        console.log("🔄 Enviando respostas para cálculo...");

        // Chama o serviço que encapsula a lógica de cálculo e salvamento no Firestore
        const result = await submitExamAttempt(
            {
                uid: currentUser.uid,
                name: userData?.name || 'Aluno',
                nickname: (userData as any)?.nickname, 
                photoURL: currentUser.photoURL || undefined
            },
            exam,
            answers,
            classId
        );

        console.log("✅ Tentativa salva com sucesso:", result);

        setShowFinishModal(false);

        // Pequeno delay para garantir UI update antes do alert/redirect
        setTimeout(() => {
             // Feedback visual ou sonoro opcional aqui
             onComplete(result); // Redireciona para o Ranking/Resultado
        }, 300);

    } catch (error: any) {
        console.error("🔥 Erro ao salvar tentativa:", error);
        alert(`Erro técnico ao salvar sua nota: ${error.message}`);
        setShowFinishModal(false); 
    } finally {
        setIsSubmitting(false);
    }
  };

  // Renderização via Portal para garantir sobreposição correta
  return createPortal(
    <div className="fixed inset-0 z-[200] flex flex-col bg-zinc-950 text-white font-sans animate-in fade-in duration-300">

      {/* HEADER */}
      <div className="flex-none h-20 bg-zinc-900 border-b border-zinc-800 px-6 flex items-center justify-between shadow-2xl relative z-50">
          <button 
             onClick={() => {
                // Aqui podemos manter um confirm simples pois é saída destrutiva, 
                // ou implementar outro modal se desejar consistência total.
                if(Object.keys(answers).length === 0 || confirm("Deseja sair do simulado? Seu progresso será perdido.")) {
                    onClose();
                }
             }}
             className="flex items-center gap-2 text-zinc-400 hover:text-white hover:bg-zinc-800 px-4 py-2 rounded-lg transition-all group"
          >
             <LogOut size={20} className="group-hover:text-red-500 transition-colors" />
             <span className="text-sm font-bold uppercase tracking-wider">Sair</span>
          </button>

          <div className="absolute left-1/2 transform -translate-x-1/2 text-center hidden md:block">
             <h2 className="text-lg font-black text-white uppercase tracking-tighter">{exam.title}</h2>
             <span className="text-[10px] text-emerald-500 font-black uppercase tracking-widest bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">Em Andamento</span>
          </div>

          <button 
              onClick={() => {
                  const pdfLink = exam.files?.bookletUrl;
                  if (pdfLink) window.open(pdfLink, '_blank');
                  else alert("Link do PDF não encontrado.");
              }}
              className="flex items-center gap-3 bg-blue-600 hover:bg-blue-500 text-white px-6 py-2.5 rounded-lg font-bold text-xs uppercase tracking-widest shadow-lg hover:shadow-blue-500/30 transition-all transform hover:-translate-y-0.5 active:translate-y-0"
          >
              <FileText size={18} />
              Baixar Caderno
          </button>
      </div>

      {/* BODY: GRID DE QUESTÕES */}
      <div className="flex-1 overflow-y-auto p-6 bg-black/40 scrollbar-thin scrollbar-thumb-zinc-800">
          <div className="max-w-[1800px] mx-auto">
               <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
                  {Array.from({ length: exam.questionCount }).map((_, i) => {
                      const qNum = i + 1;
                      const isAnswered = answers[qNum] !== undefined && answers[qNum] !== "";
                      const currentAnswer = answers[qNum];
                      const isError = missingQuestions.includes(qNum);

                      return (
                          <div key={qNum} className={`p-4 rounded-xl border flex flex-col items-center gap-3 transition-all ${
                              isError 
                                ? 'border-red-600 shadow-[0_0_15px_rgba(220,38,38,0.5)] animate-pulse bg-red-900/10' 
                                : isAnswered ? 'border-zinc-700 bg-zinc-900 shadow-lg' : 'border-zinc-800 bg-zinc-950 hover:border-zinc-700'
                          }`}>
                              <div className="flex items-center justify-between w-full">
                                <span className={`text-[10px] font-black uppercase tracking-widest ${isError ? 'text-red-500' : isAnswered ? 'text-emerald-500' : 'text-zinc-600'}`}>
                                    Questão {qNum.toString().padStart(2, '0')}
                                </span>
                                {isError && <AlertTriangle size={12} className="text-red-500" />}
                                {isAnswered && !isError && <CheckCircle2 size={12} className="text-emerald-500" />}
                              </div>

                              <div className="flex gap-1.5 justify-center w-full">
                                  {exam.type === 'multiple_choice' ? (
                                      ['A','B','C','D', (exam.alternativesCount === 5 ? 'E' : null)].filter(Boolean).map((opt: any) => (
                                          <button
                                              key={opt}
                                              onClick={() => handleOptionSelect(qNum, opt)}
                                              className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-black transition-all ${
                                                  currentAnswer === opt 
                                                  ? 'bg-brand-red text-white shadow-lg shadow-red-900/50 scale-110' 
                                                  : 'bg-zinc-900 border border-zinc-800 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300'
                                              }`}
                                          >
                                              {opt}
                                          </button>
                                      ))
                                  ) : (
                                      ['C', 'E'].map(opt => (
                                          <button
                                              key={opt}
                                              onClick={() => handleOptionSelect(qNum, opt)}
                                              className={`w-10 h-8 rounded-lg flex items-center justify-center text-xs font-black transition-all ${
                                                  currentAnswer === opt 
                                                  ? (opt === 'C' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white') + ' shadow-lg scale-110' 
                                                  : 'bg-zinc-900 border border-zinc-800 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300'
                                              }`}
                                          >
                                              {opt}
                                          </button>
                                      ))
                                  )}
                              </div>
                          </div>
                      );
                  })}
               </div>
          </div>
      </div>

      {/* FOOTER */}
      <div className="flex-none h-24 bg-zinc-900 border-t border-zinc-800 px-8 flex items-center justify-between z-50 shadow-[0_-10px_40px_rgba(0,0,0,0.5)]">
          <div className="text-xs font-bold text-zinc-500 uppercase tracking-widest">
              Respondidas: <b className="text-white text-lg mx-1">{Object.keys(answers).length}</b> / {exam.questionCount}
          </div>

          <button 
              onClick={handleFinish}
              disabled={isSubmitting}
              className="bg-emerald-600 hover:bg-emerald-500 text-white px-10 py-4 rounded-xl font-black text-sm uppercase tracking-widest shadow-xl hover:shadow-emerald-500/20 transition-all transform hover:-translate-y-1 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
              {isSubmitting ? <Loader2 className="animate-spin" /> : null}
              {isSubmitting ? 'Calculando...' : 'Finalizar Simulado'}
          </button>
      </div>

      {/* MODAL: QUESTÕES EM BRANCO */}
      {showIncompleteModal && (
        <div className="fixed inset-0 z-[300] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-zinc-900 border border-red-500/50 rounded-2xl p-8 max-w-md w-full shadow-2xl relative animate-in zoom-in-95 duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-red-500/10 p-4 rounded-full mb-6 border border-red-500/20">
                        <AlertTriangle className="w-10 h-10 text-red-500" />
                    </div>
                    <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">Simulado Incompleto</h3>
                    <p className="text-zinc-400 mb-8 text-sm leading-relaxed">
                        Este simulado não possui penalidade, portanto é <strong>obrigatório</strong> responder todas as questões.
                        <br/><br/>
                        Você ainda precisa responder <span className="text-red-400 font-bold">{missingQuestions.length} questões</span>.
                    </p>
                    <button 
                        onClick={() => setShowIncompleteModal(false)}
                        className="bg-red-600 hover:bg-red-500 text-white w-full py-4 rounded-xl font-black text-xs uppercase tracking-widest transition-colors shadow-lg shadow-red-900/20"
                    >
                        Entendido
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* PASSO 3: MODAL DE CONFIRMAÇÃO DE ENVIO */}
      {showFinishModal && (
        <div className="fixed inset-0 z-[400] bg-black/80 flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-zinc-900 border border-emerald-500/30 rounded-2xl p-8 max-w-md w-full shadow-2xl relative animate-in zoom-in-95 duration-200">
                <div className="flex flex-col items-center text-center">
                    <div className="bg-emerald-500/10 p-4 rounded-full mb-6 border border-emerald-500/20">
                        <CheckCircle2 className="w-10 h-10 text-emerald-500" />
                    </div>
                    <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">Finalizar Simulado?</h3>
                    <p className="text-zinc-400 mb-8 text-sm leading-relaxed">
                        Tem certeza que deseja enviar suas respostas? 
                        <br/>
                        Ao confirmar, sua nota será calculada automaticamente e você não poderá mais alterar as respostas.
                    </p>

                    <div className="flex gap-3 w-full">
                        <button 
                            onClick={() => setShowFinishModal(false)}
                            className="flex-1 py-4 rounded-xl font-bold text-xs uppercase tracking-widest transition-colors bg-zinc-800 hover:bg-zinc-700 text-white border border-zinc-700"
                        >
                            Revisar
                        </button>
                        <button 
                            onClick={handleConfirmSubmission}
                            disabled={isSubmitting}
                            className="flex-1 py-4 rounded-xl font-black text-xs uppercase tracking-widest transition-colors shadow-lg bg-emerald-600 hover:bg-emerald-500 text-white shadow-emerald-900/20 flex items-center justify-center gap-2"
                        >
                            {isSubmitting ? <Loader2 className="animate-spin" size={16}/> : <Check size={16} />}
                            {isSubmitting ? 'Enviando...' : 'Sim, Finalizar'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

    </div>,
    document.body
  );
};

export default SimulatedExamRunner;

import React, { useState, useRef, useEffect } from 'react';
import { 
  X, Save, Loader2, BookOpen, 
  Bold, Italic, Underline, Strikethrough,
  AlignLeft, AlignCenter, AlignRight, AlignJustify,
  Highlighter, Type, Minus, Eraser
} from 'lucide-react';

interface NotebookEditorModalProps {
  initialData?: string;
  title: string;
  onSave: (data: string) => Promise<void>;
  onClose: () => void;
  readOnly?: boolean;
}

const NotebookEditorModal: React.FC<NotebookEditorModalProps> = ({ initialData, title, onSave, onClose, readOnly }) => {
  const [saving, setSaving] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  // Color States for Pickers
  const [foreColor, setForeColor] = useState('#ffffff');
  const [hiliteColor, setHiliteColor] = useState('#eab308'); // Yellow-500 default

  useEffect(() => {
    if (editorRef.current) {
        // Set initial HTML. Handles plain text or HTML gracefully.
        editorRef.current.innerHTML = initialData || '';
    }
  }, [initialData]);

  const handleSave = async () => {
    if (!editorRef.current) return;
    setSaving(true);
    try {
        const htmlContent = editorRef.current.innerHTML;
        await onSave(htmlContent);
    } catch (error) {
        console.error("Save failed", error);
    } finally {
        setSaving(false);
    }
  };

  const execCmd = (command: string, value?: string) => {
    document.execCommand(command, false, value);
    if (editorRef.current) editorRef.current.focus();
  };

  // Helper for Toolbar Buttons
  const ToolbarBtn = ({ icon: Icon, cmd, val, title, activeClass = "" }: any) => (
    <button
        type="button"
        onMouseDown={(e) => { e.preventDefault(); execCmd(cmd, val); }}
        className={`p-2 rounded hover:bg-zinc-800 text-zinc-400 hover:text-white transition-colors ${activeClass}`}
        title={title}
    >
        <Icon size={16} />
    </button>
  );

  return (
    <div className="fixed inset-0 z-[200] w-screen h-screen bg-zinc-950 flex flex-col animate-in fade-in duration-300">

        {/* Header */}
        <div className="p-4 border-b border-zinc-900 flex justify-between items-center bg-zinc-950 shrink-0">
          <div className="flex items-center gap-3">
             <div className="p-2 bg-yellow-500/10 rounded-lg text-yellow-500 border border-yellow-500/20">
                <BookOpen size={20} />
             </div>
             <div>
                <h2 className="text-lg font-black text-white uppercase tracking-tighter leading-none">{title}</h2>
                <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">Caderno de Anotações</span>
             </div>
          </div>
          <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Toolbar (Only if not ReadOnly) */}
        {!readOnly && (
            <div className="px-4 py-2 border-b border-zinc-900 bg-zinc-900/50 flex flex-wrap items-center gap-1 shrink-0 overflow-x-auto">
                {/* Text Style */}
                <div className="flex items-center gap-0.5 border-r border-zinc-800 pr-2 mr-2">
                    <ToolbarBtn icon={Bold} cmd="bold" title="Negrito" />
                    <ToolbarBtn icon={Italic} cmd="italic" title="Itálico" />
                    <ToolbarBtn icon={Underline} cmd="underline" title="Sublinhado" />
                    <ToolbarBtn icon={Strikethrough} cmd="strikeThrough" title="Taxado" />
                </div>

                {/* Alignment */}
                <div className="flex items-center gap-0.5 border-r border-zinc-800 pr-2 mr-2">
                    <ToolbarBtn icon={AlignLeft} cmd="justifyLeft" title="Alinhar Esquerda" />
                    <ToolbarBtn icon={AlignCenter} cmd="justifyCenter" title="Centralizar" />
                    <ToolbarBtn icon={AlignRight} cmd="justifyRight" title="Alinhar Direita" />
                    <ToolbarBtn icon={AlignJustify} cmd="justifyFull" title="Justificar" />
                </div>

                {/* Font Size (Simplified) */}
                <div className="flex items-center gap-2 border-r border-zinc-800 pr-2 mr-2">
                    <select 
                        onChange={(e) => execCmd('fontSize', e.target.value)}
                        className="bg-zinc-900 text-xs text-white border border-zinc-800 rounded p-1.5 focus:outline-none focus:border-yellow-500"
                    >
                        <option value="3">Normal</option>
                        <option value="1">Pequeno</option>
                        <option value="5">Grande</option>
                        <option value="7">Enorme</option>
                    </select>
                </div>

                {/* Colors */}
                <div className="flex items-center gap-2 border-r border-zinc-800 pr-2 mr-2">
                    {/* Font Color */}
                    <div className="relative group w-8 h-8 flex items-center justify-center">
                        <ToolbarBtn icon={Type} cmd="foreColor" val={foreColor} title="Cor da Fonte" activeClass="text-white" />
                        <input 
                            type="color" 
                            className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                            value={foreColor}
                            onChange={(e) => {
                                setForeColor(e.target.value);
                                execCmd('foreColor', e.target.value);
                            }}
                        />
                        <div className="h-1 w-6 absolute bottom-1 left-1 rounded-full" style={{ backgroundColor: foreColor }}></div>
                    </div>

                    {/* Highlight */}
                    <div className="relative group w-8 h-8 flex items-center justify-center">
                        <ToolbarBtn icon={Highlighter} cmd="hiliteColor" val={hiliteColor} title="Marca Texto" activeClass="text-white" />
                        <input 
                            type="color" 
                            className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                            value={hiliteColor}
                            onChange={(e) => {
                                setHiliteColor(e.target.value);
                                execCmd('hiliteColor', e.target.value);
                            }}
                        />
                        <div className="h-1 w-6 absolute bottom-1 left-1 rounded-full" style={{ backgroundColor: hiliteColor }}></div>
                    </div>

                    <ToolbarBtn icon={Eraser} cmd="removeFormat" title="Limpar Formatação" />
                </div>

                {/* Divider */}
                <ToolbarBtn icon={Minus} cmd="insertHorizontalRule" title="Linha Divisória" />

            </div>
        )}

        {/* Editor Area */}
        <div className="flex-1 bg-zinc-950 relative overflow-hidden flex flex-col">
          <div 
            ref={editorRef}
            contentEditable={!readOnly}
            suppressContentEditableWarning
            className={`
                w-full h-full p-8 text-zinc-300 focus:outline-none overflow-y-auto custom-scrollbar
                prose prose-invert prose-sm max-w-none
                ${readOnly ? '' : 'cursor-text'}
            `}
            style={{ 
                fontFamily: 'Inter, sans-serif',
                lineHeight: '1.6',
                minHeight: '100%'
            }}
            spellCheck={false}
          />
        </div>

        {/* Footer */}
        {!readOnly && (
          <div className="p-4 border-t border-zinc-900 bg-zinc-950 flex justify-end shrink-0">
            <button
              onClick={handleSave}
              disabled={saving}
              className="px-8 py-3 bg-yellow-600 hover:bg-yellow-500 text-black font-black uppercase text-xs tracking-widest rounded-xl flex items-center gap-2 transition-all disabled:opacity-50 shadow-lg shadow-yellow-900/20"
            >
              {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
              {saving ? 'Salvando...' : 'Salvar Caderno'}
            </button>
          </div>
        )}

        {/* Style Injection for Editor Content */}
        <style>{`
            .custom-scrollbar::-webkit-scrollbar { width: 8px; }
            .custom-scrollbar::-webkit-scrollbar-track { background: #09090b; }
            .custom-scrollbar::-webkit-scrollbar-thumb { background: #27272a; border-radius: 4px; }
            .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #3f3f46; }

            /* Basic resets for contentEditable */
            [contenteditable]:empty:before {
                content: 'Digite suas anotações aqui...';
                color: #52525b;
                font-style: italic;
            }

            b, strong { font-weight: 900; color: white; }
            i, em { font-style: italic; }
            u { text-decoration: underline; }
            strike { text-decoration: line-through; opacity: 0.7; }

            hr { border: 0; border-top: 1px solid #3f3f46; margin: 20px 0; }

            /* Font Sizes mapping */
            font[size="1"] { font-size: 0.75rem; }
            font[size="2"] { font-size: 0.875rem; }
            font[size="3"] { font-size: 1rem; }
            font[size="4"] { font-size: 1.125rem; }
            font[size="5"] { font-size: 1.5rem; font-weight: bold; }
            font[size="6"] { font-size: 2rem; font-weight: 900; }
            font[size="7"] { font-size: 3rem; font-weight: 900; }
        `}</style>
    </div>
  );
};

export default NotebookEditorModal;

import React, { createContext, useContext, useEffect, useState } from 'react';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged, 
  User,
  UserCredential 
} from 'firebase/auth';
import { doc, getDoc } from 'firebase/firestore';
import { auth, db } from '../services/firebase';

interface UserData {
  role?: string;
  name?: string;
  email?: string;
  cpf?: string;
  phone?: string;
  photoURL?: string;
  access?: any[];
  [key: string]: any;
}

interface AuthContextType {
  currentUser: User | null;
  userRole: 'ADMIN' | 'STUDENT' | 'COLLABORATOR' | null;
  userData: UserData | null; // Stores full firestore document data (permissions, etc)
  loading: boolean;
  login: (email: string, password: string) => Promise<UserCredential>;
  logout: () => Promise<void>;
  seedInitialUsers: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [userRole, setUserRole] = useState<'ADMIN' | 'STUDENT' | 'COLLABORATOR' | null>(null);
  const [userData, setUserData] = useState<UserData | null>(null);
  const [loading, setLoading] = useState(true);

  // Hardcoded admin email for this phase
  const ADMIN_EMAIL = 'insanusconcursos@gmail.com';

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setCurrentUser(user);

      if (user) {
        try {
            // Fetch User Data from Firestore
            const userDocRef = doc(db, 'users', user.uid);
            const userDocSnap = await getDoc(userDocRef);

            if (userDocSnap.exists()) {
                const data = userDocSnap.data();
                setUserData(data);

                // Determine Role from Firestore Data
                if (data.role === 'collaborator') {
                    setUserRole('COLLABORATOR');
                } else if (data.role === 'student') {
                    setUserRole('STUDENT');
                } else if (data.role === 'admin' || user.email === ADMIN_EMAIL) {
                    setUserRole('ADMIN');
                } else {
                    setUserRole('STUDENT'); // Fallback
                }
            } else {
                // Fallback for Seeded/Hardcoded Admin without Firestore Doc
                if (user.email === ADMIN_EMAIL) {
                    setUserRole('ADMIN');
                    setUserData({ role: 'admin', name: 'Super Admin' });
                } else {
                    // Default fallback for users without doc (likely students created via auth directly)
                    setUserRole('STUDENT');
                    setUserData(null);
                }
            }
        } catch (error) {
            console.error("Error fetching user role:", error);
            // Default safe fallback
            setUserRole('STUDENT'); 
        }
      } else {
        setUserRole(null);
        setUserData(null);
      }

      setLoading(false);
    });

    return unsubscribe;
  }, []);

  const login = async (email: string, password: string): Promise<UserCredential> => {
    return await signInWithEmailAndPassword(auth, email, password);
  };

  const logout = async () => {
    await signOut(auth);
  };

  const seedInitialUsers = async () => {
    const users = [
      { email: 'insanusconcursos@gmail.com', pass: '123456' },
      { email: 'kelsen.pantoja.prof@gmail.com', pass: '123456' }
    ];

    console.log("Starting seed process...");

    for (const u of users) {
      try {
        await createUserWithEmailAndPassword(auth, u.email, u.pass);
        console.log(`User created: ${u.email}`);
        await signOut(auth); 
      } catch (err: unknown) {
        const error = err as { code?: string };
        if (error.code === 'auth/email-already-in-use') {
          console.log(`User already exists: ${u.email}`);
        } else {
          console.error(`Error creating user ${u.email}:`, error);
        }
      }
    }
    console.log("Seed process finished.");
  };

  const value = {
    currentUser,
    userRole,
    userData,
    loading,
    login,
    logout,
    seedInitialUsers
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

import { useMemo } from 'react';
import { EdictStructure } from '../services/edictService';

interface EditalProgressStats {
  globalProgress: number;
  disciplineStats: Record<string, number>;
  totalGoals: number;
  completedGoals: number;
}

export const useEditalProgress = (
  structure: EdictStructure | null, 
  completedMetaIds: Set<string>
): EditalProgressStats => {
  return useMemo(() => {
    // 1. Proteção contra dados vazios ou carregando
    if (!structure) {
      return { 
        globalProgress: 0, 
        disciplineStats: {}, 
        totalGoals: 0, 
        completedGoals: 0 
      };
    }

    let globalTotal = 0;
    let globalCompleted = 0;
    const disciplineStats: Record<string, number> = {};

    // 2. Iteração sobre as Disciplinas
    structure.disciplines.forEach(discipline => {
      let discTotal = 0;
      let discCompleted = 0;

      // Função auxiliar para contar metas vinculadas em Tópicos e Subtópicos
      const countGoals = (linkedGoals: any) => {
        if (!linkedGoals) return;

        // Itera sobre os tipos de meta (lesson, material, etc.)
        Object.values(linkedGoals).forEach((ids: any) => {
          if (Array.isArray(ids)) {
            discTotal += ids.length;
            ids.forEach(id => {
              if (completedMetaIds.has(id as string)) {
                discCompleted++;
              }
            });
          }
        });
      };

      // Varre Tópicos
      discipline.topics.forEach(topic => {
        countGoals(topic.linkedGoals);
        // Varre Subtópicos
        topic.subtopics.forEach(subtopic => {
          countGoals(subtopic.linkedGoals);
        });
      });

      // Calcula % da disciplina (evita divisão por zero)
      const percentage = discTotal === 0 ? 0 : Math.round((discCompleted / discTotal) * 100);
      disciplineStats[discipline.id] = percentage;

      // Soma ao total global
      globalTotal += discTotal;
      globalCompleted += discCompleted;
    });

    // 3. Cálculo Global Final
    const globalProgress = globalTotal === 0 ? 0 : Math.round((globalCompleted / globalTotal) * 100);

    return {
      globalProgress,
      disciplineStats,
      totalGoals: globalTotal,
      completedGoals: globalCompleted
    };
  }, [structure, completedMetaIds]); // Recalcula automaticamente se structure ou completedMetaIds mudar
};

import { Class } from '../types/class';
import { Topic, Subject } from '../types/curriculum';
import { Teacher } from '../types/teacher';

const parseCurrency = (value: any): number => {
  if (value === null || value === undefined) return 0;
  if (typeof value === 'number') return value;

  // If it's a string like "50.00" (standard float format), parse directly
  if (/^\d+\.\d+$/.test(String(value))) {
    return parseFloat(String(value));
  }

  // Otherwise apply the Brazilian format logic (remove dots, replace comma with dot)
  // "1.000,50" -> "1000.50"
  const stringValue = String(value).replace(/\./g, '').replace(',', '.').replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(stringValue);
  return isNaN(parsed) ? 0 : parsed;
};

export const useFinancialCalculations = (
  cls: Class,
  topics: Topic[],
  subjects: Subject[],
  teachers: Teacher[]
) => {
  const getFinancialDiagnostics = () => {
    const teachersWithoutRate: string[] = [];
    const topicsWithoutModules: string[] = [];
    const selectedTopics = topics.filter(t => t.isSelected);

    selectedTopics.forEach(topic => {
      const modules = topic.modules || [];
      const activeModules = modules.filter(mod => mod.isSelected !== false);

      if (activeModules.length === 0) {
        topicsWithoutModules.push(topic.name);
      }

      // Identify responsible teacher
      let teacherId = topic.teacherId;
      if (!teacherId) {
        const subject = subjects.find(s => s.id === topic.subjectId);
        teacherId = subject?.defaultTeacherId;
      }

      if (teacherId) {
        const teacher = teachers.find(t => t.id === teacherId);

        // Determine correct rate based on class category
        const isEnem = cls.category?.toUpperCase().includes('ENEM') || cls.subcategory?.toUpperCase().includes('ENEM');
        let rawRate = 0;

        if (teacher) {
            if (isEnem) {
                rawRate = teacher.baseHourlyRateEnem || teacher.baseHourlyRateConcurso || 0;
            } else {
                rawRate = teacher.baseHourlyRateConcurso || teacher.baseHourlyRateEnem || 0;
            }
        }

        const teacherRate = parseCurrency(rawRate);

        if (!teacher || teacherRate <= 0) {
          if (teacher && !teachersWithoutRate.includes(teacher.name)) {
            teachersWithoutRate.push(teacher.name);
          }
        }
      }
    });

    return { teachersWithoutRate, topicsWithoutModules };
  };

  const calculateProjectedCost = () => {
    const safeConfig = cls.remunerationConfig || {
      mode: 'DYNAMIC',
      fixedHourlyRate: 0,
      recordingCommission: 0,
      substitutionCommission: 0,
      weekendCommission: 0
    };

    const selectedTopics = topics.filter(t => t.isSelected);
    let totalCost = 0;

    console.log('--- Financial Calculation Debug ---');
    console.log(`Calculation Mode: ${safeConfig.mode}`);

    selectedTopics.forEach(topic => {
      const modules = topic.modules || [];
      const activeModules = modules.filter(mod => mod.isSelected !== false);

      activeModules.forEach(module => {
        // a) Determine duration in hours
        // classesPerMeeting is how many classes fit in one meetingDuration
        // So duration of one class = meetingDuration / classesPerMeeting
        // Total duration = classesCount * (meetingDuration / classesPerMeeting)
        const durationInHours = (module.classesCount / (cls.classesPerMeeting || 1)) * cls.meetingDuration;

        // b) Identify responsible teacher
        let teacherId = topic.teacherId;
        if (!teacherId) {
          const subject = subjects.find(s => s.id === topic.subjectId);
          teacherId = subject?.defaultTeacherId;
        }

        // c) Define Base Hourly Rate
        let baseHourlyRate = 0;
        let teacherName = 'Unknown';

        if (safeConfig.mode === 'FIXED') {
          baseHourlyRate = parseCurrency(safeConfig.fixedHourlyRate);
        } else {
          // DYNAMIC
          const teacher = teachers.find(t => t.id === teacherId);
          if (teacher) {
              const isEnem = cls.category?.toUpperCase().includes('ENEM') || cls.subcategory?.toUpperCase().includes('ENEM');
              let rawRate = 0;
              if (isEnem) {
                  rawRate = teacher.baseHourlyRateEnem || teacher.baseHourlyRateConcurso || 0;
              } else {
                  rawRate = teacher.baseHourlyRateConcurso || teacher.baseHourlyRateEnem || 0;
              }
              baseHourlyRate = parseCurrency(rawRate);
              teacherName = teacher.name;
          }
        }

        // d) Apply Recording Commission
        let finalHourlyRate = baseHourlyRate;
        if (cls.hasRecordings && safeConfig.recordingCommission) {
          const commission = baseHourlyRate * (safeConfig.recordingCommission / 100);
          finalHourlyRate += commission;
        }

        // e) Multiply Rate by Duration
        const moduleCost = finalHourlyRate * durationInHours;
        totalCost += moduleCost;

        console.log(`Topic: ${topic.name} | Module: ${module.name}`);
        console.log(`  Duration: ${durationInHours.toFixed(2)}h | Teacher: ${teacherName} | Rate: R$${baseHourlyRate} | Cost: R$${moduleCost.toFixed(2)}`);
      });
    });

    console.log(`Total Projected Cost: R$${totalCost.toFixed(2)}`);
    console.log('-----------------------------------');

    return totalCost;
  };

  return { calculateProjectedCost, getFinancialDiagnostics };
};

import { useState, useEffect } from 'react';
import { doc, onSnapshot } from 'firebase/firestore';
import { db } from '../services/firebase';
import { publishPlan } from '../services/syncService';

interface UsePlanSyncReturn {
  hasPendingChanges: boolean;
  lastModified: Date | null;
  lastSynced: Date | null;
  publish: () => Promise<void>;
  loading: boolean;
  publishing: boolean;
}

export const usePlanSync = (planId: string | undefined): UsePlanSyncReturn => {
  const [hasPendingChanges, setHasPendingChanges] = useState(false);
  const [lastModified, setLastModified] = useState<Date | null>(null);
  const [lastSynced, setLastSynced] = useState<Date | null>(null);
  const [loading, setLoading] = useState(true);
  const [publishing, setPublishing] = useState(false);

  useEffect(() => {
    if (!planId) {
        setLoading(false);
        return;
    }

    // Listen to the Plan Document for timestamp changes
    const unsub = onSnapshot(
      doc(db, 'plans', planId), 
      { serverTimestamps: 'estimate' }, // Garante que timestamps pendentes tenham uma estimativa
      (docSnap) => {
        if (docSnap.exists()) {
            const data = docSnap.data();

            // Helper to get millis from Timestamp or Date
            const getMillis = (val: any) => {
              if (!val) return 0;
              if (val.toMillis) return val.toMillis();
              if (val.seconds) return val.seconds * 1000;
              if (val instanceof Date) return val.getTime();
              try {
                return new Date(val).getTime() || 0;
              } catch {
                return 0;
              }
            };

            const modifiedMillis = getMillis(data.lastModifiedAt);
            const syncedMillis = getMillis(data.lastSyncedAt);

            setLastModified(data.lastModifiedAt?.toDate ? data.lastModifiedAt.toDate() : (data.lastModifiedAt ? new Date(modifiedMillis) : null));
            setLastSynced(data.lastSyncedAt?.toDate ? data.lastSyncedAt.toDate() : (data.lastSyncedAt ? new Date(syncedMillis) : null));

            // Compare dates
            // Se modificado é maior que sincronizado (com margem de 1s), ou se nunca sincronizou mas tem modificação
            const hasPending = 
              (modifiedMillis > syncedMillis + 10) || 
              (modifiedMillis > 0 && syncedMillis === 0);

            console.log(`[usePlanSync] Plan: ${planId} | Modified: ${modifiedMillis} | Synced: ${syncedMillis} | Pending: ${hasPending}`);

            setHasPendingChanges(hasPending);
        }
        setLoading(false);
      },
      (error) => {
        console.error("[usePlanSync] Error listening to plan sync status:", error);
        setLoading(false);
      }
    );

    return () => unsub();
  }, [planId]);

  const handlePublish = async () => {
    if (!planId) return;
    setPublishing(true);
    try {
        await publishPlan(planId);
        // State update handled by listener above
    } catch (error) {
        console.error("Publish failed", error);
        alert("Erro ao publicar alterações. Verifique o console.");
    } finally {
        setPublishing(false);
    }
  };

  return {
    hasPendingChanges,
    lastModified,
    lastSynced,
    publish: handlePublish,
    loading,
    publishing
  };
};

