                                            </table>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

const StudentSimulated: React.FC = () => {
  const { currentUser } = useAuth();

  // Navigation State
  const [viewState, setViewState] = useState<'CLASSES' | 'EXAMS' | 'RESULT'>('CLASSES');
  const [selectedClass, setSelectedClass] = useState<SimulatedClass | null>(null);
  const [selectedExam, setSelectedExam] = useState<SimulatedExam | null>(null);
  const [lastAttempt, setLastAttempt] = useState<SimulatedAttempt | null>(null);

  // Data State (Exams Only - Classes now handled by subcomponent)
  const [exams, setExams] = useState<SimulatedExam[]>([]);
  const [loadingExams, setLoadingExams] = useState(false);
  const [examAttempts, setExamAttempts] = useState<Record<string, SimulatedAttempt>>({}); // Cache de tentativas

  // New: Class Attempts for Dashboard
  const [classAttempts, setClassAttempts] = useState<SimulatedAttempt[]>([]);
  const [classViewMode, setClassViewMode] = useState<'LIST' | 'DASHBOARD'>('LIST');

  // Runner State
  const [isRunningExam, setIsRunningExam] = useState(false);
  const [isVideoModalOpen, setIsVideoModalOpen] = useState(false);

  // --- ACTIONS ---

  const handleSelectClass = (cls: SimulatedClass) => {
    loadExams(cls);
  };

  const loadExams = async (cls: SimulatedClass) => {
    setLoadingExams(true);
    setSelectedClass(cls);
    setViewState('EXAMS');
    setClassViewMode('LIST'); // Reset view mode when opening a class
    try {
        const data = await getExams(cls.id!);
        // Ordenar: Published primeiro
        const sorted = data.sort((a,b) => (a.status === 'published' ? -1 : 1));
        setExams(sorted);

        // Fetch All Attempts for this Class
        if (currentUser) {
            const q = query(
                collection(db, 'simulated_attempts'),
                where('userId', '==', currentUser.uid),
                where('classId', '==', cls.id)
            );
            const snapshot = await getDocs(q);
            const attempts = snapshot.docs.map(d => ({id: d.id, ...d.data()} as SimulatedAttempt));

            setClassAttempts(attempts);

            // Populate Map for List View (latest attempt per exam logic if needed, here just existence)
            const attemptsMap: Record<string, SimulatedAttempt> = {};
            attempts.forEach(att => {
                attemptsMap[att.simulatedId] = att; 
            });
            setExamAttempts(attemptsMap);
        }

    } catch (error) {
        console.error(error);
    } finally {
        setLoadingExams(false);
    }
  };

  // --- HANDLERS ---

  const handleStartExam = (exam: SimulatedExam) => {
    setSelectedExam(exam);
    setIsRunningExam(true);
  };

  const handleViewResult = (exam: SimulatedExam, attempt: SimulatedAttempt) => {
    setSelectedExam(exam);
    setLastAttempt(attempt);
    setViewState('RESULT');
  };

  const handleExamComplete = (result: SimulatedAttempt) => {
    setIsRunningExam(false);
    setLastAttempt(result);
    setViewState('RESULT');
    // Atualiza cache local
    if (selectedExam?.id) {
        setExamAttempts(prev => ({ ...prev, [selectedExam.id!]: result }));
        // Also update class attempts list to reflect new data in dashboard
        setClassAttempts(prev => [...prev, result]);
    }
  };

  const handleBackToClasses = () => {
    setViewState('CLASSES');
    setSelectedClass(null);
    setExams([]);
    setClassAttempts([]);
  };

  const handleBackToExams = () => {
    setViewState('EXAMS');
    setSelectedExam(null);
    setLastAttempt(null);
  };

  if (loadingExams) return <Loading />;

  // === RENDER: EXAM RUNNER (OVERLAY) ===
  if (isRunningExam && selectedExam) {
      return (
          <SimulatedExamRunner 
              exam={selectedExam}
              onClose={() => setIsRunningExam(false)}
              onComplete={handleExamComplete}
              classId={selectedClass?.id}
          />
      );
  }

  // === RENDER: RESULT & RANKING (NEW EXAMRESULT COMPONENT) ===
  if (viewState === 'RESULT' && selectedExam && lastAttempt) {
      return (
          <ExamResult 
              exam={selectedExam}
              attemptData={lastAttempt}
              onBack={handleBackToExams}
          />
      );
  }

  // === RENDER: EXAMS LIST ===
  if (viewState === 'EXAMS' && selectedClass) {
      // Filtrar apenas simulados PUBLICADOS para o aluno
      const visibleExams = exams.filter(e => e.status === 'published');

      return (
          <div className="space-y-8 animate-in fade-in slide-in-from-right-8 duration-500">

              {/* --- CABEÇALHO DA TURMA COM ABAS --- */}
              <div className="flex flex-col md:flex-row justify-between items-end mb-8 border-b border-gray-800 pb-2">
                  <div className="flex items-center gap-4">
                      <button onClick={handleBackToClasses} className="p-2 bg-zinc-900 border border-zinc-800 rounded-xl hover:text-white text-zinc-400 transition-colors">
                          <ArrowLeft size={20} />
                      </button>
                      <div>
                          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">{selectedClass.title}</h2>
                          <div className="flex items-center gap-3 mt-1">
                              <p className="text-zinc-500 text-xs font-bold uppercase tracking-widest">{selectedClass.organization}</p>
                              {selectedClass.presentationVideoUrl && (
                                  <button 
                                      onClick={() => setIsVideoModalOpen(true)}
                                      className="flex items-center gap-1.5 px-3 py-1 bg-zinc-800 hover:bg-zinc-700 text-white rounded-full text-[10px] font-black uppercase tracking-widest transition-all border border-zinc-700"
                                  >
                                      <PlayCircle size={12} className="text-brand-red" />
                                      Vídeo de Apresentação
                                  </button>
                              )}
                          </div>
                      </div>
                  </div>

                  {/* SELETOR DE VISUALIZAÇÃO */}
                  <div className="flex gap-6 mt-4 md:mt-0">
                      <button 
                          onClick={() => setClassViewMode('LIST')}
                          className={`pb-2 text-xs font-bold uppercase transition-all tracking-widest ${classViewMode === 'LIST' ? 'text-brand-red border-b-2 border-brand-red' : 'text-zinc-500 hover:text-white'}`}
                      >
                          Simulados Disponíveis
                      </button>
                      <button 
                          onClick={() => setClassViewMode('DASHBOARD')}
                          className={`pb-2 text-xs font-bold uppercase transition-all tracking-widest flex items-center gap-2 ${classViewMode === 'DASHBOARD' ? 'text-yellow-500 border-b-2 border-yellow-500' : 'text-zinc-500 hover:text-white'}`}
                      >
                          <BarChart2 size={14} />
                          Evolução & Performance
                      </button>
                  </div>
              </div>

              {classViewMode === 'LIST' ? (
                  <>
                      {visibleExams.length === 0 ? (
                          <div className="text-center py-20 border-2 border-dashed border-zinc-800 rounded-2xl">
                              <p className="text-zinc-500 font-bold uppercase text-xs">Nenhum simulado disponível nesta turma.</p>
                          </div>
                      ) : (
                          <div className="grid grid-cols-1 gap-4">
                              {visibleExams.map(exam => {
                                  const attempt = examAttempts[exam.id!];
                                  const isDone = !!attempt;

                                  // Lógica de Agendamento (Data de Publicação)
                                  const now = new Date();
                                  const publishDate = exam.publishDate ? new Date(exam.publishDate) : null;
                                  const isBlocked = publishDate && publishDate > now;

                                  return (
                                      <div key={exam.id} className={`bg-zinc-900 border border-zinc-800 p-5 rounded-2xl flex flex-col md:flex-row md:items-center justify-between gap-4 group hover:border-zinc-700 transition-all ${isBlocked ? 'opacity-75' : ''}`}>
                                          <div className="flex items-center gap-4">
                                              <div className={`p-3 rounded-xl ${isDone ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : isBlocked ? 'bg-zinc-800 text-zinc-600 border border-zinc-700' : 'bg-zinc-800 text-zinc-400'}`}>
                                                  {isDone ? <Trophy size={24} /> : isBlocked ? <Lock size={24} /> : <FileCheck size={24} />}
                                              </div>
                                              <div>
                                                  <div className="flex items-center gap-2">
                                                    <h3 className={`text-lg font-black uppercase tracking-tight ${isBlocked ? 'text-zinc-500' : 'text-white'}`}>{exam.title}</h3>
                                                    {isBlocked && (
                                                        <span className="px-2 py-0.5 rounded bg-zinc-800 text-zinc-500 text-[9px] font-bold uppercase border border-zinc-700 flex items-center gap-1">
                                                            <Lock size={10} /> BLOQUEADO
                                                        </span>
                                                    )}
                                                  </div>
                                                  <div className="flex items-center gap-3 text-[10px] font-bold text-zinc-500 uppercase mt-1">
                                                      <span className="flex items-center gap-1"><Layers size={12} /> {exam.questionCount} Questões</span>
                                                      {exam.hasPenalty && <span className="flex items-center gap-1 text-red-500"><AlertCircle size={12} /> Penalidade Ativa</span>}
                                                      {isBlocked && publishDate && (
                                                          <span className="flex items-center gap-1 text-purple-400">
                                                               Liberação em: {publishDate.toLocaleString('pt-BR', { day: '2-digit', month: '2-digit', year: '2-digit', hour: '2-digit', minute: '2-digit' })}
                                                          </span>
                                                      )}
                                                  </div>
                                              </div>
                                          </div>

                                          <div className="flex items-center gap-3">
                                              {isDone ? (
                                                  <button 
                                                      onClick={() => handleViewResult(exam, attempt)}
                                                      className="px-6 py-3 bg-zinc-800 hover:bg-zinc-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2"
                                                  >
                                                      <BarChart2 size={14} /> Ver Resultado
                                                  </button>
                                              ) : isBlocked ? (
                                                  <button 
                                                      disabled
                                                      className="px-6 py-3 bg-zinc-800 text-zinc-600 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 cursor-not-allowed border border-zinc-700"
                                                  >
                                                      <Lock size={14} /> Bloqueado
                                                  </button>
                                              ) : (
                                                  <button 
                                                      onClick={() => handleStartExam(exam)}
                                                      className="px-6 py-3 bg-brand-red hover:bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 shadow-lg shadow-red-900/20"
                                                  >
                                                      <PlayCircle size={14} /> Iniciar Prova
                                                  </button>
                                              )}
                                          </div>
                                      </div>
                                  );
                              })}
                          </div>
                      )}
                  </>
              ) : (
                  <StudentPerformanceDashboard attempts={classAttempts} />
              )}

              {/* MODAL DE VÍDEO DE APRESENTAÇÃO */}
              {isVideoModalOpen && selectedClass.presentationVideoUrl && (
                  <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                      <div className="absolute inset-0 bg-black/90 backdrop-blur-sm" onClick={() => setIsVideoModalOpen(false)}></div>
                      <div className="relative w-full max-w-4xl bg-zinc-950 border border-zinc-800 rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
                          <div className="p-4 border-b border-zinc-900 flex items-center justify-between bg-zinc-900/50">
                              <h3 className="text-xs font-black text-white uppercase tracking-widest flex items-center gap-2">
                                  <PlayCircle size={16} className="text-brand-red" />
                                  Vídeo de Apresentação
                              </h3>
                              <button onClick={() => setIsVideoModalOpen(false)} className="text-zinc-500 hover:text-white transition-colors">
                                  <X size={20} />
                              </button>
                          </div>
                          <div className="aspect-video w-full bg-black">
                              <iframe 
                                  src={selectedClass.presentationVideoUrl}
                                  className="w-full h-full"
                                  allow="accelerometer; gyroscope; autoplay; encrypted-media; picture-in-picture" 
                                  allowFullScreen
                              />
                          </div>
                      </div>
                  </div>
              )}
          </div>
      );
  }

  // === RENDER: CLASSES LIST (NEW COMPONENT) ===
  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="mb-8">
        <h1 className="text-3xl font-black text-white uppercase tracking-tighter">Meus Simulados</h1>
        <p className="text-zinc-500 text-sm font-medium uppercase tracking-widest mt-1">
          Treine com provas reais e acompanhe sua evolução.
        </p>
      </div>

      <StudentSimulatedList onSelectClass={handleSelectClass} />
    </div>
  );
};

export default StudentSimulated;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Users, VideoOff, FileText, ShieldAlert } from 'lucide-react';
import { doc, onSnapshot, getDoc, collection } from 'firebase/firestore';
import { db } from '../../../services/firebase';
import { LiveEvent, LiveActiveUser } from '../../../types/liveEvent';
import { useAuth } from '../../../contexts/AuthContext';
import { StudentLiveChat } from '../../../components/student/lives/room/StudentLiveChat';
import { StudentLiveWaitingRoom } from '../../../components/student/lives/room/StudentLiveWaitingRoom';
import { AdminLivePlayer } from '../../../components/admin/liveEvents/room/AdminLivePlayer';
import { StudentLiveRecording } from '../../../components/student/lives/room/StudentLiveRecording';
import { joinLiveEvent, leaveLiveEvent } from '../../../services/liveChatService';
import toast from 'react-hot-toast';

export const StudentLiveEventRoom: React.FC = () => {
  const { eventId } = useParams<{ eventId: string }>();
  const navigate = useNavigate();
  const { currentUser, userData, loading: authLoading } = useAuth();

  const [event, setEvent] = useState<LiveEvent | null>(null);
  const [loading, setLoading] = useState(true);
  const [userAccess, setUserAccess] = useState<{
    plans: string[];
    courses: string[];
    classes: string[];
    simulated: string[];
    isolatedProducts: string[];
  }>({ plans: [], courses: [], classes: [], simulated: [], isolatedProducts: [] });
  const [viewerCount, setViewerCount] = useState(0);
  const [isChatBlocked, setIsChatBlocked] = useState(false);

  const formatShortName = (fullName?: string | null) => {
    if (!fullName) return 'Aluno';
    const nameParts = fullName.trim().split(' ');
    return nameParts.slice(0, 2).join(' '); // Pega apenas o 1º e 2º nome
  };

  const resolvedName = formatShortName(userData?.name || currentUser?.displayName || currentUser?.email);

  // Heartbeat de Presença
  useEffect(() => {
    // A Trava: Bloqueia a execução se o contexto ainda estiver carregando os dados do Firestore
    if (authLoading || !currentUser || !eventId) return;

    const userPresence = {
      uid: currentUser.uid,
      name: resolvedName,
      email: currentUser.email || userData?.email || '',
      photoUrl: userData?.photoUrl || currentUser.photoURL || ''
    };

    joinLiveEvent(eventId, userPresence);

    return () => {
      leaveLiveEvent(eventId, currentUser.uid);
    };
  }, [eventId, currentUser, resolvedName, userData, authLoading]);

  // Listener de Usuários Online e Contagem
  useEffect(() => {
    if (!eventId) return;

    const presenceRef = collection(db, 'live_events', eventId, 'presence');
    const unsubscribe = onSnapshot(presenceRef, (snapshot) => {
      setViewerCount(snapshot.size);
    }, (error) => {
      console.error("Error listening to presence:", error);
    });

    return () => unsubscribe();
  }, [eventId]);

  // Listener de Moderação em Tempo Real (Banimento e Bloqueio de Chat)
  useEffect(() => {
    if (!eventId || !currentUser) return;

    const myPresenceRef = doc(db, 'live_events', eventId, 'presence', currentUser.uid);
    const unsubscribe = onSnapshot(myPresenceRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data();

        // Bloqueio de Chat
        setIsChatBlocked(!!data.isChatBlocked);

        // Banimento
        if (data.isBanned) {
          toast.error("Você foi removido deste evento pelo administrador.", {
            icon: <ShieldAlert className="text-red-500" />,
            duration: 5000
          });
          navigate('/app/eventos-ao-vivo');
        }
      }
    }, (error) => {
      console.error("Error listening to personal presence:", error);
    });

    return () => unsubscribe();
  }, [eventId, currentUser, navigate]);

  useEffect(() => {
    if (!currentUser) return;
    const loadUserAccess = async () => {
      const userDoc = await getDoc(doc(db, 'users', currentUser.uid));
      if (userDoc.exists()) {
        const userData = userDoc.data();

        const plans: string[] = [];
        const courses: string[] = [];
        const classes: string[] = [];
        const simulated: string[] = [];
        const isolatedProducts: string[] = [];

        if (userData?.access) {
          userData.access.forEach((item: any) => {
            if (!item.isActive) return;
            const now = new Date();
            const endDate = item.endDate?.toDate ? item.endDate.toDate() : new Date(item.endDate);
            if (endDate < now) return;

            if (item.type === 'plan') plans.push(item.targetId);
            if (item.type === 'course') courses.push(item.targetId);
            if (item.type === 'presential_class') classes.push(item.targetId);
            if (item.type === 'simulated_class') simulated.push(item.targetId);
            if (item.type === 'isolated_product' || item.type === 'live_event') isolatedProducts.push(item.targetId);
          });
        }

        // Legacy courses
        if (userData?.courses) {
          userData.courses.forEach((c: any) => {
            if (c.active) {
              if (c.expiresAt && new Date(c.expiresAt) < new Date()) return;
              if (!courses.includes(c.courseId)) courses.push(c.courseId);
            }
          });
        }

        setUserAccess({ plans, courses, classes, simulated, isolatedProducts });
      }
    };
    loadUserAccess();
  }, [currentUser]);

  const hasAccess = () => {
    if (!event) return false;
    if (event.isPublic) return true;

    const isIsolatedForUser = event.isIsolatedProduct && userAccess.isolatedProducts.includes(event.id!);
    if (isIsolatedForUser) return true;

    const { plans, onlineCourses, presentialClasses, simulated } = event.accessControl;

    if (plans.length === 0 && onlineCourses.length === 0 && presentialClasses.length === 0 && simulated.length === 0) {
      return true;
    }

    const hasPlanAccess = plans.some(id => userAccess.plans.includes(id));
    const hasCourseAccess = onlineCourses.some(id => userAccess.courses.includes(id));
    const hasClassAccess = presentialClasses.some(id => userAccess.classes.includes(id));
    const hasSimulatedAccess = simulated.some(id => userAccess.simulated.includes(id));

    return hasPlanAccess || hasCourseAccess || hasClassAccess || hasSimulatedAccess;
  };

  useEffect(() => {
    if (!eventId || !currentUser) return;

    // Listen to event changes in real-time
    const eventRef = doc(db, 'live_events', eventId);
    const unsubscribe = onSnapshot(eventRef, (docSnap) => {
      if (docSnap.exists()) {
        setEvent({ id: docSnap.id, ...docSnap.data() } as LiveEvent);
      } else {
        setEvent(null);
      }
      setLoading(false);
    }, (error) => {
      console.error("Error listening to event:", error);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [eventId, currentUser]);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen bg-black">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-brand-red"></div>
      </div>
    );
  }

  if (!event) {
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-black text-zinc-400">
        <VideoOff size={48} className="mb-4 opacity-20" />
        <h2 className="text-xl font-bold text-white mb-2">Evento não encontrado</h2>
        <button 
          onClick={() => navigate('/app/eventos-ao-vivo')}
          className="px-4 py-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg transition-colors mt-4"
        >
          Voltar para a lista
        </button>
      </div>
    );
  }

  if (event.status === 'ended') {
    // Se o usuário possui acesso, mostra a Gravação
    if (hasAccess()) {
      return (
         <div className="max-w-7xl mx-auto py-6 px-4">
            <button 
              onClick={() => navigate('/app/eventos-ao-vivo')}
              className="flex items-center gap-2 text-sm font-bold text-gray-400 hover:text-white transition-colors mb-6 uppercase tracking-wider"
            >
              <ArrowLeft size={18} />
              Voltar para a lista
            </button>
            <h1 className="text-2xl font-bold text-white mb-6">{event.title} - GRAVAÇÃO</h1>
            <StudentLiveRecording event={event} />
         </div>
      );
    }

    // Aluno comum (sem produto isolado)
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-black">
        <div className="text-center">
          <VideoOff size={48} className="mx-auto text-zinc-600 mb-4" />
          <h2 className="text-2xl font-bold text-white mb-2 uppercase tracking-tight">Evento Encerrado</h2>
          <p className="text-gray-400 mb-6">Esta transmissão ao vivo já foi finalizada.</p>
          <button 
            onClick={() => navigate('/app/eventos-ao-vivo')}
            className="px-6 py-2 bg-zinc-800 hover:bg-zinc-700 text-white rounded-lg transition-colors font-bold uppercase text-sm"
          >
            Voltar para a lista
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-black overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between bg-zinc-950 p-3 lg:p-4 border-b border-zinc-800 shrink-0">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => navigate('/app/eventos-ao-vivo')}
            className="p-2 hover:bg-zinc-800 rounded-lg text-zinc-400 hover:text-white transition-colors"
          >
            <ArrowLeft size={24} />
          </button>
          <div>
            <h1 className="text-lg font-bold text-white uppercase tracking-tight">{event.title}</h1>
            <div className="flex items-center gap-3 mt-1">
              <div className="flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${event.status === 'live' ? 'bg-brand-red animate-pulse' : event.status === 'scheduled' ? 'bg-blue-500' : 'bg-zinc-500'}`}></span>
                <span className="text-xs font-medium text-zinc-400">
                  {event.status === 'live' ? 'AO VIVO' : event.status === 'scheduled' ? 'AGENDADO' : 'ENCERRADO'}
                </span>
              </div>

              {event.showViewers && event.status === 'live' && (
                <>
                  <div className="w-1 h-1 bg-zinc-700 rounded-full"></div>
                  <div className="flex items-center gap-1 text-xs text-zinc-400">
                    <Users size={12} />
                    <span>{viewerCount} assistindo</span>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Grid */}
      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">
        {/* Left Column: Video Player */}
        <div className="w-full lg:w-2/3 xl:w-3/4 flex flex-col bg-black overflow-hidden lg:overflow-y-auto shrink-0 lg:shrink">
          <div className="w-full aspect-video bg-zinc-950 border-b border-zinc-800 flex items-center justify-center p-1 lg:p-6 shrink-0">
            {event.status === 'scheduled' && (
              <StudentLiveWaitingRoom 
                thumbnailUrl={event.thumbnailUrl} 
                eventDate={event.eventDate} 
                startTime={event.startTime} 
                timezoneLocation={event.timezoneLocation}
              />
            )}

            {event.status === 'live' && (
              <AdminLivePlayer event={event} />
            )}

            {event.status === 'ended' && (
              <div className="flex flex-col items-center justify-center text-center p-8 bg-zinc-900/50 rounded-2xl border border-zinc-800 w-full h-full">
                <VideoOff size={48} className="text-zinc-600 mb-4" />
                <h2 className="text-2xl font-black text-white uppercase tracking-tight mb-2">Evento Encerrado</h2>
                <p className="text-zinc-400">A transmissão ao vivo já terminou.</p>
              </div>
            )}
          </div>

          {/* Materials Section - Hidden on mobile to prioritize player and chat if they don't fit, or scrollable on desktop */}
          {event.materials && event.materials.length > 0 && (
            <div className="hidden lg:block p-6 bg-zinc-950">
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <FileText size={20} className="text-brand-red" />
                Materiais de Apoio
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {event.materials.map((material) => (
                  <a
                    key={material.id}
                    href={material.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="bg-zinc-900 p-4 rounded-xl border border-zinc-800 hover:border-zinc-700 transition-colors flex items-start gap-3 group"
                  >
                    <div className="p-2 bg-zinc-800 rounded-lg shrink-0 group-hover:bg-zinc-700 transition-colors">
                      <FileText size={20} className="text-zinc-300" />
                    </div>
                    <div className="min-w-0">
                      <h4 className="text-white font-medium truncate text-sm" title={material.title}>
                        {material.title}
                      </h4>
                      <span className="text-xs text-brand-red mt-1 inline-block">Baixar arquivo</span>
                    </div>
                  </a>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Right Column: Chat */}
        <div className="w-full lg:w-1/3 xl:w-1/4 bg-zinc-950 flex flex-col flex-1 lg:h-auto border-t lg:border-t-0 lg:border-l border-zinc-800 overflow-hidden">
          {event.isChatEnabled ? (
            <StudentLiveChat 
              eventId={event.id} 
              status={event.status} 
              isChatBlocked={isChatBlocked} 
            />
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center p-6 text-center">
              <div className="w-12 h-12 bg-zinc-900 rounded-full flex items-center justify-center mb-4">
                <VideoOff size={24} className="text-zinc-500" />
              </div>
              <h3 className="text-white font-bold mb-2">Chat Desativado</h3>
              <p className="text-zinc-500 text-sm">O chat não está disponível para este evento.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { classService } from '../../../services/classService';
import { courseService } from '../../../services/courseService';
import { classScheduleService } from '../../../services/classScheduleService';
import { curriculumService } from '../../../services/curriculumService';
import { Class } from '../../../types/class';
import { OnlineCourse, CourseModule } from '../../../types/course';
import { ArrowLeft, Calendar, GraduationCap, BookOpen, ChevronDown, Radio, Video, Clock, Play } from 'lucide-react';
import { StudentClassSchedule } from '../../../components/student/presential/StudentClassSchedule';
import { StudentModuleCard } from '../../../components/student/courses/StudentModuleCard';
import { CoursePlayer } from '../../../components/student/courses/player/CoursePlayer';
import { StudentPedagogicalPlanning } from '../../../components/student/presential/StudentPedagogicalPlanning';
import { ConcursoStatusBanner } from '../../../components/student/presential/ConcursoStatusBanner';
import { liveEventService } from '../../../services/liveEventService';
import { LiveEvent } from '../../../types/liveEvent';

export const StudentPresentialDetails: React.FC = () => {
  const { classId } = useParams<{ classId: string }>();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const moduleIdParam = searchParams.get('module');

  const [currentClass, setCurrentClass] = useState<Class | null>(null);
  const [activeTab, setActiveTab] = useState<'SCHEDULE' | 'PLANNING' | 'TEACHING' | 'LIVE'>('TEACHING');
  const [loading, setLoading] = useState(true);
  const [classLiveEvents, setClassLiveEvents] = useState<LiveEvent[]>([]);

  // Tab availability flags
  const [hasModules, setHasModules] = useState(false);
  const [hasSchedule, setHasSchedule] = useState(false);
  const [hasPlanning, setHasPlanning] = useState(false);

  // Teaching Tab State
  const [modules, setModules] = useState<CourseModule[]>([]);
  const [selectedModule, setSelectedModule] = useState<CourseModule | null>(null);
  const [loadingModules, setLoadingModules] = useState(false);

  const tabs = React.useMemo(() => [
    { id: 'TEACHING', label: 'ÁREA DE ENSINO', icon: GraduationCap, show: hasModules },
    { id: 'SCHEDULE', label: 'CRONOGRAMA', icon: Calendar, show: hasSchedule },
    { id: 'PLANNING', label: 'PLANEJAMENTO PEDAGÓGICO', icon: BookOpen, show: hasPlanning },
    { id: 'LIVE', label: '🔴 EVENTOS AO VIVO', icon: Radio, show: classLiveEvents.length > 0 },
  ].filter(tab => tab.show), [hasModules, hasSchedule, hasPlanning, classLiveEvents]);

  useEffect(() => {
    const fetchClass = async () => {
      if (classId) {
        try {
          const data = await classService.getClassById(classId);
          if (data) {
            setCurrentClass(data);

            // Check content availability in parallel
            const [modulesData, eventsData, subjectsData, liveEventsData] = await Promise.all([
              courseService.getModules(classId),
              classScheduleService.getScheduleEventsByClass(classId),
              curriculumService.getSubjectsByClass(classId),
              liveEventService.getLiveEventsByPresentialClass(classId)
            ]);

            const hModules = modulesData.length > 0;
            const hSchedule = eventsData.length > 0;
            const hPlanning = subjectsData.length > 0;
            const hLive = liveEventsData.length > 0;

            setHasModules(hModules);
            setHasSchedule(hSchedule);
            setHasPlanning(hPlanning);
            setModules(modulesData);
            setClassLiveEvents(liveEventsData);

            // Adjust active tab if current one is hidden
            const availableIds = [
              ...(hModules ? ['TEACHING'] : []),
              ...(hSchedule ? ['SCHEDULE'] : []),
              ...(hPlanning ? ['PLANNING'] : []),
              ...(hLive ? ['LIVE'] : [])
            ];

            if (availableIds.length > 0 && !availableIds.includes(activeTab)) {
              setActiveTab(availableIds[0] as any);
            }
          }
        } catch (error) {
          console.error("Error fetching class:", error);
        } finally {
          setLoading(false);
        }
      }
    };

    fetchClass();
  }, [classId]);

  useEffect(() => {
    const fetchModules = async () => {
      if (activeTab === 'TEACHING' && currentClass) {
        setLoadingModules(true);
        try {
          const data = await courseService.getModules(currentClass.id);
          setModules(data);
        } catch (error) {
          console.error("Error fetching modules:", error);
        } finally {
          setLoadingModules(false);
        }
      }
    };

    fetchModules();
  }, [activeTab, currentClass]);

  // Deep Linking: Switch to Teaching tab if module param is present, or Planning if tab param is present
  useEffect(() => {
    if (moduleIdParam) {
      setActiveTab('TEACHING');
    }
    const tabParam = searchParams.get('tab');
    if (tabParam?.toUpperCase() === 'PLANNING') {
      setActiveTab('PLANNING');
    }
  }, [moduleIdParam, searchParams]);

  // Deep Linking: Auto-select module when modules are loaded
  useEffect(() => {
    if (moduleIdParam && modules.length > 0 && activeTab === 'TEACHING' && !selectedModule) {
      const module = modules.find(m => m.id === moduleIdParam);
      if (module) {
        setSelectedModule(module);
      }
    }
  }, [moduleIdParam, modules, activeTab, selectedModule]);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-950">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-500"></div>
      </div>
    );
  }

  if (!currentClass) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-gray-950 text-white">
        <h2 className="text-2xl font-bold mb-4">Turma não encontrada</h2>
        <button 
          onClick={() => navigate('/app/presential')}
          className="px-4 py-2 bg-emerald-600 rounded-lg hover:bg-emerald-700 transition-colors"
        >
          Voltar para Turmas
        </button>
      </div>
    );
  }

  // Adapter to use CoursePlayer with Class data
  const fakeCourse: OnlineCourse = {
    id: currentClass.id,
    title: currentClass.name,
    coverUrl: currentClass.coverImage,
    bannerUrlDesktop: currentClass.bannerUrlDesktop,
    bannerUrlTablet: currentClass.bannerUrlTablet,
    bannerUrlMobile: currentClass.bannerUrlMobile,
    categoryId: currentClass.category,
    subcategoryId: currentClass.subcategory,
    organization: currentClass.organization,
    createdAt: currentClass.createdAt || new Date().toISOString(),
    updatedAt: currentClass.updatedAt || new Date().toISOString(),
    active: true
  };

  return (
    <div className="min-h-screen bg-black text-gray-100 pb-20">
      {/* --- BANNER RESPONSIVO --- */}
      <div className="relative w-full bg-zinc-900">
        <button 
          onClick={() => navigate('/app/presential')}
          className="absolute top-4 left-4 z-10 p-2 bg-black/50 hover:bg-black/70 rounded-full text-white transition-colors backdrop-blur-sm"
        >
          <ArrowLeft size={24} />
        </button>

        <picture>
          <source 
            media="(min-width: 1024px)" 
            srcSet={currentClass.bannerUrlDesktop || currentClass.coverImage} 
          />
          <source 
            media="(min-width: 768px)" 
            srcSet={currentClass.bannerUrlTablet || currentClass.bannerUrlDesktop || currentClass.coverImage} 
          />
          <img 
            src={currentClass.bannerUrlMobile || currentClass.coverImage} 
            alt={`Banner da turma ${currentClass.name}`} 
            className="w-full h-48 md:h-[400px] object-cover border-b border-red-600/30 shadow-lg"
          />
        </picture>

        <div className="absolute bottom-0 left-0 w-full bg-gradient-to-t from-black to-transparent h-24 md:h-32 pointer-events-none"></div>
      </div>

      <div className="max-w-7xl mx-auto px-4 pt-6">
        <ConcursoStatusBanner classData={currentClass} />
      </div>

      {/* --- NAVEGAÇÃO DE ABAS --- */}
      <div className="sticky top-0 z-20 bg-black/95 backdrop-blur-md border-b border-zinc-800 shadow-md">
        <div className="max-w-7xl mx-auto px-4">
          {/* Desktop Tabs Navigation */}
          <div className="hidden md:flex items-center space-x-8 overflow-x-auto no-scrollbar py-2">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center space-x-2 px-4 py-3 text-base font-medium transition-colors whitespace-nowrap border-b-2 ${
                  activeTab === tab.id 
                    ? 'border-red-600 text-red-600' 
                    : 'border-transparent text-zinc-400 hover:text-white hover:border-zinc-700'
                }`}
              >
                <tab.icon size={18} />
                <span>{tab.label}</span>
              </button>
            ))}
          </div>

          {/* Mobile Select Navigation */}
          <div className="md:hidden flex justify-center py-3">
            {tabs.length > 0 && (
              <div className="relative w-full max-w-[280px]">
                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-red-600 pointer-events-none">
                  {React.createElement(tabs.find(t => t.id === activeTab)?.icon || GraduationCap, { size: 18 })}
                </div>
                <select
                  value={activeTab}
                  onChange={(e) => setActiveTab(e.target.value as any)}
                  className="w-full bg-zinc-900 border border-zinc-800 text-white rounded-lg pl-10 pr-10 py-2.5 text-sm font-bold appearance-none focus:outline-none focus:ring-1 focus:ring-red-600/50"
                >
                  {tabs.map((tab) => (
                    <option key={tab.id} value={tab.id}>
                      {tab.label}
                    </option>
                  ))}
                </select>
                <div className="absolute right-3 top-1/2 -translate-y-1/2 text-zinc-500 pointer-events-none">
                  <ChevronDown size={16} />
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* --- ÁREA DE CONTEÚDO --- */}
      <div className="max-w-7xl mx-auto px-4 mt-6 md:mt-8">
        {activeTab === 'TEACHING' && (
          selectedModule ? (
            <CoursePlayer 
              course={fakeCourse} 
              module={selectedModule} 
              onBack={() => setSelectedModule(null)} 
            />
          ) : (
            loadingModules ? (
              <div className="flex gap-4 overflow-hidden">
                {[1,2,3].map(i => <div key={i} className="w-60 h-[300px] bg-gray-900 rounded-lg animate-pulse" />)}
              </div>
            ) : (
              <div className="space-y-6">
                <h3 className="text-xl font-semibold text-gray-200 flex items-center">
                  <GraduationCap className="mr-2 text-red-500" />
                  Módulos de Ensino
                </h3>

                {modules.length === 0 ? (
                  <div className="p-8 text-center bg-gray-900/50 rounded-xl border border-gray-800 text-gray-500">
                    Nenhum módulo disponível para esta turma.
                  </div>
                ) : (
                  <div className="flex gap-6 overflow-x-auto pb-8 scrollbar-thin scrollbar-thumb-red-900 scrollbar-track-transparent px-1">
                    {modules.map(module => (
                      <StudentModuleCard 
                        key={module.id} 
                        module={module} 
                        onClick={setSelectedModule} 
                      />
                    ))}
                  </div>
                )}
              </div>
            )
          )
        )}

        {activeTab === 'SCHEDULE' && (
          <StudentClassSchedule classId={currentClass.id} />
        )}

        {activeTab === 'PLANNING' && (
          <StudentPedagogicalPlanning 
            classId={currentClass.id} 
            totalMeetings={currentClass.totalMeetings}
          />
        )}

        {activeTab === 'LIVE' && classLiveEvents.length > 0 && (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {classLiveEvents.map((event) => (
                <div 
                  key={event.id} 
                  className="bg-zinc-900 rounded-2xl border border-zinc-800 overflow-hidden flex flex-col group hover:border-zinc-700 transition-colors"
                >
                  {/* Thumbnail */}
                  <div className="relative aspect-video bg-zinc-800">
                    {event.thumbnailUrl ? (
                      <img 
                        src={event.thumbnailUrl} 
                        alt={event.title} 
                        className="w-full h-full object-cover"
                        referrerPolicy="no-referrer"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-zinc-600">
                        <Video size={48} />
                      </div>
                    )}

                    {/* Status Badge */}
                    <div className="absolute top-3 right-3">
                      <span className={`px-3 py-1 rounded-full text-[10px] font-black tracking-widest uppercase shadow-lg ${
                        event.status === 'live' ? 'bg-red-600 text-white animate-pulse' :
                        event.status === 'scheduled' ? 'bg-blue-600 text-white' :
                        'bg-zinc-800 text-zinc-400'
                      }`}>
                        {event.status === 'live' ? 'AO VIVO AGORA' : event.status === 'scheduled' ? 'AGENDADO' : 'ENCERRADO'}
                      </span>
                    </div>
                  </div>

                  {/* Content */}
                  <div className="p-5 flex flex-col flex-1">
                    <h3 className="text-lg font-bold text-white mb-1 line-clamp-2">{event.title}</h3>
                    {event.subtitle && (
                      <p className="text-zinc-400 text-sm mb-4 line-clamp-2">{event.subtitle}</p>
                    )}

                    <div className="mt-auto space-y-2 mb-6">
                      <div className="flex items-center gap-2 text-zinc-300 text-sm">
                        <Calendar size={16} className="text-zinc-500" />
                        <span>{event.eventDate.split('-').reverse().join('/')}</span>
                      </div>
                      <div className="flex items-center gap-2 text-zinc-300 text-sm">
                        <Clock size={16} className="text-zinc-500" />
                        <span>{event.startTime}</span>
                      </div>
                    </div>

                    <button
                      onClick={() => navigate(`/app/eventos-ao-vivo/sala/${event.id}`)}
                      className={`w-full py-3 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all ${
                        event.status === 'live' 
                          ? 'bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-900/20' 
                          : 'bg-zinc-800 hover:bg-zinc-700 text-white'
                      }`}
                    >
                      {event.status === 'live' ? (
                        <>
                          <Play size={18} fill="currentColor" />
                          ACESSAR SALA DE TRANSMISSÃO
                        </>
                      ) : (
                        'VER DETALHES DO EVENTO'
                      )}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import express from 'express';
import { createServer as createViteServer } from 'vite';
import path from 'path';
import { fileURLToPath } from 'url';
import { fetchPandaVideoTranscription } from './src/backend/services/pandaVideoService.js';
import { generateStudyMaterial } from './src/backend/services/geminiService.js';
import { getAdminConfig } from './src/backend/services/firebaseAdmin.js';
import { provisionTictoPurchase, revokeTictoPurchase } from './src/backend/services/provisioningService.js';

// const __filename = fileURLToPath(import.meta.url);
// __dirname is not used in this file, but kept for reference if needed
// const __dirname = path.dirname(__filename);

interface PandaFolder {
  id: string;
  name: string;
  title?: string;
  parent_id?: string | null;
  parent_folder_id?: string | null;
  parentId?: string | null;
}

interface PandaVideo {
  id: string;
  video_id?: string;
  title: string;
  name?: string;
  folder_id?: string | null;
  folderId?: string | null;
  video_player_url?: string;
  embed_url?: string;
  length?: number;
}

interface UserAccess {
  type: string;
  targetId: string;
  isActive: boolean;
  id?: string | number;
  endDate?: any;
  startDate?: any;
}

interface StudentProfile {
  id: string;
  userId: string;
  userName: string;
  userEmail: string;
  userPhone: string;
  userCpf: string;
  userAvatar: string;
  enrollmentType?: string;
  accessOrigin?: string;
  expiresAt?: string | null;
  releasedAt?: string | null;
  active?: boolean;
  createdAt?: any;
}

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Middleware para JSON
  app.use(express.json());

  // Nota: As rotas /api/generate-material, /api/panda-videos, /api/panda-explorer, /api/webhooks/ticto
  // e /api/admin/courses/:courseId/students foram migradas para Vercel Serverless Functions na pasta /api.
  // Elas são mantidas aqui apenas para compatibilidade com o ambiente de desenvolvimento local.

  // Rota de API: /api/generate-material
  app.post('/api/generate-material', async (req, res) => {
    try {
      const { lessonIds, folderTitle } = req.body;

      if (!lessonIds || !Array.isArray(lessonIds) || lessonIds.length === 0) {
        return res.status(400).json({ success: false, error: 'IDs das aulas (lessonIds) são obrigatórios.' });
      }

      if (!folderTitle) {
        return res.status(400).json({ success: false, error: 'folderTitle é obrigatório.' });
      }

      const { dbAdmin } = getAdminConfig();
      const pandaVideoIds: string[] = [];

      for (const lessonId of lessonIds) {
        try {
          const snapshot = await dbAdmin.collection('course_contents')
            .where('lessonId', '==', lessonId)
            .get();

          snapshot.docs.forEach(doc => {
            const data = doc.data();
            if (data.type === 'video' && data.videoPlatform === 'panda' && data.videoUrl) {
              const pandaId = extractPandaId(data.videoUrl);
              if (pandaId && !pandaVideoIds.includes(pandaId)) {
                pandaVideoIds.push(pandaId);
              }
            }
          });
        } catch (err) {
          console.error(`Erro ao buscar conteúdos da aula ${lessonId}:`, err);
        }
      }

      if (pandaVideoIds.length === 0) {
        return res.status(404).json({ 
          success: false, 
          error: 'Nenhum vídeo do Panda Video encontrado nas aulas selecionadas.' 
        });
      }

      let fullTranscription = '';
      for (const videoId of pandaVideoIds) {
        try {
          const transcription = await fetchPandaVideoTranscription(videoId);
          fullTranscription += transcription + '\n\n';
        } catch (error) {
          console.error(`Erro ao extrair transcrição do vídeo ${videoId}:`, error);
        }
      }

      if (!fullTranscription.trim()) {
        return res.status(404).json({ 
          success: false, 
          error: 'Não foi possível extrair nenhuma transcrição dos vídeos selecionados.' 
        });
      }

      const generatedText = await generateStudyMaterial(fullTranscription, folderTitle);

      return res.status(200).json({ 
        success: true, 
        markdown: generatedText 
      });

    } catch (error) {
      console.error("Erro na rota de geração de material:", error);
      return res.status(500).json({ 
        success: false, 
        error: error instanceof Error ? error.message : "Erro interno no servidor." 
      });
    }
  });

  // Rota de Listagem de Vídeos do Panda com Busca
  app.get('/api/panda-videos', async (req, res) => {
    try {
      const apiKey = process.env.PANDA_API_KEY;
      const search = req.query.search as string;

      let url = 'https://api-v2.pandavideo.com.br/videos?limit=1000';
      if (search) {
        url += `&title=${encodeURIComponent(search)}`;
      }

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Authorization': apiKey,
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Erro na API do Panda: ${response.status}`);
      }

      const data = await response.json();
      const videos = data.videos || data || [];

      // Retorna ID, Título e URL de Embed se disponível
      const cleanVideos = Array.isArray(videos) ? videos.map((v: any) => ({
        id: v.id,
        video_id: v.video_id || v.id,
        panda_id: v.video_id || v.id,
        external_id: v.external_id || null,
        playback_id: v.playback_id || null,
        title: v.title || v.name || 'Sem título',
        video_player_url: v.video_player_url || v.embed_url || null,
        length: v.length || 0,
        folder_id: v.folder_id || v.folderId || null
      })) : [];

      return res.status(200).json({ success: true, videos: cleanVideos });
    } catch (error) {
      console.error("Erro ao listar vídeos do Panda:", error);
      return res.status(500).json({ success: false, error: "Falha ao carregar vídeos do Panda." });
    }
  });

  // Rota de Detalhes de um Vídeo do Panda
  app.get('/api/panda-video-details', async (req, res) => {
    try {
      const apiKey = process.env.PANDA_API_KEY;
      const videoId = req.query.id as string;

      if (!videoId) {
        return res.status(400).json({ success: false, error: "ID do vídeo é obrigatório." });
      }

      const url = `https://api-v2.pandavideo.com.br/videos/${videoId}`;

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Authorization': apiKey,
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Erro na API do Panda: ${response.status}`);
      }

      const video = await response.json();
      return res.status(200).json({ success: true, video });
    } catch (error) {
      console.error("Erro ao buscar detalhes do vídeo do Panda:", error);
      return res.status(500).json({ success: false, error: "Falha ao carregar detalhes do vídeo do Panda." });
    }
  });

  // Rota de Alunos do Curso (Admin)
  app.get('/api/admin/courses/:courseId/students', async (req, res) => {
    try {
      const { courseId } = req.params;
      const { dbAdmin } = getAdminConfig();

      // 1. Busca Matrículas Diretas (Coleção course_enrollments)
      const directEnrollmentsSnap = await dbAdmin.collection('course_enrollments')
        .where('courseId', '==', courseId)
        .get();

      const directEnrollments = directEnrollmentsSnap.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));

      // 2. Busca Alunos para verificar acesso via Combo (Coleção users -> array access)
      const studentsSnap = await dbAdmin.collection('users')
        .where('role', '==', 'student')
        .get();

      const studentMap = new Map<string, StudentProfile>();

      // Parte A: Processar alunos que ganharam acesso via Combo/Produto
      studentsSnap.docs.forEach(doc => {
        const userData = doc.data();
        const accessArray: UserAccess[] = userData.access || [];

        const courseAccess = accessArray.find((acc: UserAccess) => 
          acc.type === 'course' && 
          acc.targetId === courseId && 
          acc.isActive === true
        );

        if (courseAccess) {
          studentMap.set(doc.id, {
            id: doc.id,
            userId: doc.id,
            userName: userData.name || userData.displayName || 'Sem Nome',
            userEmail: userData.email || '',
            userPhone: userData.phone || userData.whatsapp || userData.contact || '',
            userCpf: userData.cpf || '',
            userAvatar: userData.photoURL || '',
            enrollmentType: (courseAccess.id && String(courseAccess.id).startsWith('mig_')) ? 'MIGRACAO' : 'REGULAR',
            accessOrigin: (courseAccess.id && String(courseAccess.id).startsWith('mig_')) ? 'MIGRATION' : 'COMBO',
            expiresAt: courseAccess.endDate ? (courseAccess.endDate.toDate ? courseAccess.endDate.toDate().toISOString() : courseAccess.endDate) : null,
            releasedAt: courseAccess.startDate ? (courseAccess.startDate.toDate ? courseAccess.startDate.toDate().toISOString() : courseAccess.startDate) : (userData.createdAt?.toDate ? userData.createdAt.toDate().toISOString() : userData.createdAt),
            active: courseAccess.isActive !== false
          });
        }
      });

      // Parte B: Processar Matrículas Diretas
      for (const enrollment of directEnrollments) {
        const userId = (enrollment as { userId?: string }).userId;
        if (!userId) continue;

        let userProfile = studentMap.get(userId);

        if (!userProfile) {
          const userDoc = studentsSnap.docs.find(d => d.id === userId);
          if (userDoc) {
            const userData = userDoc.data();
            userProfile = { 
              id: userDoc.id,
              userId: userDoc.id,
              userName: userData.name || userData.displayName || 'Sem Nome',
              userEmail: userData.email || '',
              userPhone: userData.phone || userData.whatsapp || userData.contact || '',
              userCpf: userData.cpf || '',
              userAvatar: userData.photoURL || '',
              createdAt: userData.createdAt
            };
          } else {
            const docRef = await dbAdmin.collection('users').doc(userId).get();
            if (docRef.exists) {
              const userData = docRef.data() || {};
              userProfile = { 
                id: docRef.id,
                userId: docRef.id,
                userName: userData.name || userData.displayName || 'Sem Nome',
                userEmail: userData.email || '',
                userPhone: userData.phone || userData.whatsapp || userData.contact || '',
                userCpf: userData.cpf || '',
                userAvatar: userData.photoURL || '',
                createdAt: userData.createdAt
              };
            }
          }
        }

        if (userProfile) {
          const enrollmentData = enrollment as { 
            enrollmentType?: string; 
            expiresAt?: any; 
            releasedAt?: any; 
            createdAt?: any; 
            active?: boolean; 
          };
          studentMap.set(userId, {
            ...userProfile,
            enrollmentType: enrollmentData.enrollmentType || 'REGULAR',
            accessOrigin: 'DIRECT',
            expiresAt: enrollmentData.expiresAt ? (enrollmentData.expiresAt.toDate ? enrollmentData.expiresAt.toDate().toISOString() : enrollmentData.expiresAt) : null,
            releasedAt: enrollmentData.releasedAt ? (enrollmentData.releasedAt.toDate ? enrollmentData.releasedAt.toDate().toISOString() : enrollmentData.releasedAt) : (enrollmentData.createdAt ? (enrollmentData.createdAt.toDate ? enrollmentData.createdAt.toDate().toISOString() : enrollmentData.createdAt) : (userProfile.createdAt?.toDate ? userProfile.createdAt.toDate().toISOString() : userProfile.createdAt)),
            active: enrollmentData.active !== false
          });
        }
      }

      const aggregatedStudents = Array.from(studentMap.values());

      return res.status(200).json({ success: true, students: aggregatedStudents });
    } catch (error) {
      console.error("Erro ao buscar alunos do curso:", error);
      return res.status(500).json({ success: false, error: "Erro ao buscar alunos." });
    }
  });

  // Rota de Explorer do Panda (Pastas e Vídeos Hierárquicos)
  app.get('/api/panda-explorer', async (req, res) => {
    try {
      const apiKey = process.env.PANDA_API_KEY;
      const folderId = req.query.folderId as string | undefined;

      // URLs para pastas e vídeos
      // Buscamos todas as pastas para filtrar em memória (hierarquia cega)
      // Para vídeos, buscamos com limite alto para garantir que pegamos os da pasta ou da raiz
      const foldersUrl = 'https://api-v2.pandavideo.com.br/folders';
      let videosUrl = 'https://api-v2.pandavideo.com.br/videos?limit=1000';

      // Se tivermos um folderId, podemos tentar otimizar a busca de vídeos na API, 
      // mas manteremos o filtro em memória para garantir a hierarquia correta
      if (folderId && folderId !== 'root' && folderId !== 'null') {
        videosUrl += `&folder_id=${folderId}`;
      }

      const headers = {
        'Authorization': apiKey,
        'Accept': 'application/json'
      };

      // Requisições paralelas
      const [foldersRes, videosRes] = await Promise.all([
        fetch(foldersUrl, { method: 'GET', headers }),
        fetch(videosUrl, { method: 'GET', headers })
      ]);

      if (!foldersRes.ok || !videosRes.ok) {
        throw new Error(`Erro na API do Panda: F:${foldersRes.status} V:${videosRes.status}`);
      }

      const foldersData = await foldersRes.json();
      const videosData = await videosRes.json();

      const foldersArray: PandaFolder[] = foldersData.folders || (Array.isArray(foldersData) ? foldersData : []);
      const videosArray: PandaVideo[] = videosData.videos || (Array.isArray(videosData) ? videosData : []);

      const targetFolderId = req.query.folderId as string | undefined;
      const isRoot = !targetFolderId || targetFolderId === 'root' || targetFolderId === 'null' || targetFolderId === '';

      // Filtro Rigoroso de Hierarquia para Pastas com checagem defensiva de propriedades
      const strictFolders = foldersArray.filter((folder: PandaFolder) => {
        // O Panda pode usar diferentes nomenclaturas. Capturamos todas:
        const parentId = folder.parent_folder_id || folder.parent_id || folder.parentId || null;

        if (isRoot) {
          // Estamos na RAIZ. Só queremos pastas "órfãs" (sem pai)
          return !parentId || parentId === 'null' || parentId === '';
        } else {
          // Estamos dentro de uma pasta. Só queremos as filhas dela
          return String(parentId) === String(targetFolderId);
        }
      });

      // Ordenação alfabética das pastas
      strictFolders.sort((a, b) => (a.name || a.title || '').localeCompare(b.name || b.title || ''));

      const folders = strictFolders.map((f) => ({
        id: f.id,
        name: f.name || f.title || 'Pasta sem nome'
      }));

      // Filtro Rigoroso de Hierarquia para Vídeos
      const strictVideos = videosArray.filter((video: PandaVideo) => {
        const videoFolderId = video.folder_id || video.folderId || null;
        if (isRoot) {
          // Se estamos na RAIZ, só queremos vídeos que NÃO estejam em nenhuma pasta
          return !videoFolderId || videoFolderId === 'null' || videoFolderId === '';
        } else {
          // Se estamos dentro de uma pasta, só queremos os vídeos dela
          return String(videoFolderId) === String(targetFolderId);
        }
      });

      // Ordenação alfabética dos vídeos
      strictVideos.sort((a, b) => (a.title || a.name || '').localeCompare(b.title || b.name || ''));

      const videos = strictVideos.map((v: any) => ({
        id: v.id,
        video_id: v.video_id || v.id,
        panda_id: v.video_id || v.id,
        external_id: v.external_id || null,
        playback_id: v.playback_id || null,
        title: v.title || v.name || 'Sem título',
        video_player_url: v.video_player_url || v.embed_url || null,
        length: v.length || 0,
        folder_id: v.folder_id || v.folderId || null
      }));

      return res.status(200).json({ success: true, folders, videos });
    } catch (error) {
      console.error("Erro no Explorer do Panda:", error);
      return res.status(500).json({ success: false, error: "Falha ao navegar no Panda Video." });
    }
  });

  // Rota de Webhook: /api/webhooks/ticto
  app.post('/api/webhooks/ticto', async (req, res) => {
    try {
      const payload = req.body || {};
      const incomingStatus = payload?.status;
      const incomingProductId = payload?.item?.product_id;
      const incomingToken = payload?.token;

      if (incomingStatus === 'waiting_payment' || incomingProductId === 1 || incomingProductId === '1') {
        return res.status(200).json({ received: true, message: "Teste Ticto Aprovado" });
      }

      const tictoToken = "Zbi2TLCWBPbYJU1Xz14JF7gt8LGm8LQ0tNfMzGcu0US35mR56ye4PFU44We9c5eHcYU6wDzNxNOkx13UDWsVd7FHzI1brmjRrt0i";
      if (incomingToken !== tictoToken) {
        return res.status(401).json({ error: 'Unauthorized' });
      }

      const { status, customer, item } = payload;
      console.log(`Webhook Ticto Recebido - Status: ${status} | Email: ${customer?.email} | Produto ID: ${item?.product_id}`);

      if (status === 'approved' || status === 'paid' || status === 'authorized') {
        await provisionTictoPurchase(customer, String(item.product_id));
      } else if (['refunded', 'chargeback', 'canceled', 'overdue'].includes(status)) {
        await revokeTictoPurchase(customer?.email, String(item.product_id));
      } else {
        console.log(`Status '${status}' ignorado. Nenhuma ação de provisionamento necessária.`);
      }

      return res.status(200).json({ received: true });
    } catch (error) {
      console.error("Webhook Error:", error);
      return res.status(200).json({ received: true, error: "Internal Error" });
    }
  });

  // Função auxiliar extractPandaId
  function extractPandaId(url: string): string | null {
    try {
      if (!url) return null;
      if (!url.includes('http')) return url.split('?v=')[1] || url.split('/embed/')[1] || url.split('/video/')[1] || url;

      const urlObj = new URL(url);
      const v = urlObj.searchParams.get('v');
      if (v) return v;

      const pathParts = urlObj.pathname.split('/').filter(Boolean);
      // Se a URL for do tipo .../embed/ID ou .../video/ID
      if (url.includes('/embed/') || url.includes('/video/')) {
        return pathParts[pathParts.length - 1];
      }

      return pathParts[pathParts.length - 1] || url;
    } catch (_) {
      return url;
    }
  }

  // Vite middleware para desenvolvimento
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
