// Batch Upload Logic
export const uploadBatchMetaFiles = async (
  planId: string, 
  files: { name: string; file?: File; url?: string }[]
): Promise<MaterialFile[]> => {

  const promises = files.map(async (item) => {
    // Se já tem URL, mantém
    if (item.url) {
      return { name: item.name, url: item.url };
    }
    // Se tem arquivo novo, faz upload
    if (item.file) {
      const url = await uploadMetaFile(planId, item.file);
      return { name: item.name, url };
    }
    return null;
  });

  const results = await Promise.all(promises);
  return results.filter((r): r is MaterialFile => r !== null);
};

// === REORDER ===

export const reorderMeta = async (
  ids: { planId: string; discId: string; topicId: string },
  items: Meta[],
  index: number,
  direction: 'up' | 'down'
) => {
  if (direction === 'up' && index === 0) return;
  if (direction === 'down' && index === items.length - 1) return;

  const targetIndex = direction === 'up' ? index - 1 : index + 1;
  const currentItem = items[index];
  const targetItem = items[targetIndex];

  if (!currentItem.id || !targetItem.id) return;

  const path = getCollectionPath(ids.planId, ids.discId, ids.topicId);
  const batch = writeBatch(db);

  const ref1 = doc(db, path, currentItem.id);
  const ref2 = doc(db, path, targetItem.id);

  batch.update(ref1, { order: targetItem.order ?? 0 });
  batch.update(ref2, { order: currentItem.order ?? 0 });

  await batch.commit();
  await touchPlan(ids.planId);
};

/**
 * Atualiza a ordem de todas as metas em lote (Batch Update).
 * Corrige índices duplicados e garante consistência total.
 */
export const reorderMetasBatch = async (
  ids: { planId: string; discId: string; topicId: string },
  items: Meta[]
) => {
  const path = getCollectionPath(ids.planId, ids.discId, ids.topicId);
  const batch = writeBatch(db);

  items.forEach((item, index) => {
    if (item.id) {
        const ref = doc(db, path, item.id);
        batch.update(ref, { order: index });
    }
  });

  await batch.commit();
  await touchPlan(ids.planId);
};

/**
 * Panda Video Frontend Service
 * Handles API calls to Panda Video via the Backend routes (/api/panda-videos, /api/panda-explorer)
 */

import { PandaVideo } from '../utils/pandaUtils';

export const pandaService = {
  /**
   * List videos from Panda Video (via Backend)
   * @param search Optional search term
   * @returns List of videos
   */
  async listVideos(search: string = ''): Promise<PandaVideo[]> {
    try {
      const url = `/api/panda-videos?search=${encodeURIComponent(search)}`;

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Erro na API do Backend: ${response.status}`);
      }

      const data = await response.json();
      return data.videos || [];
    } catch (error) {
      console.error("Erro ao listar vídeos do Panda:", error);
      throw error;
    }
  },

  /**
   * List folders and videos from Panda Video (Explorer via Backend)
   * @param folderId Optional folder ID
   * @returns Folders and videos
   */
  async explorer(folderId: string | null = null): Promise<{ folders: any[], videos: PandaVideo[] }> {
    try {
      let url = '/api/panda-explorer';
      if (folderId && folderId !== 'root' && folderId !== 'null') {
        url += `?folderId=${folderId}`;
      }

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Erro na API do Backend: ${response.status}`);
      }

      const data = await response.json();
      return {
        folders: data.folders || [],
        videos: data.videos || []
      };
    } catch (error) {
      console.error("Erro no Explorer do Panda:", error);
      throw error;
    }
  },

  /**
   * Get details of a single video from Panda Video (via Backend)
   * @param videoId The ID of the video
   * @returns Full video details
   */
  async getVideoDetails(videoId: string): Promise<PandaVideo> {
    try {
      const url = `/api/panda-video-details?id=${videoId}`;

      const response = await fetch(url, {
        method: 'GET',
        headers: {
          'Accept': 'application/json'
        }
      });

      if (!response.ok) {
        throw new Error(`Erro na API do Backend: ${response.status}`);
      }

      const data = await response.json();
      return data.video;
    } catch (error) {
      console.error("Erro ao buscar detalhes do vídeo do Panda:", error);
      throw error;
    }
  }
};

